window.BEAUBIRD_BIRD_PROFILE_SHARDS = window.BEAUBIRD_BIRD_PROFILE_SHARDS || {};
window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-030.json"] = [{"name":"短须寻蜜鸟","english_name":"Short-bearded Honeyeater","scientific_name":"Melionyx nouhuysi","overview":"短须寻蜜鸟（英文名：Short-bearded Honeyeater，学名：Melionyx nouhuysi），是雀形目吸蜜鸟科Melionyx的鸟类。在西巴布亚地区的特有鸟类。其最显著的外部特征是全身上下的灰黑色羽毛，腹部略带褐色调，喉部有白色的短须状羽毛形成独特的‘胡须’。该鸟种广泛分布在新几内亚西部的中央山脉高海拔森林地带。","appearance":"短须寻蜜鸟体长约27至27.5厘米，通体呈现暗黑褐色，腹部边缘带褐色，眼后有一片黄色至金黄色裸露皮肤。尾部尖端模糊白色，喉部有白色羽毛形成短而突出的‘胡须’，胸部、腹部和肛周有不同程度的灰色斑点，下尾覆羽淡黄褐色。虹膜深棕色至深红棕色，喙黑色，腿色浅蓝灰色。雄鸟体型大于雌鸟，幼鸟特征未详。","call":"在雪山区，发出低沉的‘chsh’声，快速重复4到6次，以及在相互追逐时重复发出甜美的‘swee’声。在星山区，叫声包括金属质感的‘pwik’声和飞行中的细薄‘weet-weet’声。","habits":"生活在开放的高山森林、森林边缘以及高山草甸附近的灌木丛中，海拔高度在3050米至4500米之间。以果实、种子、昆虫和花蜜为食，主要在灌木或地面觅食，也会在树冠层活动。性格隐秘但不胆小。","breeding":"已知巢穴位于地面1.2米高的孤立灌木丛中，由苔藓、肝蕨和线状真菌构成，内部铺垫有草茎、蕨类鳞片和羽毛，主要是的羽毛。巢穴呈松散的杯状，外部直径16厘米，深度20厘米，内部直径7.5厘米，深度6厘米。","identification":"与暗寻蜜鸟相似，但短须寻蜜鸟体型更大，拥有白色的‘胡须’。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚西部的中央山脉，包括Snow和Star山脉，海拔在3050至4500米之间，通常在树木线附近或高山草甸边缘。","other":"2019年基于分子系统发育研究，短须寻蜜鸟从Melidectes属移至Melionyx属，同时更改了其通用名。"},{"name":"长须寻蜜鸟","english_name":"Long-bearded Honeyeater","scientific_name":"Melionyx princeps","overview":"长须寻蜜鸟（英文名：Long-bearded Honeyeater，学名：Melionyx princeps），是雀形目吸蜜鸟科Melionyx的鸟类。中等体型的黑色寻蜜鸟，以其独特的长白须而著称，这些须几乎延伸到折翼处。分布于新几内亚东部的亚高山森林和灌木地带，特别是在Kaijende高地、Giluwe山、Hagen山、Kubor山脉等地区。","appearance":"长须寻蜜鸟体长26.5至28.8厘米，头部、颈部及上体呈黑褐色，顶部和侧面较暗，背部和尾羽覆盖处略显暖色橄榄棕色。下巴和喉咙被长而蓬松的灰白色至白色羽毛覆盖，形成一条长“胡须”。下体暗橄榄棕色，胸部和下腹部有灰色棕色斑点，尾部下方的覆羽有淡红棕色斑纹。幼鸟的描述不详，但据说其上部为烟黑色，下部为淡黄色，尤其是腹部，胡须为暗黄白色。","call":"这种鸟并不十分鸣叫，但会发出安静的‘eh eh eh’叫声。","habits":"栖息于高海拔的苔藓森林和林地，以及亚高山草甸中的灌木丛和灌木林。主要活动范围在海拔3000至3800米之间，最高可达4200米，最低可降至2750米。生活方式似乎定居，没有迁徙迹象。以花蜜、果实和昆虫为食，通常成对或小群体活动。","breeding":"已知繁殖信息有限，仅记录到在6月至7月间有巢穴中的雏鸟和依赖父母的幼鸟。具体繁殖行为和生态细节尚不清楚。","identification":"与暗寻蜜鸟相似，但长须寻蜜鸟体型更大，拥有白色的长须，这是辨识的关键特征。","protection":"IUCN：VU（易危）。其全球种群估计较小，分布在几个地点的小范围内，且正在减少，主要由于其生境的丧失和退化。尽管在人类密集的高地，其生存可能受到火源影响，但目前没有具体的保护措施。","distribution":"长须寻蜜鸟仅分布于新几内亚东部的山区，包括Kaijende高地、Giluwe山、Hagen山、Kubor山脉、Wilhelm山、Michael山和Kratke山脉。","other":"2019年基于分子系统发育研究，该物种从Melidectes属移至复活的Melionyx属，其通用名也从'long-bearded melidectes'改为'长须寻蜜鸟。"},{"name":"山寻蜜鸟","english_name":"Gilliard's Honeyeater","scientific_name":"Vosea whitemanensis","overview":"山寻蜜鸟（英文名：Gilliard's Honeyeater，学名：Vosea whitemanensis），是雀形目吸蜜鸟科Vosea的鸟类。主要分布在新不列颠岛的山区，属于澳新界的特有种。其橄榄褐色的外表，面部颜色稍深，眼周环绕着明显的裸皮，是其显著特征。","appearance":"成年山寻蜜鸟长约22.5厘米，体重约42至49克。头部和颈部呈橄榄褐色，额头、眼周及耳羽颜色较暗，眼圈淡灰色微黄，下颚及颈侧有淡色条纹。上体橄榄褐色，肩羽黑褐，背部有淡橄榄色斑点，下背至尾上覆羽泛黄。尾羽黑色，中央尾羽及外侧边缘黄色，翼上黄绿色明显，下体橄榄褐色，胸腹微带黄色，下翼覆羽灰黄，虹膜深棕色，喙及腿深灰色。雌雄羽色相似，雌鸟略小且色彩稍逊。","call":"其叫声为一连串3至8个柔和的双音节哨音，每秒约1.4个音节，首音简单，次音稍低，带有颤音或下滑音，类似Melidectes fuscus的叫声，但更短促。","habits":"栖息于海拔900米以上的原始山林，偶尔出现在城市花园。活跃于森林中层和上层，以花蜜和节肢动物为食。在树冠下层探查红黄槲寄生花朵，动作敏捷，突然移动，常呈现杂技般的姿态，如垂直悬挂或扭曲头部以达到目标。","breeding":"关于繁殖行为的信息尚不清楚。","identification":"山寻蜜鸟的识别特征包括其橄榄褐色的体色、眼周的裸皮和下垂的长喙，以及独特的叫声。","protection":"IUCN：NT（近危）","distribution":"分布于新不列颠岛（Whiteman山脉、Nakanai山脉和Mt Talawae），位于俾斯麦群岛。主要栖息于海拔1300米以上的地区。","other":"山寻蜜鸟被怀疑比普遍认为的更为稀少，因此自2008年起其保护状态被提升至近危级别。"},{"name":"棕眉寻蜜鸟","english_name":"Cinnamon-browed Melidectes","scientific_name":"Melidectes ochromelas","overview":"棕眉寻蜜鸟（英文名：Cinnamon-browed Melidectes，学名：Melidectes ochromelas），是雀形目吸蜜鸟科寻蜜鸟属的鸟类。主要分布于新几内亚高地的山区，栖息于中海拔森林的树冠层，是该地区的特有种之一。","appearance":"成年棕眉寻蜜鸟体长约24-25厘米，体重雄鸟约61.5-65克，雌鸟约54-62.5克。头部顶部、侧面、下巴及上喉部呈棕色至黑褐色，逐渐变为暗棕色或暗橄榄棕色，带有模糊的白色鳞状斑点。背部有白色的鳞状斑纹，翼羽橄榄色，眼周有宽大的淡绿至黄绿色裸皮，耳羽后方有细条淡肉桂色条纹。喙侧有小红色或橙红色肉垂，下体为棕色或暗棕色，腹部有灰色至白色条纹或斑点，尾下覆羽为赤褐色，尾部灰棕色。眼睛颜色为深棕色至黑色，喙为浅蓝灰色，腿脚为淡至暗蓝灰色。","call":"叫声独特，通常包括连续的4-5个鼻音滑音，还有响亮下降的‘whee oo wooo’声，以及类似蓝极乐鸟的钟铃般的音符。经常二重唱，以完美的交替节奏发出鼻音滑音。","habits":"生活在低至中海拔的山地森林及森林边缘，活动范围从大约1100米到2000米，偶尔低至770米，可能高至2590米。通常单独、成对或小群体活动，也会聚集在开花树木中与其他物种共处，如红领摄蜜鸟和仙子鹦鹉（Charmosyna pulchella）。在树冠、亚树冠和森林中层寻找食物，会探查树上的苔藓。","breeding":"已知在一月份有蛋的记录，五月中旬观察到依赖性雏鸟被双亲以昆虫喂养。巢穴特征未知，其他繁殖信息缺乏。","identification":"与Belford’s和休恩寻蜜鸟相似，但棕眉寻蜜鸟缺少从喙部延伸的面部条纹。batesi亚种与指名亚种相比，眉纹更明显，下体颜色更偏向棕色，色调更少灰色；lucifer亚种头部和胸部颜色更深。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚西北部至东南部的山区，具体范围包括西巴布亚高地、阿德尔伯特山脉、休恩山脉和中央巴布亚山脉。"},{"name":"白额寻蜜鸟","english_name":"Vogelkop Melidectes","scientific_name":"Melidectes leucostephes","overview":"白额寻蜜鸟（英文名：Vogelkop Melidectes，学名：Melidectes leucostephes），是雀形目吸蜜鸟科寻蜜鸟属的体型较大的物种。主要分布在印度尼西亚西巴布亚的鸟头半岛山区和Neck（新几内亚西北部）的中高海拔森林中，具有独特的黑色身体和橄榄色翼羽，以及醒目的白色额头。","appearance":"成年白额寻蜜鸟体长可达26厘米，体重在63至97克之间，雌雄羽毛相似但雄鸟体型较大。头部和颈部呈黑褐色至深棕色，后颈有斑驳的淡色斑点，最显著的特征是白色的额头。背部和翅膀覆盖着大胆的白色鳞状图案，胸部有斑点状的白色点缀。面部有一大片浅蓝绿色或蓝白色裸露皮肤，环绕着眼睛并向后延伸形成圆润的尖端。嘴喙浅色，两侧有明显的白色线条，构成新月形状，喉侧有粉红色到橙红色的肉垂。雌雄羽毛一致，但雄鸟体型大于雌鸟。幼鸟的详细特征尚不清楚，据说缺乏成鸟的肉垂。","call":"其叫声包括响亮的向下吹口哨声或类似鹦鹉的尖叫。","habits":"白额寻蜜鸟栖息于中高海拔的森林及其边缘地带，活动高度从地面以上5米至树冠层，主要在900米至1800米的海拔范围内，有时可能低至850米。它们的饮食习惯和觅食行为包括单独或成对出现，有时三只一起，会探查树叶和花朵以获取食物。","breeding":"关于繁殖行为的信息目前缺失。","identification":"与Ornate和棕眉寻蜜鸟共存，但白额寻蜜鸟具有独特的面部图案，包括浅色的喙和从眼睛上方和下方延伸形成的白色线条，形成新月形状。","protection":"IUCN：LC（无危）","distribution":"主要分布于印尼西巴布亚的鸟头半岛山区和Neck（新几内亚西北部），栖息于中高海拔的森林中。"},{"name":"黄眉寻蜜鸟","english_name":"Yellow-browed Melidectes","scientific_name":"Melidectes rufocrissalis","overview":"黄眉寻蜜鸟（英文名：Yellow-browed Melidectes，学名：Melidectes rufocrissalis），是雀形目吸蜜鸟科寻蜜鸟属的鸟类。主要分布于新几内亚东部的中海拔森林地带，以黄绿色眼圈和独特的面部裸皮著称。","appearance":"体长26至29厘米，体重介于56至96.5克之间，性别差异体现在体型大小而非羽色。头部灰黑，背部具白色鳞状斑纹，翼橄榄色，尾基部下方呈淡黄色。眼周环绕着浅绿至淡黄绿色的裸皮，上眼线有明亮黄色毛簇，耳羽后缘有黄色条纹，下喉部有橙红色肉垂。上体暗棕色，翼大覆羽和除最外两枚飞羽外的其他飞羽边缘为橄榄黄至黄绿色，形成折叠翼上的大型斑块。尾羽亦有宽广的黄橄榄色边缘，使折起的尾巴呈现黄橄榄色带深色中央。下体灰褐色，胸部至腹部有斑驳的米色到浅棕灰色图案，尾下覆羽为丰富的栗褐色，下翼为深橄榄褐色。","call":"发出类似鹦鹉的尖锐叫声，一连串的‘caw’音符，有时尖锐鼻音，有时沙哑刺耳，每秒2至3声，音调或保持一致或稍有起伏。两只鸟会面对面进行二重奏，交替发出下降的‘caw’音符。","habits":"栖息于低至中海拔的山林、林缘和次生植被，常见于人类干扰区，如树丛、草地、河流边的树木和受扰动的森林边缘。高度偏好1400至2450米，偶尔降至1100米。主要食物为昆虫、花蜜和果实，通常在树冠层活动，单独或成对出现，行为显眼。","breeding":"繁殖记录显示巢穴由细草和蕨茎编织而成，外观覆盖绿苔藓，悬挂在树枝末端的薄叉上，离地面2.4至4.6米高。巢中至少有一个雏鸟，但关于繁殖的其他信息有限。","identification":"与博氏寻蜜鸟杂交，但黄眉寻蜜鸟具有较淡的喙和下喉部的红肉垂，以及独特的羽色模式，易于区分。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的中央山脉东侧，包括中南部和东南部的山区。","other":"在受人类活动影响的区域，与博氏寻蜜鸟的杂交率增加，可能因自然杂交和大规模栖息地扰动所致。"},{"name":"休恩寻蜜鸟","english_name":"Huon Melidectes","scientific_name":"Melidectes foersteri","overview":"休恩寻蜜鸟（英文名：Huon Melidectes，学名：Melidectes foersteri），是雀形目吸蜜鸟科寻蜜鸟属的鸟类。主要分布在新几内亚东北部的休恩半岛山区。其显著的外部特征包括烟灰色的羽毛，背部和腹部带有白色斑点，眼后有一抹淡蓝色裸皮，以及从喙基部延伸至喉部的白红相间线条。该鸟种体型较大，叫声响亮。","appearance":"成鸟的头部和颈部大部分呈暗黑色，逐渐过渡到烟褐色，颈背、颈侧和下喉部可见密集而模糊的白色斑点，形成较浅的领圈。眼睛周围有大面积的淡蓝色裸皮，尤其在眼后部分更为宽阔。喙下缘有一条狭窄的白色须纹，下方有一个小型橙红色至红色的喉部肉垂。上体呈烟褐色至棕黑色，肩羽、背羽和覆羽上有明显的灰白色斑点。翅膀折叠时，可见暗黄色橄榄色边缘的大片区域。尾巴折叠时，中央为深色，边缘呈现黄色橄榄色。下体颜色从暗灰褐色至烟灰色不等，腹部中心为近白色，胸部有白色斑点或斑纹。尾下覆羽为肉桂棕色。虹膜为淡棕色，喙色淡，腿灰色。雌雄羽毛相同，但雄鸟比雌鸟大，且具有更大的喉部肉垂。幼鸟特征未详述。","call":"发出响亮的尖叫声，如‘wawww！weeee！weeee！weeee！’，有时会变为激动的‘wip-wip-wip！’声。","habits":"栖息于休恩半岛的中高海拔山林，高度介于1600至3700米之间。生活方式被认为是定居的，活跃于森林冠层和中间层次。觅食行为类似于同属的其他物种。","breeding":"关于繁殖的详细信息尚不明确。","identification":"与装饰寻蜜鸟和肉桂眉寻蜜鸟共存，但休恩寻蜜鸟体型更大，缺乏装饰寻蜜鸟的胸带，额头有一条白色条纹。","protection":"IUCN：LC（无危）","distribution":"仅限于新几内亚东北部的休恩半岛山区。","other":"休恩寻蜜鸟被认为是普遍常见的物种，但对其了解仍然有限。"},{"name":"博氏寻蜜鸟","english_name":"Belford's Melidectes","scientific_name":"Melidectes belfordi","overview":"博氏寻蜜鸟（英文名：Belford's Melidectes，学名：Melidectes belfordi），是雀形目吸蜜鸟科寻蜜鸟属的鸟类。广泛分布于新几内亚高地的上层山地云雾森林中。其体羽以灰色为主，背部带有白色斑点，翼羽橄榄色，尾基部下方呈浅黄色。头部黑色，面部有一条显著的白色条纹，环绕着浅蓝色的眼圈，眼后有小片裸露的蓝色皮肤，后跟一条细白线。喙部深色，缺乏红色肉垂，与Cinnamon-browed和黄眉寻蜜鸟相似，但在面部皮肤颜色、喙色及缺乏红色肉垂上有明显区别。","appearance":"体长26至29厘米，雄鸟体重59至80克，雌鸟体重51至67克。头顶及侧面黑褐色，逐渐过渡到淡棕色灰色，颈部后侧和颈部两侧暗褐色斑点模糊。脸部有短而宽的白色眉纹，环绕着大块浅蓝色眼区，眼区在眼后加宽，渐变为一条细白线。下耳覆羽微带灰色，与颈部侧面的棕色灰色融合。脸颊和上喉部黑色，下喉部棕色灰色或淡灰色，带有暗褐色斑点。背部、肩羽黑褐色，重叠灰白色斑点，臀部和上尾覆羽暗褐色。上翼和尾羽黑褐色，大覆羽尖端和边缘黄绿色，展开翅膀时可见宽阔的黄绿色区域，除最外侧两根飞羽外，其余飞羽边缘黄绿色，最外侧5至6根初级飞羽尖端窄黄褐色，尾羽外缘同样黄绿色。下体淡灰色，胸部和腹部暗褐色斑点，细白纹，下腹和肛门部位更宽的白纹或斑点，略带锈褐色，尾下覆羽锈褐色，尾下部暗褐色。虹膜棕色至深红棕色，喙黑色至暗灰黑色，腿色暗灰至暗蓝灰色，脚底黄色。","habits":"栖息于海拔1600米以上的上层山地至高山森林，偶尔出现在森林边缘、次生林和受干扰的环境，如牛牧场的散落树木、清理区域的灌木丛和残存森林。主要在1600米以上活动，最高可达树线，记录到的最高海拔为4000米。生活方式可能主要是定居。","breeding":"繁殖季节主要集中在晚雨季和旱季，筑巢时间为4月初、6月底和7月底，繁殖期在5月和8月至10月。巢为深杯状，由苔藓和树枝构成，内衬柔软的棕色材料，通常悬挂在树干分叉处，距离地面4.5至9米。一巢曾发现有一只幼鸟，双亲都会喂养巢中的幼鸟和离开巢的幼鸟。","identification":"与其他Melidectes物种如Cinnamon-browed和黄眉寻蜜鸟相比，博氏寻蜜鸟具有独特的蓝色面部皮肤、深色喙部且缺乏红色肉垂。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚中西部至东南部的山地森林，特别是在较高海拔地区。"},{"name":"棕胸寻蜜鸟","english_name":"Ornate Melidectes","scientific_name":"Melidectes torquatus","overview":"棕胸寻蜜鸟（英文名：Ornate Melidectes，学名：Melidectes torquatus），是雀形目吸蜜鸟科寻蜜鸟属的鸟类。广泛分布于新几内亚山脉的亚热带或热带湿润山地森林中。具有独特的黑色背部点缀白色鳞片状斑纹，白色的腹部以及黑色的胸部带纹，头部为黑色并带有大型橙黄色眼眶。","appearance":"体长约23厘米，体重介于39至58克之间，雌雄异型。雄鸟具有黑色头部和颈部，后颈处有暗褐色带黑点的斑纹，眼周有明亮的橙黄色裸皮，耳羽后方有大片的红棕色斑块，背部和肩部为灰褐色并具白色鳞片状斑纹，翼上覆羽和尾羽呈深褐色。腹部白色，侧腹和下腹有黑色斑点，形成类似第二个胸部带纹的视觉效果。雌鸟体型较小，色彩较为暗淡，喉部有粉红色或红色的肉垂，面部裸露皮肤亮黄色。幼鸟色彩较成鸟暗淡，胸部为浅色，下体有深色斑点。","call":"发出响亮空洞的“chok！”声，常随后跟一段略带沙哑的空洞颤音。","habits":"栖息于低海拔至中海拔的山地森林、林缘、次生林、灌木丛、农园和城镇花园中的树木。偏好半开放的生境或次生林和其他受扰动的环境。以昆虫、幼虫、花蜜和小果实为主食，也会取食由彩虹鹦鹉开启的较大和硬壳果实的果肉。单独、成对或小群体活动，有时与其他物种混群。","breeding":"繁殖季节跨度大，从晚湿季到晚干季都有记录。巢为精致的杯状，放置于树的水平分叉处，离地面高度适中。具体繁殖细节信息较少。","identification":"与同属其他物种相比，体型较小，具有独特的白色腹部和黑色胸部带纹。在鸣叫和行为上也有显著区别。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的山区，包括中央山脉、胡恩半岛和阿德尔伯特山脉等地，分布高度从约950米至2200米不等。","other":"人类活动对其有利，尤其是在林缘和次生林环境中。"},{"name":"白额澳蜜鸟","english_name":"White-fronted Honeyeater","scientific_name":"Purnella albifrons","overview":"白额澳蜜鸟（英文名：White-fronted Honeyeater，学名：Purnella albifrons），是雀形目吸蜜鸟科白额澳蜜鸟属的鸟类。以其独特的白色前额、黑色上胸和黄褐色翼部而著称。","appearance":"该鸟体型较小，背部呈斑驳的灰棕色，腹部浅色带暗条纹，最显著的特征是白色的额头，搭配白色髭纹、黑色喉咙和上胸部，以及黄色的初级飞羽。雌雄鸟外观相似，幼鸟可能颜色较为暗淡。","call":"其叫声多样，包括脉动式的电子声和快速重复的尖锐音符。","habits":"白额澳蜜鸟主要以花蜜为食，但在花蜜稀缺时也会食用种子、植物物质和昆虫。它们活跃于高大的灌木丛中，如Eremophila灌木和开花的mallee植物。","breeding":"白额澳蜜鸟通常在小群体中繁殖，雌鸟用容易找到的材料如草、蜘蛛网、根、树皮和植物茎编织杯状巢，内部铺垫羊毛、棉线、毛发和植物材料。雌鸟孵化和照料卵，孵化后，双亲共同喂养幼鸟。","identification":"白额澳蜜鸟与其他吸蜜鸟的区别在于其明显的白色前额和黑色上胸部，以及黄色的翼部羽毛。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西部至南北部地区，向东南延伸至昆士兰西南部、南澳大利亚北部、新南威尔士州西部和维多利亚州西部Mallee和Wimmera地区。","other":"白额澳蜜鸟历史上曾被归入Phylidonyris属，现置于独立的Purnella属中，属名纪念了鸟类学家Herbert A. Purnell。"},{"name":"白颊纹吸蜜鸟","english_name":"White-gaped Honeyeater","scientific_name":"Stomiopera unicolor","overview":"白颊纹吸蜜鸟（英文名：White-gaped Honeyeater，学名：Stomiopera unicolor），是雀形目吸蜜鸟科斯多米吸蜜鸟属的鸟类。这种中到大型的吸蜜鸟拥有烟灰色的羽毛，眼周至喙间有一块明亮的淡色斑。其体型远大于同样呈暗色的暗褐色吸蜜鸟。广泛分布于澳大利亚北部的干燥热带区域，包括花园、红树林和草原。","appearance":"雄鸟长约19-22厘米，重27.8-40.4克；雌鸟略小，17-20厘米，重25-33克。上身颜色单一，为深橄榄棕色至灰橄榄色，下身颜色较浅，腹部中央有微弱的淡黄色调。眼后有模糊的暗色纹，喙侧有一半圆形的白色至奶油色斑块。尾羽和次级飞羽边缘有淡绿色晕染，初级飞羽有细薄的近白色边缘。下尾覆羽橄榄灰色，下翼灰色带淡灰色边缘，尾端和边缘呈暗色。虹膜为棕色或灰棕色，有时为橄榄灰色或蓝灰色；喙黑色；腿色深灰至黑，脚底色浅。雄鸟与雌鸟羽毛相似，但雄鸟体型略大。幼鸟与成鸟非常相似，起初可通过上体柔软的羽毛、后颈轻微的棕色调、腹部中心较强的黄色调以及（至少有时）更鲜艳的黄色喙边来区分。","call":"发出响亮而悦耳的歌曲，由三个相似的乐句组成，间隔约0.5秒，例如“whit-o-wee”或“whit whit, awhit-whit, awhit-whit”。通常以二重唱形式出现，每当配偶相遇或宣告领地时歌唱，雄鸟先唱，雌鸟稍后加入，第二和第三个乐句完全同步。接触叫声“chiew”或“chop”，间隔数秒至数分钟，还有短促、尖锐的重复“chirrup”或“chirp”声，以及快速的“chp-chp-chp-chp-chp-chwerp”声，后者被认为是另一种联系叫声。","habits":"主要栖息于河流森林和林地，常见于由纸皮树（Melaleuca leucadendra）、Lophostemon或混合树种组成的河岸或沼泽地带，如Melaleuca、Lophostemon、桉树、Casuarina或Erythrina，通常伴有Pandanus和Acacia的浓密灌木丛。亦常见于季风雨林。会进入开放的桉树林地或邻近河岸森林的草原，通常草地上有分散的灌木或灌木丛；也会出现在季风雨林和开阔森林的生态交错带。偶尔出现在红树林、Acacia森林或灌木丛、Triodia草地、湿地和莎草地。亦见于城镇中的花园和公园。","breeding":"繁殖可能全年发生，记录显示除六月外所有月份在达尔文附近都有繁殖活动。雌鸟筑巢，雄鸟陪伴，巢为深杯状，通常由树皮或草构成，用蜘蛛网或蜘蛛卵囊粘合，有时包含根须、草、毛发、植物纤维、树枝或Casuarina针叶，内部或外部覆盖一层细草或植物绒毛，据称巢外部有一层光泽的唾液，有助于固定材料并使巢稳固。巢通常悬挂在树木或灌木顶部枝条的分叉处，包括红树林和寄生植物（Loranthaceae），有时靠近树的中心，通常靠近水源。巢高从1.2米至12米不等，平均高度2.18米。每次产卵2枚，由雌鸟孵化，孵化期15-16天；雏鸟由雌鸟抚育，或据称由双亲共同抚育，由双亲喂养，孵化期13-14天；双亲喂养离巢雏鸟。","identification":"通过眼后至喙间的明亮淡色斑块以及体型较大，可以与暗褐色吸蜜鸟区分开来。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部，从西澳大利亚东北部至昆士兰东北部，包括梅尔维尔岛和北领地的托普恩德地区，南至维多利亚河西南部和巴克利台地东南部，以及格罗特艾兰特岛，向南延伸至昆士兰南部接近普罗瑟派恩地区，偶尔记录于更南地区，如麦凯和阿瑟顿台地。"},{"name":"黄吸蜜鸟","english_name":"Yellow Honeyeater","scientific_name":"Stomiopera flava","overview":"黄吸蜜鸟（英文名：Yellow Honeyeater，学名：Stomiopera flava），是雀形目吸蜜鸟科斯多米吸蜜鸟属的鸟类。主要分布于澳大利亚东北部，包括城市花园和红树林地带。其体羽几乎通体为淡黄色，缺乏明显的条纹和斑块，拥有短而黑的喙。","appearance":"成年黄吸蜜鸟长约18厘米，体重介于16至30.8克之间。头部侧面和上身主要为橄榄黄色，下体为柠檬黄色。眼后有模糊的柠檬黄色斑块，脸颊线条呈暗橄榄黄色，翼和尾羽边缘宽广的柠檬黄色。虹膜颜色为橄榄灰到深棕色，喙黑色，腿色前部灰褐色，后部棕橙色。雄雌羽毛相似，雄鸟体型较大。幼鸟比成鸟更暗淡，面部图案不明显，喙基部可能季节性变黄。","call":"发出尖锐的‘whee-whee’声或单个高音哨音。","habits":"栖息于开阔的河流边森林和林地，尤其是湿地周围，常由桉树主导，下层植被为茶树和瓶刷树。偶尔出现在雨林边缘或红树林，也会在农业区、甘蔗田、城镇公园和花园中发现。主要生活在沿海低地，偶尔可达海拔约1100米。通常定居并全年保持领地，以花蜜、果实和小节肢动物为食，常单独、成对或小群体活动，会在食物丰富的地点聚集。","breeding":"繁殖记录全年均有，筑巢深度为5.1至7厘米，宽度为7.5至8.9厘米，内部直径5.5至7厘米。巢通常由雌鸟建造，位于离地面0.7至7.8米高的树枝叉上，平均高度4.1米。每窝产卵2枚，孵化期约为16天，雏鸟喂养由双亲共同承担，有时会有帮手参与，育雏期12至14天。","identification":"黄吸蜜鸟与其他吸蜜鸟相比，体羽几乎全为淡黄色，缺乏特征性的条纹或斑块，通过其独特的叫声和活动范围进行识别。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚东北部，包括城市花园和红树林地带。","other":"2011年分子系统发育分析显示，黄吸蜜鸟从原来的Lichenostomus属转移至Stomiopera属，因原属被证实为多系群。"},{"name":"杂色吸蜜鸟","english_name":"Varied Honeyeater","scientific_name":"Gavicalis versicolor","overview":"杂色吸蜜鸟（英文名：Varied Honeyeater，学名：Gavicalis versicolor），是雀形目吸蜜鸟科加维吸蜜鸟属的鸟类。常见于新几内亚沿海和澳大利亚东北部的沿海地区，特别是红树林和邻近的海岸栖息地。其背部呈橄榄绿色，腹部淡黄色带灰色条纹，具有醒目的黑色喙、黄色喉部和眼周黑斑。","appearance":"体长约19至24厘米，重量约32.5克至35.5克。头顶及颈部橄榄色，细条纹较深，前额暗灰。面部有黑色面罩，边缘以显眼的黄色条纹为界，条纹末端有小簇白色羽毛。上体橄榄色，带棕色斑点，臀部和上尾覆羽棕色，尾羽橄榄绿带绿边。翼上覆羽及次级飞羽边缘黄橄榄色，形成浅色翼斑。下体主要黄色，腹奶油色，下尾覆羽橄榄灰色。虹膜深红棕色或近乎黑色，喙黑色，腿蓝灰色至深灰色。雌雄羽毛相似，雄鸟略大。幼鸟比成鸟更淡更朴素，头顶稍浅，无条纹，上体淡棕色，下体更淡，条纹更模糊，喙灰黑，下颌基部粉红色，喙口橙黄色且肿胀。","call":"在澳大利亚，其鸣声响亮有力，旋律悠扬。在新几内亚，发出悦耳的音乐般气泡系列声，音调起伏，或欢快响亮，音节变化丰富，气泡般圆润，通常重复数次。","habits":"常栖息于红树林边缘的海岸、河口和岛屿，以及邻近的海岸灌木丛或珊瑚礁，包括以纸皮树（Melaleuca）、金合欢（Acacia）为主的植被，或有Khoa（Cordia subcordata）灌木丛和零星灌木的地带。在公园、花园和沿海城镇的海滨植被中也很常见，偶尔在雨林或桉树林中出现。以花蜜和昆虫为主食，也会在低潮时从泥中捕食甲壳类动物。通过在红树林和其他树木的外层枝叶中搜寻和探查觅食，也常在开花的红树林中探花，如白松纳特（Sonneratia alba）、伞树（Schefflera actinophylla）、椰子树（Cocos nucifera）等。","breeding":"繁殖季节在澳大利亚似乎为旱季，记录有3月至4月、6月至7月和9月至10月。筑巢于红树林中，巢为浅碗状或扁平杯状，由根须和草构成，有时附着蜘蛛卵囊，悬挂于细水平或下垂树枝端，高度0.6至3.6米。每窝产卵2枚，双亲共同喂养雏鸟和幼鸟。","identification":"与饰颈吸蜜鸟相比，杂色吸蜜鸟颜色更为鲜黄，且在群居时更为嘈杂。","protection":"IUCN：LC（无危）","distribution":"分布在新几内亚沿海地区和澳大利亚东北部，包括东北昆士兰的托雷斯海峡群岛。在新几内亚北部和东部沿海，以及澳大利亚的东北角，包括卡佩约克半岛的东北部。","other":"有两亚种，G. v. sonoroides分布于新几内亚西北部的Raja Ampat岛、Yapen岛、新几内亚北部沿海、米尔恩湾群岛和D'Entrecasteaux群岛；G. v. versicolor分布于新几内亚南部沿海、托雷斯海峡群岛和澳大利亚东北角的卡佩约克半岛东北部。"},{"name":"饰颈吸蜜鸟","english_name":"Mangrove Honeyeater","scientific_name":"Gavicalis fasciogularis","overview":"饰颈吸蜜鸟（英文名：Mangrove Honeyeater，学名：Gavicalis fasciogularis），是雀形目吸蜜鸟科加维吸蜜鸟属的鸟类。曾被视为杂色吸蜜鸟的同种，但现在被认定为独立物种。饰颈吸蜜鸟主要分布于澳大利亚东部沿海地区，从昆士兰的汤斯维尔到新南威尔士州东北部。该鸟种在近50年来向南扩展了其分布范围。","appearance":"饰颈吸蜜鸟体长约19.5厘米，雄鸟体重23.9-33.1克，雌鸟体重22-30克。上体橄榄棕色，臀部和尾上覆羽灰褐，头部和后颈有细密的暗色条纹，翼上覆羽有橄榄斑点。具宽大的黑色面罩，延伸至颈部侧面，下缘有一黄色条纹，末端为一小撮白色羽毛，与颈部下方的大片灰白色区域相连。尾巴和上翼橄榄棕色，边缘淡橄榄绿色。下巴和喉咙有细密的暗灰色和暗黄色条纹，上胸暗灰色，形成胸带，腹部偏白，有灰色条纹，尾下覆羽灰棕色，下翼奶油色至肉粉色，边缘和尖端灰色。虹膜蓝灰色，喙黑色，腿深灰或蓝灰色。性别在羽毛上相似，雄鸟略大于雌鸟。幼鸟与成鸟非常相似，但颜色较暗淡，头顶和前体无条纹或斑点，臀部和尾上覆羽略微偏棕色，下巴和喉咙淡黄色，有轻微的棕色斑点，胸部条纹较弱。","call":"饰颈吸蜜鸟的歌声响亮、悦耳而清脆，但有变化，例如“whit-u-we-u”。也有责骂似的喋喋不休。","habits":"饰颈吸蜜鸟主要栖息在澳大利亚东部沿海的红树林森林和邻近海岸、海湾、河口和岛屿的林地。偶尔也会出现在靠近红树林的沿海灌木丛、林地或灌丛（如桉树、金合欢、茶树的组合）。它们是公园和花园的常客，尤其是在靠近红树林的城镇。以花蜜和昆虫为主食，偶尔吃水果。在红树林（如盐角树、红海榄）的外层树叶、花朵上觅食，低潮时在树干、根部和气根上觅食。也会访问相邻生境中的开花树木和灌木。活跃、嘈杂且好斗，通常单独或小群松散地活动。","breeding":"饰颈吸蜜鸟的繁殖期为8月至12月（高峰在9月），在分布范围的北部地区，繁殖期还会延长至4月至5月。巢呈杯状，由干燥的草和海草或植物纤维编织，用蜘蛛网和蛋壳粘合，内部铺有细根或细草、毛发和植物绒毛。巢通常悬挂在枝头，有时支撑在枝上，距离地面0.5-2.7米高。巢穴几乎总是在小型密集的红树林中，偶尔在金合欢灌木或槲寄生中。每次产卵2枚，孵化和育雏期数据未知，但双亲都会喂养巢中的幼鸟和离巢的幼鸟。巢穴会被淡色杜鹃和扇尾杜鹃寄生。","identification":"饰颈吸蜜鸟与杂色吸蜜鸟的区别在于前者喉部有清晰的条纹，缺乏黄色下体和胸部条纹。在红树林环境中容易辨认。","protection":"IUCN：LC（无危）","distribution":"饰颈吸蜜鸟分布于澳大利亚东部沿海，从昆士兰州东北部的汤斯维尔至新南威尔士州东北部，包括Whitsunday群岛至莫尔顿湾的岛屿。","other":"饰颈吸蜜鸟在过去50年里，分布范围似乎向南扩展，首次记录出现在1947年的Yamba，之后在更南方有零星记录。"},{"name":"歌吸蜜鸟","english_name":"Singing Honeyeater","scientific_name":"Gavicalis virescens","overview":"歌吸蜜鸟（英文名：Singing Honeyeater，学名：Gavicalis virescens），是雀形目吸蜜鸟科加维吸蜜鸟属的鸟类。中等体型的吸蜜鸟。其分布广泛，遍及澳大利亚除东北部、东南部和塔斯马尼亚州以外的地区，尤其偏爱内陆地区。外观上，头部和颈部呈灰褐色，背部橄榄棕色，腹部淡灰色，尾翼和翅膀带有橄榄绿色，尾羽边缘黄色。该物种因歌声而得名，歌声从刺耳到悦耳不等，且随地域而异。","appearance":"体长16至24厘米，体重29.3克至35克，依亚种而异。头颈灰褐，头顶有暗褐色条纹，黑色面罩延伸至肩部，下缘为黄色颊纹，连至下耳羽的宽阔黄纹。背部深灰橄榄色，上尾和上翼灰褐至棕，尾羽和飞羽外缘黄绿，形成窄黄边。腹部白色，喉部微黄，胸腹密布暗色条纹。幼鸟颜色较淡，条纹模糊，下颚基部粉红，虹膜暗褐色。","call":"清晨最早鸣叫，雄鸟在黎明前30至20分钟开始歌唱。歌声在黎明时分较为常见，响亮高音，由数个音符组成，具有地域变异性。常用作领地防御和争斗。","habits":"栖息于开阔林地、灌木丛、低矮林区，偏好由金合欢、纸皮树、松柏等组成的生境，也见于公园、花园、部分清理的农田残存林地。以花蜜、昆虫、蜘蛛、软体动物和水果为食，比例约26%花蜜和74%昆虫。在低层和地面觅食，有时群居，常与红喉刺嘴雀和白眉吸蜜鸟混群。","breeding":"全年均可繁殖，大多数在8月中旬至11月下旬筑巢。巢为杯状，由草叶、蛛网等材料构成，高度0.05至20米，平均2米。每窝产卵1至3枚，通常2枚，孵化期12至14天，由雌鸟单独孵卵。幼鸟由双亲喂养，留巢期11至16天。受苍白杜鹃寄生。","identification":"与近似物种相比，歌吸蜜鸟具有独特的黑面罩和黄色颊纹，叫声和分布区域也可用于辨别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆至西海岸，包括西澳大利亚沿海岛屿，不包括东北部、东南部和塔斯马尼亚州。"},{"name":"淡黄吸蜜鸟","english_name":"Yellow-tinted Honeyeater","scientific_name":"Ptilotula flavescens","overview":"淡黄吸蜜鸟（英文名：Yellow-tinted Honeyeater，学名：Ptilotula flavescens），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。分布于新几内亚东南部和澳大利亚北部，包括澳大利亚的西部、北部地区和昆士兰州。其自然生境主要是热带湿润低地森林和热带红树林。","appearance":"体型较小，长度约13至15.5厘米，重量介于9.5至16克之间，雄鸟略大于雌鸟。上体呈淡灰棕色，额部和眼上方橄榄黄色，头部侧面和大部分下体黄色，具鲜明的黑色新月形颈斑。翼折处有明显的黄色橄榄色面板，尾羽侧面黄橄榄色，新鲜羽毛状态下尾端白色。虹膜深棕至灰棕色，喙及口裂黑色，腿粉色或灰粉色。幼鸟较成鸟暗淡，黄色偏淡，黑色新月形斑不明显，尾尖橄榄色，喙呈棕色，前端黑色，边缘黄色橙色，口裂肿胀且黄色。","call":"在澳大利亚，其鸣唱被描述为一系列‘porra-cheu’的短叫声；在新几内亚，发出短暂的泡泡状短音节串。鸣唱在飞行中、配偶间同步二重唱或争斗情境下发出。联系叫声为粗糙的下降‘tew’或‘taw’声；报警声在澳大利亚较为微弱颤音‘weeweeweeweewee’，在新几内亚为连续高音‘wi wi wi...’。","habits":"常栖息于热带开阔硬叶林和林地，偏好靠近河流或湿地，常见于以桉树为主的河岸植被群落。食物包括花蜜、昆虫（主要是各种蜘蛛）、种子和蜜露，偶尔也从地面探食落花。在新几内亚，会倒挂采食花朵。单个或成对出现，有时形成小群体，最多6至8只，会追逐其他物种。","breeding":"在澳大利亚全年均可繁殖，主要在旱季，而在新几内亚繁殖期为3月至5月和7月至12月，尤其9月至11月最为集中。巢由雌鸟建造，雄鸟辅助，通常为精致的小杯状，由细草、蜘蛛网、植物绒毛等材料编织而成，悬挂在树冠外层的枝叶丛中，高度从地面0.9至12米不等。每窝产卵1至2枚，孵化期约10至12天，雏鸟哺育期约14天。","identification":"与其他吸蜜鸟种类相比，淡黄吸蜜鸟的黄色标记和黑色颈斑是显著的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚东南部和澳大利亚北部，包括澳大利亚的西部、北部地区和昆士兰州。","other":"曾被归入Lichenostomus属，后分子系统发育分析显示原属多系群，故转移至Ptilotula属。"},{"name":"黄翅灰吸蜜鸟","english_name":"Fuscous Honeyeater","scientific_name":"Ptilotula fusca","overview":"黄翅灰吸蜜鸟（英文名：Fuscous Honeyeater，学名：Ptilotula fusca），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。主要栖息于亚热带和热带干燥森林中。曾被归入Lichenostomus属，2011年分子系统发育分析证实原属多系群后，调整至Ptilotula属。","appearance":"小型吸蜜鸟，外观平淡，全身几乎呈单调橄榄褐色，颈部有微妙黄色斑块。成鸟喙全黑，幼鸟喙基部黄色，眼周具黄色环。头部、背部橄榄色，翼上覆羽有橄榄色鳞状纹，翼弯处有深褐色斑。折翼时可见宽广的橄榄色翼板，初级飞羽尖端有细小白点（新鲜羽毛时）。上尾侧橄榄黄色，下体淡黄灰色，腹部略白，翼下浅灰褐色，尾下暗棕色带橄榄黄色边缘。虹膜深棕，嘴和眶周黑色，腿灰色。非繁殖期，喙基黄色，蜡膜、眶周和嘴裂黄色。雄雌羽毛相似，雄鸟稍大。幼鸟头部、颈背和上身更棕色，臀部泛黄，面部橄榄黄，颈部黄色羽毛较小，边界模糊，喙橙色带棕色尖，嘴裂黄或橙黄色肿胀。","call":"在觅食时经常发出单一的‘chip’声，可能是接触或定位叫声。停歇时的歌声为重复柔和、干涩的颤音或滚音‘twit’t’t’t’t’或‘arig arig a’，常以尖锐的‘taw-taw-taw…’结尾；飞行时的歌声为深沉金属般的‘tew-tew-tew’。警戒叫声包括面对空中掠食者的快速重复高音笛音，及在群体活动时的高音颤音。","habits":"栖息于干旱开阔的硬叶林和林地，偏好桉树主导的环境，如box-ironbark、box或bloodwood（Corymbia）林地，或斑点桉树林，偶尔出现在混合有松柏科的桉树林中。有时出现在农业地带残留的植被或路边植被，亦见于花园。迁徙模式多变，部分地区居民性，部分季节性迁徙，尤其在高原地区，冬季会向低海拔移动，春季返回高处。饮食以节肢动物为主，包括昆虫、蜘蛛、蜜露和虫胶，也会食用花蜜，尤其是桉树花蜜，偶尔吃果实。在维多利亚州的一个地点，昆虫及其产物（虫胶、蜜露）和花蜜在饮食中占比相当，夏季以花蜜为主，秋冬则更多依赖蜜露和虫胶。","breeding":"繁殖期为5月至3月，主要在晚冬至夏末，筑巢由雌鸟单独完成或偶有雄鸟协助，使用细草、蛛丝、树皮和毛发（可能来自活体动物）编织成杯状巢，内衬草、毛、植物绒毛，悬挂于桉树冠层或高大的金合欢树的外层枝叶间，离地面0.15至25米。每窝产卵1至3枚，平均2.4枚。孵化、育雏和巢维护仅由雌鸟承担，雄雌双方共同喂养雏鸟。孵化期11至18天，雏鸟期12至19天。幼鸟离巢后4至6周独立，但后期孵化的幼鸟可能随父母长达两个月。","identification":"与澳洲灰额吸蜜鸟、黄痣吸蜜鸟和白痣吸蜜鸟相似，辨识关键在于颜色差异、鸣叫声和分布区域。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚东部，内陆地区为主，新南威尔士州和昆士兰州也有沿海分布。","other":"在非常干旱的季节，繁殖成功率显著下降，而在条件良好的季节，成功率较高。"},{"name":"灰头吸蜜鸟","english_name":"Grey-headed Honeyeater","scientific_name":"Ptilotula keartlandi","overview":"灰头吸蜜鸟（英文名：Grey-headed Honeyeater，学名：Ptilotula keartlandi），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。主要分布在澳大利亚内陆的西澳大利亚西北部至昆士兰中北部。拥有独特的灰黑色面具，黄色颈羽，以及橄榄棕色的上体。其分布范围广阔，覆盖了澳大利亚大部分干旱和半干旱地区。","appearance":"灰头吸蜜鸟体长13至16.5厘米，体重12至18克，两性相似。头部顶部淡灰色，逐渐变为浅灰褐色，背部略带褐色，臀部和尾羽覆羽颜色更暗。面具由深灰色至黑色构成，边界清晰，边缘有明亮的黄色颈羽。下巴和喉部淡黄色，翅膀橄榄棕色，具橄榄黄色边缘，形成翼上的黄色斑块。尾巴橄榄棕色，边缘橄榄黄色，下体淡橄榄黄色，有褐色条纹。喙黑色，基部黄色，仅在繁殖季节全黑。虹膜深棕色，眼环深灰色，腿粉红褐色。","call":"发出连续而尖锐的‘chip’声，尤其在觅食时频繁。还有类似‘wee-wee-wee’的歌曲，以及响亮的单音‘kwoyt’和‘chee-toyt’叫声，后者可能仅在繁殖季节发出。","habits":"栖息于低矮开阔的干旱和半干旱林地，偏好砂岩地带，但也可见于平原和台地，常与桉树、金合欢树或格雷维尔亚树共存。以昆虫、蜘蛛和花蜜为主食，偶尔食用果实。通常成对或小群体活动，有时可达20只以上。活跃、好斗，叫声嘈杂。","breeding":"繁殖季节可能贯穿全年，尤其是在雨后。筑巢于活树或灌木中，巢为开放紧凑的杯状，由干草、植物茎和细条树皮构成，内衬植物绒毛、细根、毛发或蜘蛛卵囊。每窝产卵2枚，具体孵化和育雏时间未知，推测每年只抚养一窝。巢可能被苍白杜鹃寄生。","identification":"与其他吸蜜鸟科成员相比，灰头吸蜜鸟具有明显的灰黑色面具和黄色颈羽。幼鸟比成鸟颜色更淡，面具较模糊，喙底橙黄色至粉红色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆，从西澳大利亚北部至昆士兰中北部，包括沙地平原、山丘和河岸林地。","other":"灰头吸蜜鸟的命名是为了纪念鸟类收藏家乔治·阿瑟·基特兰。"},{"name":"澳洲灰额吸蜜鸟","english_name":"Grey-fronted Honeyeater","scientific_name":"Ptilotula plumula","overview":"澳洲灰额吸蜜鸟（英文名：Grey-fronted Honeyeater，学名：Ptilotula plumula），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。广泛分布于内陆澳大利亚，除塔斯马尼亚州北部和南部之外。中等体型的吸蜜鸟，具有橄榄棕色上部和淡黄色带模糊条纹的下部，灰冠和脸颊上有黑色边缘，后被黄色边框。其外观与黄痣吸蜜鸟相似，但后者下部更暗且带有细长弯曲的黄色颈标记。","appearance":"成年澳洲灰额吸蜜鸟体长14至16.5厘米，体重随亚种而异，介于11至27.5克之间。头部顶部和侧面橄榄黄色，前额灰色不显眼，黑色耳围和眼圈形成明显条纹，颈部有短而宽的黄色羽簇。上体浅灰褐色，翼上橄榄色边缘，尾部灰橄榄色带黄橄榄色侧边。下体偏白色，喉部、胸部和臀下覆羽带有黄色调，全身散布淡褐色条纹。幼鸟较成鸟暗淡，上体呈棕色，颈羽较淡，喙灰色带黄色基部。","call":"发出尖锐、刺耳的连续叫声，包括滚动的吱吱声和重复响亮的管笛声。雄鸟的歌声类似金丝雀，飞行时发出响亮、尖锐、几乎嘶哑的'it-wirt'、'wirt, wirt, wirt'或'it-wit it it'。","habits":"栖息于开放林地，尤其是低矮密集的mallee桉树林或灌木丛，偶尔出现在半干旱灌木地或mulga林地。在内陆和北澳大利亚，偏好低矮河岸植被或大草原桉树森林。以花蜜为主食，特别是Eucalyptus、Eremophila和槲寄生，同时捕食昆虫和蜘蛛，偶尔吃果实和种子。通常单独或成对觅食，有时组成小群。","breeding":"繁殖季节集中在冬季至春季，筑巢材料包括细草、蜘蛛网、植物纤维或细碎树皮，内部铺垫植物绒毛、羽毛或毛发。巢常悬挂于树梢或枝条间，高度从0.6至6.6米。每窝通常产2枚蛋，孵化期约14至15天，双亲共同育雏，雏鸟喂养期约12至15天。巢可能被淡色杜鹃和霍氏金鹃寄生。","identification":"与黄痣吸蜜鸟区分在于后者下体条纹更深，颈标记更细长且更弯曲。此外，灰额吸蜜鸟的前额灰斑较为隐蔽，头顶部橄榄黄色，耳后黑色线条更宽。","protection":"IUCN：LC（无危）。曾经在维多利亚州被列为'濒危'，但由于伐木活动创造了有利于其生存的再生mallee环境，数量可能有所恢复。","distribution":"分布于澳大利亚内陆，主要在南澳、西澳、北领地和昆士兰西北部，避开塔斯马尼亚州北部和南部。","other":"受农业开垦影响，特别是在南部范围内的麦田，但Eucalyptus油生产所导致的mallee砍伐和再生可能对其有利。"},{"name":"黄痣吸蜜鸟","english_name":"Yellow-plumed Honeyeater","scientific_name":"Ptilotula ornata","overview":"黄痣吸蜜鸟（英文名：Yellow-plumed Honeyeater，学名：Ptilotula ornata），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。分子系统发育分析证实该属多系发生，遂移至Ptilotula属。其主要栖息于澳大利亚南部的温带森林和地中海型灌木丛，分布范围从西澳大利亚西南部至新南威尔士州中部。","appearance":"成年黄痣吸蜜鸟主要呈橄榄褐色，腹部有明显的灰色条纹。以其长长的黄色颈羽命名，繁殖季节的成鸟喙全黑，而幼鸟和非繁殖季成鸟的喙基部为黄色。幼鸟胸部无条纹。体长14-18.5厘米，体重雄鸟16-22.1克，雌鸟12.2-21.1克。头部顶部黄色橄榄色，向后颈部和头部两侧渐变为橄榄灰色，眼前和眼周有暗色污迹，窄淡黄色髭纹，后耳羽上有一条黑色扩散带，边缘为长而尖的亮黄色颈羽；背部和上翼深棕色，臀部和上尾覆羽渐变为灰橄榄色；上翼覆羽边缘黄橄榄色，其余部分为棕色的飞羽边缘亮橄榄黄色（折叠翼时形成明亮面板，展开翼时形成中间面板）；上尾橄榄棕色，边缘黄色，细白色尖端迅速磨损；下体偏白，下颌、喉部、胸部、上腹部和侧腹强烈条纹棕色，下体下部条纹较轻；尾下覆羽灰棕色；下翼灰橙色，除最外侧飞羽外，所有飞羽基部浅灰色，尾缘和尖端灰棕色；虹膜棕色，眼环黑色；喙和口裂黑色；腿灰棕色。非繁殖季节与繁殖季节相似，但眼环黄到橙黄色，喙黑色，基部淡黄到黄橙色，口裂黄到橙黄色。雄鸟羽毛与雌鸟相同，但体型大于雌鸟。幼鸟比成鸟更淡且呈棕色，头顶棕色橄榄色，短而模糊的黄色眉纹，眼前和眼周的暗色污迹较淡，下体条纹较轻，喙黑棕色，基部黄色到橙黄色，口裂苍白黄色到黄色。","call":"发出一系列响亮、清晰或刺耳尖锐的鸣叫声，包括快速三音节的'chier wit chier'歌声，通常在黎明前由雄鸟展示飞行时发出。","habits":"主要栖息在马利桉树林，通常与Leptospermum、Acacia和Eremophila等稀疏下层植被和以藜科为主的地面覆盖物相伴。在西澳大利亚，常见于沿海桉树森林，如tuart、wandoo或偶尔的salmon gum，但在其他地区的非马利桉树林中并不常见。有时出现在金合欢林地，如西部myall主导的林地，或混合林地，如松柏-白千层（Callitris-Casuarina cristata）或Callitris-Eucalyptus。在维多利亚州，平均38%的觅食观察是在花朵上，27%在树枝上，9%在细枝上，1%在树干上，15%在叶片中，10%在空中。以花蜜、昆虫（包括蜘蛛和螨虫）、lerp、甘露和蜂蜜为主要食物，偶尔食用花朵和果实。觅食主要在树木中进行，尤其是桉树，较少在下层灌木中，几乎不在地面。觅食高度平均为6.7米，84%的观察在树冠和次树冠中。以探查的方式获取花蜜。昆虫通过从叶片、树皮和偶尔的地面收集获得；通过突袭捕捉，主要针对飞行中的昆虫，但也会在叶片或树皮上突袭或悬停捕捉；偶尔通过在树皮下探查，偶尔通过扑击捕捉。在有丰富食物的区域或水源处，数百只鸟可能聚集，例如一次记录了650只鸟。当数量较多时，黄痣吸蜜鸟倾向于占据主导地位。","breeding":"筑巢期全年都有记录，但夏季中期和晚秋似乎最少。巢为浅开杯状，通常由编织的草和羊毛制成，用蛛网绑定，有时含有其他材料（如蛛蛋囊、花朵、细纤维、树皮条、根须和羊毛束），内衬羊毛、细草、植物绒毛和羽毛，有时不衬里，外部直径6.4-7.5厘米，深度3.2-5厘米，内部直径4.4-5.5厘米，深度3-3.5厘米；通常悬挂于薄水平叉或下垂的叶片或叶状细枝上，经常位于活的马利桉树上（占记录的93%），偶尔支撑于直立的嫩枝上，偶尔位于其他地点，如悬挂于活马利桉树枯死的喷口内，或垂直叉靠在树干或寄生植物（Loranthaceae）上；距地面0.45-20米（平均3.1米），31个巢在埃耶尔半岛的高度为0.76-4.6米（平均1.8米）。一窝产1-3枚卵，通常2枚（平均2.09枚）；估计孵化期12-15天，雏鸟期12-14天，但没有准确测定；双亲喂养雏鸟和幼鸟。巢被扇尾杜鹃、淡色杜鹃、霍氏金鹃和金鹃寄生。在已知结果的44个巢的89枚卵中，每巢平均有0.55只幼鸟成功离巢；在83个巢中，53%至少有一只幼鸟离巢。","identification":"与紫颊纹吸蜜鸟、澳洲灰额吸蜜鸟和黄翅灰吸蜜鸟相似，但可通过黄色颈羽、橄榄绿头部、暗色脸庞和重条纹灰棕色下体加以区分。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部，从西澳大利亚西南部至新南威尔士州中部。在西澳大利亚，主要分布在南纬30度以南，但远西南部除外，向东至艾尔半岛（Eyre Peninsula）和弗林德斯山脉（Flinders Ranges）的零星记录，至库荣湿地（The Coorong）和默里玛拉（Murray Mallee），并向西北和东北维多利亚州以及新南威尔士州中部延伸。","other":"黄痣吸蜜鸟在一些受保护的区域中发现，包括澳大利亚多个国家公园和保护区。"},{"name":"白痣吸蜜鸟","english_name":"White-plumed Honeyeater","scientific_name":"Ptilotula penicillata","overview":"白痣吸蜜鸟（英文名：White-plumed Honeyeater，学名：Ptilotula penicillata），是雀形目吸蜜鸟科黄痣吸蜜鸟属的鸟类。广泛分布于澳大利亚的吸蜜鸟，主要栖息于开放的硬叶林和木本地带，尤其靠近水源地带。其最显著的特征是颈部两侧的白色羽毛。分布范围广泛，遍及澳大利亚大陆，但在最北端和西南部较为罕见。","appearance":"成年白痣吸蜜鸟体长13.5至18厘米，体重介于14至25克之间，性别间略有差异。头部主要呈橄榄灰色，脸部黄色。繁殖季节的成鸟喙全黑，而非繁殖期和幼鸟喙基部呈现黄色。颈部具有标志性的白色羽毛，从喉咙延伸至颈背，边缘带有黑色条纹。上体灰橄榄色，下体淡褐色，胸腹部有黄色斑纹。翼上覆羽橄榄至黄色，次级飞羽和初级飞羽边缘黄色形成明显的面板。尾部橄榄棕色，边缘黄色，末端白色。四个亚种在体型和羽毛色彩强度上有细微差别。","call":"有三种主要的鸣唱声和一系列叫声，包括‘chick-o-wee’或‘chick-oo-wee’的主歌，飞行时的流利颤音，清晨的短音节序列，以及尖锐下降的‘chip’叫声。还有多种报警叫声，包括对掠食者的快速重复‘pee-pee-pee...’声。","habits":"白痣吸蜜鸟常出现在干燥的硬叶林和湿地旁的树林中，偏好沿水道的河红桉森林。它们可以适应城市环境，常见于公园和花园。饮食以花蜜为主，辅以昆虫及其分泌物、树胶、花粉和果实。在所有层次觅食，从树冠到地面。群居，有时会结成小群。","breeding":"繁殖期全年皆有可能，主要集中在8月至11月，一年通常产两窝，偶尔三窝。雌鸟单独筑巢，巢呈杯状，悬挂在树冠中。每窝产2至3枚卵，孵化期13至15天，雏鸟期11至15天。幼鸟离巢后至少两周内由双亲喂养。","identification":"白痣吸蜜鸟通过其独特的颈部白色羽毛和橄榄灰的头部易于识别。与其它吸蜜鸟相比，其体型、颜色和鸣叫声都有所不同。","protection":"IUCN：LC (无危)","distribution":"分布于澳大利亚，除塔斯马尼亚州北部和西南部以外的大部分地区。在悉尼和纽卡斯尔等地数量有所增加，在伊洛瓦拉地区和维多利亚州威尔逊角地区数量有所减少。","other":"白痣吸蜜鸟能够适应城市环境，是澳大利亚城市中最常见的吸蜜鸟之一。"},{"name":"斑胸吸蜜鸟","english_name":"Mottle-breasted Honeyeater","scientific_name":"Microptilotis mimikae","overview":"斑胸吸蜜鸟（英文名：Mottle-breasted Honeyeater，学名：Microptilotis mimikae），是雀形目吸蜜鸟科Microptilotis的鸟类。亦被称为斑点胸吸蜜鸟。这种中型吸蜜鸟在新几内亚的山林中广泛分布，以其橄榄色的羽毛和独特的斑驳胸部为显著特征。","appearance":"成年斑胸吸蜜鸟体长16.5至17厘米，体重介于22至32.5克之间。头部、颈部和上身呈暗灰橄榄至棕橄榄色，前额带有灰色调。黑色橄榄色的面颊，黄色的耳羽形成明显的斑块，眼圈淡橄榄色。两性羽毛相似，雄鸟平均比雌鸟大。下体橄榄灰色，腹部带有淡黄色或微弱的条纹，下巴到上腹部有较深的棕色斑点。幼鸟特征未详细描述。","call":"发出响亮而短促的“tuck”、“chip”或“chup”声，类似于同属的其他种类。Granti亚种（可能其他亚种也有）会发出连续的鼻音管状鸣叫，类似红腹灰雀的叫声。","habits":"栖息于山脚森林，高度从约150米至1150米，局部地区可达海拔1800米。主要以水果、节肢动物（主要是昆虫）和几乎肯定的花蜜为食。在灌木下层和较低的中层林冠中觅食，偶尔在地面活动。单独或成对出现，有时在大型开花树上与其他吸蜜鸟和太阳鸟一同觅食。","breeding":"在Crater Mt有两个巢穴记录，分别在3月中旬和4月底。巢穴为略呈椭圆形的开放式杯状结构，由细小的植物纤维、枝条和藤蔓构成，外部密集覆盖着活苔藓和蕨类，内部用松散、撕裂且蓬松的植物绒毛衬里。巢高离地面1.7至2米，位于林下层树的水平枝丫分叉处。每个巢含2枚卵，关于繁殖行为的其他信息尚缺。","identification":"与山林吸蜜鸟相比，体型更大，喙更健壮，嘴角线更细；与Microptilotis montanus相比，耳羽为黄色而非白色，嘴角线为淡黄色而非白色。Granti亚种体型较大，上体更绿，前额更灰，下体斑点更明显。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山地中部至东南部，从山区中西部延伸至东南部，主要栖息于山脚至海拔1150米的森林中，局部地区可达海拔1800米。","other":"斑胸吸蜜鸟在Karimui是最常见的森林鸟类之一，也是该盆地六种类似物种中最常见的。"},{"name":"林吸蜜鸟","english_name":"Forest Honeyeater","scientific_name":"Microptilotis montanus","overview":"林吸蜜鸟（英文名：Forest Honeyeater，学名：Microptilotis montanus），是雀形目吸蜜鸟科Microptilotis的鸟类。常见于新几内亚的山地森林中。拥有均匀的褐色羽毛，最显著的特征是白色的耳斑和淡色的下部斑点。体型中等，长约17至18厘米。","appearance":"林吸蜜鸟上半身呈深橄榄棕色，头部和颈部顶部颜色稍暗，脸颊后方有白色耳羽形成明显的浅色斑块。腹部颜色较淡，略带灰色，胸部颜色较深，有时可见模糊的黄色条纹或色调。两翼深褐色，尾羽亦然，边缘呈暗橄榄灰色。嘴黑色，腿蓝灰色。雄鸟和雌鸟羽毛相似，但雄鸟体型略大。幼鸟特征不详，但耳羽带有黄色调。","call":"其主叫声为响亮、略带嘶哑且上扬的‘wheep’声，与同属其他物种的上扬音符类似。","habits":"栖息于未受干扰的山地和低地原始森林内部，偶尔出现在高大的次生森林和灌木丛中。主要活动在海拔400米至1500米之间，以中层树冠为主，高度通常在3至12米，通过啄食和悬停啄食寻找食物。通常单独活动，有时成对出现，偶尔加入混合鸟群，但不会聚集在开花的树木中。","breeding":"关于繁殖信息尚无具体资料，一些已发表的细节可能被误认为是灌丛吸蜜鸟的相关信息。","identification":"与灌丛吸蜜鸟相比，林吸蜜鸟上半身和头部颜色更深，翅膀的边缘和羽缘更不明显且颜色更暗，下部羽毛更灰暗，尤其是胸部。它与新几内亚其他同属物种的区别在于耳斑更浅，几乎为白色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于新几内亚的北部至东南部，包括Fakfak山脉、Kumawa山脉、Yapen岛、Foja山脉、Van Rees山脉和北海岸山脉。","other":"林吸蜜鸟的食物包括果实、种子和节肢动物（主要是昆虫），可能也会吸食花蜜，但极少访问开花的树木。"},{"name":"山林吸蜜鸟","english_name":"Mountain Honeyeater","scientific_name":"Microptilotis orientalis","overview":"山林吸蜜鸟（英文名：Mountain Honeyeater，学名：Microptilotis orientalis），是雀形目吸蜜鸟科Microptilotis的鸟类。属于吸蜜鸟科的鸟类，广泛分布在新几内亚的山区。这种鸟以山地森林为栖息地，常见于海拔550至2100米之间。","appearance":"山林吸蜜鸟体长14至16厘米，体重16至20克，雄鸟平均重18.6克，雌鸟平均重17.6克。头部呈暗橄榄色，额头颜色更深，耳羽下方有一小片黄色斑块，嘴喙细长。上体灰橄榄色，下体带有淡黄色条纹，腹部有模糊的暗色斑点。幼鸟的描述未详。","call":"山林吸蜜鸟的叫声包括单音节的‘tup’或‘tuck’，还有向上滑音的双音节叫声，以及重复的管笛状叫声。","habits":"栖息于原始森林、森林边缘和高大次生林，有时也会出现在花园中。主要活动于中低山脉，海拔范围在550至2100米之间，偏好森林内部环境，较少出现在受扰动的生境中。食物包括花蜜、节肢动物（主要是昆虫）和偶尔的果实。","breeding":"已知的一个巢穴位于Crater Mt，为略呈椭圆形的杯状结构，由植物纤维、枝条和藤蔓制成，外部覆盖着苔藓和竹叶，内部铺满植物绒毛。巢内曾发现两只孵化中的蛋。","identification":"与效鸣吸蜜鸟、Spot-breasted Honeyeater和黄嘴吸蜜鸟相比，山林吸蜜鸟体型更小，耳斑较小，上体橄榄色更浓郁，下体斑纹更淡。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山区，具体包括Foja Mts、Wandammen Mts、Fakfak Mts和Kumawa Mts等地，海拔范围从800至1450米。","other":"在中海拔地区较为常见。"},{"name":"灌丛吸蜜鸟","english_name":"Scrub Honeyeater","scientific_name":"Microptilotis albonotatus","overview":"灌丛吸蜜鸟（英文名：Scrub Honeyeater，学名：Microptilotis albonotatus），是雀形目吸蜜鸟科Microptilotis的鸟类。显著特征包括橄榄绿色的羽毛，白色的耳斑和嘴基的模糊条纹。分布于新几内亚的山脚和中山区，偏好受干扰的生境。","appearance":"成年灌丛吸蜜鸟体长17至19厘米，体重雄鸟27至34克，雌鸟20至29克。头部、颈部和背部呈灰橄榄色，黑色眼周，白色下耳羽形成小圆形耳斑，明亮黄色或橙黄色的口裂边缘，翼上覆羽和翼尖暗棕色，边缘黄橄榄色，尾羽暗棕色，边缘亦为黄橄榄色。腹部均匀淡橄榄灰色，胸腹有淡黄色色调或模糊条纹。雄雌羽毛相似，雄鸟平均比雌鸟大。幼鸟与成鸟相比，耳斑带黄色，上体深橄榄棕色，胸部有不规则的深橄榄棕色带。","call":"发出类似‘chup!’的叫声，或一系列快速的哨声，其歌声由10至12个迅速发出的细音组成，通常音调上升后转低，也可描述为缓慢的颤音‘whee’。呼叫声音清脆悦耳，带有吸气感，类似于同类物种。","habits":"常见于受干扰的生境，包括次生林、森林边缘、沿溪流的森林残余、边际原始森林、中高山草丛、人类活动造成的草地、种植园及城镇和村庄花园。主要栖息于山脚和低山区，偶尔出现在低地，海拔高度从海平面到约1950米。居民鸟种，全年居住在其分布范围内。","breeding":"繁殖记录显示在旱季和雨季中期，蛋在3月初和9月，雏鸟在7月末、9月末和10月末，离巢雏鸟在8月末、9月、2月和5月。巢由精细纤维、苔藓、草、树皮和大量动物丝线构成，内部衬以木纤维、植物绒毛和棉状种子材料，直径约8厘米，深度6.4至8厘米，内径5至7厘米，深度约3.5厘米，悬挂在1至5米高的水平枝叉处。每窝产卵1至2枚，孵化和育雏周期未知，双亲共同喂养雏鸟。","identification":"与相似的林吸蜜鸟区别在于更鲜亮的绿色冠羽和上体，黄色或奶油色的口裂边缘，翼上和尾部的黄橄榄色边缘，下体更单一，口裂边缘更富黄色。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚的鸟头半岛、韦兰德山脉、纳索山脉、奥兰治山脉、休恩半岛以及新几内亚南部和东部。","other":"灌丛吸蜜鸟适应了受干扰的环境，成功侵入了高海拔地区，那里原始森林遭到了广泛破坏。自1932年以来，似乎已经入侵了瓦乌山谷。"},{"name":"效鸣吸蜜鸟","english_name":"Mimic Honeyeater","scientific_name":"Microptilotis analogus","overview":"效鸣吸蜜鸟（英文名：Mimic Honeyeater，学名：Microptilotis analogus），是雀形目吸蜜鸟科Microptilotis的鸟类。广泛分布于新几内亚的低地和山脚林区。其橄榄色的羽毛，黄色耳斑显著，是新几内亚较为常见的物种。","appearance":"成年鸟体长15.5至19.5厘米，体重介于18至30克（雄鸟）和18至24克（雌鸟）。上身呈橄榄褐色，头部顶部更偏褐色，具黑色橄榄色眼线，眼后有一条模糊的条纹延伸至耳羽上方。下耳羽呈淡黄色形成大三角形斑块，喙基部黄色或橙黄色，翼覆羽和小翼羽边缘橄榄黄，初级飞羽边缘黄绿，内缘淡黄，尾羽暗棕色边缘橄榄黄。下体灰黄，有时侧胸带淡灰褐色，翅膀下方橄榄黄。虹膜棕到灰褐色，喙黑，腿蓝灰至灰褐色。雄雌羽毛相似，雄鸟平均略大于雌鸟。幼鸟描述不详，但颜色较浅。flavidus亚种上体更亮黄橄榄色，下体更黄，虹膜更灰。","call":"发出颤音、哨声和‘chup!’声，叫声比山林吸蜜鸟响亮。","habits":"栖息于原始森林、森林边缘、次生林、灌木林、河流边和路边植被，甚至咖啡种植园、花园和潮汐红树林。海拔从海平面至1250米，东部高地可达990米。以昆虫、果实、种子和花蜜为食，常在树冠层下觅食，单独或成对，偶尔5-6只小群活动。","breeding":"繁殖期为8月至12月，flavidus亚种3月至5月。已知巢穴可能属于灌丛吸蜜鸟，无其他繁殖信息。","identification":"与细嘴吸蜜鸟和华丽吸蜜鸟相比，体型稍大，喙较长且不那么纤细，头部侧面较不暗淡。flavidus亚种下体更黄，虹膜更灰。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的四王群岛（新几内亚西北部）、印尼阿鲁群岛（新几内亚西南部）和新几内亚（除东北部分水岭以外的东南部）。"},{"name":"塔古吸蜜鸟","english_name":"Tagula Honeyeater","scientific_name":"Microptilotis vicina","overview":"塔古吸蜜鸟（英文名：Tagula Honeyeater，学名：Microptilotis vicina），是雀形目吸蜜鸟科Microptilotis的鸟类。仅在巴布亚新几内亚的路易西亚德群岛中部的Tagula岛上发现，生活于低地森林和山麓森林边缘，海拔高度约600至800米。关于其生态和适应性的信息极为有限。","appearance":"塔古吸蜜鸟体长约16.5至17厘米，上体主要为橄榄色，额部灰白，具小而淡黄色的喙侧纹，耳羽处有圆形黄斑，臀部有一簇灰色羽毛，尖端带橄榄色，翼羽内缘呈黄白色，下体浅灰偏黄，腹部更显黄色，翼下覆羽为淡黄色。虹膜深褐至灰褐色，喙黑色或黑褐色，腿脚呈蓝灰色。雄鸟比雌鸟大，但羽毛颜色相似，幼鸟特征尚未描述。","call":"发出类似‘chup’的声音，如同近亲物种，也有音乐般的‘wee-you’和‘chew-wit’叫声。","habits":"塔古吸蜜鸟的活动模式未知，可能为留鸟，具体食性和觅食行为尚不清楚。","breeding":"繁殖相关资料缺失。","identification":"它是Tagula岛上唯一的此类吸蜜鸟，通过其独特的橄榄色外观和耳羽的黄色斑点来识别。","protection":"IUCN：LC（无危）","distribution":"分布于巴布亚新几内亚的路易西亚德群岛中的Tagula岛，最近的现代记录是在1992年的一次徒步考察中，有两次目击记录。","other":"由于基本生态信息的缺失，对其灭绝风险的评估受到限制，已知森林砍伐威胁到其栖息地。"},{"name":"细嘴吸蜜鸟","english_name":"Graceful Honeyeater","scientific_name":"Microptilotis gracilis","overview":"细嘴吸蜜鸟（英文名：Graceful Honeyeater，学名：Microptilotis gracilis），是雀形目吸蜜鸟科Microptilotis的鸟类。广泛分布在澳大利亚的阿鲁群岛、新几内亚南部、托雷斯海峡岛屿以及澳大利亚东北部的约克角半岛。该鸟以橄榄灰色为主调，具有一块圆形的淡黄色颊斑和相对纤细的喙。在新几内亚和澳大利亚的低地森林中较为常见。","appearance":"细嘴吸蜜鸟体长约15至17厘米，体重介于12.5至17克之间。其上身主要是深橄榄色，头部侧边逐渐变为灰橄榄色，下巴和喉部可见淡淡的黄色。耳羽后方有显著的黄色斑点，喙基部呈现黄色到橙黄色。翅膀和尾巴边缘比背部更亮黄绿色，下体为淡橄榄灰色，腹部中央有隐约的黄色条纹。虹膜呈灰棕色或蓝灰色，喙为黑色，腿脚颜色从浅至暗灰色不等。雄鸟和雌鸟在外表上相似，但雄鸟体型略大。幼鸟与成鸟非常相似，但背部、肩部和臀部带有棕色色调，髭纹不那么明显。","call":"细嘴吸蜜鸟会发出多种声音，其中最常见的是柔和的‘plit’或‘chip’声，有时为更尖锐的‘plik’。在新几内亚和阿鲁群岛，这种叫声表现为急促的‘kip’、‘tchick’或‘tuk’。它们还会发出高音上升的口哨声‘wip-wip wip…’或‘whit-whit-whit…’，由4至12个音符组成，每秒约4个音符。","habits":"栖息于雨林边缘、藤蔓灌木丛、再生雨林及邻近的开阔森林和树林地带。它们在树冠层、中冠层和下层灌木中觅食，高度通常在2至18米之间。食物包括花蜜、果实和昆虫，觅食时会在花朵、枝叶、果实和藤本植物中搜索。偶尔也会在花园和村庄中的果园里活动。","breeding":"在澳大利亚东北部，繁殖季节为9月至次年2月，筑巢期一般在10月至次年1月，孵化期约为15天，雏鸟期大约10至11天。巢穴为杯状，由苔藓、藤蔓、树皮纤维等构成，内部铺有植物绒毛，位于活植物的外层枝叶中，高度从0.75至3米不等。","identification":"与利氏吸蜜鸟和黄斑吸蜜鸟相比较，细嘴吸蜜鸟的颊斑形状为圆形，而非新月形或椭圆形。此外，成鸟具有蓝灰色的眼睛，而利氏吸蜜鸟的眼睛呈蓝色，黄斑吸蜜鸟的眼睛呈棕色。","protection":"IUCN：LC（无危）","distribution":"在澳大利亚，主要分布于阿鲁群岛、新几内亚南部、托雷斯海峡岛屿以及约克角半岛。在新几内亚，分布于低地、次生林、森林边缘、原始森林、季风森林、稀树草原、河岸森林和轻度林区。在澳大利亚，从海岸到山麓和山脉，偶尔到高原，大部分海拔低于500米，偶尔可达800米左右。","other":"在IOC分类中，imitatrix被独立为阿洛摄蜜鸟。"},{"name":"华丽吸蜜鸟","english_name":"Elegant Honeyeater","scientific_name":"Microptilotis cinereifrons","overview":"华丽吸蜜鸟（英文名：Elegant Honeyeater，学名：Microptilotis cinereifrons），是雀形目吸蜜鸟科Microptilotis的鸟类。新几内亚东南部特有种。主要栖息于低地雨林边缘和次生林中，偶尔出现在季风雨林、灌木沼泽森林以及花园等地。其显著特征为长而细的喙，以及围绕眼后的大黄色斑点。","appearance":"成鸟长约14至18厘米，体重约22克。头部上方呈暗橄榄色，额部颜色更深，眼周有黑色边缘环绕的黄色斑点，耳羽后方有明亮的黄色或橙黄色。上翼覆羽和翼缘为深棕色，边缘带有黄橄榄色，尾巴为深棕色，边缘同样呈现较亮的橄榄色。下体偏灰黄，侧胸部分颜色最鲜艳。虹膜呈褐色至灰色，喙为黑色，腿脚蓝灰或肉灰。雌雄羽毛相似，雄鸟平均体型大于雌鸟。幼鸟特征未详述。","call":"常发尖锐的‘tchick’、‘tick’或‘tuk’叫声，亦会发出细薄的颤音，结尾上扬，或在警戒时重复高音的‘ki-ki-ki-ki...’。","habits":"栖息于低地至海拔600米，局部可达900米的环境中，偏好低地雨林边缘和次生林。以花蜜、果实和昆虫为食，从树冠层到灌木层都有觅食行为，主要在林下层和中层活动，通常单独或成双出现，有时也会形成小群。","breeding":"繁殖期记录显示，产卵期在10月和2月初，雏鸟离巢时间为3月末，雌鸟在9月初生殖腺增大。巢为深杯状，由草、叶子和蜘蛛网构成，内部铺有种子荚的绒毛，直径约6.4厘米，深度约7厘米，内径5.1厘米，深度4.5厘米。巢悬挂在树枝末端或藤蔓上，高度从地面附近至6米不等。每次产卵2枚，孵化期12至14天，幼鸟成长期未知。","identification":"与效鸣吸蜜鸟相比，华丽吸蜜鸟体型较小，眼周有黑色边缘，面部斑点明显。","protection":"IUCN：LC（无危）。估计种群数量未知，一般认为分布区较为常见。","distribution":"分布于新几内亚东南部，包括米尔恩湾、萨里巴岛等地区，北部至少到达古德诺夫湾，南部延伸至马拉劳阿。在新几内亚北水分岭也有分布，但种族身份不确定。"},{"name":"黄嘴吸蜜鸟","english_name":"Yellow-gaped Honeyeater","scientific_name":"Microptilotis flavirictus","overview":"黄嘴吸蜜鸟（英文名：Yellow-gaped Honeyeater，学名：Microptilotis flavirictus），是雀形目吸蜜鸟科Microptilotis的鸟类。广泛分布于新几内亚的低地和山麓森林中。其最显著的特征是拥有亮黄色的大嘴裂，以及橄榄色的外表。","appearance":"这种鸟体型较小，长度约15厘米，重量在17至22克之间。上部颜色为灰橄榄色，头部侧面更偏灰色，耳羽淡黄色形成小斑点，嘴裂处有醒目的鲜黄色，向下与橙黄色的嘴角纹相连。翅膀深棕色，翼盖和羽轴边缘呈橄榄色，尾羽深棕色边缘橄榄色。腹部灰白色，下巴和喉部带有黄色调，翅膀下覆羽淡黄白色。眼睛浅灰棕色，喙黑色至灰棕色，腿橄榄黄色。","call":"鸣叫声包括重复的‘wipwipwip...’声和类似其他同类物种的‘chup’声。","habits":"栖息于原始森林及边缘地带，包括山麓森林和季雨林，海拔高度从海平面到约1400米。主要食物为节肢动物（尤其是昆虫）和可能的水果与花蜜。在树冠层觅食，常在开花或结果的树木中活动。通常单独或小群出现，有时与其他吸蜜鸟混群，如细嘴吸蜜鸟和效鸣吸蜜鸟。","breeding":"关于繁殖行为的信息尚未报告。","identification":"与灌丛吸蜜鸟的区别在于体型较小、喙更细长、耳斑较小、背部颜色更偏灰色，嘴角纹更加明显。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的低地和山麓森林。","other":"被认为是新几内亚地区Microptilotis属中最罕见的种类之一。"},{"name":"隐吸蜜鸟","english_name":"Cryptic Honeyeater","scientific_name":"Microptilotis imitatrix","overview":"隐吸蜜鸟（英文名：Cryptic Honeyeater，学名：Microptilotis imitatrix），是雀形目吸蜜鸟科Microptilotis的鸟类。近期自细嘴吸蜜鸟中分拆独立成种。常见于澳大利亚东北部，尤其是昆士兰州远北部的雨林及森林边缘地带。该鸟种具有橄榄灰色的体羽，最显著的特征是其圆形淡黄色颊斑和相对较细的喙。","appearance":"隐吸蜜鸟体型小巧，长度约为15至17厘米，雄鸟体重14至17.9克，雌鸟体重12.5至17克。全身呈暗橄榄绿色，头顶、颈背和前额颜色略深，耳羽后方有醒目的淡黄色斑点，形状略呈菱形，喙短而细，颜色由黄到橙黄色不等，翼羽和尾羽边缘比背部更亮黄绿色。下体灰橄榄色，腹部尤为明显。虹膜蓝灰色，喙黑色，腿脚颜色从浅到深灰色不等。","call":"其叫声丰富，最常见的是“chip”声，被描述为“plick”。此外，还发出4至8个尖锐的吱吱声，偶尔在繁殖季节初期会发出“choup-choup-choup...”的叫声。与细嘴吸蜜鸟不同，隐吸蜜鸟似乎没有典型的鸣唱。","habits":"隐吸蜜鸟主要栖息在雨林或森林边缘，包括藤本灌丛和再生雨林，以及邻近的开阔森林和以桉树和木麻黄为主的林地。它们在海岸至山脚和山脉间活动，海拔高度多在500米以下，偶尔可达800米左右。以花蜜、果实和昆虫为食，通常在树冠层、中层和下层灌木中觅食，高度范围为2至18米。它们通过探花获取花蜜，主要通过啄食获得昆虫，偶尔在空中捕捉。","breeding":"繁殖期为9月至翌年2月，筑巢期估计始于10月至11月，孵化期约15天，雏鸟期大约10至11天。巢呈杯状，由苔藓、藤蔓、根、树皮纤维等材料构成，内部衬以植物绒毛或其他纤维，通常悬挂在植物外层枝叶的小分叉上，离地面高度一般在0.75至3米之间，有时高达15米。","identification":"与利氏吸蜜鸟和黄斑吸蜜鸟的区别在于颊斑的形状，隐吸蜜鸟的颊斑为圆形，而利氏吸蜜鸟的颊斑为新月形，黄斑吸蜜鸟的颊斑为椭圆形。此外，隐吸蜜鸟的虹膜为蓝灰色，不同于利氏吸蜜鸟的蓝色和黄斑吸蜜鸟的棕色。","protection":"IUCN：LC（无危）","distribution":"隐吸蜜鸟分布于澳大利亚东北部，具体范围从约克角半岛东南部至昆士兰州东北部，内陆可达阿瑟顿高原。","other":"隐吸蜜鸟曾被认为是细嘴吸蜜鸟的一部分，但基于羽毛、鸣叫差异以及遗传分化，现已被确认为独立物种。"},{"name":"白纹吸蜜鸟","english_name":"White-lined Honeyeater","scientific_name":"Territornis albilineata","overview":"白纹吸蜜鸟（英文名：White-lined Honeyeater，学名：Territornis albilineata），是雀形目吸蜜鸟科Territornis的鸟类。属于吸蜜鸟科，体型中等，主要栖息于澳大利亚北部的砂岩峭壁和峡谷地带，包括卡卡杜国家公园和凯瑟琳峡谷的砂岩区域。上体呈均匀的灰绿色，胸部有淡色模糊的灰色条纹。脸颊深色，被细薄的苍白嘴角标记分割，向上延伸至蓝眼下方。","appearance":"白纹吸蜜鸟长约17-20.5厘米，体重雄鸟22.3-29.9克，雌鸟19-23.5克。体型苗条，喙短而纤细，略向下弯曲。头部、颈部和背部大部分为暗棕色，脸部渐变为烟灰色，有小而明显的黄色嘴角，白色髭纹从嘴角向后延伸至耳羽处，有时分开或不明显。次级飞羽覆羽有深色斑点，中覆羽边缘呈淡灰棕色，大覆羽边缘黄色，翅膀折叠时形成淡黄色面板；尾巴边缘同样淡黄色；下巴和喉咙有时带有模糊的棕灰色条纹；腹部灰白色，胸侧有灰棕色的斑点，逐渐变成均匀的灰色洗刷；腹部和两侧有模糊的棕灰色条纹；下尾呈灰棕色；下翼呈淡褐色，边缘和尖端宽大的灰棕色。虹膜灰白色至淡蓝灰色；喙黑色；腿灰色至棕色。两性羽毛相同，雄鸟比雌鸟大。幼鸟类似成鸟，但无髭纹，较大的黄白色耳羽，上翼覆羽带红褐色，下喉和胸部仅有微弱的斑点或条纹，下腹部淡灰褐色无条纹。","call":"白纹吸蜜鸟的叫声多样，包括响亮、波动、含糊的哨声，通常在一天中的任何时候全年都能听到。","habits":"白纹吸蜜鸟主要栖息在崎岖的砂岩悬崖和山脉的植被峡谷、沟壑、悬崖和高原，偏好茂密的常绿灌木丛和灌木林，如金合欢、紫檀和栀子花。有时在桉树树林中，有金合欢和无花果的灌木丛，山谷底的纸皮树森林，以及地形上受火保护的季风雨林。它们似乎过着定居的生活，可能有一些局部移动。它们以昆虫为主食，也吃蜘蛛、花蜜、果实和种子。在密集的上层植被中觅食，活跃快速地穿梭于叶间，从树叶和大树枝上获取食物，探查岩石缝隙，通过悬停和突袭捕捉昆虫。它们通常是隐秘和警觉的，通常单独或成对出现，偶尔在小群体中（如五只）在食物源附近，据说会与其它吸蜜鸟种类在开花树或其它食物源附近结伴，对较小的竞争对手表现出攻击性。","breeding":"关于繁殖细节很少。已知产卵时间为九月，新生雏鸟出现在十月早期，最近的空巢在一月中旬，两只离巢雏鸟在1月23日发现；根据生殖腺状况，繁殖季节主要在十月至一月之间。三个巢穴的描述，均为杯状，由细枝和藤蔓交织而成，两个内衬细长草、柔韧的植物茎和纤维（一个未内衬），边缘用蛛丝、蜘蛛网或棉状植物材料加固，外部直径7.5-9.6厘米，深度5.8-8.7厘米，内部直径5.5-7厘米，深度5-6.3厘米；支撑于树枝或悬挂在边缘1.2-5米高地面的小灌木或树的外枝和嫩枝上。仅发现一个蛋巢，含有2个蛋；雄鸟被观察到喂养离巢雏鸟，但未知雌鸟是否也参与喂养。没有更多信息。","identification":"白纹吸蜜鸟与淡色白纹吸蜜鸟（M. fordianus）的叫声有细微差别，后者歌曲音符更长，颤抖更明显，间隔不均。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚中北部的Top End中部和NT北部，包括卡卡杜国家公园和凯瑟琳峡谷。","other":"白纹吸蜜鸟曾包含淡色白纹吸蜜鸟为其亚种，但现在被认为是独立物种。"},{"name":"淡色白纹吸蜜鸟","english_name":"Kimberley Honeyeater","scientific_name":"Territornis fordiana","overview":"淡色白纹吸蜜鸟（英文名：Kimberley Honeyeater，学名：Territornis fordiana），是雀形目吸蜜鸟科Territornis的吸蜜鸟。其上体呈均匀灰绿色，下体颜色较浅，胸间有模糊的灰色条纹。深色脸颊上有一道细长的淡色口角标记，向上延伸至蓝色眼睛下方。叫声独特，包括响亮而短促的哨声短语。分布于澳大利亚西北部的 Kimberley 地区，包括 Admiral 海湾至 Drysdale 河南岸，东至 Drysdale 河国家公园，以及 Bonaparte 群岛中的 Boongaree、Bigge 和 Wollaston 岛。","appearance":"淡色白纹吸蜜鸟的上体颜色统一为灰绿色，下体色调较淡，胸前有模糊的灰色斑纹。脸颊深色，有一道细长的淡色标记，从嘴角延伸至蓝眼下方。与白纹吸蜜鸟相比，其翼羽和尾羽上没有黄色边缘，下翼覆羽呈奶油色，腹部乳白色。","call":"叫声包括快速爆发的有力颤音，最多可达12个上滑音和下滑音的啾啾哨声。与白纹吸蜜鸟相比，叫声更快，常分为2至5个音符组成的可识别短语，重复几次。","habits":"栖息于 Kimberley 地区的雨林、桉树林和纸皮树森林。在 Charnley River–Artesian Range 野生动物保护区可见。","breeding":"繁殖期从8月至次年1月，会在蜘蛛网和植物纤维制成的深巢中产下两枚红棕色斑点的粉色蛋。","identification":"与白纹吸蜜鸟的主要区别在于，淡色白纹吸蜜鸟的翼羽和尾羽上缺乏黄色边缘，下翼覆羽颜色较浅，腹部为乳白色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚 Kimberley 地区，西澳大利亚东北部，包括 Bonaparte 群岛中的 Boongaree、Bigge 和 Wollaston 等岛屿。","other":"基于遗传分析，淡色白纹吸蜜鸟现被视为独立物种，而非白纹吸蜜鸟的一个亚种。"},{"name":"纹胸吸蜜鸟","english_name":"Streak-breasted Honeyeater","scientific_name":"Territornis reticulata","overview":"纹胸吸蜜鸟（英文名：Streak-breasted Honeyeater，学名：Territornis reticulata），是雀形目吸蜜鸟科Territornis的小型鸟类，主要分布在澳大利亚的Semau（帝汶岛西部）和帝汶岛（小巽他群岛东部）。其显著特征是橄榄灰色上部羽毛，带有绿色翼羽，淡色腹部饰以浓重的暗色条纹，有时看起来像白色条纹衬于深色背景之上。","appearance":"纹胸吸蜜鸟长约15.5厘米，拥有短而粗壮的向下弯曲的喙。雄鸟上部呈灰橄榄色，眼周有明显的黑色细纹，耳羽后部有明亮的橙黄色斑点，从喙基延伸至眼后的宽阔白色胡须纹。前耳羽灰白相间，与暗橄榄色颊纹区分开来的白色胡须纹与未标记的白色到灰白色的下巴和喉咙相连；翅膀和尾巴的颜色略深于上体，飞羽和尾侧边缘呈黄绿色；下体颜色从灰白至白色，饰有大胆而杂乱的棕橄榄色条纹，从胸部延伸至尾下覆羽，腹部有黄色调，尾下覆羽深橄榄灰色，下翅棕色灰色；虹膜蓝灰色，喙黑色，腿深灰色。雌雄羽毛相似，雄鸟体型大于雌鸟。幼鸟特征未详述。","call":"纹胸吸蜜鸟发出一系列约9-10个哀怨且略微上扬的'wheep'音符，开始时迅速随后放慢，持续约5秒；单调、快速重复的3-5个音符'week week week...'，每个音符都有上升的音调；以及低沉的'work-work'声。","habits":"生活在原生林、次生林（包括落叶和常绿或半常绿森林，如季风森林）、退化森林、灌木丛、半耕作地和城市花园中；偶尔出现在红树林区域。海拔范围从低地到1300米。推测为留鸟，可能有局部移动。食物包括昆虫、花蜜和可能的果实，单个、成对或3-6个小群体出现，常在桉树的花朵中觅食。","breeding":"繁殖期估计在3月至4月和9月，基于5月末的离巢幼鸟和11月中旬的依赖性幼鸟，以及其他5月末和6月中旬的幼鸟。无其他繁殖信息。","identification":"与黄耳吸蜜鸟（Yellow-eared Honeyeater）相似，但纹胸吸蜜鸟缺乏黄色下体。通过其独特的条纹下体和耳羽上的橙黄色斑点进行区分。","protection":"IUCN：LC（无危）。分布范围有限，仅见于帝汶和Wetar EBA。在帝汶普遍且常见。以前被认为接近受威胁。","distribution":"分布于Semau（帝汶岛西部）和帝汶岛（小巽他群岛东部）。在低地至海拔1300米的范围内活动。"},{"name":"蓬背吸蜜鸟","english_name":"Puff-backed Honeyeater","scientific_name":"Meliphaga aruensis","overview":"蓬背吸蜜鸟（英文名：Puff-backed Honeyeater，学名：Meliphaga aruensis），是雀形目吸蜜鸟科吸蜜鸟属的鸟类。广泛分布于新几内亚及其周边岛屿。其显著特征包括橄榄色的羽毛，黄色的脸颊和嘴基部的条纹。生活在低地和山脚森林及其边缘地带。","appearance":"体型中等至略大，约16.5至18.5厘米长，体重在21至31克之间，雄鸟通常比雌鸟稍大。背部覆盖着密集的硬羽，上体呈深橄榄褐色到灰橄榄色，头部颜色更深。具有独特的黑橄榄色的眉纹，耳罩为大块的柠檬黄色。下体主要是灰色，胸部带有淡橄榄黄色调，腹部下方颜色更浅，带有黄绿色调。幼鸟的描述未给出。","call":"鸣声包括快速低沉、上升后减速的颤音，持续时间可达2秒，多次重复，类似黄嘴翡翠的声音。还有管道式短促、清脆、上升的音符系列，以及短促的“chup”或“chap”声，以及低哨音。","habits":"栖息于多种森林环境，包括原始雨林和平原森林，也会出现在森林边缘、次生林和高大的再生林。主要分布在低地和丘陵，海拔从海平面到约1250米。生活方式上似乎主要是定居，但存在局部迁移。以果实、种子、节肢动物（主要是昆虫）为食，可能也摄取花蜜，已知会访问Poikilospermum和Syzygium的花序。","breeding":"繁殖记录显示，巢穴是一个由枯叶（包括竹叶）、草和草状茎、细植物纤维或树皮碎片编织而成的整洁杯状结构，用蜘蛛网和植物纤维加固，内部衬有细草状茎或根须。巢悬挂在离地面0.3至1.2米高的水平叉或树枝上。一窝产1至2枚蛋，仅由雌鸟孵卵，双亲共同喂养幼鸟。","identification":"与其他近缘物种非常相似，但蓬背吸蜜鸟体型更大、更粗壮，喙较厚。亚种sharpei有更长的耳罩，上体颜色更绿橄榄色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚和周边岛屿，包括主要低地和丘陵地区，最高记录海拔达到1580米。","other":"在瓦希吉谷和埃佩谷等地有记录，最高海拔记录为1400米。"},{"name":"黄斑吸蜜鸟","english_name":"Yellow-spotted Honeyeater","scientific_name":"Meliphaga notata","overview":"黄斑吸蜜鸟（英文名：Yellow-spotted Honeyeater，学名：Meliphaga notata），是雀形目吸蜜鸟科吸蜜鸟属的鸟类。最显著的特征是头部后方的黄色斑点。该鸟种主要分布在澳大利亚东北部，特别是在昆士兰北部的湿润地区。","appearance":"成年黄斑吸蜜鸟体型中等，体长介于16.5至20厘米之间，重量范围从20克到33克不等。头部和颈部呈橄榄色，下巴和喉咙处颜色较淡，耳羽后方有圆形至菱形的突出黄色斑块。上身暗橄榄色，翅膀和尾巴边缘略带黄绿色。腹部下方颜色较浅，带有模糊的黄色斑纹，腹中部有一片模糊的稻草黄色。虹膜深棕色，喙黑色，腿脚呈深灰色，后跗跖部分粉红棕色，足底黄棕色。雄雌羽毛相似，但雄鸟体型较大。幼鸟特征未详述。有两种亚种：指名亚种和mixta种，后者翼展稍短，头部、颈部和上体颜色更深，胸部和腹部颜色较暗，腹部黄色斑纹不明显。","call":"黄斑吸蜜鸟发出响亮、尖锐、断续下降的叫声，音节缓慢而有节奏，通常由三至十个音符组成，开始时速度较慢，随后逐渐加速。此外，它还会发出单调的重复音，急促的警告声，上升的连续音调，以及重复的清脆哨音。","habits":"栖息于低地热带雨林、季风雨林和藤蔓灌木丛，也出现在红树林森林、混合林地、半落叶沙丘林地、开阔桉树森林和邻近雨林的桉树林地，以及湿地边的灌木丛。常见于城市公园和花园，偶尔会进入半干旱地区的河流沿岸。主要生活在海拔600米以下的低地和山麓地带。","breeding":"繁殖季节从8月持续到次年4月。筑杯状巢，一般由树皮条、植物纤维和苔藓构成，悬挂在树枝分叉处1.5至1.8米高，巢深4.4至7.6厘米，直径8.9至10.2厘米，内部深度3.8至5.1厘米，直径6.4至7.6厘米。每窝产卵通常2枚，有时3枚，孵化期约15天，雏鸟由双亲共同喂养，离巢期为14至15天。","identification":"与利氏吸蜜鸟和细嘴吸蜜鸟的区别在于脸颊斑的形状：黄斑吸蜜鸟为椭圆形，利氏吸蜜鸟为新月形，细嘴吸蜜鸟为圆形。成年黄斑吸蜜鸟有棕色眼睛，而另两者眼色较浅。叫声也各有特色。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚东北部，包括昆士兰北部的湿润地区。"},{"name":"利氏吸蜜鸟","english_name":"Lewin's Honeyeater","scientific_name":"Meliphaga lewinii","overview":"利氏吸蜜鸟（英文名：Lewin's Honeyeater，学名：Meliphaga lewinii），是雀形目吸蜜鸟科吸蜜鸟属的鸟类。此鸟以澳洲艺术家John Lewin命名，分布于澳大利亚东部，自北昆士兰至维多利亚中部，偏好湿润森林环境，常见于雨林和湿硬叶林中，亦适应城市公园与花园。其显著特征为橄榄灰体羽，脸颊带淡黄色斑块，喙较粗壮。","appearance":"体型中等，长约19-21.5厘米，体重27.5-49.5克（雄鸟）和27.3-41.5克（雌鸟）。上体暗橄榄色，头部转为暗灰色，具黑色眼纹，耳羽后部有突出的黄色新月状斑点，翼与尾缘呈黄橄榄色。下体略淡于上体，橄榄灰底色，腹侧有暗色条纹与淡黄色斑点。虹膜蓝灰至深灰褐色，喙黑，腿粉棕色渐变至前胫与趾尖的暗灰色。雄雌羽色相似，雄鸟体型较大。幼鸟类似成鸟，但上体更偏褐色，下体呈单调的黄橄榄色，尾下覆羽均匀稻草黄，虹膜深褐，新离巢幼鸟喙端有模糊的淡色部分。","call":"发出快速连续的断音机枪声般的叫声，持续时间可达数分钟，每秒约11个音符，声音独特。此外，也会发出重复的响亮斥责声‘schwep’或强烈而略带沙哑的‘week’，通常在警戒时发出；偶尔会发出‘toc’或‘chot’，以约2-2.5音符/秒的频率缓慢单调地重复。","habits":"栖息于雨林、湿硬叶林及其边缘植被，也见于次生林、公园、花园、果园、灌木丛、松树林以及种植园。海拔分布从海岸线到1000米，冬季小群体会向低海拔迁移。以果实、花蜜为主食，兼食昆虫、蜘蛛与软体动物。觅食活动遍及树冠至地面，常单独或成对行动，有时形成6-12只的小群体。","breeding":"繁殖季节在7月至翌年3月，筑大型深杯状巢，由树皮条、树叶、藤蔓、草、苔藓等材料构成，直径8.9-11.4厘米，深度6.4-7.6厘米，置于2.2-25米高处。一窝通常产2枚卵，孵化期14-15天，双亲共同育雏，雏鸟留巢期约15天，离巢后至少一周内仍受双亲喂养。","identification":"与细嘴吸蜜鸟和黄斑吸蜜鸟相区别，后者眼斑形状分别为圆形和椭圆形，且后者的眼色分别为蓝灰色和棕色。通过体型、叫声、耳斑形状大小辨别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部沿海地区，从北昆士兰至维多利亚中部，包括雨林、湿硬叶林及其周边的次生林、公园、花园等地。","other":"已适应人类活动区域，利用外来果实丰富饮食，可在小片残留雨林中生存。有时被视为软果作物害鸟，成熟果实吸引大量个体，造成损害。"},{"name":"瓜岛吸蜜鸟","english_name":"Guadalcanal Honeyeater","scientific_name":"Guadalcanaria inexpectata","overview":"瓜岛吸蜜鸟（英文名：Guadalcanal Honeyeater，学名：Guadalcanaria inexpectata），是雀形目吸蜜鸟科瓜岛吸蜜鸟属的中型鸟类，分布于所罗门群岛中南部的瓜达尔卡纳尔岛山区，以其独特的亮黄色颈羽而闻名。","appearance":"瓜岛吸蜜鸟体型中等，长度约18至20厘米，体重介于37.5至48.5克之间。上体呈板岩灰色，臀部和上尾覆羽带有褐色调。头部两侧有显著的亮黄色羽毛簇，延伸至喉侧。尾巴为褐灰色，边缘带黄橄榄色。翅膀上部为板岩灰色，翼端和覆羽有宽阔的黄橄榄色边缘。下体颜色较浅，胸部有暗灰色条纹，腹部灰白，尾下覆羽呈淡褐色。虹膜颜色从浅到深棕色，有时略带红棕色。喙黑色，腿脚蓝灰色。雄鸟比雌鸟稍大，尾羽更宽。","call":"通常安静，但会发出响亮悦耳的‘per-twee per-twee’叫声，曾有记录在飞行中发出单一的低沉但响亮的‘techook’声。","habits":"栖息于高山森林，尤其是海拔950米以上的苔藓森林，常见于1450米以上高度。可能为留鸟，以小型至中型软体昆虫为食，也几乎肯定采食花蜜。单个或成对在树冠层悄悄觅食，动作敏捷，但通常警觉且隐蔽。","breeding":"繁殖信息未知。","identification":"与其他吸蜜鸟相比，其亮黄色的颈羽和特定的叫声是辨识要点。","protection":"IUCN：LC（无危）","distribution":"仅分布于所罗门群岛中的瓜达尔卡纳尔岛山区，特别是在南Betilonga山脉1450至1565米的高度。","other":"瓜岛吸蜜鸟于1929年由Ernst Hartert首次描述，基于Rollo Beck夫妇1927年采集的标本。"},{"name":"橙颊吸蜜鸟","english_name":"Orange-cheeked Honeyeater","scientific_name":"Oreornis chrysogenys","overview":"橙颊吸蜜鸟（英文名：Orange-cheeked Honeyeater，学名：Oreornis chrysogenys），是雀形目吸蜜鸟科橙颊吸蜜鸟属的鸟类。是橙颊吸蜜鸟属下的唯一物种，主要分布在印尼西巴布亚的中央山脉，特别是在雪山西部和奥兰治山脉，包括卡尔斯滕山和维利米娜山。具有独特的橙黄色脸颊，周围有一条细黑线，整体呈橄榄色，腹部偏灰。这生活在高海拔地区的鸟类，常见于亚高山森林和灌木丛。","appearance":"橙颊吸蜜鸟体长24至26厘米，雄鸟体重约77克，雌鸟约62克。头部和颈部为暗橄榄色至橄榄灰色，头顶有深棕色至黑色斑点，前眼处有一小块银灰色，眼睛后方有短而窄的黑色条纹，最显眼的是从眼下方延伸到耳羽后方的金黄色至橙黄色颊斑。上体为暗橄榄至橄榄灰色，臀部较淡且偏灰，尾上覆羽颜色更浅。翅膀和尾巴的外缘呈黄橄榄色，形成与上体对比明显的橄榄色下翼。下体为灰橄榄色，逐渐过渡为淡橄榄灰色，腹部和臀部颜色最浅。腿为黄色。","call":"其叫声包括上升音调的单个泡泡声和嘶哑的下降声'nnyau'。","habits":"生活在亚高山森林和紧邻的高山草甸，偶尔也会在湿地草甸和苔藓覆盖的低矮树木附近活动。通常在低矮的灌木丛或远离密林的灌木丛中觅食，也会在潮湿的苔原草地觅食。食物主要包括果实、节肢动物（昆虫）和莎草种子。","breeding":"繁殖信息知之甚少。已知在八月时雄鸟处于繁殖状态，发现过一个巢，外观类似盆状，主要由粗苔藓和地衣构成，内部则主要由草茎和一些蕨类植物茎组成，内衬以树蕨叶片的鳞片和少量羽毛。巢位于地面以上1.5米的树蕨基部，距离森林约150米。记录显示，十月时会喂养雏鸟。","identification":"与黑喉吸蜜鸟有相似之处，但橙颊吸蜜鸟体型更大，颜色更淡，面部黄色形状不同，且没有白色颈斑。","protection":"IUCN：LC（无危）","distribution":"分布于西巴布亚的高海拔山区，包括雪山西部和奥兰治山脉，主要在中央山脉的亚高山森林和草甸。记录高度在3225至4000米之间，主要在3250米以上，偶尔低至2450米。","other":"在全球范围内并不受到威胁，但在高海拔地区相对常见。"},{"name":"绿裸吸蜜鸟","english_name":"Yellow-billed Honeyeater","scientific_name":"Gymnomyza viridis","overview":"绿裸吸蜜鸟（英文名：Yellow-billed Giant Honeyeater，学名：Gymnomyza viridis），是雀形目吸蜜鸟科裸吸蜜鸟属的鸟类。体型庞大、健壮的吸蜜鸟，全身呈现暗淡的灰橄榄色，翼和尾带有黄绿色调，最显著的特点是拥有明亮的黄色喙和眼圈。该物种依赖于成熟原始森林，尤其是低地森林，偶尔在海拔600米以上的地方也能发现它们的踪迹。在斐济的Vanua Levu和Taveuni两岛上，绿裸吸蜜鸟被认为是相当常见的。","appearance":"绿裸吸蜜鸟体长25至31厘米，拥有中等长度、细长且略向下弯曲的喙。整体羽毛颜色为暗橄榄色，有时在野外观察时会显得偏黄橄榄色。眼睛周围和眉纹呈淡黄色，上身羽翼和尾羽的末端及隐蔽部分为棕橄榄色，与上体颜色略有对比。下翼为浅灰橄榄色，边缘和尖端为较深的橄榄灰色。虹膜为灰色至深棕色，喙和腿均为鲜黄色。雌雄羽毛相似，雄鸟体型略大于雌鸟。关于幼鸟的描述尚未有记录。","call":"绿裸吸蜜鸟不常发出声音，但其最常见的叫声是一种极其响亮、清脆、传播远的‘kee-too’声。","habits":"绿裸吸蜜鸟主要栖息于连续的大片成熟原始森林，包括山地和高山森林，偶尔在森林边缘、退化森林与成熟森林交界处或在草地边缘的孤立高树中发现。它们似乎无法容忍严重砍伐的森林，除非还有剩余的成熟森林区域。通常生活在山区，记录的高度范围为460至1030米（偶尔更低）。在农业区靠近成熟森林的开花或结果的树木中偶尔也能看到它们的身影。该物种似乎具有较弱的分散能力，可能是居民性鸟类。","breeding":"关于繁殖的细节知之甚少。据信繁殖至少发生在6月至10月之间，且有记录显示8月末观察到过幼鸟。关于窝卵数、蛋的详情、孵化期和雏鸟期的信息目前尚无记录。仅观察到单个依赖性的幼鸟，推测雏鸟依赖父母的时间可能长达2至3个月或更久。","identification":"绿裸吸蜜鸟与Northern Wattled-Honeyeater相似，但体型更大，整体颜色更偏向黄色，且喙部明显为淡黄色。与褐嘴裸吸蜜鸟存在明显的表型和行为差异，分子研究表明两者在mtDNA序列上有显著区别。","protection":"IUCN：LC（无危）。绿裸吸蜜鸟在合适的栖息地中相对常见。两个岛屿上的种群被认为规模合理（并不罕见），并且似乎没有显著下降。在几乎所有的良好森林保护区中都能找到它们，同时在斐济法律中受到保护。然而，它们需要大片连续的雨林环境，过去的森林损失和退化对其构成持续威胁，尤其是在Vanua Levu岛，森林覆盖率已降至约50%，该物种可能仅限于岛的中部和西部。","distribution":"绿裸吸蜜鸟分布在太平洋的Vanua Levu和Taveuni两岛，位于斐济中北部，波利尼西亚西南部。","other":"绿裸吸蜜鸟曾被认为与巨吸蜜鸟是同种，但显示出明显的表型和行为差异。2014年的一项分子系统发育研究发现，二者在mtDNA序列上也有显著差异，建议将G. v. brunneirostris提升至物种级别。国际鸟类学家联盟接受了这一提议，为命名为‘绿裸吸蜜鸟’，而褐嘴裸吸蜜鸟则被称为‘巨吸蜜鸟’。"},{"name":"褐嘴裸吸蜜鸟","english_name":"Giant Honeyeater","scientific_name":"Gymnomyza brunneirostris","overview":"褐嘴裸吸蜜鸟（英文名：Duetting Giant Honeyeater，学名：Gymnomyza brunneirostris），是雀形目吸蜜鸟科裸吸蜜鸟属的鸟类，体型较大，全身呈暗淡的灰橄榄色，翼和尾带橄榄色调，喙黑色锥形。黄色颊须明显可见，依赖成熟原始森林生存，常见于低海拔地区，偶尔在海拔600米以上。曾与绿裸吸蜜鸟视为同种，但分子研究表明两者在遗传上显著不同。","appearance":"体型庞大，身长25至31厘米，体色单调灰橄榄色，翼和尾具橄榄绿，喙色黑，两性羽毛相似，雄鸟略大于雌鸟。与绿裸吸蜜鸟相比，喙色更偏向橄榄棕至棕黑色，腿脚颜色更深，尾稍长，整体羽色更明亮的橄榄色，缺乏暗黑调子。幼鸟仅喙尖黄色。","call":"最常见叫声为连续响亮的“kee-yow”，通常重复数分钟，形成系列叫声。","habits":"主要以花蜜（包括椰子树）和节肢动物为食，偶尔食用小浆果、软果实和蜥蜴。常在外冠层或高大森林的下层觅食，活跃跳跃，有时沿树干攀爬，以捕食节肢动物。羞涩且隐秘，常闻其声而难见其影，但会在食物源处成群出现，对某些物种如颈环鹦鹉表现出攻击性。","identification":"与西方褶皱吸蜜鸟区别在于体型更大，整体颜色更黄，无黑色颊须，黄色颊须更为下垂。与绿裸吸蜜鸟相比，喙、腿和脚的颜色更偏向橄榄棕至棕黑色，尾稍长，羽色更明亮的橄榄色。","protection":"IUCN：LC（无危）。受斐济法律保护，但面临森林退化和丧失的威胁。","distribution":"分布于太平洋的斐济维提岛（斐济西部，波利尼西亚西南部），主要栖息于低地和山地的亚热带或热带湿润森林。","other":"过去工业伐木已停止，但森林仍因国内用途的木材采集和农业扩张而逐渐退化。"},{"name":"黑胸裸吸蜜鸟","english_name":"Mao","scientific_name":"Gymnomyza samoensis","overview":"黑胸裸吸蜜鸟（英文名：Mao，学名：Gymnomyza samoensis），是雀形目吸蜜鸟科裸吸蜜鸟属的鸟类。体型较大的吸蜜鸟，全身暗色，自肩部至背部颜色渐淡，转变为黑色至黄橄榄色。眼下方具有焦糖色的髭纹。依赖于山脚和山区的原生森林生存，叫声包括一系列升调的鼻音管道音，声音响亮。","appearance":"体长28-31厘米，大型暗色吸蜜鸟，喙长而略向下弯曲。远观全暗，头部、颈部和胸部呈煤黑色至橄榄黑色，眼下方有明显的橄榄色条纹；上体和下体大部呈暗橄榄褐色或深棕色，不同程度地带有橄榄绿色，臀部和尾上覆羽较其余部位稍浅，下尾覆羽比其余下体稍浅和棕色；尾羽和翅膀上覆羽呈深橄榄褐色，外侧尾羽、大覆羽和飞羽边缘呈橄榄绿色；虹膜灰褐色至褐色，雄鸟常为蓝色；喙黑色；腿黑色至灰黑色，足底黄色。两性羽毛相似，雄鸟体型大于雌鸟。幼鸟类似成鸟，但头部和下体黑色程度较低。","call":"叫声被描述为响亮的类似猫的哀号“mee-aa-oo”或一系列低沉、嘶哑、鼻音的喵喵声，有时音调上升，随后是更清晰的高音节段落，发展为响亮的上滑颤音，然后再次减弱；持续时间可达1分钟或更长。还有鼻音下降的“yaaw”声；响亮、机械般的“chlip”声；和短促的吱吱声。","habits":"栖息于萨摩亚群岛的本土森林和森林边缘，以及残留雨林的耕作地，如陡峭山谷中的山脚和山区；在火山口海拔较高的地区密度最大，在受干扰最少的森林中。也在火山锥、荒野灌木丛和沿河流的陡峭斜坡上出现。据报道，在海岸附近的椰子树附近觅食（可能是在飓风后压力时期），过去似乎在低地更为广泛。记录到的高度为760米以上，据说在山峰的顶部更为常见；在高达1500米的剩余雨林中发现。","breeding":"通过歌声、追逐和偶尔的身体接触，两性都参与领土防御，但雄鸟更为强烈；只有雌鸟似乎会筑巢；巢呈椭圆形杯状，大约14厘米×8厘米，包含很少的衬垫，由交叉的嫩枝构建在树枝的交汇处；在从8-20米高的森林冠层高度的各种本地和外来树木中筑巢；每窝含一枚蛋（样本数=10）；蛋呈乳白色，钝端有不规则形状的棕色斑点；孵化期约20天；新生雏鸟盲而裸露，喙黄色，喙尖和淡黄色的边缘；9-10天大时，首次羽轨爆发，喙变暗；雏鸟期至少22-24天；雌鸟在幼鸟离巢后2-2.5个月照顾幼鸟，似乎在成功抚养一只雏鸟后不会重新筑巢，尽管在繁殖失败后尝试重新筑巢。","identification":"与同属的其他物种相比，黑胸裸吸蜜鸟的黑色至黄橄榄色的羽毛，尤其是眼下方的焦糖色髭纹，以及独特的叫声和栖息地偏好，使其容易识别。","protection":"IUCN：EN（濒危）","distribution":"太平洋地区：萨摩亚西部的Savaii和Upolu（波利尼西亚中部）。"},{"name":"红脸裸吸蜜鸟","english_name":"Crow Honeyeater","scientific_name":"Gymnomyza aubryana","overview":"红脸裸吸蜜鸟（英文名：Crow Honeyeater，学名：Gymnomyza aubryana），是雀形目吸蜜鸟科裸吸蜜鸟属的鸟类。大型吸蜜鸟，体长35至42.5厘米，主要分布于新喀里多尼亚的Grande Terre岛上的湿润森林中。其黑色光泽的羽毛和橙红色的面部肉垂使其外观独特，类似于乌鸦，但具有更长的弯曲喙和较长的颈部。","appearance":"红脸裸吸蜜鸟体型庞大，羽毛呈光泽黑色，头部、颈后、喉咙、胸部和腹部的羽毛有淡黄色的羽轴，近看时呈现出细纹状。面部有大块黄色到橙红色的肉质眼环，耳部覆盖着一簇黄色羽毛。翅膀和尾巴长而圆，尾巴渐尖。上喙和下喙尖端为灰黑至黑色，下喙基部和口裂为黄橙色。腿色从淡黄至橙黄色不等。雄鸟比雌鸟明显大，雌鸟颜色略浅。","call":"在繁殖季节（9月至10月）的清晨，会发出响亮悦耳的铃声般的鸣叫，此外还有一种类似乌鸦的嘶哑‘wa-wa’声，可能在警戒或激动时发出。","habits":"主要栖息于新喀里多尼亚的原始雨林中，偏好超基性土壤环境，也出现在干燥森林、niaouli灌木丛和被严重威胁的硬叶森林中。活动范围从100米至850米的海拔高度。通常单独或成对活动，偶尔在小群体中被观察到。","breeding":"筑巢于高约20米的树叉处，巢呈杯状且壁厚，估计领地大小为0.5至0.75平方公里。具体繁殖行为细节未知。","identification":"与新喀鸦相比，红脸裸吸蜜鸟拥有红色面部皮肤和较薄的喙。与岛上其他吸蜜鸟种类的区别在于其较大的体型和独特的面部特征。","protection":"IUCN：CR（极危）。红脸裸吸蜜鸟面临严重的生存威胁，特别是在Parc de la Rivière Bleue地区，由于外来鼠类的捕食和栖息地丧失，导致其数量持续下降。","distribution":"分布于新喀里多尼亚的Grande Terre岛南部地区，如Rivière Bleue区域、Kouakoué山坡等地，最近在北部的Mt Panié和Pouembout也有记录。","other":"尽管在适宜的生境中局部存在，但红脸裸吸蜜鸟的数量极为稀少，原因不明。森林的减少、镍矿开采和火灾对其构成威胁。"},{"name":"暗耳汲蜜鸟","english_name":"Dark-eared Myza","scientific_name":"Myza celebensis","overview":"暗耳汲蜜鸟（英文名：Dark-eared Myza，学名：Myza celebensis），是雀形目吸蜜鸟科汲蜜鸟属的鸟类。中型的棕色鸣禽，属于吸蜜鸟科。其最显著的特征为淡色眼环，常见于山地森林的林下层，单个或成对出现。分布于印尼苏拉威西岛的山区，华莱士区内的特定岛屿。","appearance":"体长约17厘米，雄鸟重量约22克，雌鸟较小，约17克。头颈灰至橄榄褐色，上体褐色，下体较淡，具细密的暗橄榄褐色斑纹。眼周有明显白色眼环，翼部有橄榄至黄橄榄色边缘。喙长而向下弯曲，黑色光泽。雌雄羽色相似，但雄鸟体型较大。","call":"鸣唱由上升的颤音组成，同时发出尖锐的“kip-kip-kip…”叫声。","habits":"栖息于山地雨林，主要在原始森林，包括苔藓森林，海拔从约900米至2500米。以花朵为食，快速在花间穿梭以获取花蜜。","breeding":"繁殖信息有限，已知雌鸟在3月末和7月有育雏记录。","identification":"与较大的白耳汲蜜鸟区分，暗耳汲蜜鸟具有眼环而非眼下的斑点，腹部无赤褐色调，通常栖息于较低海拔。","protection":"IUCN：LC（无危）","distribution":"分布于印尼的苏拉威西岛山区，特别是在北、中、东南部及南部山区。","other":"存在两个亚种，M. c. celebensis分布在北部、中部和东南部，M. c. meridionalis分布在南部山区。"},{"name":"白耳汲蜜鸟","english_name":"White-eared Myza","scientific_name":"Myza sarasinorum","overview":"白耳汲蜜鸟（英文名：White-eared Myza，学名：Myza sarasinorum），是雀形目吸蜜鸟科汲蜜鸟属的鸟类。中型的棕色鸣禽，长约20厘米，以眼下方显眼的白色斑点作为显著识别标志。主要栖息在印尼苏拉威西岛的山区，偏好海拔1700至2800米的环境，属于华莱士区特有种。","appearance":"头部和颈部顶部黑色，带有细小的灰色条纹，眉线和眼周黑色，两侧有大的裸露紫色耳斑，延伸至眼睛下方并扩至颈侧上方。下巴和喉咙黑色，散布着灰色条纹或斑点。背部深褐色至黑色，有灰色重条纹。上翼为暗褐色，边缘呈红褐色。下体深红褐色，胸部和腹部有细黑条纹。虹膜棕色，喙和腿黑色。雄鸟和雌鸟羽毛相似，但雄鸟体型明显较大。幼鸟特征未详述。","call":"主要发出高音的单音节‘zunk’声，有时是双音节‘zunk-zunk’，第二个音节音调较低。歌声是一系列尖锐的吱吱声，还有连续的短促尖锐‘kep’音，每秒2到4个，持续时间长，以及一系列高音的喘息声，每次持续不到一秒，间歇不规律。偶尔发出尖锐的‘zip’声。","habits":"栖息于苏拉威西岛的高山雨林和苔藓森林，通常出现在树冠层，偶尔下降至低层觅食开花灌木。以花蜜为主食，同时也吃昆虫。在洛雷林杜国家公园，偶尔加入混合物种的觅食群。","breeding":"有关繁殖的信息有限，仅知7月初雌鸟的输卵管中有卵。","identification":"与暗耳汲蜜鸟相比，体型更大，没有完整的眼环，最明显的鉴别特征是眼下方的白色斑块。","protection":"IUCN：LC（无危）","distribution":"主要分布在印尼苏拉威西岛的山区，尤其在1700至2800米之间。"},{"name":"所罗门盗蜜鸟","english_name":"Bougainville Honeyeater","scientific_name":"Stresemannia bougainvillei","overview":"布岛盗蜜鸟（英文名：Bougainville Honeyeater，学名：Stresemannia bougainvillei），是雀形目吸蜜鸟科所罗门盗蜜鸟属的鸟类。仅分布在布干维尔岛的山区，属于澳新界的特有种。其体型均匀，呈灰褐色，喉部和腹部颜色稍浅，头部和上体为暗橄榄灰色，下体为淡橄榄灰色，带有淡淡的黄褐色调。","appearance":"成年雄性布岛盗蜜鸟头部、颈部和上体为暗淡的橄榄灰色，逐渐过渡到较浅的灰色喉部和胸部，前额和头顶有细微且分散的深橄榄棕色斑点。翅膀和尾巴上部为深橄榄棕色至深橄榄灰色，尾羽和飞羽边缘略显淡橄榄色。下体为淡橄榄灰色，两胁、腹和尾下覆羽带黄色调。下翼为淡灰色，边缘和尖端为深灰褐色。眼睛为棕色至红棕色，喙为黑色至深蓝灰色，腿为蓝灰色至铅灰色。雌鸟体型略小，可能羽毛更偏灰色，腹部色调不那么橄榄色，头部顶部显得斑纹更多，但需进一步确认。幼鸟比成鸟更灰色，缺乏棕色调，下体有模糊的灰色斑点，喙色较淡，为深灰色，嘴裂明显且黄色。","call":"鸣唱包括一系列4至5个柔和的哨音，第一个音节起伏，随后的音节交替上升和下降，类似的叫声。还包括干燥且粗糙的“chht chht”声。","habits":"生活在原始的山地森林中，包括云雾林，尤其在混合竹林和树蕨丛中数量较多。栖息高度从约700米到1950米以上。以昆虫和果实为食，可能也摄取花蜜，但未见聚集在开花的树木附近。在树冠层觅食，通过从树冠内部采集食物；也会接近地面在森林中觅食。性格安静而害羞，但活动力合理。通常成对出现。曾观察到两只个体互相追逐，之后返回原位然后消失在植被中，这可能是一种领地互动。","breeding":"已知的一个巢是一个相当大的杯状结构，内部由整齐编织的根须和其他植物纤维构成，外部覆盖着绿色苔藓和小型蕨类植物，外观新鲜翠绿，外部深度约13厘米，内部直径6厘米，深度8至9.5厘米，建在3米高的小叶树上，含有一枚蛋。关于繁殖的更多信息尚待发现。","identification":"与雌性红枕摄蜜鸟相似，但体型更大，上方颜色更浅，下方不如后者橄榄绿。辨识特征在于其特有的鸣唱和栖息环境。","protection":"IUCN：LC（无危）。它是限制范围物种，在所罗门群岛EBA（Endemic Bird Area）中存在。尽管对其了解不多，但在某些地区被认为是合理的常见或普遍稀少。","distribution":"分布局限于北所罗门群岛的布干维尔岛山区。"},{"name":"横斑澳蜜鸟","english_name":"Barred Honeyeater","scientific_name":"Glycifohia undulata","overview":"横斑澳蜜鸟（英文名：Barred Honeyeater，学名：Glycifohia undulata），是雀形目吸蜜鸟科横斑澳蜜鸟属的鸟类。体型中等，具有显著的黑白条纹。以长而细的弯曲喙著称，全身覆盖着橄榄褐色与白色交错的鳞片状羽毛。这种鸟仅在新喀里多尼亚岛发现，尤其偏好高海拔和原始森林环境。","appearance":"横斑澳蜜鸟体长16至20厘米，头部、颈背和颈侧为深橄榄褐色，头顶有精细的白色鳞片状图案，逐渐变为颈部更粗大的白色鳞片。面部、眼周和眉线为深黑色，与银灰色耳羽形成对比。明显的米色颊纹延伸至颈侧，有时与下方的黑色条纹相接，形成模糊的白带。上身颜色从灰褐色到深褐色不等，背部和肩羽有淡橄榄灰色或棕色的模糊条纹。翼羽边缘呈黄橄榄色，尾羽深褐色。腹部为浅灰色，带有断续的黑褐色条纹，胸部条纹尤为明显。幼鸟较成鸟暗淡，条纹不明显。","call":"横斑澳蜜鸟最常听到的叫声是低沉圆润的哨音，通常为两三个音节，有时会以长降调颤音开头。","habits":"栖息于新喀里多尼亚岛的森林环境中，常见于较高海拔地带和优质本土生境。它们活跃于单独或小群体中，善于攀爬，经常在开花的树木间聚集。性格好斗，会与其他同类或物种争斗。","breeding":"繁殖季节从8月至次年1月。巢杯状，由枯草和蕨类植物制成，内部铺有柔软的绒毛或羽毛，外部可能覆盖有苔藓或蕨类植物。巢藏于地面以上0.3至1.6米处，平均高度1.2米。每次产卵一枚，双亲共同孵化和抚育幼鸟，但关于孵化期和育雏期的具体时间未知。","identification":"在新喀里多尼亚岛上，横斑澳蜜鸟以其独特的长喙和密集的白褐色鳞片状羽毛区别于其他吸蜜鸟。","protection":"IUCN状态未提及，因此保护状态不明。","distribution":"横斑澳蜜鸟仅分布于新喀里多尼亚的Grande Terre（大土岛）。"},{"name":"白腹澳蜜鸟","english_name":"White-bellied Honeyeater","scientific_name":"Glycifohia notabilis","overview":"白腹澳蜜鸟（英文名：White-bellied Honeyeater，学名：Glycifohia notabilis），是雀形目吸蜜鸟科横斑澳蜜鸟属的鸟类。独特的蜜鸟，主要分布在瓦努阿图北部和中部的蒙塔涅森林，偶尔下至海平面附近的低地森林和红树林。","appearance":"这种蜜鸟的上部主要是深棕色，腹部白色，带有褐色条纹。脸部呈灰色和白色的斑驳状。喙长而向下弯曲。成年雄鸟的体重约为29.7克，雌鸟则在23.3到26.4克之间。幼鸟比成鸟暗淡，上体颜色更深，翼羽边缘更宽且较浅，腹部呈淡黄色，缺乏明显的暗色条纹。","call":"其最常见且响亮的叫声是远传的“tyauu”。此外，它的声音系列还包括了响亮延长的“toowyt”，警报时的尖锐“tchea”，以及略带哀怨的“teewee”。它偶尔会发出一系列悦耳的笛音式鸣唱。","habits":"白腹澳蜜鸟主要栖息于山地原始森林和高大的次生林，偶尔出现在低地森林和红树林地带。活动范围从海平面至海拔至少1250米，主要在450至850米以上的高地。它们以花蜜、花粉、昆虫、蜘蛛和可能的果实为食，活跃且嘈杂，通常单独、成对或小群（最多15只）活动。","breeding":"关于繁殖的信息非常有限，据说繁殖期在9月至1月间，有未具体说明的证据表明10月至11月期间有繁殖活动。巢为杯状，每次产2枚淡色的蛋，其余信息未知。","identification":"与其他蜜鸟相比，白腹澳蜜鸟具有独特的黑白色调和向下弯曲的长喙，以及显著的白色眉纹。幼鸟与成鸟在色彩上有所不同，但具体的区分特征需参照详细的外观描述。","protection":"IUCN：LC（无危）。白腹澳蜜鸟虽然分布范围有限，仅存在于瓦努阿图和特莫图EBA，但在当地广泛且常见。","distribution":"分布于瓦努阿图北部和中部，主要集中在n, c Vanuatu。"},{"name":"棕刺莺","english_name":"Eastern Bristlebird","scientific_name":"Dasyornis brachypterus","overview":"棕刺莺（英文名：Eastern Bristlebird，学名：Dasyornis brachypterus），是雀形目刺莺科刺莺属的鸟类。是澳大利亚中东部特有的小型、长尾陆生鸟类，主要特征是斑驳的灰褐色羽毛，下体颜色较淡，拥有红色眼睛和红棕色翅膀，喉部呈淡色，有微弱的淡色眉纹，尾部长而渐细，呈锈色。嘴周围有深色的刚毛，赋予了它刺莺之名。分布在澳大利亚东南部，偏好密集植被的森林地带和沿海灌木丛，很少飞行，常在地面活动。","appearance":"棕刺莺体长18至21厘米，体重35至50克。具有短而圆的翅膀，长而渐细的尾巴，末端有时呈圆形，略向下弯曲的喙。头部、颈部侧面和上体为深橄榄褐色，臀部和上尾覆羽变为丰富的赤褐色。耳盖有精细的白色条纹，冠部有时带有浅灰色斑点。上翼有赤褐色或淡栗色的冲洗。下体颜色从浅灰色到棕色不等，胸部侧面颜色较深，侧腹和下尾覆羽颜色更暖，腹部中心呈偏白色，胸部有模糊的大灰色斑点或鳞片状花纹，下体有暗棕色斑点。翅膀下方为棕灰色。虹膜为红色至红棕色。喙呈深棕色，下颌基部为角质色，上颌可能呈浅色，边缘和下颌为粉白至粉红色，通常带灰色尖端，嘴角为粉白至粉红色。腿为灰棕色或粉棕色。雌雄羽毛相似，但雌鸟体型较小。幼鸟非常类似于成鸟，最佳识别特征为浅棕色或棕色虹膜，黄色嘴角，颈部后部和胸部颜色更暖，耳盖稍暗。","call":"棕刺莺的叫声包括欢快的哨音'chip chip whirr-eee'。","habits":"棕刺莺广泛分布于各种栖息地，包括芦苇地、灌木地、沼泽地、灌木林、硬叶林和森林，以及雨林；偏好植被茂密且种类多样的环境，常出现在树下或灌木下的下层植被中。北部种族(monoides)通常栖息在开放的森林中，下层植被密集，特别是在接近雨林的生态过渡带；下层植被高度通常为95至145厘米，包含野高粱、芒草、雪草、袋鼠草和灌木。南部种族（指名亚种）主要栖息在灌木地、芦苇地、灌木丛或邻近林地的厚丛中；喜欢河流边的纸皮树和芦苇草丛，出现在以桉树和金合欢为主的开阔硬叶林或森林中，下层植被高度小于3米，覆盖着草和蕨类植物；灌木丛中的灌木地和芦苇地高度通常低于2米，包含多种植物。以昆虫和种子为主食，偶尔会吃花蜜。已报道的食物包括禾本科种子、莎草科、金合欢科、茄科和豆科植物的种子；昆虫，包括蟑螂、甲虫幼虫和成虫、苍蝇、蝉、蚁科和其他膜翅目昆虫、鳞翅目幼虫和直翅目昆虫；蜘蛛和环节动物；观察到它从金合欢属植物的花朵中吸取花蜜。单独或成对觅食；伴侣在繁殖季节紧密相伴，其他时间经常分离。在密集植被中觅食，如果不受干扰，也会在开阔地带觅食；观察到在海边岩石上的海藻中觅食。缓慢地在植被中行走或跳跃，偶尔短距离疾跑。在地面上或附近寻找食物，包括落叶层、开阔地带或树叶中。啄食地面；用强壮的喙探查并左右扫动，移动叶子；偶尔从树叶中获取食物或做短暂的空中扑食。","breeding":"繁殖季节为8月至2月，每年繁殖一次。可能终身配对。巢大、穹顶形、卵形或球形，有侧面入口靠近顶部，松散地由粗硬的草茎、莎草或芦苇，或树皮条构成，有时底部有叶片，内衬柔软的干草或莎草，位于低处（通常14至45厘米）的莎草、草、蕨类或灌木的中心或基部（野高粱特别受青睐）。领土面积可变，约2至4.06公顷，大小可能取决于栖息地，北部种群的领土可能比南部种群小。每窝产2枚蛋（偶尔报道3枚），淡棕色至几乎白色，有许多紫色至红棕色的斑点和污迹，主要集中在较大端，尺寸为26.5 x 19.7毫米；如果巢被破坏，可能会产替代卵；孵化可能仅由雌鸟完成，孵化期至少3周；雏鸟似乎由双方父母喂养，巢期至少11天。通常只有一个卵孵化，有时显然只有一个卵是受精的；如果受到打扰，容易弃巢。圈养繁殖计划在昆士兰州东南部的黄金海岸进行，基于从野生对中取出卵并在人工条件下孵化，然后人工饲养雏鸟并将其释放到特制的笼舍中，以形成圈养繁殖种群的核心，最终目标是在野外适宜的栖息地中释放鸟类，威胁最小化；一对圈养的鸟类成功地养育了自己的幼鸟，计划是在开始放归之前在圈养环境中繁殖20只个体。最近的研究表明，避免在栖息地中发生火灾是一种有效的保护工具。牧草可能允许外来杂草入侵，可能损害栖息地的完整性和适宜性，某些外来植物可能构成长期的潜在威胁。老鼠和猫的捕食以及道路交通造成的死亡对种群的影响相对较小，但在数量减少时，它们可能在总体种群下降中发挥更重要的作用；可能对人类干扰敏感，尤其是在筑巢时，但大部分栖息地过于密集，不允许轻易进入。","identification":"棕刺莺与西刺莺的区别在于体型略大，羽毛斑纹不那么明显和鳞片状。雌雄羽毛相似，但雌鸟体型较小。幼鸟与成鸟非常相似，最佳识别特征为虹膜颜色、嘴角颜色、颈部后部和胸部颜色。","protection":"IUCN：VU（易危）","distribution":"棕刺莺分布在澳大利亚中东部，具体包括东南部地区。在昆士兰州南部的Conondale山脉发现了孤立的种群。2021年末估计，野生中大约只有2,500只个体，存在于东部新南威尔士州和昆士兰州南部的孤立种群中。四个独立的种群分别位于：新南威尔士州北部和昆士兰州南部，包括边境山脉国家公园（约40只）；南方高地；杰维斯湾地区；以及新南威尔士州与维多利亚州边界南部的人口，包括Nadgee自然保护区和Croajingolong国家公园。","other":"由于种群小且孤立，棕刺莺面临基因多样性缺乏的问题，这可能导致灭绝风险增加。为了对抗这一问题，正在实施一项名为“遗传救援”的技术，选择来自大种群的成功繁殖个体，引入小种群中。此外，昆士兰州Currumbin野生动物保护区正在进行圈养繁殖计划，旨在通过选择性繁殖提高疾病抵抗力，增加遗传多样性和提高生育率，特别是在新南威尔士州北部的小种群中。"},{"name":"西刺莺","english_name":"Western Bristlebird","scientific_name":"Dasyornis longirostris","overview":"西刺莺（英文名：Western Bristlebird，学名：Dasyornis longirostris），是雀形目刺莺科刺莺属的鸟类。又名: 长尾刺鸟或长嘴须莺，是刺莺科刺莺属的小型陆栖鸟种，特有于西澳大利亚沿海的密集灌木丛。灰褐色羽毛，上体具淡色条纹，下体类似但颜色更浅，拥有深红色眼睛，红棕色翅膀，明显的颊纹，以及渐细的锈色长尾。喙周围暗色硬羽赋予其名。鸣叫声清脆，似‘chip-too-too-peetle-pet’的口哨声。","appearance":"体长约17厘米，体重26至39克。体型矮胖，翼短圆，尾长而渐细，常呈破旧状，喙中等长度略向下弯且结实。眼周及面颊区呈灰白至乳白色，具微暗斑点；耳羽淡棕色，具细白纹；头顶深棕色，具淡色斑驳；背部深棕色，肩部斑点明显；腰背及臀部锈洗深棕色；尾上覆羽锈棕色；飞羽及次级飞羽端部暗色；尾羽橄榄棕色，尾羽边缘锈色；颈侧灰棕色，具暗棕色鳞片状斑纹；胸腹部浅棕灰色，侧腹更暖棕色，具细暗斑；腹中部近白色，渐变为侧腹的暖棕色，均具细暗棕色斑纹；翅下暗灰棕色；虹膜砖红或红棕色；喙暗灰色，下颌基部乳粉；腿灰色或污粉色。两性相似。幼鸟与成鸟相似，但上体无斑点，下体无鳞片状斑纹。","call":"鸣叫声响亮且独特，全年可闻，夏季较少，冬季和春季最为频繁。鸣唱通常从浓密的遮蔽处发出，有时自灌木顶端，甜美穿透的‘chee tiddly-too chip wee too’系列音调，有许多变化，也有较柔和的喉音短歌；鸣唱用于维持伴侣或群组间的联系，宣告领地，其中一种歌型用于领土争斗；两性均能歌唱，经常合唱。鸣唱在不同地理区域有变化：在菲茨杰拉德河国家公园，归家鸣叫常以颤音结尾；而在Two Peoples Bay，仅偶尔听到非常弱的颤音。","habits":"栖息于沿海的密集灌木丛，包括多种灌木和草本植物组成的复杂生态系统。活动范围固定，偶有局部移动，尤其是在森林火灾后。食物包括昆虫和种子，如Anarthria scabra、Daviesia和Acacia的种子，以及甲虫幼虫和成虫、膜翅目和直翅目昆虫，蚯蚓和蜗牛。通常单独或成对在茂密植被中觅食，有时在无人打扰的开阔地带活动。在植被中缓慢行走或跳跃，从叶片上觅食；偶尔做短距离冲刺，约50厘米。在地面或近地面觅食，或从叶片上取食。活跃，啄食地面或用喙快速探查，脚部旋转时做侧向摆动；用喙从一侧到另一侧扫除叶片。","breeding":"繁殖季节未知，记录稀少。7月至10月/11月间繁殖，单窝产。可能终生配对，伴侣长时间共处，但需进一步证实。全年占据领地。巢大而圆顶或球形，侧面顶部有大入口，由芦苇、莎草、枝条和粗草茎松散构建，内部未衬垫或铺以柔软纤维，四巢平均长度12厘米，宽度10厘米，高度12厘米；巢置于10至60厘米高的地面，隐藏于悬垂植被下，通常位于莎草丛中，有时在灌木（如Banksia）或藤蔓中；领地约6至8公顷，伴侣大部分时间在核心区域（推测为领地）的1至3公顷内。每窝几乎总是产2枚卵，淡棕色，有时接近白色，具众多紫棕色至红褐色斑点和斑块，尤其在较大端，尺寸24×18.6毫米；孵化和育雏周期信息缺失；幼鸟与成鸟同住至离巢后，可能至次年1月独立。通常仅一枚卵孵化成功；有报道称有时仅一枚卵受精。","identification":"与其他刺莺相比，西刺莺具有较短的尾巴，但尾羽仍相当长，呈锈色，具深棕色条纹。身体锈色，下体羽毛暗棕色，形成鳞片状外观。红眼和前颈及面部的灰白色是识别特征。鸣唱和行为模式也是区分关键。","protection":"IUCN：EN（濒危）","distribution":"分布于西澳大利亚西南部，自Two Peoples Bay至Waychinicup，以及菲茨杰拉德河国家公园。小规模移植群体曾在Albany西的Walpole附近存在，可能现已灭绝。","other":"历史上，西刺莺曾遭受严重栖息地破坏，尤其是森林火灾和土地开发导致的生境收缩。对火灾尤为敏感；过度燃烧和排水与土地开垦相关，导致分布范围缩减。在定期燃烧间隔不足5至10年的区域，植被恢复时间不足，造成局部灭绝。在燃烧频率低的区域，族群能够迁移至邻近未烧毁区域，但大规模失控的森林火灾仍构成重大威胁。"},{"name":"短翅刺莺","english_name":"Rufous Bristlebird","scientific_name":"Dasyornis broadbenti","overview":"短翅刺莺（英文名：Rufous Bristlebird，学名：Dasyornis broadbenti），是雀形目刺莺科刺莺属的鸟类。最显著的特征为长尾和短翅，分布于澳大利亚西南部和东南部。该鸟种拥有三种亚种，其中之一可能已灭绝。","appearance":"体长约25厘米，重约77克。头部富丽的红褐色，尤其是翅膀和冠部，下体灰褐色带斑点。明显的苍白眼圈，脸颊标记和髭纹。上体橄榄灰色，带有微弱的红褐色调，背部有模糊的浅棕色斑点，臀部和尾羽覆羽呈纯红褐色。尾羽深褐色，尾羽端缘窄红褐色。下颚白色，喉部和胸部暗褐色，大胆地以淡灰色斑点装饰，腹部中心白色，侧翼和胁部橄榄棕色，向后渐变为更红棕色。","call":"叫声包括一系列轻柔重复的清晰“chit”音符，随后是一串含糊的哨声短语。","habits":"栖息于沿海沙丘和悬崖上的低矮密集灌木丛和荒地，偶尔沿山谷延伸至内陆40公里。偏好低矮密集的植被覆盖，允许自由移动。常见于海岸线的Myoporum insulare。在开放的桉树林中，下层植被密集，包括茶树、石楠树和剑叶草。经常出现在花园、停车场和道路上，是最不羞怯的刺莺之一。","breeding":"繁殖季节为8月至次年1月，单次繁殖。可能终身配对。雌鸟独自筑巢，巢期约2-3天，巢大且圆顶，近地面，由粗硬的草、苔草、树枝、干叶和纤维根构成，内部铺垫柔软的干草、毛发、根须或羊毛。每窝通常产2枚蛋，孵化期16-21天，仅雌鸟孵化。幼鸟由双亲共同喂养，留巢期18-21天。","identification":"与其它刺莺相比，本种体型最大，尾羽长而渐尖，头部富丽的红褐色。幼鸟比成鸟颜色更深，头部缺乏红褐色，脸部呈黄褐色，下体较单调。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西南部和东南部，包括维多利亚州和南澳大利亚州的部分地区。","other":"曾广泛分布于澳大利亚，但由于农业、居住区开发和火灾的影响，一些亚种面临威胁，甚至可能灭绝。"},{"name":"斑翅食蜜鸟","english_name":"Spotted Pardalote","scientific_name":"Pardalotus punctatus","overview":"斑翅食蜜鸟（英文名：Spotted Pardalote，学名：Pardalotus punctatus），是雀形目斑食蜜鸟科斑食蜜鸟属的鸟类。小巧绚丽的食蜜鸟，广泛分布于澳大利亚的东部和南部地区，栖息于海拔高达2,000米的环境。这种小鸟因其独特的斑点羽毛而得名，又被称为‘钻石鸟’。斑翅食蜜鸟有三个亚种，分别分布在不同的地理区域。","appearance":"雄性斑翅食蜜鸟身长8至10厘米，体重约6克，拥有灰色至棕色的上部羽毛，点缀着淡色斑点，黑色的冠顶和翅膀、尾巴上有白色斑点，白色的眉毛和红色臀部。下体颜色为淡黄至肉桂色，胸部颜色较深，黄色喉咙和腹部。雌鸟色彩较暗淡。幼鸟颜色更暗，冠部斑点不明显。不同亚种在体型、嘴的大小、斑点细节和下体颜色上有所差异。","call":"发出清脆重复的双音节叫声，类似‘叮叮’声，尤其是塔斯马尼亚的种群，其叫声更简单、更短，通常由两个音符组成。","habits":"斑翅食蜜鸟栖息于各种桉树（Eucalyptus）形成的森林，从沿海到半干旱内陆，甚至高至2000米的高山地带。它们在繁殖后倾向于向内陆干旱低地和范围北部更干燥的地区迁移，避开高海拔和南方地区。以昆虫和植物分泌物为食，主要食用一些介壳虫的碳水化合物丰富的覆盖物和某些桉树产生的糖质分泌物。","breeding":"繁殖季节记录为6月至次年3月，主要集中在8月至12月。每季可能繁殖两窝，但再繁殖比例未知。配偶双方共同筑巢，巢穴位于斜坡土壤中的近水平隧道尽头，巢呈松散穹顶状，由树皮和草茎构成。每窝产3至5枚白色蛋，孵化期16至22天，雏鸟喂养期18至25天，离巢后约8天即可独立。","identification":"斑翅食蜜鸟与纹翅食蜜鸟的区别在于其眉毛前端完全为白色。不同亚种间，如militaris和xanthopyge，在体型、嘴的大小、斑点细节和下体颜色上有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部、东部地区，包括昆士兰东南部、新南威尔士东部、维多利亚东部和南部、南澳大利亚东南部以及西澳大利亚西南部。在塔斯马尼亚，分布于东部和西北部。在昆士兰中部北部沿海地区也有分布。","other":"斑翅食蜜鸟的密度在不同地区变化很大，从0.1到17只鸟/10公顷不等。在许多保护区都有它们的身影。"},{"name":"多斑食蜜鸟","english_name":"Forty-spotted Pardalote","scientific_name":"Pardalotus quadragintus","overview":"多斑食蜜鸟（英文名：Forty-spotted Pardalote，学名：Pardalotus quadragintus），是雀形目斑食蜜鸟科斑食蜜鸟属的小型绿色鸟类。主要分布在澳大利亚塔斯马尼亚州东南部，特别是Maria岛和Bruny岛上。成鸟具有鲜明的黄色脸部，幼鸟则无此特征。","appearance":"体长约8.5至11厘米，体重9至13克。体色以橄榄绿为主，上体呈淡橄榄绿色，翼黑而具显著白色斑点。成年鸟的脸部黄色，而幼鸟则缺乏这一特征。翼上有两行规则排列的小白点，尾羽深灰至黑色，尖端白色。下体颜色较淡，呈灰白色，眼虹膜棕色，喙黑色，腿粉红棕色。雌雄相似，幼鸟较成鸟暗淡，头部灰色，有细黑纹，全身色彩偏褐色。","call":"发出远不如同类响亮但种类较多的声音。雄鸟的歌曲为重复的‘k-choo’声，较为低调的‘where-where’声作为联系叫声，伴随争斗的嘶鸣声，还有短暂柔和的颤音。","habits":"主要栖息于沿海及近沿海的桉树森林和林地，尤其是以白桉（Eucalyptus viminalis）为主的区域。几乎全年定居，但在繁殖季结束后可能有局部分散现象。饮食以昆虫和勒普（某些昆虫的糖质覆盖层）为主，特别依赖桉树的甘露作为食物来源，甚至通过咬断叶柄刺激甘露产生。常在桉树冠层觅食，有时与同属其他物种混合群居。","breeding":"繁殖期为9月至次年1月，每季可能产两窝。营巢由双亲共同建造，巢形似穹顶或杯状，主要材料为桉树皮纤维和草茎，内部铺垫羊毛、毛发或羽毛。巢通常位于树洞、枯木或地面隧道中。每窝产3至5枚白色蛋，孵化期18至23天，由双亲轮流孵卵，幼鸟约23至25天离巢。","identification":"与同属的斑翅食蜜鸟相比，四十斑食蜜鸟背部和头部颜色更暗淡，无眉纹，翼上的白色斑点更为密集。幼鸟与成鸟颜色差异明显。","protection":"IUCN：EN（濒危）","distribution":"分布于澳大利亚东部巴斯海峡的弗林德斯岛（Flinders I.）和塔斯马尼亚州东南部，主要集中在Maria岛和Bruny岛，以及大陆的Tinderbox半岛、Howden、Coningham和Southport等地。","other":"面临的主要威胁包括土地开垦、气候变化导致的低降雨量、森林火灾、竞争物种如黑额矿吸蜜鸟和纹翅食蜜鸟、捕食者如笑翠鸟，以及寄生虫Passeromyia longicornis。"},{"name":"红眉食蜜鸟","english_name":"Red-browed Pardalote","scientific_name":"Pardalotus rubricatus","overview":"红眉食蜜鸟（英文名：Red-browed Pardalote，学名：Pardalotus rubricatus），是雀形目斑食蜜鸟科斑食蜜鸟属的鸟类。为澳大利亚特有种。其显著特征包括橙红色的眉毛，分布于澳大利亚北部及中部地区。","appearance":"红眉食蜜鸟体长9至11.5厘米，重约9到14克。成年雄鸟具有黑色顶冠，点缀着白色斑点，淡黄色的眉纹，靠近喙基部有一红色斑点，眼圈浅色。上体呈灰褐色，翼上有独特的黄色翼斑。下体颜色较浅，胸部有黄色斑块。雌雄相似，幼鸟比成鸟暗淡，冠部黄棕色，腹部泛黄。亚种差异主要体现在羽色深浅及黄色部分的鲜明程度。","call":"鸣声为低沉音符后接五连快速升调的哨音，\"yoouuuu-did-did-did-did-did\"，类似某种鹦鹉的叫声。","habits":"栖息于多种林地和开阔森林，偏好沿水边生长的桉树林。与同类相比，更倾向于非桉树林，如金合欢低木林。以昆虫为主食，常在树冠层觅食。通常单独、成对或小群活动，偶尔地面觅食。叫声比直接观察更容易发现。","breeding":"繁殖期多在8月至10月间，巢由双亲共同建造，杯状且坚实，置于地面挖掘的隧道末端。隧道长45至120厘米，巢室约10厘米见方。每窝产卵3至4枚，白色。双亲共同孵化和喂养幼鸟，具体孵化和离巢时间未知。","identification":"与纹翅食蜜鸟相比，后者顶冠有条纹，无黄色翼斑，眼后有黄色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部和中部，包括远北昆士兰州的约基半岛。在澳大利亚内陆和北部广泛分布。"},{"name":"纹翅食蜜鸟","english_name":"Striated Pardalote","scientific_name":"Pardalotus striatus","overview":"纹翅食蜜鸟（英文名：Striated Pardalote，学名：Pardalotus striatus），是雀形目斑食蜜鸟科斑食蜜鸟属的鸟类。亦被称为pickwick、wittachew和chip-chip，是斑食蜜鸟科斑食蜜鸟属中色彩较为朴素但分布广泛的物种。这种小型鸟儿以其独特的翼纹和悦耳的鸣叫声而闻名，常见于澳大利亚及塔斯马尼亚州的各类生境。","appearance":"纹翅食蜜鸟体长9至12厘米，体重介于9到15克之间，拥有短而圆的尾巴和深色短喙。其头部黑色，具白色条纹，眼眉白色渐变为黄色靠近喙部。上体呈淡褐色，臀部颜色较浅。翼部黑色，初级飞羽边缘形成狭窄的白色条纹，三级飞羽边缘更为显著的白色，最外侧三级飞羽部分边缘红褐色。成年鸟的喉部鲜黄，胸部黄绿色，腹部奶油色至肛周，两胁有黄橄榄色带。虹膜暗棕色至黑色，喙黑色，有时下颚基部或双颌颜色较浅，腿色从暗灰色至棕色或粉棕色。雌雄相似，幼鸟色泽较淡，头部图案不明显，喉部黄色不突出。不同亚种间在羽色和色调上有差异。","call":"发出响亮的2至7个音节的歌曲，通常为“wit-e-chu”或“wit-wit”，带有区域性变化，尤其在繁殖季节频繁鸣唱。还有其他声音，如颤音和群居时的简短接触叫声。","habits":"栖息于多种桉树（Eucalyptus）形成的环境，从高大的开放森林到稀疏低矮的林地。它们广泛分布于沿海和半干旱内陆至海拔2000米以上的山区。移动模式多样，可能包括季节性迁移，如塔斯马尼亚种群迁至澳大利亚大陆，冬季时山地种群移至沿海或内陆低地。以昆虫为主食，尤其是富含碳水化合物的lerps（某些Psyllid昆虫的覆盖物），偶尔食用植物分泌物manna。独行或成对活动，在繁殖季节外常形成数百只的大群。","breeding":"繁殖记录全年均有，典型季节为8月至12月，南澳大利亚的温带区。每季可能产两窝，但多窝繁殖的比例未知。巢由两性共同建造，形式为松散的穹顶或杯状，材料包括树皮、草茎和松树等类似物种的“针叶”。巢位于树洞或地面隧道中，后者通常在侵蚀的河岸、悬崖或近垂直面。隧道长度15至100厘米，开口宽4至6厘米，远端有较大的巢室。每窝产3至5枚白色卵，两性共同孵卵，孵化期15至23天；雏鸟由双亲喂养，离巢期21至25天。","identification":"与斑翅食蜜鸟和红眉食蜜鸟的区别在于其独特的冠纹、翼纹和色彩。不同亚种在羽色和翼部特征上有所差异。","protection":"IUCN：LC（无危）","distribution":"遍布澳大利亚全境，除西澳大利亚的部分沙漠地区外，包括塔斯马尼亚州。","other":"纹翅食蜜鸟有六个公认的亚种，过去曾将部分亚种视为独立物种，但现在均被归类为纹翅食蜜鸟的亚种，有证据表明存在种间杂交现象。"},{"name":"金脸啸鹟","english_name":"Goldenface","scientific_name":"Pachycare flavogriseum","overview":"金脸啸鹟（英文名：Goldenface，学名：Pachycare flavogriseum），是雀形目细嘴莺科金脸啸鹟属的鸟类。小型、色彩鲜艳的雀形目鸟类，为新几内亚山区特有种。其最显著的特征是明亮的黄色脸部和额头，以及灰色的背部和冠部。分布于新几内亚的山林地带。","appearance":"金脸啸鹟长约13厘米，重14至19克。雄鸟头部和颈后呈淡蓝灰色，与黄色前额形成鲜明对比，上体淡蓝灰色，翼羽尖端有白色斑点，两排沿背线相连。雌鸟相似，但耳羽有暗色斑块，前冠部黑色减少。幼鸟外观似雌鸟。亚种subaurantium颜色更深，略带橙色；randi更橙；subpallidum最浅，黄色最多。","call":"金脸啸鹟发出响亮的上升哨音，通常为两声（有时三到四声），如“wheep wheep”，随后是低音的双声“chew chew”，每一系列叫声音量逐渐增大。近巢时发出高音的啾啾声和低音颤音。","habits":"栖息于海拔400至1800米的山地森林，偏好密集森林的较高层。以昆虫和蜘蛛为主要食物，常在树冠中层觅食，偶尔加入混合物种觅食群。","breeding":"关于繁殖生物学知之甚少，可能有季节性。繁殖期记录显示从六月至十一月，巢由双方共同建造，呈球形，侧面向下开口。","identification":"金脸啸鹟的特征明显，难以与其他物种混淆。亚种之间在颜色上有细微差异，如subaurantium的上体颜色较深，带橙色色调。","protection":"IUCN：LC（无危）。在较高海拔范围内常见，但在较低海拔处较少见。","distribution":"该物种仅分布于新几内亚岛，包括巴布亚和巴布亚新几内亚，主要栖息于山地森林。","other":"已知有四个亚种，分类学位置尚不确定，曾被认为属于细嘴莺科，但最新研究将其归入刺鸟科。"},{"name":"蕨鹩刺莺","english_name":"Fernwren","scientific_name":"Oreoscopus gutturalis","overview":"蕨鹩刺莺（英文名：Fernwren，学名：Oreoscopus gutturalis），是雀形目细嘴莺科蕨鹩刺莺属的鸟类。又被称为山地守护者或喉斑刺莺。体型小巧，长约12至14厘米，重约20克。其最显著的特征是白色的眉纹和喉部，搭配黑色的颈带。分布于澳大利亚东北部昆士兰州的阿瑟顿高原，生活在海拔300至1500米的湿润雨林中。","appearance":"成年蕨鹩刺莺全身呈深橄榄棕色，上体颜色较深，下体较为淡雅。头部有窄白眉纹，宽黑褐色眼纹；喉咙和下巴白色，上胸部有黑色新月形斑纹。眼睛深棕色，喙黑色，腿呈灰色或浅棕色。雄鸟和雌鸟外观相似，但在野外观察中，雌鸟似乎比雄鸟更暗淡，胸斑较小，眉纹不那么明显。幼鸟几乎全为深棕色，喉部和额头有隐约的淡色痕迹。","call":"鸣唱通常从离地面1米内的倒木或小树苗发出，在繁殖季节尤为常见，由一系列重复的高音颤音组成，声音尖锐而悠长，逐渐升高至高潮。接触叫声为柔和的‘chip, chirr-ip’，警报声为独特的嘶哑上升音‘shweeeee’，还有尖锐的‘churrs’声和责备似的五音符断奏，随后是三个延长且音调较高的‘chip’音。","habits":"栖息于潮湿的雨林环境中，单独或成对活动。在茂密阴暗的生境中安静而不显眼，但并不特别胆怯。在潮湿的落叶层或倒下的树枝上觅食，有时会将自己埋在树叶下或将它们抛向空中。觅食技巧包括搜寻、刨土和探查。偶尔会跟随橙脚塚雉和黑头刺尾鸫，利用它们的觅食动作惊扰出猎物。","breeding":"繁殖季节为7月至2月，主要集中在10月至11月。可能全年维持领地，但在繁殖期间最为活跃。巢由双方共同建造，呈穹顶状，有一侧入口，由苔藓、根须、枝条、叶子和地衣构成，颜色深沉，伪装良好。巢位于地面附近，藏于洞穴、裂缝或蕨丛中，常在溪流边或沟壑边，偏好悬垂处。每窝产2枚蛋，蛋壳光滑，白色底色，偶尔有淡红棕色斑点。孵化可能仅由雌鸟承担，孵化期约为29天；幼鸟由双方喂养，巢中停留时间为21至23天。","identification":"与其他刺莺的区别在于其特有的喉部标记和深橄榄棕色的羽色。幼鸟与成鸟在羽毛上有所区别，缺乏成鸟的胸斑，喉部斑驳，下体呈浅棕色。","protection":"IUCN：EN（濒危）","distribution":"蕨鹩刺莺分布于澳大利亚东北部，具体在约克角半岛东南部山区和昆士兰州东北部，特别是在海拔650米以上的地区。主要栖息在帕卢马山脉、汤斯维尔附近，以及从图利峡谷国家公园到卡佩特里伯尔地区。","other":"蕨鹩刺莺被列为《世界自然保护联盟》（IUCN）红色名录中的濒危物种。"},{"name":"随莺","english_name":"Pilotbird","scientific_name":"Pycnoptilus floccosus","overview":"随莺（英文名：Pilotbird，学名：Pycnoptilus floccosus），是雀形目细嘴莺科随莺属的鸟类。小型而健壮的鸟类，主要栖息在澳大利亚东南部的湿润森林区和灌木丛地带。其羽毛呈深巧克力棕色，胸部带有隐约斑驳，喉部和臀部略带红褐色调。以在地面翻找落叶为食，使用强健的腿脚进行觅食。叫声嘹亮清脆，类似‘guinea-a-week’的哨音。","appearance":"体长约17至19厘米，体重约27克。头部较大，喙粗壮，尾巴较长且丰满，常翘起并上下摆动。头顶至颈背为深棕色，与淡黄红褐色的前额、眼圈、耳羽、颊部、下颏和喉部形成对比。上体包括背部和尾羽为深棕色，臀部带有红褐色晕染。下体红棕色，有棕色羽毛边缘形成斑驳效果，腹部白色，有时有细微的暗色斑点，尾下覆羽为暗橄榄棕色。虹膜深红或鲜红色，喙灰黑色渐变为下颚基部的浅棕或淡粉色，腿脚为深灰色至深棕色，足底较浅呈粉棕色。雌雄相似，幼鸟下巴和喉部灰色，缺乏暗色斑点，全身均匀的红褐色，侧腹、腹下部和尾下覆羽更丰富，喙由灰黑色逐渐变为下颚的暗黄色或肉色，虹膜灰棕色。","call":"发出响亮、悦耳、穿透力强的3至5个音节的音乐般的叫声，音调上扬，开始有轻微的吱吱声，随后是响亮的‘pee choo wee’变体，声音强烈，与体型相比显得格外响亮，类似于‘guinea-a-week’，与棕刺莺的声音非常相似。雌鸟也会发出这些叫声，并在觅食时作出柔和的回应，用于保持联系。筑巢期间，雌鸟可能会离开巢穴并呼叫，雄鸟迅速回应并带来食物。","habits":"主要以昆虫为食，偶尔食用种子和果实。活动于地面，常在森林下层或溪流附近湿润地带觅食，用脚翻转地表残骸，用喙抛掷落叶。与华丽琴鸟有密切关联，跟随后者并利用其扰动土壤而惊飞的猎物。","breeding":"繁殖季节为8月至12月，筑巢于森林地面上堆积的枯枝落叶中，巢呈球形，侧开入口，由树皮、蕨类植物、死叶和根须杂乱构建。每窝通常产两枚蛋，尺寸约为27×20毫米，颜色从灰绿色到紫棕色不等，由雌鸟孵化20至22天。雄鸟会喂食雌鸟或协助照料雏鸟，持续14至17天的育雏期。巢可能被扇尾杜鹃寄生。","identification":"与棕刺莺有相似的叫声，但外形特征明显不同，尤其是体色和体型。","protection":"IUCN：VU（易危）","distribution":"分布于澳大利亚东南部，包括从新南威尔士州的Wollemi国家公园和蓝山国家公园，延伸至维多利亚州的Dandenong山脉附近。","other":"随莺与华丽琴鸟的关系在自然界中较为独特，但观察到这种现象的机会不多。"},{"name":"灌丛丝刺莺","english_name":"Scrubtit","scientific_name":"Acanthornis magna","overview":"灌丛丝刺莺（英文名：Scrubtit，学名：Acanthornis magna），是雀形目细嘴莺科细嘴莺属的鸟类。主要分布在澳大利亚东南部的塔斯马尼亚州和澳大利亚的新西兰地区。其最显著的外部特征包括弯曲的喙，棕色的上体，淡色的下体，灰色的脸部，橄榄色的侧翼，以及翼上的小白色条纹。生活在温带雨林、Nothofagus山毛榉森林和桉树林中。","appearance":"灌丛丝刺莺的体型大约为11至12厘米，体重约为10克。其羽毛特征明显，拥有白色的喉部和腹部，背部、冠部、侧翼和尾巴呈棕色，翅膀黑色，脸部灰色，眼睛颜色较浅，喙短而略弯，黑色。雌雄羽毛颜色相似，幼鸟的细节变化未详述。","call":"这种鸟通常很安静，但会发出响亮的接触叫声，其鸣唱被描述为甜美且具有音乐性。","habits":"灌丛丝刺莺在地面附近的浓密植被中单独、成对或以小家庭群体觅食，主要以小型无脊椎动物，尤其是昆虫及其卵为食。它参与混合物种的觅食群落，栖息地为温带雨林、山毛榉森林和桉树树林。","breeding":"灌丛丝刺莺是领地性和一夫一妻制的，繁殖季节从九月持续到一月。它们的巢是一个带有侧面入口的编织球形，内部铺有羽毛和毛发，通常位于离地面1至3米的地方。每窝通常产3个蛋，有时4个，蛋呈珍珠白色，带有细小的红褐色斑点，主要集中在较大的一端。孵化时间和雏鸟成长周期未知。","identification":"与褐色丝刺莺相比，灌丛丝刺莺更棕色，体型更大，具有明显的眉线。此外，它特有的曲喙和灰脸是识别的重要特征。","protection":"IUCN：LC（无危）。然而，金岛亚种（A. m. greeniana）被列为 Critically Endangered（极危）。","distribution":"灌丛丝刺莺主要分布在澳大利亚的塔斯马尼亚州（东南部）和金岛。","other":"灌丛丝刺莺是塔斯马尼亚的特有种，也是金岛的特有种之一，但金岛亚种的种群数量严重下降，面临灭绝的风险。"},{"name":"岩刺莺","english_name":"Rockwarbler","scientific_name":"Origma solitaria","overview":"岩刺莺（英文名：Rockwarbler，学名：Origma solitaria），是雀形目细嘴莺科岩刺莺属的鸟类。主要分布在澳大利亚东南部的新南威尔士州，特别是在霍克斯伯里砂岩地区。其最显著的特征是上体呈褐色，下体为红棕色，喉部颜色较浅。岩刺莺是新南威尔士州唯一的特有种。","appearance":"岩刺莺长约14.5厘米，重约14.5克。体色上半身呈暗褐灰色，臀部带有深赤褐色，尾巴黑色且末端平截，与随莺的翘尾明显不同。头部和耳羽暖棕色，眼圈白色，下巴和喉咙为对比鲜明的灰白色，带暗灰色斑点（新鲜时边缘较淡）。下体为深赤褐色，尾下覆羽深棕色。虹膜深棕色或深红棕色，喙黑褐至暗灰色，下颌基部粉红棕色，腿灰黑色或深黑棕色。雄雌相似，幼鸟比成鸟更淡更暗，喉咙灰带赤褐色，与头部和下体的对比不那么强烈。","call":"岩刺莺的叫声包括重复的尖锐‘chis-sick’声，主要在繁殖季节发出；也有类似Sericornis的斥责式叽喳声，但音调更高，以及嘶哑的流利接触叫声。它们还会模仿其他多种鸟类的叫声。","habits":"岩刺莺与暴露的砂岩、石灰石、花岗岩和其他岩石地貌紧密相关，常出现在水边的沟壑、陡峭的岩石山坡、峡谷、岩石露头和悬崖附近。以昆虫为主食，也会吃种子，常见食物有甲虫、蚂蚁、黄蜂、鳞翅目幼虫，以及Panicum和Triticum的种子，以及Chenopodiaceae和Eucalyptus melliodora的种子。通常单独或成对出现，有时会形成由五只鸟组成的家庭群体，它们在地面和岩石上觅食，偶尔会在树和灌木低处或树干上觅食。","breeding":"岩刺莺在8月至1月繁殖，有时会产两窝。它们通常是成对生活的，可能是单配偶制。巢由双方共同建造，形状为卵圆形，两端尖细，侧面入口，位于洞穴或其他遮蔽的岩石地点，有时在人造地点如道路涵洞、棚屋、隧道、矿井或建筑物中，甚至在完全或近乎完全黑暗的地方。每窝产3枚蛋，有时为2枚，孵化期21-27天，雏鸟期16-21天。","identification":"岩刺莺与随莺的区别在于体型较小、头部更瘦小、尾巴较长且末端方正，喉咙白色。幼鸟的喉咙灰带赤褐色，与成鸟相比色彩较淡。","protection":"IUCN：LC（无危）","distribution":"岩刺莺主要分布在澳大利亚东南部，具体为新南威尔士州的中央东部，距离悉尼约240公里的范围内。其栖息地多在受保护的国家公园内。","other":"岩刺莺是新南威尔士州唯一的特有种，其巢悬挂在洞穴中，曾因此得名‘hanging dick’。"},{"name":"巴布亚丝刺莺","english_name":"Papuan Scrubwren","scientific_name":"Aethomyias papuensis","overview":"巴布亚丝刺莺（英文名：Papuan Scrubwren，学名：Aethomyias papuensis），是雀形目细嘴莺科Aethomyias的小型鸟类。主要分布于新几内亚高山区的西部、中部、东北部和东南部，栖息于亚热带或热带湿润山地森林的底层。该物种被列为世界自然保护联盟（IUCN）红色名录中的低危物种。","appearance":"该鸟体型小巧，上体呈棕色，翼部和尾部为赤褐色，下体颜色较浅，呈淡棕色至灰色。其眼周有一圈淡色的眼环，前额部位也呈现淡色。翼上有深色斑点，飞羽基部呈淡色，与大型丝刺莺相比，巴布亚丝刺莺体型更小，且面部无锈色，与灰冠丝刺莺的区别在于巴布亚丝刺莺通常栖息于更高海拔地区，且无灰冠。","call":"巴布亚丝刺莺的鸣唱是一连串欢快的哨音，重复着愉悦的旋律。","habits":"巴布亚丝刺莺偏好群居，常在小群体中活动，它们在森林底层搜寻昆虫作为食物。","breeding":"关于巴布亚丝刺莺的繁殖习性的具体信息较少，一般而言，它们会在适宜的季节进行繁殖，营巢于密林之中。","identification":"与大型丝刺莺相比，巴布亚丝刺莺体型较小，且面部不具锈色。与灰冠丝刺莺的区别在于栖息地的海拔高度和头部冠羽的颜色。","protection":"IUCN：LC（无危）","distribution":"巴布亚丝刺莺主要分布在新几内亚的高山区，包括西部、中部、东北部和东南部。","other":"2018年发表的一项分子系统发育研究，将此物种从Sericornis属重新分类至Aethomyias属。"},{"name":"棕脸丝刺莺","english_name":"Buff-faced Scrubwren","scientific_name":"Aethomyias perspicillatus","overview":"棕脸丝刺莺（英文名：Buff-faced Scrubwren，学名：Aethomyias perspicillatus），是雀形目细嘴莺科Aethomyias的鸟类。体型极小、羽色朴素的鸟类，主要分布于新几内亚的山地森林中。其最显著的特征是面部呈橙棕色斑块，环绕眼周形成明显的眼圈，头顶至后颈呈灰色，背部和尾部为橄榄色。该物种常活跃于中下层林冠，成小群或与混群鸟类共同活动，以昆虫为食。","appearance":"体长约10厘米。成鸟面部、眼周及颏部为橙棕色，形成明显的眼圈，与灰橄榄色的头顶和前额形成鲜明对比；上体包括上翼和尾部为橄榄色，尾羽除中央一对外，其余末端具暗色次端斑；下体为浅赭棕色，侧腹和腹部颜色较深；虹膜黑褐色、褐色或红褐色；喙黑褐色或黑色，下喙基部有时浅色；腿浅褐色或淡褐灰色。雌雄羽色相似。幼鸟羽色与成鸟相近。","call":"鸣唱为重复的音乐性哨音“wee sippee wee-sippee wee-sippee”，也有上升的“ju ju jee”系列，或先升后降的“jit-tita-weha-ta”。警戒时发出粗糙的斥责声“chut”。","habits":"主要栖息于海拔1,500–2,450米的湿润山地和中山地森林、木麻黄林、次生林及村庄花园，局部可低至850米或高达2,800米。为留鸟，不进行迁徙。以昆虫为食，成鸟以节肢动物如蛾类和小毛虫（鳞翅目）喂雏。主要在林下层至中层活动，有时可达林冠层。常结成活跃嘈杂的群体活动，常与其他鸟类混群，如黑扇尾鹟、睦扇尾鹟、黑领啸鹟和棕鵙鹟。主要通过叶片上掠食获取食物。与山丝刺莺同域分布时，通常活动于更高层次，且不像后者那样探啄树干。","breeding":"繁殖期可见于5月、8月和10月。巢为大型结构，侧入口靠近顶部，具轻微的门廊或帽檐，由苔藓、细根和竹叶构成，内衬羽毛、细草和细根，悬挂于林缘的灌木或幼树上，一例巢距地面0.75米。关于卵、孵化期和育雏期的信息尚缺；雏鸟由双亲共同喂养。","identification":"与山丝刺莺相比，棕脸丝刺莺体型更小，具明显的棕眼圈和灰色头顶，且活动于更高层次；与灰绿丝刺莺在低海拔重叠，但觅食策略不同。","protection":"IUCN: LC（无危）","distribution":"分布于新几内亚北部、中部、东部及东南部的山地：包括福贾山脉、贝瓦尼山脉、阿德尔伯特山脉，中部山脉从韦兰山脉向东，博萨维山，以及休恩半岛和东南部山脉。","other":"该物种曾被描述为Sericornis nigroviridis（暗橄榄绿色，头部至胸部及腹部中央为暗黑灰色，上喉部具灰色羽尖），基于采自新几内亚东南部瓦乌附近的一具标本，现被认为极可能是本种的黑色型个体。单型种，无亚种分化。"},{"name":"瓦格丝刺莺","english_name":"Vogelkop Scrubwren","scientific_name":"Aethomyias rufescens","overview":"瓦格丝刺莺（英文名：Vogelkop Scrubwren，学名：Aethomyias rufescens），是雀形目细嘴莺科Aethomyias的鸟类。细小、颜色暗淡。生活在新几内亚岛鸟头半岛的山地森林底层，为新几内亚特有种。其自然栖息地位于亚热带或热带湿润的山地森林。","appearance":"上体呈暗至暖棕色，下体为浅棕色，具有明显的厚而淡色的眼环。体型非常小，比同类的大型刺莺更小，脸部不具锈色。","call":"发出干燥的“chek”声或鼻音的责备声“meh-meh-meh”。","habits":"常以小组形式活动，或混在多种鸟类群中，在森林低层到中层寻找昆虫为食。","identification":"与大型刺莺相似，但瓦格丝刺莺体型较小，且脸部无锈色。","protection":"IUCN：LC（无危）","distribution":"分布于印尼西巴布亚的鸟头半岛山区（Tamrau Mountains, Arfak Mountains）和Bomberai半岛（Kumawa Mountains），位于新几内亚西北部。"},{"name":"灰绿丝刺莺","english_name":"Grey-green Scrubwren","scientific_name":"Aethomyias arfakianus","overview":"灰绿丝刺莺（英文名：Grey-green Scrubwren，学名：Aethomyias arfakianus），是雀形目细嘴莺科Aethomyias的小型鸟类。栖息于新几内亚的高山森林中，以昆虫为食。其上体橄榄绿色，头部淡灰色，腹部白色，胸部带有淡灰色斑纹，喉部洁白。与Vogelkop、Pale-billed和Perplexing丝刺莺在同一海拔共同生活，但可通过其橄榄色而非温暖的棕色上体来区分。","appearance":"灰绿丝刺莺体型小巧，上体呈现橄榄绿色，头部为淡灰色，翅膀带绿色。胸部有淡灰色的斑点，腹部则是白色的。喉部颜色洁白，与胸部的淡灰色斑纹形成鲜明对比。雌雄成鸟与幼鸟的羽毛颜色基本一致，但在色彩饱和度上可能略有差异。","call":"鸣唱是一串刮擦般的音符，随后是起伏的“chi-doo！chi-doo！chi-doo！”叫声。日常叫声包括各种粗糙的、鼻音重的音节和喋喋不休的声音。","habits":"栖息于新几内亚的高山森林内部，通常成小群活动，积极地在树叶和树枝间搜寻昆虫。分布范围包括Vogelkop、Fakfak山脉、新几内亚中部山脊，以及从Cyclops山脉向东至Adelbert山脉和Huon半岛的北部山脉。","identification":"与Vogelkop、Pale-billed和Perplexing丝刺莺相比，灰绿丝刺莺的上体呈橄榄色而非暖棕色，这是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的高山区，包括Vogelkop、Fakfak山脉和中部山脊，以及从Cyclops山脉向东至Adelbert山脉和Huon半岛的北部山脉。"},{"name":"中山鼠莺","english_name":"Bicolored Scrubwren","scientific_name":"Aethomyias nigrorufus","overview":"中山鼠莺（英文名：Bicolored Scrubwren，学名：Aethomyias nigrorufus），是雀形目细嘴莺科Aethomyias的鸟类。特征在于仅呈现两种颜色，上体黑色或黑褐色，下体为亮红色至红栗色，活跃于新几内亚高地的中海拔山林底层，分布于山区中西部至新几内亚东南部。","appearance":"中山鼠莺体长约12-13厘米，上体呈黑色或黑褐色，下体为鲜明的红色至红栗色，腹部色泽较淡。头部、翅膀和尾巴颜色一致，喉咙至胸部为亮红色，腹部颜色略显暗淡。虹膜红棕色，喙灰褐色，腿为棕色至黑色。性别间外观相似，幼鸟描述不明，但可能比成鸟更显暗淡，上体棕色，下体红棕色。","call":"鸣叫时发出兴奋的喋喋不休声，歌唱时为一系列清晰、哨音般的音符，音调或升或降。","habits":"居住在1220米至2500米的山地森林中，通常在地面和灌木层中觅食昆虫，会迅速跳跃于枝头之间，同时发出责备般的叫声。在某些区域，与低地鼠莺生态位重叠，具体生态分离机制未知。","breeding":"繁殖习性了解不多，仅有的两巢数据显示，巢穴为圆形穹顶状，侧入口靠近顶部，由细小的暗根须和少量苔藓碎片构成，内部铺以草或竹叶，衬以更细腻的材料和少许绒羽。每窝产2枚白色几乎无斑点或仅大端有淡紫色斑点的蛋。","identification":"与低地鼠莺相似，但中山鼠莺上体颜色更深，下体统一为红色而非白色。Blissi亚种腹部黑色，带有橄榄色洗纹。","protection":"IUCN：LC（无危）。在全球范围内并未受到威胁，但在局部地区数量稀少，栖息地可能因局部伐木和农田开垦而受到影响。","distribution":"主要分布在新几内亚的中西部山区至东南部，占据1220米至2500米的狭窄海拔带。","other":"物种曾被归类于Crateroscelis属，但2018年分子系统发育研究将其重新归入复活的Aethomyias属。"},{"name":"澳洲丝刺莺","english_name":"Atherton Scrubwren","scientific_name":"Sericornis keri","overview":"澳洲丝刺莺（英文名：Atherton Scrubwren，学名：Sericornis keri），是雀形目细嘴莺科丝刺莺属的鸟类。此物种主要栖息于澳大利亚昆士兰东北部，特别是在Atherton Tablelands山区和约克角半岛东南部的雨林及湿润桉树林地带。","appearance":"该鸟体型较小，主要生活在陆地上，上身呈棕色，下身灰黄色，拥有长而尖锐的喙，粉红色的长腿，以及一圈略显淡白的眼环。雌雄及幼鸟的羽毛颜色与成鸟相似，但可能较为暗淡。","call":"其鸣唱变化多端，通常包含重复的双音节元素。","habits":"澳洲丝刺莺主要在地面或低层树冠中寻找昆虫为食，显示出它对森林底层生态位的适应。","breeding":"关于该鸟的繁殖行为信息有限，但一般认为它们会在雨季进行繁殖，筑巢于密林中。","identification":"与巨嘴丝刺莺相比，澳洲丝刺莺颜色更深，更常在地面觅食，体型稍小，叫声更为清脆。","protection":"IUCN：VU（易危）","distribution":"分布局限于澳大利亚东北部的昆士兰州，特别是在Atherton Tablelands和约克角半岛东南部。","other":"尽管一度被归类于Pardalotidae科，但现已确认其属于Acanthizidae科。"},{"name":"白眉丝刺莺","english_name":"White-browed Scrubwren","scientific_name":"Sericornis frontalis","overview":"白眉丝刺莺（英文名：White-browed Scrubwren，学名：Sericornis frontalis），是雀形目细嘴莺科丝刺莺属的鸟类。生活在澳洲沿岸。广泛分布于东、南、西南澳大利亚的非沙漠和半干旱地带，偏好浓密的灌木丛生环境。这种小鸟以其鲜明的白色眉纹和淡色虹膜著称，体长11-14厘米，全身主要呈现橄榄棕色，且拥有三种显著不同的亚种。","appearance":"白眉丝刺莺体长约为11.5厘米，上部呈橄榄棕色，灰褐色冠部带有锈色洗染，背部至尾上覆羽略带锈色。头部特征明显，黑色颊部与耳羽形成宽幅面具，由明亮白色眉纹和次级髭纹勾勒，眉纹在眼后逐渐淡化。下颏白色，随位置不同，黑色条纹程度各异。胸部侧边灰色，胁部带锈色。雄鸟指名亚种具有黑色前额，沿眉纹上方延伸至眼后的窄带，肩部有明显的黑白色斑块，翼小覆羽和初级覆羽尖端白色。雌鸟色彩较暗淡，面部图案对比度较低，颊部灰或棕色。幼鸟比雌鸟更暗淡，黑色前额减少或缺失，上体具棕色色调，喉部无条纹，胸腹至下腹部颜色由灰棕至淡奶油色过渡，两翼有时可见淡黄色翼斑。虹膜颜色多样，从浅橙至淡黄或粉白。喙黑色，有时边缘呈棕色，下颚基部渐变为奶油色。腿色从粉棕色至深棕色，足底奶油色。","call":"白眉丝刺莺的叫声多变，既可发出急促的、类似抱怨的嗡嗡声，也能唱出清晰悦耳的歌曲。其歌声通常包含5-20个多音节‘词汇’，节奏快速，如‘tseer, whee-u, seet-yu, whee-a-chee, whee-whee-whee-de-de’及其变体。","habits":"白眉丝刺莺栖息于多种植被密集的生境，包括桉树林、雨林、灌木丛、沿海灌木地、沙丘和内陆沙地。它们适应性强，能在各种受干扰的环境中生存，包括兰特纳（Lantana）、黑莓（Rubus fruticosus）等外来植物丛生的地带，甚至在松树林中也能繁衍生息。常见于红树林边缘、郊区公园和花园，有时会进入建筑物或车辆内。偏好沟壑和水道旁的生境。在昆士兰和新南威尔士州北部的温带雨林中与柠檬丝刺莺（S. citreogularis）共存；在昆士兰湿热地带的雨林边缘活动，内部则被近缘种澳洲丝刺莺所取代。海拔高度从海平面至约1830米。","breeding":"繁殖季节从6月或7月持续至11月或12月，可能在一个季节内有多窝繁殖。社会结构包括一夫一妻制和一夫多妻制，主导雄鸟在一项研究中育有76%的后代。以简单配对或合作群体的形式繁殖，群体包括繁殖雌鸟、主导雄鸟和最多四名辅助者（通常是前一窝的后代或兄弟姐妹，偶尔也会接纳流浪个体）。辅助者参与雏鸟的养育、巢穴卫生维护和领地守卫，有助于缩短两次繁殖尝试间的间隔时间。总体上，有辅助者的群体在经验不足的繁殖雌鸟的巢育成功率似乎更高。","identification":"白眉丝刺莺与柠檬丝刺莺（S. citreogularis）的区别在于后者有更亮黄色的下体和更暗的上体，以及不同的叫声。此外，白眉丝刺莺的不同亚种在羽色、体型和叫声上有细微差异。","protection":"IUCN：LC（无危）","distribution":"白眉丝刺莺广泛分布在澳大利亚东部、南部和西南部，避开沙漠和半干旱地区。在昆士兰的新英格兰高原和沿海地区常见。","other":"白眉丝刺莺曾与褐色丝刺莺和斑丝刺莺被视作同一物种的不同亚种，但现在这二者已被重新分类为独立物种。"},{"name":"褐色丝刺莺","english_name":"Tasmanian Scrubwren","scientific_name":"Sericornis humilis","overview":"褐色丝刺莺（英文名：Tasmanian Scrubwren，学名：Sericornis humilis），是雀形目细嘴莺科丝刺莺属的鸟类。小型灰棕色鸟类，特有于澳大利亚塔斯马尼亚州和邻近的金岛。栖息在温带森林的灌木层，包括雨林、林地、干燥森林、沼泽和沿海灌木丛。","appearance":"这种鸟具有黑色和白色的肩斑，淡白色的眉纹和微弱的浅色颏线。与白眉丝刺莺极为相似，但颜色更深，面部图案不那么明显。体型较小，羽色以灰棕色为主，肩部的黑白斑块是其显著特征。","habits":"在各种植被茂密的环境中于地面觅食。它们活跃于森林底层，偏好在浓密植被中活动。","identification":"与白眉丝刺莺相比，褐色丝刺莺颜色更暗，面部图案不那么突出，通过观察肩部的黑白斑块和整体色调可进行区分。","protection":"IUCN：LC（无危）","distribution":"分布在澳新界的塔斯马尼亚州（澳大利亚东南部），包括主岛塔斯马尼亚和附近的金岛。","other":"关于其分类地位，曾被置于细嘴莺科，但现在通常归类于独立的细嘴莺科Acanthizidae。有时被视为较小的白眉丝刺莺的亚种，需进一步研究明确两者关系。"},{"name":"巨嘴丝刺莺","english_name":"Large-billed Scrubwren","scientific_name":"Sericornis magnirostra","overview":"巨嘴丝刺莺（英文名：Large-billed Scrubwren，学名：Sericornis magnirostra），是雀形目细嘴莺科丝刺莺属的鸟类。小型棕色雀形目鸟类，特征是拥有长而尖的喙，粉色的长腿，以及独特的偏白色眼圈。该物种主要分布于澳大利亚东部的雨林和湿润桉树林地带，偏好于热带雨林和湿润硬叶林的密集灌木层。","appearance":"巨嘴丝刺莺体长约11.5至13厘米，体重约10克。头部呈现暗红棕色的眼睛，位于淡色脸部上，长而略上翘的黑色喙十分显眼。背部为浅灰棕色带橄榄色光泽，喉咙为淡黄白色，腹部呈灰色，臀部和尾巴则是淡赤褐色。","call":"通常保持沉默，偶尔会发出穿透力强的领地叫声“s-cheer s-cheer”，或是尖锐响亮的“chwip-chwip”声，以及觅食时的‘sip-sip’声。","habits":"栖息于低至中层森林，通常在树干和树枝上寻找昆虫等节肢动物，如蜘蛛、蚂蚁、黄蜂、甲虫和鳞翅目幼虫。它不会经常出现在地面，更常见于北方的分布区域。","breeding":"繁殖期主要集中在7月至翌年1月，尤其在11月至12月。它们会建造粗糙的穹顶状巢，由树皮、草和苔藓构成，内部衬以羽毛，安置在藤蔓、树蕨或棕榈叶片中。一窝产卵3到4枚，尺寸约为19×15毫米，颜色为哑光白至淡紫褐色，大端带有细斑点。孵化期未知，雏鸟期大约13天。巢穴可能会被扇尾杜鹃和栗胸杜鹃寄生。","identification":"与其他丝刺莺属鸟类相比，巨嘴丝刺莺拥有显著较大的喙。三个亚种 magnirostra、S. m. viridior和S. m. howei在分布区域上有明显的差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从昆士兰北部的库克敦附近到维多利亚州墨尔本附近的金湖和丹德农山脉。在澳新界，主要见于澳大利亚东部。"},{"name":"小丝刺莺","english_name":"Tropical Scrubwren","scientific_name":"Sericornis beccarii","overview":"小丝刺莺（英文名：Tropical Scrubwren，学名：Sericornis beccarii），是雀形目细嘴莺科丝刺莺属的小型鸟类。又称热带丝刺莺或贝卡里的丝刺莺。主要分布于澳大利亚东北部、新几内亚和阿鲁群岛的热带湿润森林。","appearance":"小丝刺莺体色上部呈棕色，下部偏淡，拥有短尾和长而尖锐的喙。最显著的特征是其非常细薄且明显的白色眉纹，肩部有黑色斑块边缘泛白，这一特征使其在同类中独树一帜。","habits":"偏好浓密的热带雨林环境，常在低层树冠和地面寻找食物，主要栖息在澳大利亚东北部、新几内亚及阿鲁群岛的热带湿润森林中。","identification":"与其他丝刺莺相比，小丝刺莺的白色眉纹和肩部的黑白相间斑块是其独特的识别标志。","distribution":"分布于澳大利亚东北部、新几内亚和阿鲁群岛的热带湿润森林，具体包括昆士兰州、新几内亚南部和澳大利亚东北部。"},{"name":"迷丝刺莺","english_name":"Perplexing Scrubwren","scientific_name":"Sericornis virgatus","overview":"迷丝刺莺（英文名：Perplexing Scrubwren，学名：Sericornis virgatus），是雀形目细嘴莺科丝刺莺属的鸟类。命名缘于复杂的分类学问题，曾一度被错误归类于Pardalotidae科，现确认归属Acanthizidae科。分布于印尼及巴布亚新几内亚的热带森林中。","appearance":"具体外观特征描述缺失，通常丝刺莺属鸟类具有细长的喙，适应于在灌木丛中觅食昆虫。","habits":"栖息于亚热带或热带的湿润低地森林及山地森林，生活方式及活动范围需进一步研究。","identification":"与山丝刺莺在某些区域存在杂交现象，但在其他区域两者似乎不发生杂交，区分主要依据分布区域及可能的行为差异。","distribution":"主要分布于澳新界的西北部和中北部新几内亚，具体为印尼及巴布亚新几内亚的特定地区。","other":"在分类学上，曾与山丝刺莺合并考虑，但现今认为两者在部分区域保持独立性。现为山丝刺莺亚种。"},{"name":"山丝刺莺","english_name":"Large Scrubwren","scientific_name":"Sericornis nouhuysi","overview":"山丝刺莺（英文名：Large Scrubwren，学名：Sericornis nouhuysi），是雀形目细嘴莺科丝刺莺属的鸟类。为中等体型、长嘴的高原刺莺，分布于新几内亚高地及亚彭岛的山地森林。整体羽色以橄榄褐与栗色为主，面部具明显锈红渲染，是该属中体型最大者，海拔分布范围1400–3500 米，偶至3750 米。","appearance":"体长11.5–13.5厘米，体型相对较大，嘴长。两性同型。指名亚种头顶橄榄褐，额及面部淡栗红；上体暗褐橄榄色，翼及尾羽更褐，羽缘带栗色渲染；下体淡橄榄褐，颏及喉具锈色；虹膜红褐或橙褐；嘴黑色或黑褐色；腿色变异，从淡肉色至暗褐色。幼鸟未描述。cantans亚种面部栗色延伸至胸，腹灰褐，尾下覆羽栗色；jobiensis亚种额及面部更深赭肉桂色，上体暗而少橄榄，下体更淡；virgatus亚种上体绿褐，冠及尾羽更褐，额、眉纹及脸侧淡赭或栗色，翼覆羽常具白或灰端斑；stresemanni亚种尾色更深、少栗，下体淡橄榄黄，胸具明显栗褐渲染；oorti亚种头、尾及翼更褐，背橄榄，喉及头侧淡栗，下体淡橄榄黄；monticola亚种似oorti但体型更大，下体更淡。","call":"鸣唱为连续下降的音乐性絮语“weesee weesee weesee”，每二音略低；另有“sit ti tuwit, sit tu tuwit”的下降音列。发出粗糙斥责“chit”与音乐哨音“weet see see tu tu tu”的组合。virgatus亚种的鸣唱似指名亚种但更高、更稀疏。","habits":"留鸟。栖息于海拔1200–3750 m的山地森林及其次生灌丛，东南部monticola亚种多栖于3000 m以上，virgatus与jobiensis亚种在600–1520 m的低山及丘陵森林活动。常4–5只小群活动于森林下层至中层，参与混群觅食。觅食方式类似澳大拉西亚爬树鸟或蓝顶鹛，在苔藓树干、藤蔓及附生植物上探取节肢动物，偶食种子。","breeding":"繁殖期记录于4–12月，涵盖雨季及旱季。巢为大型穹顶状侧口巢，筑于露兜树叶丛或悬挂的苔藓团中，由干露兜叶、细根、苔藓状苔类、蕨类及纤维构成，内衬细纤维及羽毛。每巢2枚卵，卵白色带淡紫褐底色，大端具暗色斑块，余部具淡褐斑；孵卵及育雏期未详。","identification":"与巴布亚丝刺莺相比，羽色更栗、少绿色，尾无次端带；与棕脸丝刺莺及灰绿丝刺莺相比体型明显更大。不同亚种之间主要差异在羽色深浅、下体色调及翼覆羽端斑有无。","protection":"IUCN: LC（无危）","distribution":"繁殖区：新几内亚高地（西北部的鸟头半岛、韦兰山脉、拿骚岭、雪山山脉、伊登堡河坡、托里切利山脉、贝瓦尼山脉、亚历山大王子山脉、塞皮克–拉穆北坡、博萨维山、锡萨山、阿德尔伯特山脉、赫尔佐格山脉、胡翁半岛及东南欧文斯坦利山脉）及亚彭岛（亚彭岛）。非繁殖区：无迁徙，留鸟。","other":"分类地位复杂，曾将迷丝刺莺视为杂交种群并入本种；多个亚种界限尚待厘清，部分亚种可能为异名。"},{"name":"斑丝刺莺","english_name":"Spotted Scrubwren","scientific_name":"Sericornis maculatus","overview":"斑丝刺莺（英文名：Spotted Scrubwren，学名：Sericornis maculatus），是雀形目细嘴莺科丝刺莺属的小型鸟类，主要分布在澳大利亚西南部至南部沿海地区，西至Shark Bay，东至Adelaide附近。其显著特征为白色的眉纹和淡色虹膜，以及暗色脸部上的清晰白眉和下巴条纹。","appearance":"斑丝刺莺体型小巧，整体呈橄榄褐色，肩部具有黑白相间的斑块，前胸较浅。下巴白色，胸部和上腹部有细腻的黑色条纹。眼睛周围呈现独特的白色眉纹，与暗色脸部形成鲜明对比。","call":"该物种常发出不满的嗡嗡叫声，同时也能够演唱清脆悦耳的歌曲。","habits":"斑丝刺莺栖息于澳大利亚南部沿海地带的各种生境中，偏好植被茂密的环境。它们广泛分布，但在植被覆盖较好的地方更为常见。","identification":"斑丝刺莺与白眉丝刺莺在形态上有相似之处，特别是在Adelaide地区的重叠分布区，两者可能发生杂交现象。通过基因分析，斑丝刺莺被确认为独立物种，与白眉丝刺莺有显著的遗传差异。","protection":"IUCN：LC（无危）","distribution":"斑丝刺莺主要分布在澳大利亚西南部和南部沿海地区，从Adelaide向西延伸至Western Australia的Shark Bay。","other":"在2018年的一项遗传学研究中，斑丝刺莺被发现与白眉丝刺莺的遗传差异明显，因此在2019年被重新分类为独立物种。"},{"name":"黄喉丝刺莺","english_name":"Yellow-throated Scrubwren","scientific_name":"Neosericornis citreogularis","overview":"黄喉丝刺莺（英文名：Yellow-throated Scrubwren，学名：Neosericornis citreogularis），是雀形目细嘴莺科Neosericornis的鸟类。广泛分布于澳大利亚东部沿海地区。以黄色喉咙和眼眉为显著特征，生活于湿润森林或雨林地带，主要以昆虫为食。","appearance":"成年黄喉丝刺莺体型约12.5至15厘米，雄鸟体重约18克，雌鸟约16克。拥有相对较长的尾巴和腿。雄鸟头部橄榄褐色，眼上方有由白转黄的狭窄超眉纹，下额和喉部为鲜明的黄色，上体棕色，臀部和尾部红褐色，翅膀边缘绿色泛黄，形成独特的翼斑。雌鸟相似但头部对比度较低，上胸可能带有暖棕色。幼鸟上体暗红棕色，缺乏成鸟的橄榄色，虹膜深棕或灰色。","call":"发出响亮粗糙的叫声和生动的歌声，后者有时是对响声如汽车门关上的反应。","habits":"栖息于沿海温带至山地亚热带雨林的阴暗下层，常沿溪流而居，与多种植物共生。单个或成对觅食，有时加入混合觅食群。主要在地面觅食，偶尔会跟随其他鸟类如刺尾鸫或两种琴鸟，捕食它们翻动的土壤中的食物。","breeding":"繁殖季节从8月至次年3月，一季可能孵化一到两窝。巢为悬吊的梨形结构，由各种自然材料制成，内部铺垫柔软物质。通常建在离地1至12米处，有时位于水面上方。每窝产2至3枚蛋，孵化期17至24天，雏鸟期约3周。已知寄生现象，涉及几种寄生鸟。","identification":"与其他丝刺莺的区别在于黄色的喉咙和眼眉，以及黑色的面部图案（雄鸟）。与大型丝刺莺（Sericornis magnirostris）的区别在于觅食高度的不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从库克敦至汤斯维尔的北昆士兰，以及从赫维湾南至新南威尔士州东南部的南部沿海地区。","other":"其巢穴常被金色尖耳蝠（Phoniscus papuensis）用作日间栖息地。"},{"name":"褐阔嘴莺","english_name":"Weebill","scientific_name":"Smicrornis brevirostris","overview":"褐阔嘴莺（英文名：Weebill，学名：Smicrornis brevirostris），是雀形目细嘴莺科褐阔嘴莺属的小型鸟类，体长约8至9厘米，体重平均6克，为澳大利亚最小的鸟种之一。头部灰褐色，上体橄榄灰至灰橄榄色，下体颜色较浅，偏黄，由南至北呈现从棕到黄色的渐变。分布于澳大利亚大陆（除塔斯马尼亚州外）的广阔地带。","appearance":"褐阔嘴莺拥有短而粗的淡灰色喙，上体颜色从橄榄灰至灰橄榄色，下体颜色从奶油色至极淡黄色，腹部和肛周区域更富黄色，两胁亮黄色。尾羽基部的上覆羽呈淡橄榄黄色，尾羽暗褐灰色，具宽阔的黑色亚端斑。上翼深褐色，次级飞羽覆羽和三级飞羽边缘淡黄色，初级飞羽边缘更细的黄色。虹膜奶油色或淡黄色，下颚骨有时呈淡粉色。幼鸟的头部和上体较为暗淡，具棕色调，胸腹部颜色更淡，喉部无条纹，虹膜呈暗灰色或青绿色。","call":"褐阔嘴莺发出独特响亮的歌声，全年可闻，常被描述为类似“I’m a wee-bill！”的旋律。此外，它们还会发出颤音叫声，用作联络和警报，可能穿插在歌曲片段中。","habits":"褐阔嘴莺栖息于各种林地环境，尤其偏好桉树（Eucalyptus）林地，也见于干燥硬叶树林、灌木丛和灌木林地。常见于半干旱区，而非干旱地带，主要分布在排水线附近。它们通常避免雨林和季风雨林。以昆虫为主食，偶尔摄取种子，如蜘蛛、甲虫、蝇类、蝽象、蚁类和毛虫等。褐阔嘴莺单个或成对出现，有时形成小群至十只左右，偶尔会加入混合觅食群。","breeding":"繁殖季节主要在8月至12月，但全年都有记录，可能受降雨影响。通常单独筑巢，由两只成鸟照料，但有报告指出存在社群或合作繁殖现象，有帮手参与。巢由双方共同建造，有时有帮手协助，耗时6至15天。巢呈穹顶状，侧入口近顶部，由草、叶、茎、羊毛、花、草头、苔藓、纤维、树皮、羽毛、蛛网和卵囊构成，内衬羽毛和柔软材料。巢悬挂在枝条上，通常位于树冠的叶子中，有时在较低的树枝上，最常见于桉树（超过35种记录），也利用其他植物。每窝产卵2至4枚，有时更多，平均孵卵期约18至21天，雏鸟孵化后17至20天离巢。","identification":"褐阔嘴莺与其他细嘴莺科鸟类的区别在于其短而粗的喙。四个亚种在色彩上有细微差异，主要体现在色调的不同。南方和东部地区的occidentalis和brevirostris亚种呈淡棕色，西南部的occidentalis亚种羽毛更灰，而北部和内陆地区的flavescens亚种更淡更黄。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚大陆（除塔斯马尼亚州外），包括干燥的桉树林、硬叶树林、灌木丛和灌木林地。","other":"尽管普遍认为数量稳定，但局部地区因栖息地丧失和退化导致的鸟类数量下降已引起关注。"},{"name":"褐噪刺莺","english_name":"Brown Gerygone","scientific_name":"Gerygone mouki","overview":"褐噪刺莺（英文名：Brown Gerygone，学名：Gerygone mouki），是雀形目细嘴莺科噪刺莺属的鸟类。曾称作褐林莺，小型的雀形目鸟类，原生于澳大利亚东部沿海地区。其上部羽毛呈深橄榄灰至橄榄褐色，面部和下体颜色较淡，为灰色、奶油色或淡褐色。尾羽深色，部分可能带白色尖端，体长约10厘米。在澳大利亚东部的雨林中广泛分布，常见于沿海雨林，有时也会出现在红树林和干燥硬叶林。","appearance":"体型小巧，约9-11厘米长，体重约5.5克。上体橄榄褐色，头部略带灰色调，具黑色眼线和淡色眉纹延伸至眼后，灰褐色面颊和颈侧；尾部与背部相似，带有宽黑亚端带，除中央尾羽外其余尾羽内网近尖端有大白色斑点；下体偏白，胸腹部有淡黄褐色晕染，下尾覆羽乳白色；虹膜砖红色或深棕色；喙黑色；腿橄榄灰至黑色，足底黄色。雌雄相似，幼鸟虹膜暗淡或偏浅，与成鸟相似但更显朴素。不同亚种间存在微小的体型和羽毛差异。","call":"全年歌唱，声音为单调平直的‘what-is-it, what-is-it’，缺乏同类甜美音乐般的音质，或发出柔和、均匀音调的3-5音节‘diddle-it-did-it’，亦用于联系叫声。有模仿黄脸吸蜜鸟和东黄鸲鹟的报道。","habits":"主要栖息于雨林，亦可见于其他湿润森林、沟壑和沿河植被，非繁殖季节会迁移到非雨林环境。食性以昆虫为主，包括甲虫、蝇、蝽、蚜虫、膜翅目昆虫和鳞翅目幼虫。通常成对或小群（最多六只）活动，活跃于树冠层，偶尔加入混合物种群，如巨嘴丝刺莺、黄斑吸蜜鸟、淡黄歌鸲鹟、山刺嘴莺、灰扇尾鹟和黄胸船嘴鹟。","breeding":"繁殖期为6月至2月，主要集中在9月至12月，热带地区较早。雌鸟筑巢，巢为椭圆形、顶窄结构，入口狭长，常用绿色苔藓、蜘蛛网或细根系固定，并装饰以浅色苔藓，内壁为细树皮纤维，衬以柔软植物绒毛、毛发、羽毛或苔藓，常有下垂的“尾巴”，悬挂在离地面3-6米的树、灌木、树苗或藤蔓上。每窝产2-3枚蛋，白色至淡红色，有细小红至紫斑点，由双方孵化，孵化期18-19天；雏鸟由双亲喂养，育雏期14-16天。巢穴可能被霍氏金鹃和金鹃寄生。","identification":"与沼泽噪刺莺和棕胸噪刺莺相似，但具有独特的白眉纹和灰脸。红树林细嘴莺虽有白眉纹，但无灰脸，两侧更多白色，眼更红。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚东部，从海岸到大分水岭的斜坡和高原；在维多利亚州南部和西部的分布范围有所扩大。","other":"褐噪刺莺的声音是澳大利亚东海岸雨林的典型声响之一，其巢穴有时会被两种蝙蝠作为栖息地。"},{"name":"灰噪刺莺","english_name":"Grey Gerygone","scientific_name":"Gerygone igata","overview":"灰噪刺莺（英文名：Grey Gerygone，学名：Gerygone igata），是雀形目细嘴莺科噪刺莺属的鸟类。为细嘴莺科噪刺莺属的小型鸟类。广泛分布于新西兰的森林地带，包括南岛、斯图尔特岛及其周边岛屿。以灰褐色上体、淡灰色至近白色下体为特征，尾部深色带白色尖端，飞行中尤为显眼。拥有独特的红宝石色眼睛，雌雄体型相似，幼鸟呈淡色且眼色为棕色。","appearance":"体长约10厘米，体重约6.5克。上体橄榄灰褐色，脸、喉、胸为淡灰色，腹部偏白，侧腹有时带有淡黄或灰色。尾羽暗色，具宽黑亚端斑，末端白色。面部黑色，尾羽除中央外皆有大白色斑点。虹膜深红色，喙和腿黑色。雌雄外观相同，幼鸟面色较淡，眼环苍白。","call":"雄鸟的鸣唱从一系列吱吱声开始，逐渐形成独特而悠长的哀婉颤音序列，时而升高时而下降，全年均可听到，春季筑巢期间尤为活跃。雌鸟和幼鸟发出的是次鸣叫声。此外，还有短促的颤音和啾啾声，以及追逐或交配时的尖锐叽喳声。","habits":"栖息于新西兰的森林、林地、次生植被、农田、公园、花园、林缘、灌木丛、树篱和红树林，偏好混合本地和外来树种的环境，如松树（Pinus）和桉树（Eucalyptus）。从海岸平原到海拔1500米的亚高山区都有分布，但密度较低。主要以昆虫和蜘蛛为食，偶尔食用小果实和种子。单独或成对觅食，有时会形成多达八只的小群。常与多种混群活动。","breeding":"繁殖季节为6月中旬至次年1月，南岛和斯图尔特岛稍晚，9月开始。通常一夫一妻制，独居筑巢。巢为梨形或瓶形，侧入口靠近顶部，由根须、草茎、苔藓、毛发、蕨类和树皮构成，用蛛丝粘合，内部铺垫羽毛、羊毛、绒毛种子和树蕨鳞片。每窝产卵3-4枚，孵化期约19.5天，仅雌鸟孵卵，两性共同喂养雏鸟，巢期17-19天，幼鸟离巢后继续被喂养最多38天。是金鹃寄生的主要宿主。","identification":"与灰胸绣眼鸟相比，略大，背部更绿，无白色眼环。在新西兰，是金鹃唯一的寄主物种，因此可看到灰噪刺莺喂养比自己大得多的鸠雏。在新西兰同域的鸟类中，可通过大小、颜色和鸣叫声进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于新西兰的北岛、南岛和斯图尔特岛及其周边卫星岛屿，适应各种林木环境，包括本土和外来树种混杂的森林，城市和乡村有树木聚集的地方。","other":"对于毛利人而言，灰噪刺莺春季的鸣唱标志着作物种植季节的开始。"},{"name":"诺岛噪刺莺","english_name":"Norfolk Gerygone","scientific_name":"Gerygone modesta","overview":"诺岛噪刺莺（英文名：Norfolk Gerygone，学名：Gerygone modesta），是雀形目细嘴莺科噪刺莺属的鸟类。主要栖息在澳大利亚东部的诺福克岛上，是该岛特有种。其羽毛橄榄褐色，腹部灰白，具有一条穿过眼睛的暗色线，脸部淡灰色，眼圈白色断续，喙细长且黑色。","appearance":"诺岛噪刺莺身长9.5至12.3厘米，体重约7克。上部羽毛呈橄榄褐色，脸部呈淡灰色，眼圈白色，眼部前方有一小块暗斑；尾部有宽广的黑褐色亚端带，除中央一对尾羽外，其余尾羽近尖端有暗边白色斑点，由内向外逐渐增大；下部羽毛从下巴、喉咙到胸部呈淡灰色，其余下体白色，侧翼至尾下覆羽带有浅黄色，腋下羽毛白色；虹膜红棕色至鲜红色；喙及腿黑色至灰棕色，足底淡黄色。雌雄外观相似，幼鸟眼圈黄色，面部和下体有黄色色调，虹膜较暗呈棕色，喙色较淡。","call":"鸣唱为旋律优美的高音颤音，结尾滑音，与同属其他种类相似，但不如灰噪刺莺的歌曲结尾强烈。","habits":"栖息于雨林、次生林、树篱、牧场残余植被和花园中，似乎避开农田中的残留诺福克松（Araucaria heterophylla）。主要以昆虫为食，在树冠和灌木丛中活跃觅食，常在空中捕捉昆虫，也会在地面觅食。性格温顺，不惧人。","breeding":"繁殖季节记录在11月至2月，可能有两次繁殖。巢呈梨形，顶部一侧有入口，由树皮、草、苔藓、纤维根、蜘蛛网、牛毛或羊毛制成，内部铺有羽毛，悬挂在树冠边缘的细枝上。每窝产卵2至4枚，卵壳颜色从白色到浅粉红色，带有红色条纹、斑点或斑块；孵化期和雏鸟期信息不详；雏鸟由双亲喂养，离巢后数周仍受照顾。巢穴被闪亮青铜杜鹃寄生，主要的巢穴掠食者是黑鼠。","identification":"与雌鸟和幼年的金笛鸟相比，诺岛噪刺莺具有更细的喙，腹部颜色较浅，头部比例较小。","protection":"IUCN：LC（无危）","distribution":"分布于诺福克岛（包括东澳大利亚的植被岛屿）。","other":"诺岛噪刺莺是岛上最丰富的本土鸟类之一，已适应了小型岛屿上的改造栖息地，尽管岛上存在野猫和黑鼠。岛上剩余的优质森林受到诺福克岛国家公园的保护。"},{"name":"豪勋爵岛噪刺莺","english_name":"Lord Howe Gerygone","scientific_name":"Gerygone insularis","appearance":"","protection":"IUCN：EX (灭绝)","distribution":"豪岛噪刺莺的地理分布仅限于豪勋爵岛，这是一个位于澳大利亚东部海域的岛屿。"},{"name":"查岛噪刺莺","english_name":"Chatham Gerygone","scientific_name":"Gerygone albofrontata","overview":"查岛噪刺莺（英文名：Chatham Islands Gerygone，学名：Gerygone albofrontata），是雀形目细嘴莺科噪刺莺属的小型鸣禽，仅见于新西兰查塔姆群岛。其最显著的特征为暗橄榄棕色上体与白色至淡黄色下体，雄鸟额头、眉毛、胸部和腹部呈白色，雌鸟色彩较为低调，幼鸟眼色较深，下体略带黄绿色调。查岛噪刺莺栖息于南部森林和灌木丛中。","appearance":"查岛噪刺莺体型小，约12厘米长，雄鸟体重约11克，雌鸟约9.5克。雄鸟头部和上体呈橄榄棕色，下体白色，脸部、眼圈部分白色，具深色眼纹；雌鸟较雄鸟小，白色部分减少，色彩更灰暗。幼鸟眼睛为褐色，下体带有明显黄绿色。","call":"查岛噪刺莺的鸣唱独特，由雄鸟发出，通常为重复的四音节短语“chi-ch-ch-ch”，声音清脆响亮。","habits":"查岛噪刺莺偏好密集的本土森林、灌木丛，从海岸延伸至高原地带，亦可见于被蕨类和藤蔓覆盖的开垦地区。它们以昆虫为主食，常单独、成对或家庭小群觅食，有时会形成非繁殖季节的小群。它们在密林下层和沿海灌木丛中活动，频繁触地觅食，偶尔与新西兰灰扇尾鹟相伴。","breeding":"繁殖季为9月至次年1月，多为单窝繁殖。雄鸟通过追逐和歌唱保卫领地，雌鸟独自筑巢，巢呈穹顶状，入口侧面，用根、苔藓、小枝条、地衣、树叶、树皮、草茎和羽毛构建，内部铺以羽毛。每窝产3至4枚白色带红褐色斑点的蛋，雌鸟孵化，孵化期17至21天，雏鸟由双亲共同喂养，离巢期19至23天。","identification":"查岛噪刺莺与灰胸绣眼鸟的区别在于缺乏显眼的白色眼环。与灰细嘴莺相比，查岛噪刺莺体型更大，羽色有明显差异。","protection":"IUCN：LC（无危）","distribution":"查岛噪刺莺分布于新西兰查塔姆群岛的主岛及周边岛屿，如芒格雷岛和东南岛，也曾记录于Houruakopara和Little Mangere等地。","other":"查岛噪刺莺在某些岛屿上对生态变化非常敏感，数量有所波动。"},{"name":"扇尾噪刺莺","english_name":"Fan-tailed Gerygone","scientific_name":"Gerygone flavolateralis","overview":"扇尾噪刺莺（英文名：Fan-tailed Gerygone，学名：Gerygone flavolateralis），是雀形目细嘴莺科噪刺莺属的鸟类。小型而可爱的细嘴莺科鸟类，头部呈灰橄榄色，喉部颜色较浅，眼周有断裂的白色环圈，腹部及下侧呈现鲜艳的黄色，翅膀为灰橄榄色。广泛分布于多种生境，包括城市花园。此鸟种在2021年由IOC认定为独立物种，此前曾与伦纳噪刺莺视为同种。","appearance":"扇尾噪刺莺体长约10厘米，体重约7.5克。成年鸟头部上方橄榄灰，喉部及上胸淡灰色，下胸至腹部、两胁及尾下覆羽呈明亮的硫磺黄色。背部更显绿色，翼覆羽、主翼羽及次级飞羽边缘同背羽绿色一致，臀部颜色稍淡，尾上覆羽暗橄榄色，前额、头顶及颈部为灰白色带橄榄色调。眼先、眉纹及眼下羽毛近白色；腋羽和腕缘黄色；翼下覆羽白色，尖端黄色；耳羽和喉侧灰色，略带棕色调。雄鸟上体橄榄褐色，头更偏橄榄灰，眉纹不明显，眼圈断裂；上翅及尾橄榄褐色，尾羽外侧有白色斑点；喉部灰白色，两胁及腹部柠檬黄色，其余下体淡灰色；虹膜红色；喙黑色；腿黑色或深灰色。雌鸟比雄鸟颜色淡。幼鸟尚未具体描述。","call":"鸣唱为连续重复的几个（通常四个）断奏音符组成的短句，声音轻薄、清脆，如\"tee poo tee tee poo tee\"，在瓦努阿图的亚种（correiae）的叫声更为强烈，连贯，\"toodly toodly teedle tee too\"。此外，觅食时持续发出轻微的啾啾声作为联系。","habits":"栖息于森林、次生林、村庄花园和灌木丛，海拔高度从海平面至山丘，瓦努阿图地区可达至少1600米，但在某些岛屿上，海拔超过550米的密林中较为少见。该物种为留鸟，但有能力进行短距离移动，可能曾多次在瓦努阿图的各岛上扩散。以昆虫为食，包括昆虫幼虫、蛹及成虫。单独或成对活动，有时加入由绣眼留下（Zosterops）、扇尾（Rhipidura）和啸鹟（Pachycephala）组成的混群。觅食范围从低层至树冠，主要在中间层次，从叶、枝条上觅食，有时悬停追捕猎物。性格温顺。","breeding":"繁殖季节在瓦努阿图为9月至1月/2月，在新喀里多尼亚为9月至12月，多数繁殖记录出现在10月。巢为有顶结构，侧面入口，底部有延伸部分，由植物纤维、根须、软皮和苔藓构成，用蛛丝固定，内衬羽毛和柔软植物，通常悬挂于离地面1至5米高的藤蔓上。每窝产卵2至3枚，颜色为白色或肉色，带有棕色斑点。孵化和离巢时间未知。巢穴会被金鹃寄生。","identification":"与 correiae的区别在于喉部及上胸颜色更淡，覆盖范围更小，不完全覆盖整个胸部；下胸、腹部、两胁及尾下覆羽更亮的硫磺黄色；背部更绿；翼覆羽、主翼羽及次级飞羽边缘同背羽绿色一致；臀部颜色稍淡；尾上覆羽暗橄榄色；前额、头顶及颈部为灰白色带橄榄色调；幼鸟全身下体黄色，胸部有暗色带，上体略带暗色。不同亚种在色彩、眉纹的范围和显著程度以及生物计量学上略有差异。","protection":"IUCN：LC（无危）。扇尾噪刺莺在所处的地理范围内常见，适应次生环境，只要周围有树木即可生存。当地人为食物和娱乐的捕猎对其构成威胁，尤其是Rennell岛上的鸟类，但外来入侵物种的潜在引入是更大的威胁（如猫Felis catus和太平洋鼠Rattus exulans）。在瓦努阿图和新喀里多尼亚，该物种在大多数岛屿上都很常见，尽管它可能已从某些岛屿消失，但也可能在其他岛屿上定居。","distribution":"澳新界：新喀里多尼亚和瓦努阿图。在瓦努阿图的分布海拔可达至少1600米。在某些岛屿上，海拔超过550米的密林中较少见。","other":"扇尾噪刺莺在2021年前与伦纳噪刺莺被视作同一种，但之后被IOC确认为独立物种。"},{"name":"褐胸噪刺莺","english_name":"Brown-breasted Gerygone","scientific_name":"Gerygone ruficollis","overview":"褐胸噪刺莺（英文名：Brown-breasted Gerygone，学名：Gerygone ruficollis），是雀形目细嘴莺科噪刺莺属的小型鸟类。主要分布在新几内亚的山区，栖息于山地森林边缘和村庄附近。最显著的特征是其褐色的胸部，以及白色的眼环和尾羽外侧的白色带纹。","appearance":"体长约9至10厘米。头部侧面、冠部及上体呈棕色，具狭窄的白色眼环；翼上覆羽黑褐色，次级飞羽边缘淡色；尾羽黑褐色，外侧尾羽有明显的白色次端斑点；喉部及下体白色，胸部两侧常带有变异性红褐色或浅黄褐色的斑纹，有时形成不规则的胸部带状。虹膜红褐色到深褐色，喙和腿黑色。性别间外观相似。幼鸟背部呈暗橄榄褐色，逐渐变得灰暗，下体淡黄色，腹部更浅。不同亚种之间仅在颜色细节上有微小差异。","call":"鸣声独特，由5个或更多的同音高滑音组成，每次略向下递减，最后在较深的音调水平处平稳。叫声为兴奋的叽叽喳喳声。","habits":"生活在原始森林、森林边缘、花园、次生林、种植区的木麻黄树（Casuarina）丛中，城镇和村庄，以及亚高山草甸中的树蕨。海拔高度从1100米以上，最高可达新几内亚雪山山脉和东南新几内亚的约3300米，常见于较低和中等海拔地区。以昆虫为食，单个、成对或以小家庭群的方式觅食，活跃地在树冠层中寻找食物，偶尔也会低至地面觅食。加入多种混群，如与西方山白眼鸟（Zosterops fuscicapillus）一同活动。","breeding":"繁殖季节记录在湿季和旱季都有，已知筑巢活动最早在10月，筑巢在12月，携食成鸟在1月，幼鸟出现在6月和8月。筑巢期间会鸣唱。已知的一个巢穴是悬挂在2.1米高的细树枝上的垂挂球形结构，侧面入口，装饰有苔藓，位于园地清理处。其余繁殖信息未知。","identification":"与新几内亚刺嘴莺相比，褐胸噪刺莺的棕色调更为明显，而后者偏灰色。与之共存的还有类似的灰刺嘴莺，它们的叫声也相似，但褐背噪刺莺的背部颜色明显为棕色而非灰色。","protection":"IUCN：LC（无危）。在新几内亚的中高山地区相当常见，分布于广阔且难以触及的偏远地区。其独特的鸣声往往是发现该物种存在的首要指标。","distribution":"分布于新几内亚山区，具体范围包括蒙塔纳新几内亚。"},{"name":"黄胸噪刺莺","english_name":"Golden-bellied Gerygone","scientific_name":"Gerygone sulphurea","overview":"黄胸噪刺莺（英文名：Golden-bellied Gerygone，学名：Gerygone sulphurea），是雀形目细嘴莺科噪刺莺属的鸟类。主要分布在东南亚，包括马来半岛、大巽他群岛、苏拉威西岛、小巽他群岛东部至Alor以及菲律宾等地。其显著特征为下体呈现鲜艳的黄色，头部及上体呈灰色。","appearance":"黄胸噪刺莺体型微小，体长介于9.5至10.4厘米之间，上体颜色为灰褐色，下体为明亮的柠檬黄色。雄雌外观相似，幼鸟则具有较为灰暗的上体和稍淡的黄色下体，眼周有狭窄的白色环。不同亚种在上体颜色和黄色下体的程度上有所差异。","call":"鸣唱在地理范围内变化明显，包含多种音调，通常含有高音的滑音式上升或下降的哨声，有时伴有下滑的颤音，重复多次，且在不同地区有显著差异。","habits":"栖息于各种森林环境，包括山地森林、红树林以及城市街道边的树木，海拔高度可达2300米。以昆虫为主要食物来源，常在树冠和中间层的叶子下觅食，偶尔从蜘蛛网中窃取食物，常加入混合物种群。","breeding":"繁殖季节在东南亚为12月至次年10月，菲律宾记录显示为4月至6月。巢呈袋状，侧面有入口，悬挂于树枝上，每窝产2-3枚蛋，孵化期未知，雏鸟约在14-15天后离巢，双亲共同照顾幼鸟和离巢雏鸟。","identification":"与雌鸟和幼年的黄腹花蜜鸟相似，但可通过较短且不弯曲的喙部区别开来。不同亚种在颜色上有细微差别，如simplicis亚种上体颜色更深，而flaveola亚种下体颜色更暗。","protection":"IUCN：LC（无危）, 黄胸噪刺莺广泛分布且常见，但可能受到土地清理、火灾和栖息地退化的局部负面影响。在一些国家公园和其他保护区中存在。","distribution":"繁殖区域包括马来半岛、大巽他群岛、苏拉威西岛、小巽他群岛东部至Alor以及菲律宾。在东南亚广泛分布，包括印尼、马来西亚、泰国等地。","other":"黄胸噪刺莺的巢穴会被小青铜杜鹃寄生。"},{"name":"红胁噪刺莺","english_name":"Rufous-sided Gerygone","scientific_name":"Gerygone dorsalis","overview":"红胁噪刺莺（英文名：Rufous-sided Gerygone，学名：Gerygone dorsalis），是雀形目细嘴莺科噪刺莺属的小型鸟类，体型纤细，喙部细长。其分布限于印度尼西亚东部小岛群，包括弗洛勒斯海以南苏拉威西西南部、东小巽他群岛及南摩鹿加群岛。","appearance":"红胁噪刺莺成鸟上体呈红褐色，头部灰暗，下体白色，两胁及侧腹带有淡红赭色。成年个体具浅色眼圈，虹膜颜色多变，可为红褐色、深灰色或黄灰色。幼鸟下体泛淡黄色。性别间无明显差异，但不同亚种在色泽和大小上存在细微差别。","call":"其鸣声为高音颤音歌曲，音调有规律地升降。此外，还会发出双音节的“wi-wir”叫声。","habits":"偏好低地和沿海森林、森林边缘、次生林、部分清理区、轻度林木覆盖的农地以及红树林。常在密集森林中的藤蔓纠结处活动。以昆虫为主要食物，通常成对出现，偶尔与其他物种混群。觅食时在中层树冠下2至6米处，会翻动叶片觅食，同时摆动尾巴。","breeding":"关于繁殖行为信息未知。可能成为小青铜杜鹃（棕胸金鹃）的寄主，但尚未经证实，特别是在Kai、Tayandu和Tanimbar岛屿，因当地小青铜杜鹃的幼鸟与本物种相似。","identification":"红胁噪刺莺具有短而苍白的眉纹，不延伸至眼后，窄淡的眼环，橄榄棕色的顶冠，红褐色的上体和翅膀，红棕色的尾巴，以及白下体带红赭色的两胁和侧腹。与其他莺科鸟类相比，其独特之处在于红褐色的上体和红棕色的尾巴。","protection":"IUCN：LC（无危）。红胁噪刺莺是限定范围的物种，在班达海岛屿EBA和Salayar及Bonerate群岛次级区域出现。虽然在有限范围内相当常见，但最近发现似乎已从Kai Besar和Kai Kecil消失。由于小岛环境容易受到人类活动影响，故潜在脆弱。","distribution":"分布于澳大利亚弗洛勒斯海以南苏拉威西西南部、东小巽他群岛及南摩鹿加群岛。"},{"name":"棕胸噪刺莺","english_name":"Mangrove Gerygone","scientific_name":"Gerygone levigaster","overview":"棕胸噪刺莺（英文名：Mangrove Gerygone，学名：Gerygone levigaster），是雀形目细嘴莺科噪刺莺属的鸟类。这种小型鸟类体长约9至11厘米，体重约6克，上体灰褐色，下体白色，具有独特的白色眼纹和红色眼睛。主要分布于新几内亚南部沿海和澳大利亚北部、东部的红树林及周边森林地带。","appearance":"棕胸噪刺莺体色灰上白下，上体略带灰色，下体洁白，喉咙、腹部、侧腹和臀部皆为白色。翅膀圆润，尾部有显著的白色斑点，尤其在飞行时更为明显。喙、腿黑色，虹膜红色。雌雄两性外观相似，而亚种G. l. pallida上体颜色偏棕色，G. l. cantator体型稍大。","call":"其鸣声清脆悦耳，旋律优美，音调高低起伏，如同音乐家练习音阶，富有韵律感。","habits":"栖息于红树林及其边缘的森林和灌木丛，偶尔会进入附近的森林觅食，尤其是在繁殖季节。以昆虫为主食，包括甲虫、蚱蜢、黄蜂、蚂蚁和飞蛾等，较少在空中捕食，常加入多种鸟类混群觅食。","breeding":"全年均可繁殖，东澳大利亚春季至夏季为主要繁殖期，北澳大利亚干季亦繁殖。雌鸟负责筑巢，巢呈卵圆形，顶部有盖，由草根、蜘蛛网、苔藓、海藻和树皮构成，悬挂于红树林枝条上。每窝产卵2至3枚，孵化期14至17天，幼鸟由双亲共同喂养，离巢期同样为14至17天。","identification":"与同属其他物种相比，棕胸噪刺莺的白色尾斑和红眼是其独特标识，同时，其歌声与西噪刺莺相似。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚南部沿海和澳大利亚北部、东部，包括昆士兰州至新南威尔士州的沿海区域。","other":"已知寄生其巢的鸟类有棕胸金鹃、金鹃和霍氏金鹃。"},{"name":"纯色噪刺莺","english_name":"Plain Gerygone","scientific_name":"Gerygone inornata","overview":"纯色噪刺莺（英文名：Plain Gerygone，学名：Gerygone inornata），是雀形目细嘴莺科噪刺莺属的鸟类。主要分布在东巽他群岛的Sawu至帝汶岛，包括Atauro和Wetar等岛屿。以独特的灰褐色上部和干净无斑点的白色下部为显著特征。","appearance":"纯色噪刺莺体型极小，形状类似林莺。其上部羽毛呈灰褐色，下部为纯净无斑的白色。幼鸟的下部羽毛泛黄。眼周有微妙的白色标记，眼睛显得格外醒目。通常单独或成对出现在森林、边缘地带、红树林和灌木丛中。","call":"其鸣唱由一系列高音下降的哨声组成，例如“pee-pee-ooo-ooo-pee-ooo-ooo”。叫声频繁且持续时间较长。","habits":"栖息于从海岸到山区的森林、边缘、红树林和灌木丛，常在树冠层下部活动。它在这一范围内是唯一的灰色与白色相间的微小鸟类。","identification":"在所处范围内，纯色噪刺莺以其独特的灰白两色和小巧的体型，以及眼周的白色标记容易辨认。","protection":"IUCN状态未提供。","distribution":"分布于东巽他群岛的Sawu至帝汶岛，包括Atauro和Wetar等岛屿。在澳大利亚和新西兰生物地理区中，从Sawu至帝汶岛，Atauro和Wetar（位于帝汶岛北侧，东巽他群岛东部）。","other":"无"},{"name":"西噪刺莺","english_name":"Western Gerygone","scientific_name":"Gerygone fusca","overview":"西噪刺莺（英文名：Western Gerygone，学名：Gerygone fusca），是雀形目细嘴莺科噪刺莺属的鸟类。是澳大利亚内陆和西南部特有的小型灰褐色鸟类，以昆虫为食，栖息于开阔森林、灌木林和干燥灌木丛地带。","appearance":"体长9至11.5厘米，体重约6克。上体灰褐色，下体灰白至白色，喉部和胸部可能带有灰色调。尾羽具显著的黑白相间模式，翼下覆羽有黄色斑点（幼鸟特有）。虹膜红色，喙黑色，腿色深灰至黑色。雌雄相似，幼鸟眼色较淡，下喙基部浅色。","call":"鸣声主要在繁殖季节，由一系列甜美而略带哀伤的高音旋律组成，旋律连贯下降，常在结束前突然中断再开始，被形容为‘月光下微小提琴的回响’。","habits":"栖息于干旱桉树（Eucalyptus）和金合欢（Acacia）林地，海拔可达850米，避免高降雨量区域。在内陆和西南部澳大利亚进行局部迁移，尤其在雨季或非繁殖季节。加入混合群落，与多种小鸟共食。","breeding":"繁殖季节通常为8月至次年3月，主要集中在9月至1月。巢呈椭圆形袋状，有侧入口和短尾，由植物纤维和树皮构成，内部铺以羽毛和干草，悬挂在小枝或树叉上。每窝产卵2至3枚，粉白色，带有红褐色斑点，孵化期10至12天，双亲共同育雏，雏鸟留巢期约10至13天。","identification":"与澳大利亚其他gerygone物种在外观上有细微差异，但可通过尾羽基部的大白色斑块进行区分。","protection":"IUCN：LC（最不关注）。在西澳大利亚的小麦带因土地开发导致种群减少，类似情况在昆士兰Rockhampton地区的exsul亚种也有报道。","distribution":"分布于澳大利亚内陆及西南部，包括Rottnest岛和Garden岛，避免了高降雨量区域和塔斯马尼亚。在内陆和西南部澳大利亚，部分群体表现出季节性迁移。","other":"西噪刺莺在1950年代成功殖民了Rottnest岛，迅速占据所有适宜生境。"},{"name":"暗色噪刺莺","english_name":"Dusky Gerygone","scientific_name":"Gerygone tenebrosa","overview":"暗色噪刺莺（英文名：Dusky Gerygone，学名：Gerygone tenebrosa），是雀形目细嘴莺科噪刺莺属的小型鸟类，主要分布于澳大利亚沿海西北部和西部的热带及亚热带地区，尤其偏好密集的红树林环境。","appearance":"成鸟体长约10至12.5厘米，体重约7.5克。上体灰褐色，下体偏白，头部顶侧和背部呈淡灰色或橄榄灰色，翅膀上覆羽边缘较浅。尾巴灰棕色，末端有隐约的暗色横纹，外侧尾羽尖端附近有小白点。喉部和腹部淡灰色或偏白色，两胁及腹部侧面有灰色调。眼睛虹膜白色或乳白色，喙和腿黑色。幼鸟眼虹膜较暗，喙基部下半部分黄色，体色略带黄调。雌雄外观相似。","call":"鸣声为一系列‘chewee-chew-chewee-cheweechee-chut-chee-chewee-chee’，比棕胸噪刺莺的鸣声更重复且力度较小，类似简化版的沼泽噪刺莺的歌声。伴侣在近旁觅食时常发出短促的啾啾声。","habits":"主要栖息于红树林林地和沿海灌木丛，有时也会出现在沼泽森林、溪流边和岩石峡谷。以昆虫为主食，包括鳞翅目、鞘翅目、半翅目、膜翅目和双翅目的昆虫，偶尔捕食蜘蛛、蜗牛和螃蟹。单独、成对或小群体活动，数量最多可达五只。主要在树冠层觅食，从叶片和花朵中寻找食物，也会在树干、树枝和红树林的支柱根上觅食。","breeding":"繁殖季节记录在9月至次年1月，主要在旱季。巢穴为紧凑、紧密编织的穹顶状结构，带有短而细的‘尾巴’，顶部附近有狭窄的帽状或喷嘴状侧入口，由树皮、干海藻、树叶和羽毛构成，用蛛网和植物纤维固定，内部铺垫羽毛和柔软的植物材料，悬挂在约2.5至5米高的红树林枝条上。每窝产卵2枚，蛋壳颜色为白色或淡粉色，较大的一端有红色斑点或斑块，关于孵化期和雏鸟期的信息未知，由双亲共同喂养雏鸟。已知寿命超过8年7个月。","identification":"与棕胸噪刺莺的区别在于后者有红色眼睛、较短的喙和尾部白色斑点；与沼泽噪刺莺的区别在于后者有深色眼睛和较粗的喙。不同亚种之间差异不大，christophori亚种翼展和尾部稍长，头部灰色略少。","protection":"IUCN：LC（无危）。暗色噪刺莺虽为限制分布物种，但在西澳大利亚红树林二级区可见。在偏远的热带和亚热带红树林环境中较为常见。","distribution":"繁殖区域主要位于澳大利亚西北部沿海。在澳大利亚西部也有记录。"},{"name":"沼泽噪刺莺","english_name":"Large-billed Gerygone","scientific_name":"Gerygone magnirostris","overview":"沼泽噪刺莺（英文名：Large-billed Gerygone，学名：Gerygone magnirostris），是雀形目细嘴莺科噪刺莺属的鸟类。主要分布在新几内亚和澳大利亚北部。其最显著的特征是拥有比同类更为粗壮的细长喙，上体呈棕色，下体偏白色，具有淡色的眼环和鲜红的眼睛。","appearance":"沼泽噪刺莺体型小巧，喙部细长但较为厚实，上半身呈棕色，下半身颜色较浅，接近米白色。眼周有一圈淡色眼环，眼睛鲜艳的红色是其独特标志。幼鸟的眼睛并非红色，而呈现黄色，喙基部也是黄色。与之相似的芒rove Gerygone喙部较小，无断裂的眼环，且歌声更加柔和；而褐噪刺莺的喙更小，发出的是不悦耳的'which-is-it'歌声。","habits":"栖息于红树林和茂密的河岸植被中。它们在低树、灌木或藤蔓的枝条上建造巢穴，通常位置较低，有时甚至伸手可及，位于水面之上，或临近道路，但高度可达10米。巢穴由两性共同建造，外观显得杂乱，顶部有长而参差不齐的‘尾巴’，侧面有入口，由树皮、植物纤维、干草、树叶、根须、藤蔓、苔藓、昆虫茧和蜘蛛卵囊混合而成，常以蜘蛛网加固，内部铺垫羽毛和植物绒毛。","breeding":"繁殖季节全年均可发生。筑巢由双亲共同承担，巢为穹顶结构，悬挂于低矮树木、灌木或藤蔓的枝条上。每窝产2至3枚蛋，蛋壳呈粉白色，表面密集覆盖着红或紫色斑点。孵化可能仅由雌鸟承担，孵化期约15至21天。雏鸟由双亲喂养，离巢期超过13天。在澳大利亚，其巢穴常被淡色杜鹃和金鹃寄生；在澳大利亚和新几内亚，还被小青铜杜鹃（棕胸金鹃）寄生。在澳大利亚北部，已记录到小青铜杜鹃的幼鸟被驱逐出寄生巢穴的现象。","identification":"与棕胸噪刺莺相比，沼泽噪刺莺具有更大、更粗的喙，眼环断裂，叫声更为急促；而与褐噪刺莺的区别在于后者喙更小，歌声单调。","protection":"IUCN状态未知。","distribution":"分布于新几内亚和澳大利亚北部地区，包括澳大利亚的卫星岛屿。"},{"name":"仙噪刺莺","english_name":"Biak Gerygone","scientific_name":"Gerygone hypoxantha","overview":"仙噪刺莺（英文名：Biak Gerygone，学名：Gerygone hypoxantha），是雀形目细嘴莺科噪刺莺属的小型鸟类。主要分布于印度尼西亚的Biak和Supiori岛（位于新几内亚西北部的Geelvink湾）。其自然栖息地为亚热带或热带湿润低地森林和亚热带或热带湿润灌木丛。","appearance":"拥有橄榄棕色背部，灰色头部，淡黄色腹部以及断续的白色眼圈。黑色的下喙和腿，与同属物种相比，显著区别在于其下喙和腿的颜色为黑色而非橙色。","call":"发出杂乱、高低起伏、音调不协调的哨声，混杂着一些刮擦音符。","habits":"活跃于林中层，通常以成对或混合物种群的方式觅食。偏好在亚热带或热带湿润的低地森林和灌木丛中栖息。","identification":"与Biak岛上的海岛柳莺非常相似，但仙噪刺莺具有黑色而非橙色的下喙和腿，通过这一特征可进行区分。","protection":"IUCN：NT（近危）","distribution":"仅分布于印度尼西亚的Biak和Supiori岛，位于新几内亚西北部的Geelvink湾。"},{"name":"黄腹噪刺莺","english_name":"Yellow-bellied Gerygone","scientific_name":"Gerygone chrysogaster","appearance":"黄腹噪刺莺体长约10厘米。成鸟上体呈橄榄褐色，翅膀和尾巴颜色更深，脸颊偏灰，具有一条狭窄的浅色眉纹和几乎在两侧断裂的薄淡色眼圈。下体从下巴到胸部呈灰白色，与淡黄色腹部、两胁、下腹和尾下覆羽明显分界。虹膜红棕色，喙黑色，腿呈淡角质色至紫肉色。雌雄相似，幼鸟耳羽比成鸟更灰，少带棕色。不同亚种在总体色彩上有所差异。","call":"其鸣唱为一系列上升的三音节‘pu-pu-pu pe-pe-pe pi-pi-pi’，随后变为上下交错的混乱音符。","habits":"居住在雨林、次生林、季风林和河岸植被中，海拔高度从海平面到约760米，但更常见于低地。昆虫为食，常单独、成对或以小群体（最多五只）活动，主要在中层树冠觅食，但也会在高低不同的层次活动。非常活跃，主要从树叶（占时间的76%）中觅食，偶尔悬停和突袭。与多种物种共存，如细嘴莺属的其他种类，形成混合觅食群。","breeding":"繁殖记录出现在干湿季节，即8月至9月，2月和5月。以成对形式筑巢，可能偶尔会有合作繁殖的现象，如四只个体共同喂养雏鸟。巢为悬挂的椭圆形，有一个短的向下延伸的‘喷口’通往顶部侧面的入口，由纤维物质与蜘蛛网结合而成，内部铺垫柔软的纤维，下方垂挂长‘尾巴’。巢中通常有3枚蛋，但关于孵化和离巢期的信息尚不清楚。","identification":"与雌性黑头噪刺莺相似，但黄腹噪刺莺具有棕色而非绿色的背部和尾巴。亚种间在颜色上有细微差别。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚及其周边卫星岛屿的低地森林。"},{"name":"灰头噪刺莺","english_name":"Green-backed Gerygone","scientific_name":"Gerygone chloronota","overview":"灰头噪刺莺（英文名：Green-backed Gerygone，学名：Gerygone chloronota），是雀形目细嘴莺科噪刺莺属的小型鸟类，以瘦长的喙和灰绿色的上体为显著特征。分布于澳大利亚西北部、中北部及新几内亚，常在靠近水源的热带生境中出没。","appearance":"体长9.5-11厘米（澳大利亚种群）至7.5-8.3厘米（新几内亚种群），体重约6.5克。头顶和颈侧灰色，上体暗绿橄榄色，翼上和尾部呈棕色，尾端有淡淡的暗色横带。下巴、喉咙和下体白色，胸侧可能带有褐色或灰色调，两胁至尾下覆羽可能有淡黄色斑点。眼睛红色，喙黑色或黑褐色，腿黑色到深灰色。雌雄相似，幼鸟与成鸟类似，但面部区域模糊的灰白色，上体颜色较暗且少绿。不同种群间头部色彩和下体黄调有所不同。","call":"发出快速、尖锐的音乐般的“choopi choopi choopi”声，音调逐渐上升，连续重复。在兴奋时会发出单调的重复音节，持续时间较长。在新几内亚，cinereiceps亚种的声音更高，具有类似的上升颤音序列。","habits":"栖息于多种热带生境，尤其偏好靠近水边的地带。在澳大利亚，主要栖息于河岸和季风雨林，也可见于红树林、沙岩露头周围的残存森林、峡谷和沟壑附近的生态过渡带，以及干枯的桉树（Eucalyptus）林地。在新几内亚，常见于森林、花园和次生植被，海拔低至1500米。通常为居民鸟种，偶尔形成假定的伴侣或小家庭群体，有时单独活动。捕食蜘蛛、蟑螂卵囊、甲虫、蝽象、胡蜂和鳞翅目幼虫。在各种高度觅食，偏好在中上层森林中活动。","breeding":"繁殖信息有限，已知在3月至10月期间繁殖。巢由双亲共同建造，呈紧凑的椭圆顶形，有一短“尾巴”和侧面入口，靠近顶部有延伸的短“喷口”。巢由软皮、草和细根编织，内部密集铺垫植物纤维、植物绒毛或羽毛，外部装饰有蜘蛛卵囊或苔藓。悬挂在离地1.8至10米的树枝或藤蔓上，通常接近胡蜂巢和水源附近。一窝产卵2-3枚，蛋壳白色，细小的红棕色斑点集中在较大的一端。孵化可能仅由雌鸟承担，关于孵化和育雏期的持续时间信息缺失。巢穴可能会被小青铜杜鹃寄生。","identification":"通过其独特的灰绿色头部和无尾部斑点与其他细嘴莺科成员区分开来。不同亚种间的辨识主要基于头部颜色的细微差异和下体的黄色调变化。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚和澳大利亚西北部、中北部。在澳大利亚，分布零散但较为普遍；在新几内亚，普遍但分布不均。"},{"name":"白喉噪刺莺","english_name":"White-throated Gerygone","scientific_name":"Gerygone olivacea","overview":"白喉噪刺莺（英文名：White-throated Gerygone，学名：Gerygone olivacea），是雀形目细嘴莺科噪刺莺属的小型鸟类。主要分布在澳大利亚和新几内亚的东南部。其别称包括白喉林莺、白喉食虫鸟、灌丛金丝雀及本土金丝雀。这种鸟上身灰棕色，下体鲜黄色，尾羽有白色斑点，喉部白色，眼红色，嘴和腿黑色。","appearance":"体长9至11.5厘米，体重约7克。成鸟面部暗色，有黑色眉线延伸至眼睛，背部灰棕色略带橄榄色，尾部有宽黑亚端带和大白色边缘的斑点，除中央尾羽外皆有。下体明亮黄色，喉部白色明显。雄雌外观相似。幼鸟下体全黄，面部标记对比不强烈，眉斑黄色，眼和喙呈褐色。各亚种主要在大小、尾斑和喙的大小上有差异。","call":"鸣唱功能用于领地声明和吸引异性，全年都可能发出，春季更频繁，是一系列悦耳的哨音，音调平稳，持续时间较长，类似西噪刺莺但更为响亮和自信。还有一种连续下降的颤音，由双音节引入。在新几内亚，cinerascens亚种的鸣声尤为独特，高音、精致、银色的下降颤音。","habits":"以昆虫为食，猎食多种节肢动物，如甲虫、蝇、蝽，包括树液虫，以及膜翅目的黄蜂、蚂蚁和鳞翅目的蛾类。单独或成对觅食，有时加入混合群，与灰扇尾鹟、棕啸鹟、、西噪刺莺和白喉抚蜜鸟一起活动。在树冠层和地面觅食，经常飞扑和悬停。","breeding":"繁殖季节一般为8月至次年1月，有时3月至5月也有记录，通常单窝繁殖。巢为椭圆形，顶部覆盖，有一侧入口和长细尾，由树皮碎片和蜘蛛网粘合，内部铺有羽毛或细植物纤维，悬挂于树或灌木的外枝上，高度2至12米。巢寄生现象常见，被扇尾杜鹃、灌丛杜鹃和几种青铜杜鹃寄生。","identification":"与黑头噪刺莺相比，白喉噪刺莺色彩更鲜艳，尾部有白色斑点，缺乏雄鸟头部的深色标记。幼鸟与黑头噪刺莺相似，但后者尾部无白色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部和东部，新几内亚东南部。"},{"name":"黑头噪刺莺","english_name":"Fairy Gerygone","scientific_name":"Gerygone palpebrosa","overview":"黑头噪刺莺（英文名：Fairy Gerygone，学名：Gerygone palpebrosa），是雀形目细嘴莺科噪刺莺属的鸟类。曾被称为仙鹟，原生于新几内亚和澳大利亚东北部。其显著特征为橄榄色背部与黄色腹部，雄鸟拥有黑色喉部。分布于亚热带湿润森林与红树林地带。","appearance":"成鸟具橄榄色上体，黄色下体，棕色尾巴，短黑喙与腿，红眼。雄鸟具黑色喉部，雌鸟和幼鸟喉部白色，下体黄色。亚种差异主要体现在头部与胸部颜色深浅。","call":"雄鸟发出响亮悦耳的重复‘whee-chee-choo-too-chee-choo-wee’系列鸣叫，伴有轻柔的叽喳声与颤音，通常在空中追逐时发出。亚种 wahnesi 的叫声类似 Queensland 的 personata 亚种。","habits":"栖息于热带雨林边缘、藤蔓密丛与河岸浓密植被，海拔低至1460米。以昆虫为食，常单独、成对或小群活动，最常见于树冠至地面的中间层。是混合物种群的核心成员，与多种鸟类共栖。","breeding":"繁殖期从10月开始（干季末）在新几内亚，澳大利亚记录到7月至5月。巢由一对或仅雌鸟筑造，呈延长的穹顶状，入口处有防护罩。每窝产1-3枚蛋，通常2枚，由雌鸟孵化，双亲共同喂养雏鸟。","identification":"与灰头噪刺莺区分，具有更鲜明的面部标记，雄鸟有黑色喉部。亚种 wahnesi、inconspicua、tarara、personata 和 flavida 在头部与胸部颜色上有差异。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚和澳大利亚东北部、中东部。在澳大利亚，常见于昆士兰州。","other":"已知会寄生在金鹃和小青铜色拟鹂（棕胸金鹃）的巢中。"},{"name":"伦纳噪刺莺","english_name":"Rennell Gerygone","scientific_name":"Gerygone citrina","overview":"伦纳噪刺莺（英文名：Rennell Gerygone，学名：Gerygone citrina），是雀形目细嘴莺科噪刺莺属的鸟类。小型类似鸣禽的鸟类，仅分布在所罗门群岛南部的伦纳岛（Rennell Island）。曾被认为是扇尾噪刺莺的一个亚种，但在2021年被国际鸟类学家联盟认定为独立物种。其自然栖息地为亚热带或热带湿润山地森林。","appearance":"伦纳噪刺莺拥有细长的黑色喙，灰色的顶冠，白色的喉部，橄榄色的背部，以及黄色的腹部。眼睛淡色，周围有白色的眼眉纹，这些特征使其在小范围内较为独特。","call":"鸣唱简单，由一系列上上下下反复的清脆音符组成。","habits":"广泛分布于多种生境，包括森林边缘和花园。","identification":"与扇尾噪刺莺的区别在于其独特的颜色模式和地理分布。","protection":"IUCN：LC（无危）","distribution":"澳新界：伦纳岛（Rennell，所罗门群岛南部）。"},{"name":"山刺嘴莺","english_name":"Mountain Thornbill","scientific_name":"Acanthiza katherina","overview":"山刺嘴莺（英文名：Mountain Thornbill，学名：Acanthiza katherina），是雀形目细嘴莺科刺嘴莺属的鸟类。小型细嘴莺科刺嘴莺属的鸟类，主要分布在澳大利亚东北部，具体在昆士兰东北部的高山雨林地带，包括约克角半岛山区东南部。","appearance":"山刺嘴莺体型小巧，喙尖细长。其上体呈灰绿色，腹部颜色较淡，胸部有微弱的条纹，前额冠灰色带有隐约的斑点。眼色较浅，与暗色眼的其他物种形成对比。","habits":"山刺嘴莺栖息于中高海拔的热带雨林中，偏好在森林树冠层活动，穿梭于树叶之间觅食。","identification":"与褐噪刺莺相比，山刺嘴莺具有更浅的眼色和缺乏白色尾尖的特点。","distribution":"山刺嘴莺的分布局限于澳大利亚东北部，包括约克角半岛山区东南部，昆士兰东北部的高地，向内陆延伸至Atherton和Windsor Tablelands。"},{"name":"褐刺嘴莺","english_name":"Brown Thornbill","scientific_name":"Acanthiza pusilla","overview":"褐刺嘴莺（英文名：Brown Thornbill，学名：Acanthiza pusilla），是雀形目细嘴莺科刺嘴莺属的鸟类。主要分布在澳大利亚东部和东南部，包括塔斯马尼亚岛。其特征为橄榄褐色至棕色上体，灰褐色下体，带有暗红色眼睛和红褐色前额，以及白色喉部带有黑色条纹。","appearance":"褐刺嘴莺长约9-11.5厘米，重约7克。上体橄榄棕至棕色，额头有淡色的红褐色鳞片状斑点，眼周较浅的灰褐色羽毛突出深色的眼睛。背部有一块红褐色的斑点，尾巴灰棕色，边缘有狭窄的白色边缘（当羽毛新鲜时），黑色次末端带和较浅的灰色尖端。翅膀上的飞羽有精细的淡色边缘（可能形成淡色翼面）。喉咙和下体呈偏白色，逐渐变成奶油色或黄色在腹下和尾下覆羽，侧面被淡黄褐色或淡肉桂色洗涤，从颏到胸有精细的黑色条纹。下尾覆羽灰黑色，带有窄的灰色尖端。虹膜为深红色或红棕色，喙为黑色或灰黑色，有时下颚基部较浅；腿为灰黑色至肉棕色或紫棕色。两性相似。幼鸟与成鸟相似，但标记不那么明显，喙色较浅，虹膜为深棕色至灰棕色或橄榄色（有时为浅灰色），腿部颜色更浅；非常年轻时可能有粉红色的口裂。不同的亚种在喙和/或跗跖测量值以及次要的羽毛细节上有差异。","call":"褐刺嘴莺的鸣叫声多样而悦耳，相当响亮，全年都有听到，尤其是在繁殖季节，声音被描述为“tzzt tzzt too weet et wrrrt”和类似的声音，被认为是该属中最优美的歌声。它经常模仿其他鸟类的叫声，将其混合在自己的歌声中，通常以‘低语歌’的形式发出；被模仿的物种包括东黄鸲鹟、华丽细尾鹩莺、东澳玫瑰鹦鹉、褐短嘴旋木雀、白耳吸蜜鸟、金啸鹟、灰扇尾鹟和暗燕鵙。它还被报道模仿过笼养的金丝雀。叫声包括‘tzzz’，类似于白眉丝刺莺的叫声但不那么刺耳，和其他柔和的‘peep’叫声，非常像褐色丝刺莺和灌丛丝刺莺的叫声；警报声是一种高音的‘seee’，还有各种尖叫和嘟噜声，同时也作为接触信号，以及一种快速重复的‘tzzt-tizz-tchit！’作为接触和/或警报叫声。雏鸟有高音的乞食叫声。","habits":"褐刺嘴莺主要栖息在密集灌木层的生境中，包括湿性和干性的硬叶林森林、再生林、桉树（Eucalyptus）林地、浓密的河岸植被、灌木丛、雨林和荒野。它们的分布范围从海岸和平原到山脉约1200米的高度。它们在新南威尔士州占据着荆棘荒野，在松树（Pinus）种植园中偶尔可以看到，那里有发达的本土或外来植被下层。它们出现在乡村公园和花园中，有时在果园中，也在城市狭长地带的本土植被中。在非繁殖季节，它们也会出现在沿海沙丘灌木丛中。在塔斯马尼亚，冬季主要在山坡上，与塔岛刺嘴莺一起在沟壑中；夏季更多地使用沟壑，但在植被中更高处觅食，从而与后者物种保持一定程度的生态分离。","breeding":"褐刺嘴莺的繁殖期在6月至1月之间，幼鸟出生在8月至1月之间，繁殖周期持续7至11周；有时会双窝繁殖。配对关系长期维持。一对褐刺嘴莺全年维护多功能领地，在筑巢季节期间进行更多的声音广告；通过竖起头部羽毛、下垂翅膀、展开尾巴并露出红褐色臀部来驱赶入侵的雄鸟。雌鸟选择筑巢地点并建造巢穴，巢穴小巧而厚实，顶部呈穹顶状，入口部分有遮盖，由粗草、树皮条、叶子、苔藓、蕨类碎片、羊毛、蜘蛛网和蜘蛛卵囊制成，内部衬有羽毛、毛发、羊毛、毛皮、蕨类毛发和柔软的植物绒毛，有时外饰以茧和金合欢（Acacia）花；巢建在地面或接近地面的地方（503个巢中的78%位于1米以下），大多在小灌木下，或在草丛、苔草和蕨类植物中，常附着在蕨类叶片的下方，或茎或树枝的分叉处，位于树叶和枝条间或落叶堆中，也可在多刺的灌木丛中；在482个巢中，25.9%在草丛中，13.9%在蕨类植物中，9.7%在金合欢中，8.5%在茶树（Leptospermum）或纸皮树（Melaleuca）中；可能在Sericornis citreogularis的旧巢中筑巢；在堪培拉的领地面积约为2公顷，在新南威尔士州为0.25至3.5公顷，其中最小的领地在下层植被最密集的地方。每窝产卵2至4枚，通常为3枚，早上每隔48小时产一枚，卵为白色，略带粉色或淡黄色，有些卵壳上有深色斑点，主要集中在大端的区域；孵化由雌鸟承担，可能在卵完全产出后开始，孵化期为16至20天；卵在24小时内相继孵化，雏鸟由雌鸟密切照顾（坐得非常紧），由两性喂养，育雏期约为16天；在最初的两周里，离巢的雏鸟会一起栖息在茂密的隐蔽处以接受喂养，之后跟随父母，每个父母照顾一到两只幼鸟，或者如果尝试第二次繁殖，则由雄鸟喂养所有幼鸟，幼鸟依赖父母约6周，经常喂养至8周；大多数雌鸟幼鸟会分散，年轻的雄鸟可能会在整个秋季和冬季留在出生地，占据空置的领地或在下一个繁殖季节分散；幼鸟有时会在冬天与父母一起留下，但也可能形成群落。巢穴被扇尾杜鹃、金鹃和霍氏金鹃寄生；有迹象表明，在新南威尔士州的一个地点，扇尾杜鹃到达得太晚，无法寄生主巢，只在替代巢中产卵。在167个巢中的477枚蛋中，226枚（47.4%）孵化，140枚（29.4%）成功孵化出雏鸟，相当于每巢0.83只幼鸟；在巢记录计划中，148个失败的巢中，捕食可能是85个（57.4%）的主要损失原因，遗弃是32个（21.6%）的主要原因，27个（18.2%）被杜鹃寄生。所有雌鸟和大约80%的雄鸟试图在第一年繁殖。环志研究显示，褐刺嘴莺的寿命超过17年5个月。","identification":"褐刺嘴莺与其他细嘴莺科鸟类的辨识要点在于其独特的颜色模式，包括红褐色前额、深红色眼睛、灰色喉咙上的黑色条纹以及红褐色臀部。与塔斯马尼亚刺嘴莺相比，它的尾巴更短，翅膀上有红褐色斑块；内陆刺嘴莺的上体更灰，胸部条纹更多，尾巴更长；条纹刺嘴莺的上体更绿，红褐色头冠上有细白条纹，以及苍白的眼眉。在不同的亚种之间，识别差异主要涉及喙和/或跗跖的测量值以及次要的羽毛细节。","protection":"IUCN：LC（无危）","distribution":"褐刺嘴莺广泛分布于澳大利亚东部和东南部，包括塔斯马尼亚岛。它们的分布范围通常在距离海岸线300公里以内。在澳大利亚首都领地附近观察到了指名亚种A. p. pusilla，在塔斯马尼亚观察到了A. p. diemenensis。"},{"name":"宽尾刺嘴莺","english_name":"Inland Thornbill","scientific_name":"Acanthiza apicalis","overview":"宽尾刺嘴莺（英文名：Inland Thornbill，学名：Acanthiza apicalis），是雀形目细嘴莺科刺嘴莺属的小型鸟类。在澳大利亚被Noongar人称为'Djoobi-Djoolbang'。其特征为细长尖喙，上体灰褐至棕灰色，下体偏白，喉部与胸部有暗色条纹，臀部红褐色，前额有白色斑点，眼深红色。常见于干燥林地和灌木丛，亦可见于较湿润的西南部边缘地带。分布广泛，遍布澳大利亚大陆，除北端和东端以及塔斯马尼亚。","appearance":"宽尾刺嘴莺体型小，长度9至11.5厘米，体重约7克。上体颜色从灰褐色到棕灰色，下体偏白，喉部和胸部有细腻的暗色条纹，臀部呈红褐色。头部前额有明显的白色斑点，眼睛深红或红棕色。尾巴长且常竖起，末端有黑色带状纹，外侧尾羽尖端白色。翅膀有淡色边缘，形成浅色翼斑。下腹灰黑，尾下覆羽灰色。两性相似，幼鸟与成鸟相比，条纹不明显，上体略显棕色，喙较暗，虹膜颜色较浅。","call":"发出音乐般的鸣唱，带有颤音，包含模仿其他鸟类的声音。叫声穿透力强，包括类似红喉刺莺的尖锐叫声，响亮清脆的哨声'chweeip'和尖锐的'tsip-chip'声。在受惊时发出嘈杂的嗡嗡声，同时有细弱的啾啾声作为联络叫声。在觅食时保持轻柔的音乐系列叫声，与混群中的责骂声混合。","habits":"栖息于干燥的林地和硬叶树林，也见于高灌木丛和密集的河岸植被。在西澳大利亚，出现在以Xanthorrhoea preissii和Dryandra sessilis为主的森林和灌木丛，以及有Banksia grandis和Allocasuarina fraseriana的森林。常见于农村公园、花园和农田附近，特别是在国家森林、防护带和道路旁的残余植被中。通常为留鸟，但可能有局部移动，尤其在澳大利亚中部和西部地区。以昆虫为主食，偶尔吃种子，记录的食物包括蜘蛛、甲虫、虫子、蚂蚁、毛虫、黄蜂和其他节肢动物。","breeding":"繁殖季节为7月至12月，主要在9月至11月。筑巢紧凑，圆形或椭圆形，顶部有部分遮盖的侧入口，通常由草、树皮碎片和树枝构成，偶尔加入树叶、苔藓、羊毛、蜘蛛网和蜘蛛卵囊，内衬羽毛、毛发、羊毛、兽毛或柔软的植物绒毛。巢高8.9至10.8厘米，宽约6.5至8.3厘米，入口直径1.9至3.2厘米。巢通常位于地面约1.1米高的低矮灌木中，有时在小树或幼树中，常悬挂在枝干上。一窝产卵2至3枚，通常为3枚，每日一枚，卵色为白色至粉白色，布满深色斑点，孵化期19至21天，雏鸟期16至18天。巢可能被扇尾杜鹃和金鹃寄生。","identification":"与褐刺嘴莺相似，但上体更灰，额头有白色斑点，臀部红褐色对比更鲜明，尾巴更长且经常竖起，有明显的黑色尾带和白色尾尖。与Chestnut-rumped和Buff-rumped thornbills的区别在于后者有浅色眼睛，胸部无条纹，尾巴大多黑色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚内陆及西南部，除北部、东部地区和塔斯马尼亚岛外，广泛存在于澳大利亚大陆的干旱和半干旱地带。","other":"长寿命，有记录显示至少能活11年10个月。"},{"name":"塔岛刺嘴莺","english_name":"Tasmanian Thornbill","scientific_name":"Acanthiza ewingii","overview":"塔岛刺嘴莺（英文名：Tasmanian Thornbill，学名：Acanthiza ewingii），是雀形目细嘴莺科刺嘴莺属的鸟类。澳大利亚东南部塔斯马尼亚州特有的小型鸟类。在塔斯马尼亚和巴斯海峡岛屿上常见，偏好居住在较冷湿的森林地带。","appearance":"塔岛刺嘴莺上体橄榄褐色，背部和尾部颜色加深，额头可见红褐色斑块。翅膀呈深灰色，边缘为橄榄褐色。下巴至胸部有灰色与淡灰色的鳞状纹饰，头部两侧也有类似纹饰。喙、脚和腿均为深灰色，眼睛大而黑，虹膜红色。下尾覆羽明显白色，喙长而尖，形状似刺，平均体长约10厘米，两性色彩和大小相似。","call":"具有细嘴莺科典型的颤音鸣唱风格，其主要叫声被描述为连续的'zit zit zit'声。","habits":"栖息于塔斯马尼亚的雨林、湿润森林和灌木丛，偏好密集的灌木丛和湿润的峡谷环境。主要以昆虫为食，偶尔食用种子和果实，会在树冠到地面的不同层次觅食。","breeding":"繁殖季节通常从九月持续到一月，会筑造小型圆顶巢，位于低矮浓密的植被中。巢由草、绿苔藓和细树皮条构成，入口处有可活动的盖板。每窝产3至4枚蛋，蛋色从淡白底带大量棕色斑点到棕色或青铜色带小点，具体孵化期和幼鸟独立时间未知。","identification":"与褐刺嘴莺相比，塔岛刺嘴莺拥有更长的尾巴、更灰的侧腹和红褐色而非浅色的翼片。两者在外观和行为上极为相似，容易混淆。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚塔斯马尼亚州及其附近的巴斯海峡岛屿。"},{"name":"巴布亚刺嘴莺","english_name":"New Guinea Thornbill","scientific_name":"Acanthiza murina","overview":"巴布亚刺嘴莺（英文名：New Guinea Thornbill，学名：Acanthiza murina），是雀形目细嘴莺科刺嘴莺属的鸟类。拥有暗褐色的上身、灰白的腹部和带有黄晕的头部、颈部与上胸部，最显著的特点是白色的眼睛和较短的喙。主要分布于新几内亚山区的中高海拔森林。","appearance":"这种小鸟体长9-10厘米，头与背部呈橄榄褐色，前额有模糊的浅色斑点，脸颊与喉侧有盐胡椒状的斑驳。眼圈白色，喙部黑色或深棕色，下颌基部颜色较浅，腿色变化较大，有时脚底带有黄色。两性外观相似，幼鸟描述未知。","call":"发出一系列音符对，首音比第二音更高，常在觅食时持续发出类似'见提托托'的尖锐、略带粗糙但悦耳的声音，间杂着更刺耳的斥责声和颤音。","habits":"巴布亚刺嘴莺栖息于新几内亚山脉的高海拔森林及其边缘地带，偶尔低至约1930米，常见于海拔2500米以上直至林线。以昆虫为主食，偶尔访问开花树木，可能为了昆虫或花蜜。它在3-10只的小群中活跃觅食，有时与或Sericornis papuensis结伴，从树冠到约4-5米的高度都有它们的身影。","breeding":"繁殖信息知之甚少。巢呈圆顶状，侧面有入口，位于森林中的树上。十月时，两只幼鸟由三只成鸟喂养，暗示可能存在合作养育的策略。除此之外，无更多信息。","identification":"与褐胸噪刺莺相似，但巴布亚刺嘴莺在较高海拔更为常见，且避免开阔生境。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的中西部山区至东南部，常见于中央巴布亚山脉的特定区域。"},{"name":"栗尾刺嘴莺","english_name":"Chestnut-rumped Thornbill","scientific_name":"Acanthiza uropygialis","overview":"栗尾刺嘴莺（英文名：Chestnut-rumped Thornbill，学名：Acanthiza uropygialis），是雀形目细嘴莺科刺嘴莺属的鸟类。小型雀形目鸟类，以其独特的淡栗色臀部命名，广泛分布于澳大利亚内陆，西至西澳大利亚内陆西部，南至昆士兰东南部和维多利亚州北部。体长约9.8厘米，重约6克，属于国家保护动物。","appearance":"中等体型，上体呈灰褐色至棕灰色，具明显的白色鳞状斑纹于深棕色额部；头部侧面和耳羽处带有斑驳的近白色；臀部为鲜明的栗褐色，与上体形成强烈对比；尾巴主要是黑色，尖端带窄的灰白边；翅膀的翼盖有不明显的浅褐色或乳白色翼条；下体大部分为未标记的近白色，有时胸侧或颏喉部略显淡灰色；腹部泛淡黄褐色。虹膜奶油色或近乎白色；喙黑色，有时下颌基部略显淡灰色；腿黑或灰黑色。幼鸟与成鸟相似，但头部图案较暗淡，尾尖为淡黄褐色，虹膜略暗。","call":"典型的叫声为非常尖锐而快速的叽喳声，间歇着缓慢、高音的'seeeep seeeep'声。","habits":"栖息于干燥的林地和灌木丛，特别是在马利灌木林、三蕊草、艾瑞莫菲拉和卡西亚等植被环境，以及多加灌木林下的盐碱草丛。亦可见于河流、湖泊和湿地周围的茂密河岸植被。能够适应次生环境，如牛牧场、防火线和路边残余地带，只要存在足够的低矮遮蔽。通常为留鸟，但在局部地区有报道移动距离可达约2.5公里。夏季记录率较低可能由于炎热天气、观察活动减少和物种行为更加隐蔽。","breeding":"繁殖季节为6月至12月，产卵期从7月至12月。每窝产卵2至4枚，通常为3枚，间隔两天产一枚。卵呈肉白色，细小点状散布深色斑点，大端形成帽状。孵化期约为19天；双亲共同喂养雏鸟，雏鸟期约18至20天。家庭成员在繁殖后一段时间内保持在一起，幼鸟随后在夏末和秋季分散，以两到三只为一群移动。巢穴可能被霍斯菲尔德铜色杜鹃寄生。","identification":"与其它细嘴莺科鸟类相比，如宽尾刺嘴莺和蓝灰刺嘴莺，栗尾刺嘴莺具有更明显和鲜艳的栗色臀部，以及不同的叫声。幼鸟与成鸟相比，头纹更暗淡，尾尖颜色为淡黄褐色。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界：西澳大利亚内陆西部，西南部至昆士兰东南部和维多利亚州北部（中西部至澳大利亚中南部）。在内陆和半干旱区域广泛分布，但远离最极端的沙漠区域。","other":"该物种在一些地区因栖息地丧失而数量下降，尤其是在西澳大利亚小麦带的道路边缘残留植被遭到破坏，导致当地数量减少。"},{"name":"棕尾刺嘴莺","english_name":"Buff-rumped Thornbill","scientific_name":"Acanthiza reguloides","overview":"棕尾刺嘴莺（英文名：Buff-rumped Thornbill，学名：Acanthiza reguloides），是雀形目细嘴莺科刺嘴莺属的鸟类。分布于澳大利亚东部至东南部。以灰橄榄色的上体和淡黄色的下体为特征，最明显的标志是其橙棕色的臀部。该鸟种长8-10厘米，具有白色的虹膜，成鸟与幼鸟在眼色上有明显差异。","appearance":"棕尾刺嘴莺体长9.5-11厘米，重约8克。它拥有一张略显厚实、基部较深的尖喙。头部顶部和侧面呈灰橄榄色，前额带有丰富的淡褐色浸染，细小的奶油色斑点散布其间。眼睛周围有淡色的眉纹，头顶至颈部橄榄棕色，尾巴黑色带有狭窄的淡灰色尖端。翅膀橄榄棕色，覆羽和次级飞羽边缘浅色。下巴、喉咙和上胸白色或奶油色，下胸至腹部均匀的淡黄色。幼鸟额头斑点不明显，上体颜色偏棕色，胸部无斑点。","call":"全年鸣叫，但时常安静。其歌声为快速交替的两个音符组成的清脆颤音，比的歌声更硬更高。觅食群会发出细高音的啾啾声。雏鸟以持续的嗡嗡声乞食。","habits":"栖息于开阔的桉树森林和林地，偏好有草和灌木的稀疏下层植被。也可见于柏松、按树、金合欢或混合有按树、Banksia和茶树的灌木丛中。活动范围从海岸到高亚高山地区，通常在山脚下，避开植被茂密的沟壑。","breeding":"繁殖季节为7月至次年2月。以单对或合作群体形式繁殖，巢由单一个体（可能为雌鸟）建造，是一个卵形、大而圆顶的结构，侧入口带小檐，由树皮条、干草和苔藓构成，用蛛网和蜘蛛卵囊粘合，内部铺垫羽毛、毛发或植物绒毛。巢通常建在树叉、树干裂隙、地面的土堤或草丛中。每窝产卵2-4枚，平均孵化期16-21天，雏鸟喂养期16-19天。","identification":"与其他Acanthiza属鸟类相比，棕尾刺嘴莺的上体颜色、下体色调和臀部色彩较为独特。不同亚种在羽色深浅、头部颜色和下体亮度上有所差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从昆士兰州的Chinchilla向西至新南威尔士州的Cobar，跨过维多利亚州和南澳大利亚州的东南部。","other":"城市化和栖息地改造导致部分地区数量下降。"},{"name":"西刺嘴莺","english_name":"Western Thornbill","scientific_name":"Acanthiza inornata","overview":"西刺嘴莺（英文名：Western Thornbill，学名：Acanthiza inornata），是雀形目细嘴莺科刺嘴莺属的鸟类。分布于澳大利亚西南部的桉树林和灌木丛中。其主要特征为灰色至灰褐色的上体，淡色腹部，具有独特的淡色眼睛和温暖的棕色前额。该鸟种常见于西澳大利亚的森林地带。","appearance":"西刺嘴莺体型小，长度约8至10.5厘米，体重约7克。整体呈均匀的灰褐色，尾部颜色一致，腹部颜色较浅。头部有细微的奶油色鳞状斑纹，耳羽有细小的奶油色条纹和斑点。上体橄榄棕色，尾羽基部和覆尾羽略带暖色调。翼羽边缘白色，形成明显的白色翼斑。虹膜奶油色，喙黑色或暗褐色，有时下喙基部较浅。腿黑色或深棕灰色。雌雄相似，幼鸟背部颜色更偏棕色，鳞状斑纹不明显。","call":"其叫声被描述为‘pitta-pitta-pitta’，类似细嘴莺科其他物种的声音，但音调更为恒定。也发出快速清脆的‘twee twee twee twee twee’声，以及‘twitchee twitchee twitchee’的旋律声，偶尔夹杂颤音。据报道，它能模仿西方鹦鹉、灰扇尾鹟和灰鸦鹃的声音，但这种模仿行为较为罕见。","habits":"西刺嘴莺主要以昆虫为食，包括甲虫、蝽象、黄蜂、蚂蚁和鳞翅目幼虫，偶尔也摄取花蜜。它们通常成对出现，偶尔单独或以3至5只的小家庭群活动，有时会聚集到20只的大群体中。它们会加入混合物种的群体，与金冠细嘴莺、顶冠细嘴莺和灰扇尾鹟共同活动。它们在低矮的灌木和树木中觅食，甚至可达树冠层，也经常在地面觅食，冬季时地面觅食可能更加频繁。","breeding":"繁殖季节一般在8月至2月，偶尔从7月中旬开始。以一对繁殖，有时由三至四只个体共同照料一个巢。巢呈椭圆形，顶部有侧入口，由干草、树枝、植物茎、根须、树皮碎片、植物绒毛、干叶或花朵等材料构成，用蜘蛛网粘合，内部铺有羽毛、毛发或植物绒毛。巢高0.6至13米，平均高度4.7米，位于树或大灌木上，包括桉树、马里树、金合欢、班克斯亚树和草树。每次产卵3枚，间隔两天，蛋壳白色至粉白色，带有深色斑点。雌鸟负责孵化，孵化期为18至21天。雏鸟由双亲喂养，离巢期为17至19天。巢穴可能被霍斯菲尔德铜绿鹃和闪光铜绿鹃寄生。","identification":"西刺嘴莺与其他细嘴莺科成员的区别在于其单调的色彩、没有明显的臀部斑块以及淡色的眼睛。幼鸟与成鸟相比，背部颜色更深，鳞状斑纹不明显。","protection":"IUCN：LC（无危）","distribution":"西刺嘴莺主要分布于西澳大利亚南部，北至希尔河和穆拉地区，东至斯特林山脉。栖息于温多伍德林地、加里树和玛丽树森林，以及洪水桉树森林、河岸植被、灌木丛和混合林地。从沿海平原延伸至低丘陵。"},{"name":"细嘴刺嘴莺","english_name":"Slender-billed Thornbill","scientific_name":"Acanthiza iredalei","overview":"细嘴刺嘴莺（英文名：Slender-billed Thornbill，学名：Acanthiza iredalei），是雀形目细嘴莺科刺嘴莺属的小型鸟类，分布于澳大利亚中西部至中南部。拥有细长尖喙，常栖息于沿海沼泽、灌木丛及盐湖周边环境，以昆虫为主食。","appearance":"体长8.5至11厘米，体重约6克。头部橄榄灰至橄榄棕色，上体具鲜明的奶油色或淡黄色覆羽；尾巴黑色，边缘微白，末端浅灰色；翅膀深棕色，边缘略呈白色；耳羽奶油色，带有橄榄灰色斑点；腹部奶油色，胸部有细微暗色斑点；腿黑色或灰黑色。雌雄相似，幼鸟额头斑纹较暗淡，翼上有窄棕色条纹。","call":"发出波动的‘preeur’颤音，持续数秒，不常见；常见的联系叫声为快速高音的‘tsit tsit tsit’，有时以低沉的‘chur-wee’双音节声开头。","habits":"居住在咸草灌木地、蓝灌木丛、盐碱灌木地和硬叶灌木丛中，分布于海岸到半干旱和干旱内陆区域。成群或成对活动，主要在低矮灌木和地面觅食，食物包括各种无脊椎动物和少量种子。","breeding":"繁殖季节为7月至11月，通常以一对形式繁殖，偶尔有合作繁殖现象。巢由草、树皮、软茎植物构成，内部铺垫羽毛、毛发和植物绒毛，位于低矮灌木中，离地高度5厘米至2.5米。每窝产卵2至4枚，通常3枚，白色带淡褐色或粉红褐色斑点。","identification":"与棕尾刺嘴莺相比，具有更细的喙、额部鳞片更明显、臀部和下体颜色更淡，腿黑色。rosinae亚种比其他亚种嘴更长，颜色更深。","protection":"IUCN：LC（无危）；但rosinae亚种被列为‘Vulnerable’（易危），hedleyi亚种被列为‘Near-threatened’（近危）。","distribution":"分布于澳大利亚中西部至中南部，包括多个隔离的群体，hedleyi亚种见于南澳大利亚东南部和维多利亚西部，rosinae亚种常见于南澳大利亚Gulf St Vincent地区。","other":"细嘴刺嘴莺适应于包含成熟和烧过区域的生境马赛克，hedleyi亚种在Ngarkat Conservation Park的管理建议为提供烧过的生境马赛克，以利于其保护。"},{"name":"黄尾刺嘴莺","english_name":"Yellow-rumped Thornbill","scientific_name":"Acanthiza chrysorrhoa","appearance":"黄尾刺嘴莺体型小，长度在9.5至12厘米之间，体重约9克。其特征为黑色额部点缀白色，灰褐色头部渐变为颈侧较淡，喉咙处呈奶油色。眼上有一条宽阔的白色眉纹，延伸至眼角上方，形成一条狭窄的浅色带，末端逐渐变细。耳羽呈偏白色，带有暗色斑点。上体灰褐色，尾上覆羽及尾基部黄色，与主要黑色的尾巴形成鲜明对比，尾尖有窄的偏白色边缘。翅膀灰褐色，黑色翼尖，深棕色初级飞羽覆羽和三级飞羽中心，三级飞羽边缘偏白，次级飞羽有细的偏白色边缘。下体偏白色，胸部可能有淡黄色浸染，两胁呈黄褐色。幼鸟较成鸟斑纹不明显，头部斑点为暗淡的棕褐色，大覆羽的淡色边缘可能形成狭窄的翼带。成鸟雌雄外观相似。","call":"黄尾刺嘴莺的鸣唱独特，为清脆、悦耳、高音且略带嘶声的连续颤音系列，有时以强调的“swit”结尾，通常在觅食时发出，似乎作为联系信号。据报道，该鸟种是出色的模仿者，能模仿黑额矿吸蜜鸟的警告叫声和其他鸟种的叫声。","habits":"黄尾刺嘴莺栖息于各种开放环境，包括桉树（Eucalyptus）林地和森林的下层植被、灌木丛、金合欢（Acacia）灌木地、Banksia林地和草原。常见于半开垦的牧场、城市公园、花园、路边和轻度林木覆盖的水道残迹，也在异域Monterey松（Pinus radiata）种植园中被记录到。主要生活在低海拔地区，高达800米，在维多利亚州则低于400米。强烈倾向于地面活动，出现在地面和灌木层；在较密的生境中，更常出现在开阔草地或边缘。以昆虫为主食，也吃种子，主要猎物包括蚂蚁、甲虫、蝽、蚜虫、苍蝇、蟋蟀、胡蜂、鳞翅目幼虫和蜘蛛，也吃Chenopodium album的种子。群居觅食，通常3至12只组成一群，有时多达30只。行为类似小型的鹨（Anthus），在开阔地带行走于地面。75%至85%的时间在地面觅食，其余时间在灌木层活动；偶尔上升至次冠层，但很少超过10米。从裸露地面、落叶层、草丛和倒木中觅食。在叶面、树皮下、树枝上觅食，有时从花朵中觅食；偶尔追逐猎物，观察到在捕食苍蝇时悬停。是混合物种群体的核心成员，常与同属的宽尾刺嘴莺和栗尾刺嘴莺一同在地面活动；在这样的群体中还记录到黑白扇尾鹟、灰扇尾鹟、红喉刺莺、斑刺莺、纵纹刺嘴莺、棕尾刺嘴莺、小刺嘴莺、褐阔嘴莺、斑纹白脸刺莺、棕啸鹟、Petroica robin、华丽细尾鹩莺、纹翅食蜜鸟、Singing Gavicalis virescens和褐岩吸蜜鸟。","breeding":"繁殖记录全年皆有，遍布广大范围；在西澳大利亚除2月和3月外，塔斯马尼亚在7月至12月；通常每年育雏两次，但最高纪录可达四次。以配对形式繁殖，偶尔与1至3个帮手合作。单独筑巢，有时巢间距不超过100米。巢由双方共同建造，若有帮手也会协助，一周内完成，有时会延长至2至4周。巢是一个体积较大且不整齐的穹顶结构，侧面有入口，由干草、树皮纤维、植物茎、叶片和根须构成，用蛛网和/或羊毛粘结，外表附有苔藓、地衣、蜘蛛卵囊或卫生纸，内部铺垫细草、毛发、头发、羽毛和植物绒毛，尺寸变化大，长度18至30厘米（随材料增加可能变得更大），雄鸟在雌鸟孵卵时继续筑巢，甚至在喂养幼鸟时（通常有帮手）也会持续修建。巢在寒冷天气时可能具有良好的保温性能，结构会在炎热季节变得松散；有时在主巢顶部或侧面建有一个或多个杯状、穹顶或部分穹顶的“假巢”，用于重筑巢穴（因此可能形成多达五个此类巢的集群），假巢的功能不确定，包括为帮手提供筑巢练习、欺骗捕食者或杜鹃（Cuculidae）、作为雄鸟或幼鸟离巢后的栖息地，或是雄鸟过度筑巢冲动的结果；巢位于树、灌木、藤蔓、草树或槲寄生（Loranthaceae）的垂枝密集叶丛中，使用本土和外来植物，尤其是桉树（32%的365个巢穴记录）、金合欢（14%）、松树（10%）和Casuarina（7%），奇特的巢址包括旧桶、猪舍、稻草堆、路堤边的洞穴，以及地面60厘米高的枯叶簇；有时建在猛禽或鸦科鸟的棍状巢下（罕见情况下在巢内），也使用Australasian babbler、butcherbird或currawong的巢；能在斑胸草雀的殖民地中繁殖，可能接管并改造该物种的旧巢，也记录到在communal spider巢旁以相同方式筑巢，如同棕尾刺嘴莺一样；有时重复使用巢穴，同一地点可能连续多年使用。每窝产2至5枚卵，通常3至4枚，间隔48小时产一枚，纯白色至淡粉色，有时在大端有红色或红棕色斑点；仅由雌鸟孵卵，孵化期通常为16至18天；大多数卵在同一天孵化，幼鸟由双亲和任何在场的帮手喂养，育雏期为17至21天。巢穴会被扇尾杜鹃、金鹃和霍氏金鹃寄生，例如在一个地点，四年间135个巢中有35个（26%）被Shining Bronze-Cuckoos寄生；寄生巢可能会被封死和弃置，或在旧巢上重建新巢。在333个巢中的1056枚卵中，586枚孵化（55.5%），385枚（33.9%）产生离巢幼鸟，相当于每个巢平均1.07只幼鸟；捕食率高，一些研究中约为58%，捕食者包括鸦科、currawongs、Australasian babblers、红垂蜜鸟和澳洲钟鹊；此外，honeyeaters可能摧毁巢穴以获取筑巢材料，灰胸绣眼鸟和其他同类物种也可能这样做。环志研究表明，该鸟种的寿命可超过9年零6个月。","identification":"黄尾刺嘴莺与同属其他种类的区别在于其更大的体型、黄色臀部和黑色额部的特征性斑纹。与宽尾刺嘴莺和栗尾刺嘴莺相比，黄尾刺嘴莺的头部斑纹更为明显，且体形较大。不同亚种间的辨识差异主要体现在羽毛色调上：leighi亚种比指名亚种颜色更深，上体更橄榄色，尾上覆羽更亮黄，下体更偏黄色；normantoni亚种像leighi亚种但跗跖较长，颈背浅灰色带深色斑点，上体较浅，臀部更亮橄榄色，尾上覆羽更亮黄，下体大多明亮淡黄色，有时上胸有暗色斑点；leachi亚种是最大的亚种，上体颜色比其他亚种更深的橄榄褐色，下体与指名亚种相似。","protection":"IUCN：LC（无危）","distribution":"黄尾刺嘴莺广泛分布于澳大利亚大陆（除北部）和塔斯马尼亚岛，包括西澳、南澳、东澳，但不在北澳的北部海岸、昆士兰北部和北领地中部及北部地区。","other":"黄尾刺嘴莺已经适应了被改变的栖息地，但在澳大利亚主要城市如阿德莱德、悉尼和墨尔本周边地区，由于栖息地丧失和退化以及捕食水平的增加，其数量有所下降；同样，西南西澳大利亚小麦带的种群也已减少。然而，总体而言，该物种的未来似乎至少在中期内是安全的。"},{"name":"小刺嘴莺","english_name":"Yellow Thornbill","scientific_name":"Acanthiza nana","overview":"小刺嘴莺（英文名：Yellow Thornbill，学名：Acanthiza nana），是雀形目细嘴莺科刺嘴莺属的鸟类。体型小巧，主要分布在澳大利亚东部，包括澳大利亚本土和新西兰，尤其在塔斯马尼亚及其附近岛屿可见。以黄绿色为主色调，上体呈橄榄褐色，下体黄色鲜明，脸颊有深色条纹，额头无花纹，与近似种有明显区别。生活在开放森林和灌木地带，偏好卡苏里纳、松柏、金合欢、纸皮树和桉树环境。","appearance":"体长8.5至10厘米，体重6至7克。具有尖锐的喙，头部至颈背橄榄至淡黄橄榄色，眼周淡色，有狭窄的淡色眼环，耳羽密集的黄褐色刷状条纹，有时有黄褐色眉纹。背部橄榄色，臀部略亮，尾上覆羽更黄，尾羽棕色边缘黄，具宽黑色亚端斑和橄榄色尖端。翼覆羽黄橄榄色，外侧大覆羽有时白尖，主翼羽有细淡色缘形成浅色翼斑。下巴、喉部和颊区淡橙色，下体黄色至鲜黄橄榄色，胸侧有淡黄橄榄色洗染，尾下覆羽黄色；尾下棕色带宽黑色亚端斑。虹膜暗棕至红棕色，喙和腿黑色。幼鸟比成鸟颜色暗淡，背部更偏褐色，下体颜色较淡。不同亚种在细节上有所差异。","call":"发出重复的双音节‘tzid-id’或‘tzid-id, tiz-tiz’，声音不如昆虫般，更接近的叫声，全天候重复，可能是联系叫声，也可能用于领地宣示或防御。","habits":"栖息于开放森林和干燥林地的灌木丛，以蚂蚁、黄蜂、甲虫、蝽象、蚜虫、蝇、蟋蟀、鳞翅目昆虫、蟑螂、蜘蛛等小型无脊椎动物为食，偶尔吃种子。通常3至5只小群活动，有时多达10只，曾记录到最多35只的群体，也会单独或成对出现。几乎完全在树上活动，很少落地，主要在树冠层觅食，利用各种树木和灌木，秋季和冬季似乎在较低层次觅食，春季和夏季较高。","breeding":"繁殖季节从7月至翌年3月，可能连续繁殖两次。以独对形式繁殖，有时有帮手参与筑巢。巢由两性共同建造，呈圆形或近球形，顶部有窄入口，由薄树皮条、纤维、细草、蜘蛛网装饰，内部铺有干草、羽毛、毛发、羊毛或种子荚白色丝绒，外部可能大量覆盖树皮条或绿苔藓。巢位于树枝上的薄叶枝条或树叶中，高度2至12米，平均6.6米。每窝产卵3至4枚，有时2枚，卵白色，带有暗色斑点，孵化期估计为16至17天，幼鸟由父母喂养，若有帮手也会参与。巢可能被金鹃和霍氏金鹃寄生。","identification":"与褐阔嘴莺相比，体型更大，喙更细且往往颜色更深。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚东部，包括北部和中部西部昆士兰州，南至澳大利亚东部海岸，贯穿新南威尔士州大部分地区，遍及维多利亚州和澳大利亚首都特区，进入南澳大利亚东南角。","other":"虽然目前全球状态评估为无危，但观察到其种群数量正在减少。远北昆士兰的flava亚种知之甚少，且分布范围相对有限。在部分地区，因栖息地退化和城市扩张面临局部威胁。"},{"name":"新几内亚刺嘴莺","english_name":"Grey Thornbill","scientific_name":"Acanthiza cinerea","overview":"新几内亚刺嘴莺（英文名：Grey Thornbill，学名：Acanthiza cinerea），是雀形目细嘴莺科刺嘴莺属的鸟类。这体型微小的山地森林鸟类，以中灰色的上部和洁净的白色下部为显著特征，拥有黑色的喙和深色的眼睛。主要分布于新几内亚高地的山地森林中。","appearance":"新几内亚刺嘴莺身长约为9厘米，体羽呈现灰烬般的浅灰色，上翼和尾巴略带棕色，尾部有不明显的黑褐色次端斑。其腹部洁白，胸部和两侧带有淡淡的灰色调。眼睛呈深棕色，喙部暗灰色，腿部为灰色。成鸟与幼鸟在外观上相似，不过幼鸟下颌基部有黄色。","call":"鸣唱为一系列高音、滑音式的下降音符，与褐胸噪刺莺的鸣声极为相似。叫声为尖锐的连续‘tee tee tee’或‘tee ta tee’，还有类似Myzomela honeyeater的训斥声‘zznt zznt’。","habits":"栖息于海拔2000米至树线附近的上部山地森林及边缘地带，偶尔降至1600米，极少数情况下低至1000米。以昆虫为食，通常结成2至10只的小群，与Sericornis属的scrubwrens及睦扇尾鹟一同觅食。活动于中层至树冠，常悬停捕食昆虫，有时沿林缘低飞。","breeding":"关于繁殖习性的信息尚无报道。","identification":"与Papuan Thornbill和褐胸噪刺莺相似，但新几内亚刺嘴莺上部明显更灰，下部更白，且尾部无白色斑点。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的Vogelkop（Arfak山脉）及中部、东部和东南部山脉；可能也出现在Foja山脉。"},{"name":"纵纹刺嘴莺","english_name":"Striated Thornbill","scientific_name":"Acanthiza lineata","overview":"纵纹刺嘴莺（英文名：Striated Thornbill，学名：Acanthiza lineata），是雀形目细嘴莺科刺嘴莺属的鸟类。小型细嘴莺科刺嘴莺属鸟类，广泛分布在澳大利亚东部和东南部，包括塔斯马尼亚岛。其显著特征包括绿褐色上体、淡黄色橄榄色的侧面和红棕色的头冠，以及明显的暗色条纹贯穿喉部和胸部。主要栖息于桉树森林和其它林地，以昆虫为食。","appearance":"纵纹刺嘴莺体型小巧，长度约9至11厘米，体重仅7克。成鸟的头部顶部呈棕褐色，向下渐变为较淡的颈部颜色，头侧和颈背有密集的白色条纹。上体呈暗绿色橄榄色，逐渐过渡到棕色的尾羽覆羽。尾羽上方橄榄棕色，有黑色次端带，尾羽有黄边，最外侧尾羽边缘白色。翅膀基部的外侧主羽边缘为淡橄榄黄色。下体白色，喉部有黑色条纹，胸部白色，向侧面逐渐变为淡黄色，有黑色条纹，腹部和臀部白色或淡黄色，有时上腹部有模糊的黑色条纹，两侧灰橄榄色，后部逐渐变为黄棕色。下尾羽淡黄褐色，有窄的深色次端带。虹膜棕色或灰棕色，喙深灰色至黑色，下颌基部较浅。两性相似，幼鸟比成鸟更暗淡，条纹不明显。不同亚种之间存在细微的差异。","call":"纵纹刺嘴莺发出持续的尖锐高音‘tiziz-tiziz’声，类似昆虫的叫声，当觅食时不断发出。还会有单独的‘zit’或‘zip’声，有时重复单调。群鸟准备飞离时会发出快速的啁啾声。据报道，它的歌声美妙、短暂而甜美；春天还会发出安静的极高音颤音。","habits":"纵纹刺嘴莺主要栖息于桉树（Eucalyptus）森林和有良好灌木层的林地，包括灌木丛和河岸植被，偶尔出现在雨林和茂密灌丛中。它们在农田、散落的桉树和残留植被中活动，甚至在郊区花园中也能见到，但需要成熟的植被环境。通常避免异域松树林。它们在东南部新南威尔士州的雪山区海拔1530米以上时，可能会因积雪而迁移到较低海拔的Brindabella山脉附近，冬季可能成为昆士兰南部的部分访客，干旱时也会离开受影响地区。它们以蜘蛛、昆虫幼虫、甲虫、苍蝇、蝽、勒普斯、蚂蚁、黄蜂和其他节肢动物为食，偶尔食用种子和花蜜。它们通常成群活动，群体规模可达20只以上，但在繁殖季节分散成对或小群体。在觅食时，它们会攀爬到亚冠层和树冠的高处，但在秋季和冬季可能在某些区域降低觅食高度，这可能与山桉的开花有关，吸引昆虫或提供花蜜。","breeding":"纵纹刺嘴莺的繁殖季节为6月至3月，产卵期为6月至12月，可能偶尔双窝繁殖。以简单配对或三至四只个体的协作群繁殖，群规模可增至4至8只，可能包括已出巢的幼鸟。群似乎每年在同一领地繁殖，对蜂蜜鸟（Meliphagidae）的攻击性互动很常见，包括对红垂蜜鸟的防御和对半殖民地蜂蜜鸟如贝尔和黑额矿吸蜜鸟、黄翅灰吸蜜鸟和白颈抚蜜鸟的防御，后者可能试图长时间排除本物种，可能是为了保护食物资源。巢由双方共同建造，助手的角色不确定，巢呈椭圆形或梨形，顶部有部分遮蔽的侧面入口，由树皮碎片与细草交织而成，内部用柔软的内树皮纤维制成，衬有羽毛、毛发、头发或植物绒毛，外部常使用白色材料如线、白色树皮、羊毛、纸巾。巢放置于树、灌木或树苗的外枝叶中，高度通常在3至6米以上。每两天产一枚蛋，粉白色至淡奶油色，有暗斑和条纹，形成较大的一端的区域。孵化仅由雌鸟完成，孵化期11至17天；雏鸟由双方父母和任何在场的助手喂养，巢期18至20天；所有群体成员都会喂养幼鸟，直到下一个繁殖季节。巢穴可能被扇尾杜鹃、金鹃和霍氏金鹃寄生。在82个巢中的238枚蛋中，109枚（45.8%）孵化成功，62枚（26%）产生出巢鸟，相当于每巢0.76只幼鸟；协作群往往比简单配对具有更高的繁殖成功率。环志研究表明，寿命可达15年7个月以上。","identification":"纵纹刺嘴莺与褐刺嘴莺相似，但褐刺嘴莺缺乏白色条纹的橙棕色帽，且生活在灌木中。可以通过头部的颜色和条纹的定义程度进行区分。","protection":"IUCN：LC（无危）","distribution":"纵纹刺嘴莺分布于澳大利亚东部和东南部，包括塔斯马尼亚岛，以及澳大利亚和新西兰的相邻岛屿。","other":"纵纹刺嘴莺在冬季以7至20只鸟的小群活动，繁殖季节前会分解为2至4只的小组，包括繁殖对和辅助鸟。"},{"name":"蓝灰刺嘴莺","english_name":"Slaty-backed Thornbill","scientific_name":"Acanthiza robustirostris","overview":"蓝灰刺嘴莺（英文名：Slaty-backed Thornbill，学名：Acanthiza robustirostris），是雀形目细嘴莺科刺嘴莺属的鸟类。其主要特征为体型较小，拥有细长尖锐的喙，上体呈蓝灰色，下体为奶油色，头部有深色条纹，眼周暗色，尾羽尖端淡色，臀部栗色，飞行时尤为显眼。常见于澳大利亚干旱内陆的mulga林地。","appearance":"蓝灰刺嘴莺身长9.5至11.5厘米，体重约6克。其体羽上部蓝灰色，前额和头顶有细微的黑色条纹，眼先狭窄的暗色带，眼环白色，耳羽边缘有细白点。上尾覆羽和尾基部为赤褐色，与蓝灰色上体和黑色主尾形成鲜明对比。初级飞羽覆羽、三级飞羽中心和小翼羽较暗，大翼羽尖端的白色形成窄翼带，三级飞羽有显著的白色边缘，飞羽边缘白色。下体白色，有时颏喉部呈浅灰色，胸部侧边为淡棕色，逐渐过渡到腹部的淡黄色。尾下覆羽为灰黑色，尖端明显为灰白色。虹膜为深红色或红棕色，喙和腿均为黑色或灰黑色。雌雄相似，幼鸟类似成鸟，但冠羽偏棕色，无眼环，三级飞羽边缘较钝，翼带为棕色，眼睛为棕色。","call":"其典型叫声包括薄脆的叽叽声和清晰的连续颤音。","habits":"蓝灰刺嘴莺主要栖息于mulga（Acacia aneura）林地，下层植被为emu-bush（Eremophila），分布于沙平原、岩石区和干旱半干旱地带的低山丘。它们通常成对或单独出现，偶尔会组成小群，多达八只，可能为家庭群体。它们主要以昆虫为食，常在低矮灌木和树木的外层叶子中觅食，偶尔在地面活动。在觅食时，它们非常活跃，通过啄食为主，偶尔也会飞扑和悬停。","breeding":"繁殖季节为7月至11月，有时会二次繁殖。据报道，它们成对繁殖，但繁殖行为知之甚少。雌鸟筑巢，巢为小型松散球状，侧面入口略带罩状，屋顶呈尖顶，巢壁和屋顶薄而脆弱，但巢杯紧密编织。巢由干草和小枝条构成，用蜘蛛丝绑结，外部装饰有蜘蛛卵囊和苔藓，内部衬有毛发、羽毛、植物绒毛和柔软材料。巢通常位于灌木或低树中，高度1至2米，有时低至地面或高达5米。一窝通常有3枚蛋，有时为2枚，蛋壳颜色为白色或极淡粉色，带有深色斑点和斑块，形成较大的末端带。关于孵化期和育雏期的信息未知。雏鸟和离巢幼鸟由双亲喂养。巢穴可能被霍氏金鹃寄生。","identification":"蓝灰刺嘴莺与栗尾刺嘴莺主要通过深色眼睛、白色眼环、额头上的黑色条纹和更灰色的上体来区分。","protection":"IUCN：LC（无危）","distribution":"分布于西澳大利亚州至昆士兰州西南部，从中西部至澳大利亚中东部。"},{"name":"白脸刺莺","english_name":"Southern Whiteface","scientific_name":"Aphelocephala leucopsis","overview":"白脸刺莺（英文名：Southern Whiteface，学名：Aphelocephala leucopsis），是雀形目细嘴莺科白脸刺莺属的鸟类。小型的澳大利亚本土鸟类，广泛分布在澳大利亚南部的干旱地区，排除塔斯马尼亚岛。主要栖息在干燥的开阔林地和灌木丛中，以昆虫为主食，也吃种子和叶子。白脸刺莺具有独特的白色面部标记，身体上部呈灰褐色，下部白色，两性外观相似。","appearance":"体长约11.5厘米，外形丰满，尾巴短，喙粗壮，类似雀类。上体灰褐色至灰棕色，下体白色，腹部有时带有灰色调，两胁可能呈现灰色或红褐色。头部最显著的特征是白色的前额带，边缘黑色，从额头中央延伸到喙基部，尾羽黑色，末端白色。幼鸟相似于成鸟，但黑色面部条纹不明显，翼上覆羽边缘浅棕色。存在两个亚种，emcastaneiventris/em亚种的两胁呈赤褐色，脸部更白，羽毛颜色较淡，臀部有时带浅红褐色，胸部两侧的灰褐色调较淡。","call":"经常发出持续的尖锐颤音系列，类似于仙鹟（Malurus）的声音，但更为响亮。也会发出沙哑的、类似Sericornis的责骂式叽喳声，以及‘wit, wit-awit’的飞行叫声。emcastaneiventris/em亚种的叫声较为柔和，不那么有力，略带尖锐，活力稍减。","habits":"主要栖息于澳大利亚南部的阿卡西亚（Acacia）和桉树（Eucalyptus）林地和灌木丛，特别是在mulga林区，也出现在mallee地带，通常有草本植物和低矮灌木的下层植被，尤其是盐生植物（Atriplex）和蓝灌木（Maireana），以及Eremophila。偶尔在柏松（Callitris）林地和灌木丛中发现。它们通常成对或小群体活动，有时会形成较大的松散群落，多达60只。主要在地面觅食，有时也在小树和灌木中活动，偏好裸露区域或树木、灌木或灌木丛基部的稀疏植被中寻找食物。会探查枯枝上的树皮。经常参与由同类（栗胸白脸刺莺和斑纹白脸刺莺）、红喉刺莺、Acanthiza属物种、红头鸲鹟、棕啸鹟、黑白扇尾鹟和黑脸燕鵙组成的混合觅食群。","breeding":"繁殖季节记录在全年各月，主要集中在7月至11月和3月至4月；一季可能育雏多次。主要以成对形式筑巢，但也存在社群性和合作性繁殖现象。巢为大型穹顶状结构，侧面或顶部有入口，有时有遮盖，由柔软的树皮、草、根须、毛发、羽毛、羊毛、树枝和细枝构成，有时加入软花、蜘蛛网、苔藓、枯叶和线或布料，常以羽毛、毛发或羊毛内衬，通常置于树洞、灌木、栅栏柱或建筑物中的空穴中。高度机会主义，会利用人造物品（如锡、衣物），甚至有记录显示使用牛头骨。一窝产卵2至6枚，通常3或4枚，蛋色从白色到浅米色，可能带粉红色调，密集地斑点和不规则地带有棕色至红褐色的斑块，标记通常集中在大端；确切的孵化期未知，据说约为22天，但这一数据有争议；雏鸟由双亲共同喂养，若有帮手在场也会参与喂食，育雏期超过19天。巢穴可能会被霍氏金鹃寄生。","identification":"与其他白脸刺莺物种相比，外观略显暗淡，缺乏胸带，这是斑纹白脸刺莺和栗胸白脸刺莺所具有的特征。","protection":"IUCN：VU（易危）","distribution":"分布于澳大利亚西部、中部和南部地区，不在塔斯马尼亚或大陆沿海地区。偏好阿卡西亚木地，尤其在mulga和抗旱的chenopod灌木物种，包括盐生植物和蓝灌木为主的林地。","other":"白脸刺莺的两个亚种为：指名亚种和emcastaneiventris/em亚种。"},{"name":"栗胸白脸刺莺","english_name":"Chestnut-breasted Whiteface","scientific_name":"Aphelocephala pectoralis","overview":"栗胸白脸刺莺（英文名：Chestnut-breasted Whiteface，学名：Aphelocephala pectoralis），是雀形目细嘴莺科白脸刺莺属的鸟类。主要分布在澳大利亚中南部的干旱地区。其最显著的特征是拥有温暖棕色的上体，白色下体，宽阔的锈褐色胸部带纹，以及带有红棕色侧翼标记。","appearance":"这种小鸟体型小巧，喙短粗，面部区域呈米白色，边缘有黑色细边，头顶至颈部为灰色，上体为锈褐色，尾羽黑而基部淡棕色，翼上有一浅色横杠，下体白色，胸部有明显的栗色宽带，与白色喉部和腹部清晰分界，两性相似。幼鸟的面部图案较淡，胸带和侧翼标记不那么明显，虹膜蓝灰色。","call":"鸣叫特征表现为稳定的颤音啾啾声。","habits":"栖息于开阔的石质沙漠和半干旱地区的白千层灌木丛中，偏好蓝灌木（Maireana）、Eremophila和盐生植物（Atriplex）的斑驳覆盖。小群活动，以地面觅食为主，食物包括昆虫和种子。","breeding":"繁殖习性了解不多，记录显示在8月至9月期间繁殖，筑球状巢，入口位于侧面顶部附近，由枝条和草构成，内部铺垫羊毛、软植物材料或细羽毛。每窝产2-4枚淡粉色蛋，带有深紫色斑点。","identification":"与同属物种相比，叫声更弱更柔和。在有水源的林线附近或沙质区域，可能与同属其他物种共同觅食。","protection":"IUCN：NT（近危）。在南澳大利亚沙漠次要区域分布，因过度放牧和严重干旱而脆弱，部分栖息地已被欧泊矿开采破坏。","distribution":"主要分布于澳大利亚中南部，集中在Mt Lyndhurst、Oodnadatta和Coober Pedy周边的干旱区。","other":"受威胁于栖息地丧失，目前全球数量稀少。"},{"name":"斑纹白脸刺莺","english_name":"Banded Whiteface","scientific_name":"Aphelocephala nigricincta","overview":"斑纹白脸刺莺（英文名：Banded Whiteface，学名：Aphelocephala nigricincta），是雀形目细嘴莺科白脸刺莺属的鸟类。主要分布在澳洲干燥地区，如西澳大利亚中西部至昆士兰西南部和南澳大利亚东北部。其最显著的外部特征是白色的面部，带有黑色眼带，以及胸部的黑色细带。","appearance":"斑纹白脸刺莺体长约10厘米，重约11克。上身和头部为灰褐色，面部有白色面罩，由一条穿过眼睛区域的较暗色带环绕。上胸呈淡蓝灰色，下身白色，二者被一条突出的黑色胸带隔开。两翼侧有红棕色斑点，喙和腿黑色，眼白色。雌雄羽毛相似，幼鸟颜色较淡，面部图案不明显，胸部黑带模糊。","call":"鸣叫声为柔和的颤音哨声。","habits":"栖息于干燥地区的开阔灌木丛和草地，包括多尔沙丘和石质平原。以昆虫和种子为食，常在地面或低矮的树丛中觅食，有时加入其他种类的鸟群。冬季或雨季后在地面筑巢，巢由枝条和草构成，入口为长管状，内部铺垫花朵和羽毛。","breeding":"繁殖季节在冬季，通常从7月至9月，或雨季之后。巢位于地面近灌木处，每窝产3至4枚带有褐色斑点的哑光白色蛋，形状为锥形椭圆，尺寸约为17毫米×13毫米。","identification":"与同属的其他种类相比，斑纹白脸刺莺的特征在于其独特的面部图案和胸部的黑色细带。","protection":"IUCN状态未提供。","distribution":"斑纹白脸刺莺广泛分布于澳大利亚干燥地带，从西澳大利亚州的中西部到昆士兰州的西南部，以及南澳大利亚州的东北部。","other":"斑纹白脸刺莺在冬季夜晚会进入假死状态，随着早晨的温暖而苏醒。"},{"name":"弯嘴鹛","english_name":"Papuan Babbler","scientific_name":"Garritornis isidorei","overview":"弯嘴鹛（英文名：Papuan Babbler，学名：Garritornis isidorei），是雀形目弯嘴鹛科弯嘴鹛属的鸟类。以其独特的长而弯曲的黄色喙和锈褐色的羽毛著称。","appearance":"体型中等，全长约25厘米，体重30至47克。全身主要呈锈褐色，头部顶部、背部和翅膀上覆羽橄榄棕色到锈棕，尾部丰富锈红；下巴、喉咙、耳羽和上胸部橙色带浅黄，较其余羽毛颜色更淡，形成模糊的面部淡色面具，向下渐变为较深的锈红色。腹部、腹侧和尾下覆羽同为锈色；下翼覆羽和腋羽锈褐；虹膜淡棕色或暗黄色；喙橙黄色，上喙基部暗色；腿深灰色。性别相似，幼鸟虹膜更深的棕色，头顶更加橄榄色（锈色较少）；幼鸟与成鸟难以区分，但虹膜为深棕色，上体色调有斑驳变化。","call":"发出响亮的下降式重复哨音“weeuuuu！”混杂着粗糙的嘶哑声和叽叽喳喳的叫声。","habits":"生活在新几内亚的低地森林中，常以嘈杂的群居方式活动，寻找树丛中的昆虫，有时会与其他物种混合，如新几内亚鹃鵙和锈色林鵙鹟。它们在树丛中搜寻昆虫。","breeding":"繁殖记录见于雨季和旱季中期。少量信息表明可能实行合作繁殖模式，一对配偶可能得到帮助者的协助，共同筑巢和喂养幼鸟。巢穴为大型吊状结构，长达1至2米，侧面入口处有屋顶式门廊，内部室宽约30厘米，下垂“尾巴”长约50厘米，由干枯的藤蔓和纤维构成，内衬棕榈叶和竹叶，通常悬挂于森林空地3至9米高的垂直藤蔓或律师藤（Calamus）上。","identification":"与新几内亚鹃鵙和锈色林鵙鹟相似，但弯嘴鹛具有更长的喙。","protection":"IUCN状态未知。","distribution":"分布于澳新界：Misool（四王群岛，新几内亚西北部），鸟头半岛和Neck（新几内亚西北部）至新几内亚东南部。"},{"name":"灰冠弯嘴鹛","english_name":"Grey-crowned Babbler","scientific_name":"Pomatostomus temporalis","overview":"灰冠弯嘴鹛（英文名：Grey-crowned Babbler，学名：Pomatostomus temporalis），是雀形目弯嘴鹛科伪弯嘴鹛属的鸟类。拥有长而弯曲的喙，深灰色面罩，淡灰色顶冠和白色眼圈。分布于新几内亚中南部和澳大利亚北部、中部及东部（除塔斯马尼亚州）。其独特的外形和习性使其成为当地生态系统中的重要成员。","appearance":"成年灰冠弯嘴鹛体型大，约23至27厘米长，体重60至85克。头部特征明显，有宽广的眉纹，白色或红褐色的胸部，以及翅膀上突出的红褐色斑块（当翅膀闭合时隐藏）。冠部中央有一条狭窄的灰色条纹，向后扩展至颈背，形成更宽的白眉纹，几乎给人一种白色头盖的印象。黑色的面罩从喙延伸至眼周，覆盖耳羽和颈部侧面。上体主要为灰色，臀部和尾上覆羽渐变为深棕色。翼上的小翼羽和中翼羽呈灰褐色，大覆羽、初级飞羽和次级飞羽为深棕色，翼上有一显著的红褐色斑块，仅在飞行时可见。尾羽深棕，外侧尾羽的尖端有最宽的白色。下巴、喉部和上胸白色，侧胸至红褐色，胁部和上腹红褐色，其余下体深棕色。下翼覆羽和腋羽浅灰褐色。虹膜淡黄色，喙黑色，下颌基部有狭窄的粉红色条纹，腿暗灰色。雄雌相似。幼鸟与成鸟类似，但喙较短且弯曲程度较小，虹膜深棕色，嘴角黄色，耳羽较淡，翼上覆羽和副翼有狭窄的红褐色尖端。","call":"发出多种刺耳的叽喳声作为联系信号；最具特色的叫声是由繁殖中的雄鸟和雌鸟进行的‘呀-呼’式反响二重唱。","habits":"偏好开放的原生森林和林地，通常以成熟的桉树（Eucalyptus）、柏松（Callitris）或松果木（Casuarina）为主，地面有丰富的落叶层和开阔的草地底层。在澳大利亚北部和新几内亚南部，也出现在草原、季雨林、茶树（Melaleuca）灌丛和金合欢（Acacia）灌木丛中。常沿水道分布，偶尔在路边残留的原生植被或农田附近被发现。生活习性上，它们通常是定居的，但在局部可能有游荡或游牧行为，几乎所有回收标记个体都在距离原标记地点10公里范围内。食物主要包括昆虫，如象鼻虫（Curculionidae）、甲虫（Coleoptera）、蚱蜢（Orthoptera）、蝽（Hemiptera）、蝴蝶幼虫（Lepidoptera）、白蚁（Termitidae）和蚂蚁（Formicidae）；也吃种子、蜘蛛（Araneae）、蝎子（Scorpiones）甚至小型爬行动物和小鸟巢中的雏鸟。觅食时，它们在地面或低矮的灌木和树木中活动，常用喙翻转叶子和小石块。经常在树皮和倒下的木材间探索。通常成群活动，群体大小从2到15只不等。","breeding":"繁殖记录显示，新几内亚在12月和2月，澳大利亚全年都有繁殖活动，但主要集中在7月至次年2月。以合作方式繁殖，由一夫一妻制的繁殖对和数量不等的帮助者组成群体，帮助者通常是这对夫妇的兄弟姐妹或后代。巢用于繁殖和夜宿，由群体中的所有或大部分成员共同建造，是一个大型的穹顶状巢，一侧常有一个‘烟囱’，由树枝、草、细根和树皮构成，内部铺垫着更精细的材料，如羊毛、羽毛、软草和落叶。巢通常位于离地1至15米高的小树（常见于桉树、柏松或金合欢属）中，常由叉枝或直立枝支撑。群体的领地范围从1.5到50公顷不等。每窝产2至6枚卵，平均3枚；孵化通常仅由雌鸟亲鸟承担，孵化期为21至25天；雏鸟由群体中所有或大部分成员喂养，离巢期为17至23天。孵化成功率约为65%，离巢成功率约为20%至50%。","identification":"灰冠弯嘴鹛与同属物种的区别在于其明显的冠部特征、面部条纹、红褐色的胸部以及翼上的红褐色斑块。两个亚种的区别主要在于胸部颜色，P. t. temporalis亚种的胸部由奶油白色渐变为中灰色，而P. t. rubeculus亚种的胸部为中至深红褐色。其他差异包括眉毛的颜色、眼带、尾长和整体大小。","protection":"IUCN：LC（无危）\n尽管全球范围内并不受到威胁，但在部分地区由于栖息地碎片化和火源管理的变化导致数量下降，特别是在澳大利亚南部维多利亚州和南澳大利亚州的部分地区已经消失。在北维多利亚州进行的栖息地恢复工作，包括种植本地或外来树木和灌木、自然再生树木和灌木以及围栏以排除牲畜，有效阻止了1995年至2008年间种群的衰退。\n猫和狐狸（Vulpes）已知会猎杀这种鸟类，野猪也可能破坏其栖息地。蓝脸吸蜜鸟对共存地区的本种巢穴的干扰可能对其繁殖成功产生负面影响。","distribution":"新几内亚中南部和澳大利亚北部、中部及东部（除塔斯马尼亚州）。","other":"灰冠弯嘴鹛的两个亚种P. t. temporalis和P. t. rubeculus在澳大利亚和新几内亚均有分布。东部亚种（P. t. temporalis）因栖息地丧失和片段化导致数量减少，被认为是受威胁的。"},{"name":"哈氏弯嘴鹛","english_name":"Hall's Babbler","scientific_name":"Pomatostomus halli","overview":"哈氏弯嘴鹛（英文名：Hall's Babbler，学名：Pomatostomus halli），是雀形目弯嘴鹛科伪弯嘴鹛属的鸟类。拥有显著的长而弯曲的喙，深色面罩，宽阔的白色眉纹和明确的白色喉部与胸部形成围巾状，与腹部的深褐色形成鲜明对比。主要分布于澳大利亚中东部，特别是在昆士兰州中西部至新南威尔士州西北部的干燥Acacia灌木丛地带。","appearance":"体长19至21厘米，体重30至47克。具有宽大的白色眉纹和明显的白色围巾状胸部。头部从额头中心到颈背呈深棕色，上体包括翅膀均为深棕色。尾巴为黑褐色，外侧尾羽尖端白色最明显。下巴、喉咙和上胸中央白色，与深褐色的下体形成锐利分界。虹膜暗棕色，喙黑色，腿黑色。雌雄相似，幼鸟喙较短，曲线不明显，口裂黄色，初级飞羽覆羽边缘黄褐色。","call":"发出嘈杂的尖锐叽叽声和嗡嗡声，以及尖锐的断音、哨音和责骂般的叫声。","habits":"栖息于开放的高大Acacia树林和灌木丛，偏好石头沟壑或石质平原或斜坡地带，树冠覆盖率超过70%，树高7至11米，灌木层稀疏。通常地面觅食，也会在灌木和树木的枝干上寻找食物，经常在裂缝中探查，翻转石头和木头寻找食物。以昆虫为主食，包括甲虫和蝴蝶幼虫。群居，常形成5至15只的小群体。","breeding":"繁殖季节未知，但记录显示全年均有繁殖活动。合作繁殖，由一对亲鸟和一到两个辅助者组成。群体会建造多个巢穴，但每次仅使用其中一个。巢穴为紧凑的穹顶形状，外部由树枝构成，内部铺垫草、羽毛和毛发，位于地面以上3至8米的Acacia树中。巢区估计大小2至18公顷。窝卵数约2枚，孵化期未知，辅助者协助喂养雏鸟，离巢期可能超过10天。","identification":"与白眉弯嘴鹛相比，白眉延伸至颈背更宽，而白眉弯嘴鹛的白眉较窄，且白色胸部不会延伸到腹部。此外，哈氏弯嘴鹛的尾羽尖端白色分布模式独特，外侧尾羽白色尖端最宽，向内逐渐减少，中间一对尾羽通常无白色尖端。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中东部，从昆士兰州西南部（Finucane山脉以南，Forsyth山脉以东）向南延伸至新南威尔士州西北部。","other":"以澳大利亚出生的慈善家Major Harold Wesley Hall命名，其资金支持了收集标本的探险队，首次发现了哈氏弯嘴鹛。"},{"name":"白眉弯嘴鹛","english_name":"White-browed Babbler","scientific_name":"Pomatostomus superciliosus","overview":"白眉弯嘴鹛（英文名：White-browed Babbler，学名：Pomatostomus superciliosus），是雀形目弯嘴鹛科伪弯嘴鹛属的小型鸟类。以独特的白眉和暗色眼纹著称，广泛分布于澳大利亚南部及中部的开阔林地和灌木丛地带。","appearance":"白眉弯嘴鹛体长17至22厘米，体重30至50克，是最小的澳大利亚鵙之一。其特征为长而弯曲的喙，头部顶部呈深棕色，两侧有明显的白色眉毛，黑色眼纹，上体多为棕色或灰棕色，下体白色，侧腹和腹部下方为暗色。幼鸟类似成鸟，但喙较短，弯曲度较小，缺乏淡色线，口裂黄色。","call":"它们发出低沉重复的‘chuck’声，可能作为觅食时的联系信号。长距离呼叫由连续三次以上的‘mee’声和上升音调的‘wee-aw’哨声组成，用于远距离通讯。","habits":"白眉弯嘴鹛主要栖息于干燥的开阔林地，偏好有密集灌木层的环境。它们通常在地面觅食，也出现在低矮的灌木或树木中。饮食包括昆虫、蜘蛛、果实、种子等，有时饮水。群体通常由15个个体组成。","breeding":"繁殖期主要在7月至11月，但全年均有记录。它们采取合作繁殖模式，每群最多有六名帮手参与。巢穴建于地面以上0.5至6米，由繁衍母鸟建造，其他成员协助。每窝产卵1至6枚，孵化期约19至20天，幼鸟离巢期16至17天。","identification":"与哈氏弯嘴鹛相比，白眉弯嘴鹛具有较窄的白眉和较暗的冠纹，眼纹在头后部逐渐淡化，而哈氏弯嘴鹛的白眉更宽更亮，眼纹无淡化。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚南部和中部，包括从东到西的南澳海岸线，向内陆延伸至半干旱和干旱地区。","other":"已知寄生者包括淡色杜鹃和黑耳金鹃，巢穴寄生现象已被记录。"},{"name":"栗冠弯嘴鹛","english_name":"Chestnut-crowned Babbler","scientific_name":"Pomatostomus ruficeps","overview":"栗冠弯嘴鹛（英文名：Chestnut-crowned Babbler，学名：Pomatostomus ruficeps），是雀形目弯嘴鹛科伪弯嘴鹛属的鸟类。澳大利亚东南部干旱开阔林地里的群居鸣禽，体型大而显眼，具长而下弯的喙、栗色头顶、白色喉胸与黑色镶边，最醒目的特征是一对明显的白色翼斑。","appearance":"体长19–23厘米，体重50–60克。头顶自额至后颈栗红；眉纹窄而白，上下缘以不整齐黑线勾勒；过眼纹黑色，向后渐褐。上体褐色带淡灰斑点；翼覆羽端白，形成两道显著翼斑，停歇及飞行时均明显。尾羽黑褐，外侧尾羽具宽白端。颏、喉、胸及腹中央白色，胸侧及腹侧灰褐，向下转为暗灰褐；尾下覆羽暗灰褐带白鳞斑；翼下覆羽及腋羽栗色。虹膜暗褐；喙黑，下喙基部具窄白或淡蓝条纹；腿灰黑。两性同色。幼鸟头顶栗色较暗，眉纹带棕，颏喉乳白，翼斑淡栗；喙较短直，无浅色基纹。","call":"嘈杂的尖锐“chattering”与哀婉哨音，比同属的弯嘴鹛属 白眉弯嘴鹛更尖厉。已记录13种叫声，分为3类警戒声、5类联络声、4类社交声及1类兼具社交与警戒功能的叫声；无用于领域宣示的“歌声”。","habits":"栖息于澳大利亚东南内陆干旱、半干旱的疏林、灌丛及沙地平原，常见于滨水区。植被以桉树、金合欢、决明、滨藜、蓝滨藜、糖木、河岸赤桉或河岸胶为主。基本为留鸟，环志回收均在10千米内。主要以甲虫、鳞翅目幼虫、白蚁、蚂蚁为食，兼食滨藜及桑寄生科种子与果实。多在地面觅食，也到低灌或树上探缝、剥树皮、掘土。常见4–6只群体，偶见30只大群。新南威尔士州研究显示，16群家庭规模2–13只，平均活动区28公顷，偏好排水沟区域取食，以避空中掠食者并获更高猎物密度。","breeding":"繁殖期6–12月，以9月为主，具合作繁殖习性，但群体结构尚不清楚。群体常筑多个繁殖与夜宿巢，巢为大型深圆顶，比同属他种更大，侧方具微遮檐，偶分双室，由枝条、草、粪等材料构成，内衬草、树皮、羽毛、植物绒及爬行动物皮，置于3–10米高的灌乔木（桉、柏松、木麻黄、牛眼树、金合欢）分叉处。每窝3–5枚卵，常4枚；孵化期约20天；育雏期21–25天。新南威尔士州研究显示，繁殖单元2–13只，平均首窝4卵、次窝3.5卵；每单元每季平均育出3.5只雏鸟，每增加3名帮手可多育1雏。年存活率约66%。","identification":"与同域其他弯嘴鹛属种类相比，本种具栗色冠顶、白色翼斑及大型白色胸斑，结合长而下弯的喙即可区分。","protection":"IUCN: LC（无危）。","distribution":"繁殖区：澳大利亚东南内陆，自昆士兰西南、南澳东北向南延伸至新南威尔士西部及维多利亚极西北部。","other":"单型种，无亚种分化。"},{"name":"新几内亚刺尾鸫","english_name":"Papuan Logrunner","scientific_name":"Orthonyx novaeguineae","overview":"新几内亚刺尾鸫（英文名：Papuan Logrunner，学名：Orthonyx novaeguineae），是雀形目刺尾鸫科刺尾鸫属的鸟类。中等体型的地面栖息鸟类。主要分布在新几内亚的高山区，自然栖息地为湿润的山地森林。","appearance":"成年雄性新几内亚刺尾鸫的头顶呈深红褐色，肩背和背部为暗棕色，翼上有灰色和棕色条纹，喉咙和胸部为白色，边缘有黑色线条；雌鸟喉咙和上胸部为橙红色，侧胸暗灰色，腹部白色，两翼和尾巴有明显的斑点和条纹。幼鸟全身呈淡褐色，背部羽毛边缘有较窄的暗色边框。","call":"其鸣唱为一系列下降的重复哨音，前几个音符紧密相连，最后一个音符拉长，声音清晰穿透力强，略显不和谐。","habits":"栖息于海拔1980至2840米的高山森林，可能最高可达3450米，局部地区低至1200米。以昆虫和其他无脊椎动物为食，常在森林地面上觅食，行为数据较少。非常隐秘，难以观察。","breeding":"筑巢于地面，巢为小而圆的穹顶状，侧面有入口，由苔藓、根纤维和植物茎构成，内部铺满柔软的纤维。繁殖季节为3月和11月底，巢中有单个白色的蛋，尺寸约为29-33.6×22-22.7毫米，关于孵化和雏鸟成长期的信息尚不清楚。","identification":"与其他地面栖息鸟类相比，新几内亚刺尾鸫的外形特征独特，尤其是其鸣唱声音明显，易于通过声音识别。","protection":"IUCN：LC（无危）；物种一般稀少到罕见，但在新几内亚西北部局部常见，由于其隐秘性和易被忽视的特性，实际数量评估较为困难。","distribution":"分布于新几内亚的山区，从西北部延伸至东南部。","other":"曾被认为是澳大利亚刺尾鸫的同种，现已确认为独立物种。"},{"name":"刺尾鸫","english_name":"Australian Logrunner","scientific_name":"Orthonyx temminckii","overview":"刺尾鸫（英文名：Australian Logrunner，学名：Orthonyx temminckii），是雀形目刺尾鸫科刺尾鸫属的鸟类。栖息于澳大利亚东部的温带、亚热带或热带湿润低地森林中。曾被认为与新几内亚刺尾鸫同种，但2002年的研究显示两者在遗传和声音上有显著差异。","appearance":"刺尾鸫拥有红褐色背部，灰色面部，黑色翅膀上带有醒目的白色翼斑，强健的腿和脚。雌鸟具有黑色镶边的橙色喉部，雄鸟为白色喉部，两侧均为灰色，腹部白色。雄鸟体重58-75克，雌鸟49-58克，身长18-21厘米。幼鸟上部锈红色，羽轴淡色，羽尖黑褐色，翅膀标记淡红棕色，下部淡锈色，腹部较浅，有黑褐色斑点。","call":"发出类似豚鼠的吱吱叫声，通常在黎明和黄昏时分听到，包括响亮、穿透力强的高音‘kweek, be-kweek-kweek-kweek-kweek’，可能具有领地和求偶功能；还发出‘tu-weet-weet-weet’叫声，重复3-4次。接触叫声为响亮的双音‘kweet’，偶尔单独发出；快速的断音喋喋不休；报警声尖锐刺耳。","habits":"栖息于亚热带和温带雨林，以及湿硬叶林边缘和密集的周边植被中，包括外来物种如万寿菊和黑莓。以昆虫和其他土壤中的小型无脊椎动物为食，主要在地面活动，清晨开始觅食。通过侧向踢脚去除表面较大物体，利用尾巴支撑，前后移动腿和脚，形成明显的清理圆圈。","breeding":"繁殖季节通常为5月至8月，有时会提前或延后，一年可产一窝或两窝。筑巢由雌鸟单独完成，耗时约一个月，巢呈穹顶状，入口位于地面水平，内部有走廊，由树叶、落叶、枝条、苔藓和蕨类构成，内衬苔藓、草和植物纤维。每窝产卵通常为2枚，有时1或3枚，白色，平均尺寸为28.7×21.3毫米。孵化期21-25天，仅由雌鸟孵化，雏鸟在18-19天后离巢，离巢后由双方父母喂养。","identification":"刺尾鸫的辨识特征包括其红褐色背部、灰色面部、带有白色翼斑的黑色翅膀、橙色（雌鸟）或白色（雄鸟）喉部、灰色侧面和白色腹部。其独特的地面觅食行为和叫声也是重要的辨识点。","protection":"IUCN：LC（无危）。在北部较为常见，向南逐渐减少，最南端变得稀少。受到栖息地改变的影响，包括砍伐和碎片化，但在1-2.5公顷的碎片中仍能生存。","distribution":"分布于澳大利亚东部，从昆士兰州东南部至新南威尔士州中南部。","other":"刺尾鸫的尾羽中央轴突出且硬化，赋予其独特的‘刺尾’外观。"},{"name":"黑头刺尾鸫","english_name":"Chowchilla","scientific_name":"Orthonyx spaldingii","overview":"黑头刺尾鸫（英文名：Chowchilla，学名：Orthonyx spaldingii），是雀形目刺尾鸫科刺尾鸫属的鸟类。独特的陆栖雀形目鸟类，主要分布在澳大利亚东北部的昆士兰北部热带雨林中。具有深巧克力棕色的外观，明显的白眼环和尖锐的尾羽末端。雄鸟拥有白色喉部和腹部，而雌鸟则是橙色喉部和白色腹部。","appearance":"成年黑头刺尾鸫体长24至29厘米，体重介于113至215克之间。雄鸟具有黑色的冠部和颈背，淡蓝灰色的眼环，深橄榄棕色的上体，暗黑色的尾羽；下体为白色，侧翼呈暗灰色。雌鸟相似，但喉部和胸部为橙红色。幼鸟上体羽毛呈锈红色，有浅色中央轴线和黑褐色尖端，下体为锈红色带有较暗的斑点。","call":"发出响亮的哨音式叫声，类似“chow-chilla-chow-chow-chilla”或“chowy-chook-chook chowy-chook-chook”，具有节奏感和吟唱特质，能识别出不同的方言。","habits":"栖息于热带雨林，包括原始森林和20至30年树龄的再生林区，通常在茂密的灌木丛中。它们是定居性的，标记的个体重捕地点距离初始标记点不超过10公里。以昆虫和其他陆生无脊椎动物为主食，偶尔食用青蛙、小型蜥蜴和种子。在地面觅食，通过踢开落叶和较大物体寻找食物。","breeding":"繁殖季节贯穿全年，筑巢期在5月至次年2月（通常是7月至12月），幼鸟在雨季离巢。通常每季仅繁殖一窝。巢由雌鸟建造，耗时从两周到几个月，是一个大型的穹顶状结构，内部衬以细根和苔藓，隐藏在低矮的浓密植被中，靠近地面或高达3.5米。每次产卵一枚，白色，平均尺寸为37×26.3毫米。雌鸟孵化，孵化期约为25天。幼鸟22至27天后离巢，此后由双亲共同喂养。","identification":"黑头刺尾鸫以其独特的颜色模式和鸣叫声与其他鸟类相区分，尤其是其显著的白眼环和尖锐的尾羽末端。","protection":"IUCN：LC（无危）","distribution":"主要分布于澳大利亚约克角半岛中东部、东南部和昆士兰东北部的热带雨林中。","other":"黑头刺尾鸫虽受栖息地丧失的影响，导致其分布范围有所缩减，但目前没有明显威胁，总体状态稳定。"},{"name":"黑短嘴极乐鸟","english_name":"Loria's Satinbird","scientific_name":"Cnemophilus loriae","overview":"黑短嘴极乐鸟（英文名：Loria's Satinbird，学名：Cnemophilus loriae），是雀形目冠极乐鸟科冠极乐鸟属的鸟类。纪念意大利民族学家兰贝托·洛里亚而命名。黑短嘴极乐鸟主要栖息于新几内亚高地的山林间，偏好热带湿润低地森林及山地森林。","appearance":"雄鸟个体通体黑色，头部略显圆润，翼后方及眼前方带有绿色金属光泽，喙基部具明显棱角，尾羽呈渐变长度。雌鸟则以橄榄绿为主，翼和尾羽偏褐色，腹部更显黄色，无裸露的喙缘。成年雄鸟体重介于75-101克，雌鸟体重约60-96克，全长22厘米。幼鸟灰色，仅短暂拥有该羽毛，亚成年雄鸟类似雌鸟，但尾羽更长。","call":"雄鸟的招引叫声单调而规律，发出远传的‘weeep’或‘pseep’声，虽非强有力，但穿透力强。雌鸟在巢穴附近会发出柔和低沉的嘶哑警告音。","habits":"主要以果实为食，尤其喜食浆果和无脊椎动物如蚯蚓。通常独自觅食，偶尔会与其他鸟种组成小群（3-4只，有时多达十只），在森林中层和下层寻找食物。","identification":"雄鸟与短尾肉垂风鸟的区别在于缺乏黄色肉垂，雌鸟与黑腹短嘴极乐鸟和冠园丁鸟相比，体型更小，整体颜色为橄榄绿而非棕色，且无黑腹短嘴极乐鸟的淡色眼圈。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的新几内亚中部山脉至东南部地区。"},{"name":"黑腹短嘴极乐鸟","english_name":"Crested Satinbird","scientific_name":"Cnemophilus macgregorii","overview":"黑腹短嘴极乐鸟（英文名：Crested Satinbird，学名：Cnemophilus macgregorii），是雀形目冠极乐鸟科冠极乐鸟属的鸟类。原称黑腹极乐鸟，属于冠极乐鸟科。分布于新几内亚的山区，特别是在东部和东南部的山林地带。以其独特的外观和色彩吸引人，雄鸟拥有蓝色的眼睛和黑色的下部，头顶有不明显的冠羽。","appearance":"雄鸟长约24厘米，重94至120克，具宽阔的扁平喙上缘，宽大的喙裂，尾羽渐变。雄鸟的额头、耳羽和整个上身为亮丽的丝质火焰黄色，带有虹彩白光，背部较暗，翼上覆羽和尾上覆羽呈肉桂色；小而可竖起的冠羽由4至6根镰刀状的暗褐色羽毛组成，带有金色虹彩光泽；面部、下耳羽、眼上方的细线和全身下部为棕色带铜色光泽；大腿和侧腹有变化的肉桂色羽毛。雌鸟较小，均匀的橄榄棕色，下部稍浅，腹部和尾下覆羽更偏黄棕色，眼睛为深灰褐色至蓝灰色。幼鸟短暂为灰色。","call":"雄鸟可能没有广告性的叫声。已知的叫声包括粗糙的嘶哑声、低沉的嘶嘶声、响亮的连续点击声和间隔长时间的爆炸性低沉吠声。","habits":"生活在海拔2100至3650米的高山和亚高山森林边缘，包括次生林、受干扰的植被和灌木丛。通常单独觅食，但有时多个雄鸟和雌鸟个体会在结果实的植物中聚集，与其它食果鸟类共同活动。","breeding":"繁殖季节为8月至次年1月。雄鸟在6月至11月间出现扩大的生殖腺，6月开始求偶，7月至9月达到精子产生的高峰期，11月中旬前进行交配。雄鸟巡逻约200米直径的可能领地，雌鸟独自筑巢和照顾巢穴。巢呈球形，高度约220毫米，宽度197毫米，深度175毫米，入口水平椭圆形，由绿色苔藓和蕨类叶片构成，内部铺有绿黄色的附生兰茎。巢置于腐朽的苔藓树桩顶部、苔藓树干侧面或树木枝条和相关植被内，离地面1.9至3.7米高。一窝可能只有一个蛋，粉红带暗斑点，尺寸约为38.9毫米×25.8毫米，孵化期至少26天，雏鸟期超过30天。","identification":"雄鸟与其他物种明显不同。雌鸟与黑短嘴极乐鸟雌鸟相似，但体型更大，眼睛颜色较浅。与冠园丁鸟雌鸟相比，体型较小，颜色更偏向绿色而非棕色。","protection":"IUCN：LC（无危）。分布范围有限，仅限于新几内亚中央山脉的特定区域。列入CITES附录II。","distribution":"分布在新几内亚东部（至少从Ekuti Divide，Wau以南到Knutsford山，东北方向Port Moresby，可能更向南延伸）和东南部山区。在新几内亚中部高地也有未确定身份的种群。","other":"历史系统学上，曾与C. sanguineus视为同一物种，但雄鸟的上体颜色、喙色、冠羽颜色以及尾羽和翅膀外侧的色调差异显著，翅膀略长，尾部较短。"},{"name":"黄胸短嘴极乐鸟","english_name":"Yellow-breasted Satinbird","scientific_name":"Loboparadisea sericea","overview":"黄胸短嘴极乐鸟（英文名：Yellow-breasted Satinbird，学名：Loboparadisea sericea），是雀形目冠极乐鸟科黄胸极乐鸟属的鸟类。属于冠极乐鸟科黄胸极乐鸟属的珍稀鸟类，分布于新几内亚高山区的中海拔森林中。雄鸟具有独特的暗色头部、红褐色背部与翅膀，尾部亮黄色，胸前至喉咙亦呈亮黄色。雌鸟较雄鸟稍大，色泽较为暗淡，胸部具条纹，缺乏雄鸟的绿色肉垂。成年个体容易识别。","appearance":"雄鸟拥有暗色头部，红褐色背部、翅膀和尾巴，最显著的是亮黄色臀部和下体直至喉咙。喙基部上方有一绿色肉垂延伸至喙根部。雌鸟类似雄鸟但颜色更为暗淡，胸部有条纹，无喙上的肉垂。成年雄鸟体重50-75克，雌鸟60-77克，长17厘米。幼鸟的下体为浅棕色，具条纹，外观上类似于纹园丁鸟，但体型更小，且分布范围不完全重叠。","call":"其叫声为一系列尖锐、刺耳的音符，通常两声后短暂停顿，随后再次发出2至3声，随着系列的延续，音符逐渐放慢且增强。","habits":"栖息于中海拔森林内部，高度介于600至2000米，主要在1200米以上。饮食习惯以水果为主，可能包括简单的浆果和果实，偶尔发现有节肢动物残骸。觅食于森林冠层、下层冠层和上层中间层，偶尔会访问森林较低层次。单个或成群活动，最多可达十只。","breeding":"雄鸟在五月和十月生殖器官显著增大，推测为多配偶制，由雌鸟独自筑巢和孵化。巢穴为开放式的苔藓结构，据当地信息源报告，每窝产一枚蛋。具体繁殖细节未知。","identification":"雄鸟的特征包括明亮的黄色臀部和下体，以及独特的喙基部肉垂。雌鸟与雄鸟的主要区别在于颜色较为暗淡，胸部具条纹，缺乏肉垂。幼鸟下体浅棕色，具条纹，与纹园丁鸟相似但体型较小。","protection":"IUCN：LC（无危）。黄胸短嘴极乐鸟虽在局部地区常见，但分布零散，可能因食物植物不足而在适宜森林中缺失。因其隐秘的生活习性和崎岖的栖息环境而被忽视。人口数量似乎较小，正因采矿和伐木活动而减少。然而，其大部分栖息地相对安全，免受大规模生境退化的影响。","distribution":"分布于新几内亚高山区，主要集中在中部巴布亚山脉。","other":"黄胸短嘴极乐鸟曾被称为黄胸鸟-of-paradise或丝质极乐鸟，是其属内的唯一物种。"},{"name":"暗色啄果鸟","english_name":"Obscure Berrypecker","scientific_name":"Melanocharis arfakiana","overview":"暗色啄果鸟（英文名：Obscure Berrypecker，学名：Melanocharis arfakiana），是雀形目啄果鸟科啄果鸟属的鸟类。小型、罕见且知之甚少的山麓森林鸟类，以中灰色头部和背部、淡灰色喉部和胸部以及橄榄色飞羽为显著特征。暗色啄果鸟在林中层和次冠层觅食小浆果。","appearance":"体长约11.5厘米，体重约11.5克。上体呈暗褐色至橄榄绿色，头部明显灰，冠、颈背和肩部灰色；下体污橄榄灰色，喉部较浅，侧翼泛黄，腹部灰白色有时泛黄，两侧有明亮的柠檬黄色胸饰；尾下覆羽和尾下部灰色，翼下覆羽近白；虹膜深色，有时淡棕色，有极细的橙色眼环（仅手握可见）；喙角质色或带粉色角质，有时上部棕灰色而下部暗橙色，口裂橙黄色；腿橄榄绿（野外观似棕色），足底略浅。雌雄相似，幼鸟描述不详，可能有暗斑纹。","call":"鸣声为快速的高音短语“swizzly swizzly swizzly swit”，有时缩短，从树顶发出，与黑啄果鸟类似但速度更快、音调更高。还记录到尖锐的“zit-zit-zit”叫声。","habits":"主要栖息于山麓森林，活跃于中层树冠，偶尔降至灌木层觅食浆果。常单独或成对出现，行为类似于红帽花蜜鸟，会悬停并从叶片上捕食节肢动物。飞行迅速，频繁穿梭于树木之间。","breeding":"关于繁殖信息的数据极少。","identification":"与雌性黑啄果鸟和中高山啄果鸟相似，但暗色啄果鸟具有橙色的喙基和黄色的胸饰，灰头和淡色喙，可通过声音进一步区分。","protection":"IUCN：LC（无危）。受威胁物种，分布于西巴布亚高地和中巴布亚山脉。该鸟种容易被忽视，因栖居于树冠层，行动敏捷且难以观察清楚。自1867年首次发现以来记录稀少，直到近年来在多个地点再次被确认。","distribution":"分布于新几内亚东半部，包括塔布比尔地区、阿德尔伯特山脉的凯基、拉埃附近的博阿纳以及莫尔兹比港附近的埃福吉和瓦里拉塔。另有记录于西北新几内亚的阿尔法克山脉，但之后未再有发现。","other":"森林在其分布范围内受到伐木和农业开垦的威胁，如塔布比尔地区的栖息地正遭受重度退化。尽管可能面临缓慢下降的风险，但其能适应退化森林环境并在相隔遥远的地点被发现，显示其分布较为广泛但隐秘，很可能过去被忽视。"},{"name":"黑啄果鸟","english_name":"Black Berrypecker","scientific_name":"Melanocharis nigra","overview":"黑啄果鸟（英文名：Black Berrypecker，学名：Melanocharis nigra），是雀形目啄果鸟科啄果鸟属的鸟类。此鸟以黑色头部、背部、尾巴和独特的白色侧羽簇为显著特征，分布于新几内亚及其周边岛屿的低地和山麓森林。","appearance":"黑啄果鸟体长约11.5厘米，体型较小，尾部较短，喙短粗。雄鸟地理变异明显，但共同特征包括黑色的头、背、尾和白色的侧羽簇。下体颜色为灰色或黑色，翅膀为橄榄色或黑色。雌鸟主要呈橄榄色，下体略淡，具白色或黄白色的侧羽簇。幼鸟似雌鸟，但下体微带黄色，下颌基部较浅色，胸羽簇和翼下覆羽为黄白色。","call":"其叫声为重复的、粗糙的‘witoo-chii！’，结尾音调较高。","habits":"栖息于雨林、山地森林、季风林和高大的次生植被中，偶尔访问成熟的柚木（Tectona）种植园的树冠层。海拔高度从海平面至约1200米，局部地区可达1450米，尤其在同类缺位的地方。以小浆果为主食，亦食昆虫和蜘蛛。","breeding":"具体繁殖细节未详述。","identification":"与Obscure和Mid-Mountain Berrypeckers相似，但黑啄果鸟的尾部比黄胸啄果鸟短，且不具备暗色啄果鸟的橙色喙。亚种间在雄鸟的羽毛颜色上存在差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界的新几内亚和其西部卫星岛。","other":"活跃的觅食者，经常移动，除采食浆果时，很少长时间静止。"},{"name":"黄胸啄果鸟","english_name":"Mid-mountain Berrypecker","scientific_name":"Melanocharis longicauda","overview":"黄胸啄果鸟（英文名：Mid-mountain Berrypecker，学名：Melanocharis longicauda），是雀形目啄果鸟科啄果鸟属的小型鸟类，分布于新几内亚的山区森林中。其最显著的外部特征是黄色的胸部和较长的尾巴，具有白色边缘。","appearance":"该鸟体型小，具有一张相对厚实的喙，下体呈淡黄色调，两侧有黄色羽毛簇。雄鸟上体黑色，冠部和披肩蓝绿色光泽，尾羽外缘白色，下体浅橄榄灰色，两胁带黄色，腹部更黄，胸羽淡黄色，翅膀下面白色。雌鸟上体暗橄榄色，下体较淡，尾部棕色，基部有白色边缘。幼鸟似雌鸟，但嘴裂和下颌基部黄色。不同亚种在羽毛颜色和尾部图案上有细微差异。","call":"发出快速重复的模糊‘jjeteleet jjeteleet jjeteleet’声或‘weetcha weetcha tínk’声，还有三音节略带粗糙的‘tree ti tsee’声，典型的Melanocharis音质，以及下滑的‘bzhsst’声和连续的嘶哑鸣叫，以及尖锐、深沉的‘tschree’声。也有细长、颤音‘whee chippy-chip-chippy-chip’的歌声，类似于红背刺莺。","habits":"栖息于山地森林和次生林，偏好密集灌木丛和灌木丛，尤其在森林边缘，也会在邻近森林的本土花园周围觅食。活动范围从海拔700米至约2100米，主要位于低海拔黑啄果鸟和高海拔扇尾啄果鸟之间，可能有边际重叠。以小浆果、蜘蛛（Araneae）和昆虫为食。通常单独活动，偶尔在结果树中与其他物种一起被发现，但似乎不加入混合物种觅食群。","breeding":"繁殖信息了解不多。记录到的筑巢时间在一月，九月有处于繁殖状态的雌鸟。已知一个巢，对于鸟的大小来说相当大，是一个杯状的巢，有高边，顶部略微收缩，固定在离地面7.5米高的水平树枝分叉处。","identification":"与其它Melanocharis种类相比，主要通过更长的尾巴和白色的尾羽外缘，以及黄色而非白色的胸羽簇来区分。雌鸟比雄鸟略大，尾巴比例较短。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的山区，从700米至约2100米的海拔范围内，占据主岛新几内亚的广阔范围。","other":"在某些区域相当常见，在其他地方则较为罕见，似乎在相当大的区域内不存在。"},{"name":"扇尾啄果鸟","english_name":"Fan-tailed Berrypecker","scientific_name":"Melanocharis versteri","overview":"扇尾啄果鸟（英文名：Fan-tailed Berrypecker，学名：Melanocharis versteri），是雀形目啄果鸟科啄果鸟属的鸟类。具有明显的雌雄异型性。分布于新几内亚山区的亚热带或热带湿润山地森林。","appearance":"雄鸟拥有黑色上部，蓝绿色光泽的头部、披肩、上翼和尾巴，在良好的光线下，头部和上翼覆羽几乎呈现出蓝绿色的金属光泽。脸部侧面和耳覆羽有时显得较暗，与头顶形成对比。尾羽基部有白色，但在飞行中通常难以察觉。雌鸟体型稍大，上部呈暗橄榄绿，下部为橄榄灰色，腹部泛黄，尾羽基部有斑点。幼鸟类似雌鸟。","call":"发出重复的、下降的、鼻音‘weh！’和高音的咔嚓叫声。","habits":"栖息于山地森林和茂密的次生林中，从约1250米至3680米的海拔高度，主要分布在1700米以上，尤其在2300至2600米最为常见。以小浆果和节肢动物为食，常在低层、灌木丛和森林边缘觅食，有时也会在地面觅食。与混合物种群临时关联。","breeding":"繁殖信息较少，已知筑巢记录出现在7月和11月，幼鸟观察到在8月。巢穴为深杯状，由苔藓纤维制成，内部铺有橙棕色的蕨叶绒毛，用‘动物丝线’固定并装饰有淡绿色、棕褐色或浅黄色的苔藓以伪装。","identification":"雄鸟与雌鸟有显著区别，雌鸟比雄鸟颜色更深，体型更大。与绿背鹛鸫相比，扇尾啄果鸟有更苍白的腹部、侧纹、尾部的白色部分，以及喙基部周围较浅的颜色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚的山区，主要在主岛新几内亚。"},{"name":"纹啄果鸟","english_name":"Streaked Berrypecker","scientific_name":"Melanocharis striativentris","overview":"纹啄果鸟（英文名：Streaked Berrypecker，学名：Melanocharis striativentris），是雀形目啄果鸟科啄果鸟属的较为罕见的鸟类。主要分布于新几内亚高地的中海拔森林内部，以橄榄色为主色调，下体带有条纹，具有模糊的眼环和喙基橙色。体长约12.7至14厘米。","appearance":"雄鸟标本橄榄绿色上体，尾羽基部白色隐蔽，喉部和下体橄榄灰色，许多羽毛边缘呈白色或黄色，形成条纹外观。雌鸟体型较大，尾部较短，羽毛颜色相似，尾基白色减少或消失。幼鸟类似成年个体，尾部如雌鸟，但口角和鼻孔为淡黄色。不同亚种在色彩和尾部图案上有细微差异。","call":"发出粗糙刺耳的叫声，'schree schree schree'，比同类物种更为刺耳，还有独特的响亮'seep'声，每隔几秒重复一次。","habits":"在山地森林、森林边缘和次生林中活动，海拔约1150至2300米。觅食小浆果，频繁出现在灌木丛和栖息地的中层。活动隐秘，容易被忽视或误认。与黑啄果鸟和昏暗啄果鸟共存时，其栖息地划分机制未知。","breeding":"繁殖信息了解不多。12月在新几内亚东南部发现过巢穴，巢为杯状结构，由细纤维状蕨类植物部分构成，外部覆盖植物绒毛和蜘蛛丝，装饰有绿色苔藓帮助伪装。每窝产2枚粉白底色带深色斑点的蛋。","identification":"通过其下体的条纹外观、橙色喙基和模糊的眼环来区分于其他啄果鸟，尤其是与长尾啄果鸟和昏暗啄果鸟的区别。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚新界地区的山区中西部至新几内亚东北部和东南部。","other":"在全球范围内，纹啄果鸟通常被认为是不常见到稀有的物种，但在某些地区可能较为常见或丰富。"},{"name":"缎蓝啄果鸟","english_name":"Satin Berrypecker","scientific_name":"Melanocharis citreola","appearance":"雄性缎蓝啄果鸟拥有深蓝色、光泽亮丽的头部、背部和臀部，面部也是深蓝色，与喉咙、胸部、腹部和肛周区域明亮的丝光白色形成强烈对比，这些部位带有柠檬黄色调，尤其在喉咙、胸部和腹部更为明显。翼羽黑色，带有白色内部边缘，主要和次要飞羽尤为显著。尾羽除最外侧尾羽外全部为深蓝色光泽，该尾羽外侧80%部分，包括羽轴，呈白色，最后3-4毫米的白色部分向叶缘逐渐变淡。下翼羽白色。雌鸟尚未被确切描述，但据推测，整体为橄榄色，下体颜色较浅，略带黄色条纹。成年雄鸟全长约13-14厘米，体重9.2克，而亚成年雄鸟体重在11.1至11.7克之间。","call":"鸣叫声信息几乎未知，已知的几次叫声可能为被捕获时的高音调叫声，类似扇尾啄果鸟的接触叫声，但可能是因压力发出，不一定代表其自然叫声。","habits":"缎蓝啄果鸟生活在中海拔山地云雾林中，偏好树木稀疏、树蕨丰富的开阔地带。它们可能加入混合物种觅食群，活动高度从地面以上2米至9米不等。其饮食习惯尚不清楚，但已知参与由多种鸟类组成的觅食群，包括不同种类的鶲和莺、黑头林鵙鹟、黑嘴镰嘴风鸟和丽色极乐鸟。","breeding":"繁殖生态信息缺失。一只11月采集的成年雄鸟标本睾丸增大，提示繁殖季节可能在此期间。","identification":"雄性缎蓝啄果鸟可通过其丝光白色的下体与其他啄果鸟区分开来，黄胸啄果鸟体型较小，下体灰黄色，尾部白色斑点覆盖两片最外侧尾羽，而缎蓝啄果鸟仅有一片。扇尾啄果鸟尾部更长，下体灰色，可能不在缎蓝啄果鸟的分布范围内。雌鸟可能与纹啄果鸟最为相似，但缺乏橙色口角或嘴角条纹。","protection":"IUCN：LC（无危）","distribution":"缎蓝啄果鸟仅分布于新几内亚西部，具体为西巴布亚的库马瓦山脉和法克法克山脉，两个山脉相隔80公里的低地雨林。在库马瓦山脉，其栖息于海拔900至1440米的中海拔云雾森林，在法克法克山脉则位于1200至1500米的高度。","other":"关于该物种的系统发育历史和生态习性的研究仍在进行中，其确切的分布范围和种群状况仍需更多探索。"},{"name":"厚嘴啄果鸟","english_name":"Thick-billed Berrypecker","scientific_name":"Rhamphocharis crassirostris","overview":"厚嘴啄果鸟（英文名：Thick-billed Berrypecker，学名：Rhamphocharis crassirostris），是雀形目啄果鸟科斑啄果鸟属的鸟类。雄鸟上身呈深灰色，腹部淡灰色，具微小的侧向浅色羽簇。雌鸟上身深色，有厚重的白色斑点，腹部条纹状，橄榄绿边缘的飞羽。与斑啄果鸟曾被视作同一物种，但2021年被IOC认定为独立种类。","appearance":"雄鸟体长11-12厘米，重约18克。特征为长而粗的喙和窄方尾，性二色明显。雄鸟指名亚种上身橄榄绿色，有油绿色光泽，头顶较暗；尾羽黑色；腹部珍珠灰，略带黄色，翼下覆羽白或黄白，腋下淡黄。雌鸟头部至下胸深棕黑，全身密布白色尖端斑点，翼上覆羽有白色尖，形成不规则翼带；翅膀边缘橄榄黄，尾羽端部变白；腿灰至黑色。幼鸟信息极少，可能与雌鸟相似。","call":"鸣声为尖锐的高音‘tsiip’，还报道有类似红领摄蜜鸟的快速、嘶嘶声，以及连续下滑的‘seeu’音符，有时发出吸入式的嘶嘶声系列。","habits":"栖息于海拔1150米至2300米的山地森林及边缘地带，偶尔进入次生林和本土花园。以浆果、小型果实如无花果，及叶面和附生植物上的节肢动物为食。通常单独活动，偶尔成小群聚集，如家族群体，高度9-27米处觅食。","breeding":"繁殖信息未知。","identification":"雌鸟与斑吸蜜鸟的区别在于缺乏黄色耳斑，且下体颜色更深。雄鸟与同属其他种类相比，喙更长，尾更短。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚山脉的西北部和中部，包括胡恩半岛的赫尔佐格山脉（Herzog Mts）。","other":"其分类历史中，曾与斑啄果鸟视为同一物种，但现已确认为独立种类。"},{"name":"斑啄果鸟","english_name":"Spotted Berrypecker","scientific_name":"Rhamphocharis piperata","overview":"斑啄果鸟（英文名：Spotted Berrypecker，学名：Rhamphocharis piperata），是雀形目啄果鸟科斑啄果鸟属的鸟类。小型而稀有，原被认为是厚嘴啄果鸟的亚种，但在2021年被国际鸟类联盟（IOC）认定为独立物种。其特征在于雌鸟带有斑点的羽毛，生活在新几内亚的中海拔山地森林中。","appearance":"雄性斑啄果鸟上身呈深灰色，腹部颜色较淡，侧面有轻微的淡色羽冠。雌鸟整体色调较暗，布满斑点，腹部黑色，翼部有一橄榄色区域。雄鸟与Mid-mountain和扇尾啄果鸟相似，但嘴更长，尾巴更短。雌鸟与斑啸鹟相似，但体型明显较小。","call":"鸣叫声为尖细的高音“tsiip”。","habits":"栖息于新几内亚的中海拔山地湿润森林，具体生境偏好和活动模式尚待进一步研究。","breeding":"关于繁殖行为的具体信息有限，需进一步观察记录。","identification":"雄鸟通过比Mid-mountain和扇尾啄果鸟更长的喙和更短的尾巴区分，雌鸟则通过较小的体型与斑啸鹟区分开。","protection":"IUCN状态未提及。","distribution":"分布于新几内亚的中东部山区、东北部（休恩半岛）和东南部。","other":"在2021年之前被视为厚嘴啄果鸟的亚种，后被确认为独立物种。"},{"name":"小弯嘴吸蜜鸟","english_name":"Spectacled Longbill","scientific_name":"Oedistoma iliolophus","overview":"小弯嘴吸蜜鸟（英文名：Spectacled Longbill，学名：Oedistoma iliolophus），是雀形目啄果鸟科小弯嘴吸蜜鸟属的鸟类。广泛分布于新几内亚的低地到中山区森林底层。其背部橄榄色，胸部灰色，腹部淡黄，具窄眼环和中长弯曲喙。","appearance":"体长约11厘米，非常小巧，外观暗淡。上部深橄榄绿，下部橄榄灰，侧腹泛黄。有暗褐色虹膜和显眼但狭窄的肉黄色眼环，喙黑色，基部较淡呈黄色，腿蓝灰色。性别相似，幼鸟特征未详述。不同亚种在大小和色彩上有细微差别。","call":"发出独特的颤音颤鸣。","habits":"栖息于雨林及局部季风林，高度可达1200米，偶尔至1750米。以昆虫、花蜜和偶尔的果实为食，在植被较低层活动，常在开花树木和灌木中觅食。非常活跃，难于观察，经常在路径或森林底层快速穿梭。在开花树木和灌木中摄取花蜜，探入花朵中，偶尔悬停。","breeding":"繁殖信息知之甚少，但在新几内亚的布朗河附近记录到其在8月至9月干季繁殖，10月处于繁殖状态。一巢来自Fergusson岛，含一枚蛋，蛋壳奶油白色，大端有红色斑点形成环状，中间有少量棕色发丝状线。","identification":"与黑太阳鸟雌鸟相似，但腹部颜色更淡；与侏儒长嘴鸟相比，体型更大，有眼环；与黄腹长嘴鸟和蓝颏长嘴鸟的区别在于其灰色胸部和较短的喙。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚，除了Trans-Fly地区和新几内亚中南部。在低地森林和山地森林中常见，但在南Trans-Fly地区似乎缺失。","other":"在布朗河研究站点，密度约为每10公顷40只，与黄腹噪刺莺和棕鵙鹟的数量相当。"},{"name":"侏弯嘴吸蜜鸟","english_name":"Pygmy Longbill","scientific_name":"Oedistoma pygmaeum","overview":"侏弯嘴吸蜜鸟（英文名：Pygmy Longbill，学名：Oedistoma pygmaeum），是雀形目啄果鸟科小弯嘴吸蜜鸟属的鸟类。体型微小，活跃于新几内亚及邻近岛屿的低地和山脚森林树冠层。其自然生境为亚热带或热带的干燥及湿润低地森林。","appearance":"背部呈橄榄色，头部和胸部为灰色，腹部淡色，侧边略带黄色。拥有较短的尾巴和相对于其他长嘴鸟而言较短的喙。与小弯嘴吸蜜鸟相似，但体型更小且缺乏眼环特征。","call":"发出高音调的‘鞭打！’声或短暂的嘁嘁喳喳叫声。","habits":"常在树和灌木的外围觅食昆虫或蜘蛛，经常加入混种群鸟群中活动。偶尔可见于开花树木附近。","breeding":"相关信息未详。","identification":"与小弯嘴吸蜜鸟最为相似，但可通过体型较小和无眼环特征来区分。","protection":"IUCN状态未知。","distribution":"分布于新几内亚及一些邻近卫星岛屿，属于澳新界区域。","other":"系统学历史未详，曾被归类于Toxorhamphus属。"},{"name":"黄腹弯嘴吸蜜鸟","english_name":"Yellow-bellied Longbill","scientific_name":"Toxorhamphus novaeguineae","overview":"黄腹弯嘴吸蜜鸟（英文名：Yellow-bellied Longbill，学名：Toxorhamphus novaeguineae），是雀形目啄果鸟科弯嘴吸蜜鸟属的鸟类。主要分布于新几内亚（除中南部和东南部）及其西部周边岛屿。体型较小的鸟，拥有橄榄色上体和鲜明的黄色腹部。","appearance":"这种鸟长12.5厘米，具有显著的细长弯曲的喙。成鸟上体橄榄绿色，尾羽末端边缘呈窄白色（仅在飞行时明显）。喉部和下体为柠檬黄色，胸部带有橄榄色。眼睛棕色，眼圈窄白，喙黑色，下颚基部较浅。腿色介于灰到蓝灰色之间。雌雄相似，但雌鸟体型略小，喙稍短。幼鸟特征未详述。","call":"鸣唱为一系列下降的滑音哨声，常被听到而比看到更为频繁。叫声包括沙哑的‘zwik’音和类似花蜜鸟的高音‘tsweet tsweet’。","habits":"栖息于低地森林、山地森林和季风林中，偏好植被茂盛的环境，偶尔在较为密集的次生林中出现。在南部分布区，海拔可达约500米，罕见至750米；北部分布区主要在低地，但在中央高地可达1200米。它们是留鸟，但可能有局部移动。以昆虫为主食，也食用花蜜，具体饮食细节未知。活跃于树冠层，探查叶间寻找节肢动物，常单独或成对出现，有时加入混合物种群。","breeding":"2014年10月在巴布亚新几内亚的马当记录到正在筑巢的成鸟。7月至8月期间，在西部省的基翁加和西塞皮克的卡拉瓦里也有观察到似乎在领地上的个体。缺乏更多繁殖信息。","identification":"与小弯嘴吸蜜鸟、黑花蜜鸟和黄腹花蜜鸟雌鸟相比，黄腹弯嘴吸蜜鸟缺少灰色胸、黄色眉纹和对比明显的黄色喉咙。与灰颏弯嘴吸蜜鸟的区别在于头部和翅膀更橄榄色而非灰色，以及黄色的喉部和下巴。","protection":"IUCN：LC（无危）","distribution":"主要分布于新几内亚（除中南部和东南部）及其西部周边岛屿。"},{"name":"灰颏弯嘴吸蜜鸟","english_name":"Slaty-headed Longbill","scientific_name":"Toxorhamphus poliopterus","overview":"灰颏弯嘴吸蜜鸟（英文名：Slaty-headed Longbill，学名：Toxorhamphus poliopterus），是雀形目啄果鸟科弯嘴吸蜜鸟属的鸟类。主要分布在新几内亚的高地，栖息于山地森林地带，以其独特的灰蓝头部和橄榄色身体而著称。","appearance":"这种小型鸟类长约12.5厘米，重约14-15克，拥有细长且弯曲的深色喙，头部颜色较暗。雄鸟具有暗蓝灰色的头颈，背部为深橄榄绿色，翅膀和尾巴呈暗灰色，尾羽外侧有窄白尖。下巴和上喉为石板灰色，下喉有一显著的黄色斑点，下体淡黄橄榄色。雌鸟外观相似，但体型较小，颜色较淡。幼鸟描述未详。","call":"其鸣声多样，包括高音调的模糊音符串，有时穿插响亮的下降式“chew！”叫声。","habits":"它们居住在丘陵和低山的原始森林中，偶尔出现在次生林和花园边缘的森林。活动高度通常在海拔500米到2000米之间，但也有记录显示，它们可以在低至300米和高达2450米的地方被发现。以昆虫和花蜜为食，主要在林下层和中层觅食，偶尔造访树冠。它们通常独行，反应迅速，警惕性极高。","breeding":"繁殖记录在新几内亚高地的五月、六月、八月和十月，以及索格里高原附近的四月和九月，表明其繁殖时间广泛，可能受当地条件影响。巢穴是一个精致、光滑的杯状结构，由细腻的绿色植被和纤维编织而成，内部衬有厚厚的白色植物绒毛，常建于小树叉或细枝上。","identification":"与Slaty-chinned Longbill的区别在于后者缺乏灰色胸部，与黄腹花蜜鸟的雌鸟相比，前者头部为灰色，无黄色眉纹，喙更长更弯曲，且生活在森林中。","protection":"IUCN：LC（无危）","distribution":"主要分布在新几内亚的山区中西部至东北部和东南部，包括丘陵和低山森林。"},{"name":"拟雀啄果鸟","english_name":"Tit Berrypecker","scientific_name":"Oreocharis arfaki","overview":"拟雀啄果鸟（英文名：Tit Berrypecker，学名：Oreocharis arfaki），是雀形目冠啄果鸟科拟雀啄果鸟属的鸟类。由Christian Erich Hermann von Meyer于1875年首次描述。该物种分布于新几内亚的山区，特别是在新几内亚高地以及岛屿北部较为稀少的地区，栖息于亚热带或热带湿润山地森林中。","appearance":"成年雄鸟体长12至14厘米，体重16.5至21.7克，头部侧方有大片黄色区域，覆盖脸颊和耳羽；头、颈侧、喉部和胸部上方黑色；上体橄榄绿色，尾上覆羽蓝灰色；飞羽黑色边缘绿色，三级飞羽每片有突出的淡黄色尖端斑点；尾上表面蓝灰色，向尖端渐深；下体黄色，腹部中央区域橙色。雌鸟外观模糊，但具有诊断性的三级飞羽黄色斑点（如同雄鸟），两侧腹部有鳞状斑纹；头顶橄榄绿色，可能有不明显的暗色斑驳，帽部和颈部两侧更黄；颊和耳羽灰白色斑点，喉部和胸部灰色，下胸和两侧黄色带暗色鳞状斑纹，腹部黄白色带暗色斑纹；虹膜棕色；喙黑色；腿灰色至棕色。幼鸟和未成熟个体类似雌鸟。","call":"鸣叫声通常尖锐而嘶哑，频繁发出，包括细小的‘tzee-tzee’声和长细的啸声，类似于侏鹦鹉（Micropsitta）的叫声，亦被描述为非常高的、拉长的‘sss’或‘z-z-z’声，与雪松太平鸟的叫声相似。","habits":"主要栖息于山地森林，尤其偏好苔藓森林，也访问受扰动和部分清理的生境。主要活动于海拔2200米至2800米之间，偶尔低至850米，高至3650米。成对活动，或以小型群体至松散的五到三十个个体以上的群落活动，访问各种结果树、灌木和植物，如Schefflera、Pipturus树和Nothocnide藤蔓。主要以小型果实为食，从多种树木和灌木中获取，通常整个吞下。","breeding":"关于繁殖的数据有限。在西部范围内，雄鸟在10月和2月有增大的睾丸；在东部，雄鸟在8月至10月有增大的睾丸，10月有处于繁殖状态的雌鸟，7月观察到幼鸟离巢。巢穴报告为杯状，由苔藓构成；孵化由两性共同承担；两个离巢幼鸟由双亲喂养。无更多信息。","identification":"雄鸟具有独特的黄色腹面和黑色头部标记，易于识别。雌鸟与许多共存的小型橄榄色鸟类相似，但其腹部的鳞状斑纹和翼背的黄色斑点是辨识要点。","protection":"IUCN：LC（无危）。在整个分布范围内普遍常见。目前没有已知威胁，但在某些地区的栖息地有所丧失。","distribution":"分布于新几内亚的山区，包括Vogelkop（Tamrau山脉、Arfak山脉）、Wandammen山脉、Foja山脉、Bewani山脉、Torricelli山脉、中央山脉以及Huon半岛的山脉。"},{"name":"冠啄果鸟","english_name":"Eastern Crested Berrypecker","scientific_name":"Paramythia montium","overview":"冠啄果鸟（英文名：Eastern Crested Berrypecker，学名：Paramythia montium），是雀形目冠啄果鸟科冠啄果鸟属的鸟类。新几内亚山区中东部、东北部和东南部的常见居民。以独特的黑色面罩、尖顶冠和白色眉纹而著称，羽毛主要呈现蓝绿色调，腹部下方呈黄色。","appearance":"冠啄果鸟体长20-23厘米，拥有醒目的黑脸、胸及可竖立的黑冠，背部为绿色，腹部和两侧为黄色。其特征性的白色标记从眼后延伸至头部后方。有两种亚种： montium和 brevicauda，后者尾巴明显较前者短。","call":"不常鸣叫，但会发出各种粗糙的叫声和鼻音的‘wek！’声。","habits":"栖息于新几内亚高海拔森林和灌木地带，通常单独、成对或小群体活动，有时会加入混合群与其他鸟类共处。","breeding":"关于其繁殖行为的具体细节未详述。","identification":"与西冠啄果鸟极为相似，但两者的分布范围几乎不重叠，可通过较长的眼后白纹、更鲜亮的绿色背部和黄色侧面进行区分。","protection":"IUCN状态未提及。","distribution":"主要分布于新几内亚的山区中东部、东北部和东南部， montium亚种位于新几内亚高地的东部， brevicauda亚种则在Huon半岛。","other":"西冠啄果鸟曾被认为是同一物种，但在2021年被划分为独立物种。"},{"name":"西冠啄果鸟","english_name":"Western Crested Berrypecker","scientific_name":"Paramythia olivacea","overview":"西冠啄果鸟（英文名：Western Crested Berrypecker，学名：Paramythia olivacea），是雀形目冠啄果鸟科冠啄果鸟属的鸟类。在新几内亚山区中西部的高海拔森林和灌木丛中常见的中型鸟类。其显著特征为石板灰色的主体，橄榄绿色背部以及黄色下腹。","appearance":"该鸟全身主要呈石板灰色，背部橄榄绿，下腹部黄色。面部、胸部以及头部的冠羽为黑色，且冠羽可上下竖立或垂下。眼上有一明显的白色标记，非常引人注目。","call":"鸣叫不频繁，发出各种粗糙的声音和鼻音的“wek!”叫声。","habits":"西冠啄果鸟可以单独、成对或以小群体的形式出现，有时会与其他鸟类混群。它们主要栖息于新几内亚的高海拔森林和灌木丛中。","identification":"与冠啄果鸟极为相似，但分布范围几乎无重叠，可通过较短的眼后白色标记、暗淡的橄榄绿色背部以及缺乏侧边黄色来区分。","distribution":"新几内亚山区中西部。"},{"name":"北岛垂耳鸦","english_name":"North Island Kokako","scientific_name":"Callaeas wilsoni","overview":"北岛垂耳鸦（英文名：North Island Kokako，学名：Callaeas wilsoni），是雀形目垂耳鸦科垂耳鸦属的大型鸣禽。其独特之处在于拥有蓝灰色身躯与鲜艳的天蓝色耳垂，幼鸟则呈淡粉色。分布于新西兰北岛及其周边岛屿，数量稀少。该物种与南岛垂耳鸦的主要区别在于耳垂颜色，北岛垂耳鸦为蓝色，而南岛垂耳鸦为橙色。","appearance":"成年北岛垂耳鸦体型中到大，身长38厘米，体重介于200至250克之间。具有短而宽的向下弯曲喙，异常长且结实的腿，长而宽的尾巴，尾尖呈圆弧状且向下弯曲。翅膀宽阔而圆润，翼尖刚好超过上尾覆羽。脸部有显著的蓝色耳垂，从嘴角延伸覆盖大部分脸颊，繁殖季节时耳垂增大并色彩更加鲜明。全身羽毛主要为蓝灰色，有明显的黑色面罩，尾羽为深褐色，边缘和尖端带有暗橄榄灰色。翼部主要为蓝灰色，外侧飞羽橄榄棕色并带有蓝灰色洗涤痕迹。虹膜深棕色，眼圈黑色，喙和腿均为黑色。雌雄相似，雌鸟略小于雄鸟。幼鸟体羽主要为烟灰色，耳垂小且粉红色。","call":"北岛垂耳鸦的鸣声全年可闻，尤其在晚春和夏季最为频繁。其鸣声是森林中最动听的声音之一，由一系列缓慢执行的丰富、类似管风琴的音符组成，持续约30秒，由两性发出，有时以二重唱形式呈现。鸣唱通常在日出开始，持续60至90分钟，其余时间较为安静，仅偶尔发出轻柔的联系和社会叫声。","habits":"北岛垂耳鸦主要栖息于低地豆杉-桃金娘硬木林及其丰富的下层植被，海拔高度从海平面至至少900米。它们偏好在茂密的森林中活动，偶尔也会出现在灌木丛和再生的次生林，以及邻近领地的成熟异域森林中。它们主要是树栖性的，但在觅食时会滑翔于树木间，缓慢攀爬每棵树寻找食物，然后滑向下一棵树。它们的饮食主要包括树叶和果实，偶尔食用花朵、芽、花蜜和昆虫。它们是不良的飞行者，更倾向于滑翔而非拍打翅膀飞行，且很少一次性飞行超过50米。","breeding":"北岛垂耳鸦一般在南半球春季和夏季繁殖，食物充足时也会在早秋繁殖，产卵期为10月至次年3月，最晚记录到5月仍有巢中幼鸟或离巢雏鸟。巢由粗枝条编织而成，内衬细枝和树叶，隐藏于树叉、树蕨顶、附生植物或藤蔓丛中，大多位于下层林冠或次冠层，距离地面2至38米。每窝产卵1至3枚，通常是2或3枚，卵壳呈粉灰色，不规则散布着棕色和紫棕色斑点，平均大小为38.5毫米×26毫米。孵卵由雌鸟承担，平均孵化期为18天，成功孵化期记录为16至21天。雏鸟由雌鸟照顾，双亲共同喂养，离巢期变化较大，27至42天不等，多数为32至37天，但幼鸟会在同一领地内停留长达一年。","identification":"北岛垂耳鸦与南岛垂耳鸦的主要辨识特征在于耳垂的颜色差异，前者为蓝色，后者为橙色。此外，北岛垂耳鸦的黑色面罩更为广泛，耳垂在繁殖季节颜色更加鲜艳且体积更大。幼鸟的耳垂较小且呈粉红色，与成鸟形成明显对比。","protection":"IUCN：LC（无危）","distribution":"北岛垂耳鸦分布于新西兰北岛，包括Hunua Ranges、Mataraua、Kaharoa、Rotoehu、Pureora和Mapara森林，以及Te Urewera国家公园。通过保护工作，该物种在Little Barrier I、Tiritiri Matangi I和Kapiti I等岛屿上也有分布。","other":"北岛垂耳鸦历史上数量的下降归咎于大规模的栖息地破坏和碎片化，外来掠食者和竞争者的引入加剧了这一问题。尽管目前数量有所回升，但该物种仍完全依赖于保护措施，尤其是控制哺乳动物掠食者，以维持种群增长。"},{"name":"垂耳鸦","english_name":"South Island Kokako","scientific_name":"Callaeas cinereus","overview":"南岛垂耳鸦（英文名：South Island Kokako，学名：Callaeas cinereus），是雀形目垂耳鸦科垂耳鸦属的鸟类。是新西兰特有的雀形目鸣禽，因嘴基部一对下垂的肉质装饰而得名。体长约37厘米，拥有灰色的体羽和黑色的面容，喙角处可见蓝橙相间的条纹。分布于新西兰南岛、斯图尔特岛及其周边小岛，数量极其稀少，被列入濒危物种。","appearance":"南岛垂耳鸦是一种中到大型的森林鸣禽，体长约为37厘米。具有短而宽的向下弯曲的喙，异常长而健壮的腿，长而宽的尾巴，末端呈圆形并有明显的下弯曲线，翅膀宽大且圆。成年南岛垂耳鸦最显著的特点是两侧颚下延伸至脸颊的醒目橙色肉垂，肉垂在繁殖季节会增大且颜色更鲜艳。羽毛主要呈现深蓝灰色，腹部转为灰色，黑色面罩覆盖从喙上方至眼后方及下巴。尾羽深棕色，翼部主要为深蓝灰色，外侧飞羽橄榄棕色带蓝灰晕染。虹膜深棕色，眼圈黑色，喙及腿均为黑色。雌雄外观相似，但雌鸟体型略小于雄鸟。幼鸟较成鸟暗淡，肉垂较小。","call":"南岛垂耳鸦的歌声是一连串长达30秒的缓慢执行的丰富音符，由两性共同发出，有时以二重唱形式。通常从日出开始歌唱，持续约60至90分钟。白天大部分时间保持沉默，但记录了各种安静的联系和社会叫声，包括‘took-took-took’报警声、钟声般的响声和喵喵叫声。","habits":"南岛垂耳鸦栖息于新西兰特有的高树种混生的森林中，如豆科树、南方山毛榉、南部红花木、卡马希树和里穆树，从海平面至林线，偏好植被种类丰富的环境。似乎不在选择性砍伐的森林和其他受干扰的生境中被发现。","breeding":"繁殖期在12月至1月，求偶活动始于10月，幼鸟主要出现在1月至2月，大多数雏鸟在5月前已完全成长。相信为单窝繁殖，一夫一妻制并具有领地意识，巢穴直径约40厘米，深度约9厘米，由树枝和泥炭藓构成，内衬柔软的草，位于密集的灌木丛或植被中。每窝产卵2至3枚，石色带有紫色和棕色斑点，平均尺寸为40.2毫米×27.5毫米；孵化由雌鸟负责，孵化期大约18天；雏鸟的巢期未知，但幼鸟似乎与父母一起生活直至下一个繁殖季节。","identification":"南岛垂耳鸦通过其独特的嘴基部肉垂、体色和鸣叫声与其他鸟类区分开来。此外，它在特定类型的森林中生活，也是识别其的重要线索。","protection":"IUCN：CR (PE)（极危（可能已灭绝））","distribution":"南岛垂耳鸦历史分布于新西兰南岛西海岸、班克斯半岛，以及斯图尔特岛和附近的小岛。最近一次正式确认的记录是在2007年的上因加胡瓦山谷。目前可能已灭绝，最后一次确认的目击记录为2007年。","other":"南岛垂耳鸦的数量在过去几十年间急剧下降，主要原因是栖息地破坏、入侵物种的捕食和竞争。目前，其剩余的栖息地大多受到保护，但该物种的未来仍岌岌可危。"},{"name":"北岛鞍背鸦","english_name":"North Island Saddleback","scientific_name":"Philesturnus rufusater","overview":"北岛鞍背鸦（英文名：North Island Saddleback，学名：Philesturnus rufusater），是雀形目垂耳鸦科鞍背鸦属的鸟类。是新西兰特有的垂耳鸦科鞍背鸦属的中型鸣禽。其显著特征为光泽黑羽配上独特的栗色鞍状斑纹，覆盖背部，赋予其独特名称。广泛分布于新西兰北岛的离岸岛屿及无捕食者的保护区。","appearance":"北岛鞍背鸦体长约25厘米，重61至94克，雄鸟平均80克，雌鸟平均70克。拥有强健微弯的喙，长尾尖圆且向下弯曲，短而圆的翅膀。成鸟羽毛光亮呈黑色，带有金属蓝光泽，胸背部有醒目的暗橙或红棕色鞍状斑纹，边缘有窄黄带，雄鸟的肉垂比雌鸟更大更鲜艳。幼鸟羽毛呈尘土般的棕色，缺乏光泽，腹部有弱化的棕色条纹，肉垂小且呈粉色。","call":"鸣叫喧闹，最常见的是响亮重复的“cheet te-te-te-te”声，由两性发出，穿透力强，能穿越茂密森林。此外，还有一系列安静的接触和社会叫声。","habits":"主要以昆虫和浆果为食，偶尔摄取花蜜。成对或家庭群觅食，活跃于森林各层，从地面落叶到树冠，日间大部分时间都在觅食。会利用强壮的喙翻找树叶和挖掘腐木寻找猎物，也会攀爬树木并在树枝上啄食果实。","breeding":"繁殖季节主要在春季和夏季，食物丰富或种群密度低时，可在早秋繁殖。筑巢由雌鸟单独完成，使用附近找到的枝条，内衬细枝和叶子，通常建于树洞或树冠中。每窝产1至4枚蛋，平均孵卵期18天，雏鸟由双亲喂养，约23至27天后离巢。受多种掠食者威胁，如沼泽鹞、新西兰鹰鸮和新西兰秧鸡。","identification":"与欧亚黑鸫相比，北岛鞍背鸦具有明显的鞍状斑纹和肉垂。不同亚种间的辨识要点尚未详述。","protection":"IUCN：NT（近危）。受限于新西兰北岛的离岸岛屿，面临入侵物种如褐鼠的威胁。全球种群已超过6000只，但依赖于严格管理的无捕食者围栏区。","distribution":"主要分布于新西兰北岛周围的卫星岛，如亨岛和卡皮蒂岛，以及一些尝试建立的大陆围栏保护区。","other":"北岛鞍背鸦是长寿命鸟类，最大记录年龄为21年，常见18至20年。"},{"name":"鞍背鸦","english_name":"South Island Saddleback","scientific_name":"Philesturnus carunculatus","overview":"鞍背鸦（英文名：South Island Saddleback，学名：Philesturnus carunculatus），是雀形目垂耳鸦科鞍背鸦属的鸟类。是新西兰特有的中型鸣禽，身长25厘米，雄鸟平均重85克，雌鸟平均重75克。其显著特征是黑色光亮的羽毛上有一块红褐色的鞍状斑块，位于背部。嘴角有醒目的橙色肉垂。","appearance":"鞍背鸦是一种中型鸣禽，体长约25厘米，体重在61至94克之间，雄鸟平均85克，雌鸟平均75克。其体态特征包括强健的略向下弯曲的喙、长而圆尖的尾巴、短而圆的翅膀。羽毛主要为光泽的黑色，具有金属蓝光泽，最明显的特征是背部到臀部的红棕色鞍状斑纹。脸部肉垂为鲜亮的橙红色，随季节变化而更加显眼。虹膜深棕色，眼圈黑色，喙和腿均为黑色。雌雄羽毛相似，但雄鸟略大且肉垂通常更大。幼鸟的羽毛呈巧克力棕色，头和臀部有赤褐色痕迹，嘴角肉垂较小且呈粉色，初始时有黄绿色口缘线。","call":"鞍背鸦发出独特的叫声，类似于响亮的‘cheeet ta-chet ta-chet ta-chet’声，极具辨识度。","habits":"鞍背鸦栖息于新西兰的森林中，偏好阴凉且茂密的林地，周围有腐木和湿润的苔藓。它们主要以昆虫和浆果为食，偶尔也会食用蜜露、花蜜和特定植物的果实。鞍背鸦在地面和树冠间活跃觅食，会翻动叶子并用强壮的喙挖掘腐木寻找无脊椎动物。","breeding":"鞍背鸦的繁殖活动可能受密度影响，一般在南半球春夏季进行，当食物丰富或种群数量低时，繁殖期会延长至早秋。筑巢由雌鸟独自完成，巢为中等大小的杯状，由附近找到的细枝、苔藓等材料编织，内衬更细的枝条和叶子，偶尔含羽毛，通常建在自然洞穴或树蕨顶端。每窝产卵1-2枚，多数为2枚，由雌鸟孵卵，孵化期约20天。雏鸟由雌鸟照料，双亲喂养，离巢期约为25-27天。","identification":"鞍背鸦通过其背部独特的红棕色鞍状斑纹和脸部的橙色肉垂与欧洲黑鸫明显区分开来。此外，其栖息地局限于新西兰无掠食者的岛屿，也是辨识的重要依据。","protection":"IUCN：LC（无危），无法与任何鼠类或其他引入的哺乳动物共存。全球种群已增至1200多只，具有增长至2500只的潜力。尽管种群状况良好且分布广泛，但剩余岛屿上潜在的捕食者引入仍是一大担忧，尤其是考虑到最近记录的鸟类痘和疟疾爆发。","distribution":"鞍背鸦分布于新西兰南岛的极端东北部和西南部（Motuara岛和Fiordland附近的岛屿）以及斯图尔特岛附近的岛屿。所有现存种群都是从其他岛屿迁移过来的结果。","other":"鞍背鸦面临着外来动物的威胁，如鼬类和狐袋貂，这些捕食者对其生存构成重大挑战。"},{"name":"镰嘴垂耳鸦","english_name":"Huia","scientific_name":"Heteralocha acutirostris","overview":"镰嘴垂耳鸦（英文名：Huia，学名：Heteralocha acutirostris），是雀形目垂耳鸦科镰嘴垂耳鸦属的鸟类。最显著特征为雌雄喙形显著差异，雌鸟喙长且弯曲，雄鸟喙短而粗壮。广泛分布于新西兰北岛的原始森林中，直到1907年最后一次确认目击。","appearance":"镰嘴垂耳鸦拥有深蓝色带绿光泽的黑色羽毛，喙部和腿部为象牙白至灰蓝色，尾羽末端有宽白带。雄鸟长45厘米，雌鸟略大，约48厘米。雌鸟喙长10厘米且向下弯曲，雄鸟喙仅6厘米，短而直。幼鸟具淡色小肉垂，尾羽尖端有淡红褐色晕染。","call":"鸣声多样，包括奇异而独特的口哨声，有时柔软悠扬，如同笛音。叫声在清晨最为响亮，可远传数百米。","habits":"栖息于新西兰北岛的低地和山地原生森林，偏好有丰富腐木的环境。以昆虫、蜘蛛及少数本地植物果实为食，夏季可能在高山森林活动，冬季下降至低地森林避寒。","breeding":"繁殖季为晚春，筑巢于树洞、树枝或近地面处，巢呈大盘状，直径可达35厘米，深7厘米，每次产卵2至4枚，卵呈灰色带有紫色和棕色斑点。","identification":"性别差异明显，雌鸟喙长而弯，雄鸟喙短而粗，通过喙形可轻易辨别。此外，雄鸟头部肌肉发达，适应于啄食腐木。","protection":"IUCN：EX（已灭绝）","distribution":"原产于新西兰北岛，分布范围涵盖从北端至南端的Aorangi山脉，尤其在Ruahine、Tararua、Rimutaka和Kaimanawa山区的原始森林中。","other":"在毛利文化中占有重要地位，尾羽被视为珍宝，用于装饰和贸易。最后一次确证目击时间为1907年，其灭绝可能与栖息地破坏、过度猎杀及引入物种有关。"},{"name":"须吸蜜鸟","english_name":"Stitchbird","scientific_name":"Notiomystis cincta","overview":"须吸蜜鸟（英文名：Stitchbird，学名：Notiomystis cincta），是雀形目缝叶吸蜜鸟科缝叶吸蜜鸟属的鸟类。仅限于北岛及周边无掠食者的离岸岛屿。其最显著特征为雄鸟的黑色头部、醒目的白色耳羽簇及黄色颈肩带。分布于新西兰北岛及卫星岛。","appearance":"成年雄性须吸蜜鸟具有天鹅绒般黑色的头部，白色耳羽簇，以及一条鲜艳的黄色颈肩带。雌鸟和幼鸟仅具有白色翼条。雄鸟背部呈灰色至深褐色橄榄色，下体浅棕色，具深色条纹。雌鸟较小，上部橄榄褐色，缺乏黄色特征，下体偏白，有暗褐色斑点。幼鸟类似雌鸟，但颜色更暗淡。","call":"两性都会发出尖锐的单音警告叫声'titch'。雄鸟还会发出2-3音符的哨声。","habits":"偏好密集的本土森林，季节性移动以利用开花或结果。活跃于各种树冠层，偶尔地面觅食。主要食物为花蜜、果实和小型节肢动物。","breeding":"繁殖期为9月/10月至2月/3月，筑巢由雌鸟单独完成，位于成熟树木的树洞中。每窝产卵3-5枚，孵化期13-19天，幼鸟孵化后26-32天离巢。","identification":"与铃鸟区别在于缺乏绿色色彩，尾巴常翘起，翼上有白色斑块。","protection":"IUCN：VU（易危）","distribution":"分布于新西兰北岛及其周边离岸岛屿，包括小屏障岛、提里提里马塔吉岛、卡皮蒂岛以及北岛的两个保护区。","other":"须吸蜜鸟曾广泛分布于北岛及邻近岛屿，但至19世纪80年代中期，自然种群仅限于小屏障岛。"},{"name":"绿背鹛鸫","english_name":"Papuan Whipbird","scientific_name":"Androphobus viridis","overview":"绿背鹛鸫（英文名：Papuan Whipbird，学名：Androphobus viridis），是雀形目啸冠鸫科绿背鹛鸫属的鸟类。中等体型、罕见而神秘的啸冠鸫科鸟类。其橄榄绿色的羽毛和较长的尾巴是显著特征，雄鸟拥有黑色的喉部和胸部，以及一道独特的白色髭纹。分布于新几内亚西部山脉，如韦兰德山脉、纳索山脉、奥兰治山脉和南部高地省的塔里峡谷。","appearance":"绿背鹛鸫体长约16-17厘米，比澳大利亚的鞭鸟小。雄鸟具有明显的白色髭纹和黑色喉部，而雌鸟通体呈现苔藓绿色，幼鸟颜色更深，面部和下体偏黑。其羽毛色彩随成长而变化。","call":"其鸣声为上升的哨音，类似宝石雀的叫声，同时伴有轻微的责备式低鸣。","habits":"绿背鹛鸫生活在海拔1,400至2,700米的山地森林中，偏好茂密的林下层。它们似乎以昆虫为食，通常成对出现，非常隐秘，除非在鸣唱时才容易被发现。","identification":"与扇尾蓝莓啄木鸟雌鸟的区别在于，绿背鹛鸫缺乏较浅的腹部颜色、尾部的白色、侧条纹和喙基部周围的淡色。","protection":"IUCN：LC（无危）。绿背鹛鸫的分布范围、种群数量和趋势以及面临的威胁信息不足，其栖息地的偏远可能有助于保护它免受人类活动的影响。","distribution":"绿背鹛鸫分布于新几内亚西部中央山脉，包括韦兰德山脉、纳索山脉（哈贝马-伊贝勒河区域）、奥兰治山脉（戈利亚特山）和南部高地省的塔里峡谷。","other":"尽管记录的地点有限，但绿背鹛鸫可能在更广泛的范围内存在。由于其栖息地的陡峭和难以接近，它似乎不太受栖息地破坏的影响。"},{"name":"绿啸冠鸫","english_name":"Eastern Whipbird","scientific_name":"Psophodes olivaceus","overview":"绿啸冠鸫（英文名：Eastern Whipbird，学名：Psophodes olivaceus），是雀形目啸冠鸫科啸冠鸫属的鸟类。独特的‘鞭裂’叫声是当地森林中标志性的声音。物种分为两个亚种，外观上以橄榄绿色和黑色为主，具有醒目的白色颊斑和小黑冠。雄鸟和雌鸟在外表上相似。","appearance":"绿啸冠鸫长约25至30厘米，体重47至72克。头部和胸部呈黑色，背部为暗橄榄绿色。具有一块明显的白色颊斑，腹部颜色较淡，尾部深橄榄绿色并带有白色尖端。眼睛棕色，喙和脚黑色。雄鸟略大于雌鸟。幼鸟色泽较为暗淡，缺乏成鸟的白色颊纹和深色喉部。","call":"绿啸冠鸫的叫声以其独特的‘鞭裂’声闻名，这是由雄鸟的长音和‘鞭裂’声以及随后雌鸟的回应声组成。这种叫声在清晨最为频繁，偶尔在中午和傍晚也有发生。","habits":"栖息于雨林、湿桉树林和河岸植被，偏好沟壑和低矮密集的植被。海拔高度从海平面至1500米。主要食物为昆虫和其他小型无脊椎动物，偶尔也食用小蜥蜴、青蛙、种子、嫩芽和果实。绿啸冠鸫在地上或低植被中觅食，有时也会在树干和枝叶间搜索。","breeding":"繁殖季节为7月至11月在昆士兰东北部，7月至翌年2月在新南威尔士州，9月至10月在维多利亚州。通常一季繁殖两次。巢为精致的杯状，由树枝、草和根茎构成，内部铺垫柔软材料，建于地面以上0.3至3米的密植处。每窝产卵1至3枚，通常为2枚，孵化期16至18天。雌鸟负责孵卵，雄鸟协助喂养。","identification":"绿啸冠鸫与其它物种的区别在于其独特的叫声、黑色头部和胸脯、橄榄绿色背部以及白色的颊斑。亚种间的辨识主要基于地理位置和轻微的色彩差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东部，从维多利亚州向北至昆士兰州中部。北部亚种（ lateralis）见于昆士兰北部热带雨林区，从库克镇至汤斯维尔。","other":"绿啸冠鸫历史上曾被错误分类，现已确定属于啸冠鸫科。"},{"name":"黑喉啸冠鸫","english_name":"Black-throated Whipbird","scientific_name":"Psophodes nigrogularis","overview":"黑喉啸冠鸫（英文名：Western Whipbird，学名：Psophodes nigrogularis），是雀形目啸冠鸫科啸冠鸫属的鸟类。啸冠鸫属中体型中等、尾具黑白横带的特有鸟类，仅见于澳大利亚西南与东南部的灌丛和桉树矮林。因喉部具显著黑色斑块且具响亮的“鞭响”二重唱而闻名，目前被分为4个亚种，受栖息地破碎化与火灾频率改变影响，总体呈下降趋势。","appearance":"体长19–25.5厘米，体重约45克。指名亚种头顶及短三角冠羽灰褐，脸与后颈橄榄褐，眉纹近白；上体橄榄色带灰；翼灰橄榄，飞羽、初级覆羽及大覆羽内翈褐色；尾灰橄榄，除中央一对外各羽具向外渐宽的黑端斑及淡色端缘（内淡黄向外变白）。具细黑髭纹及宽白亚髭纹，颏至喉至上胸黑色；胸腹橄榄灰，中央有模糊近白色纵纹，胁橄榄褐，尾下覆羽褐色；虹膜暗红至褐色；嘴黑色或烟黑色；腿深灰。两性同色。幼鸟无髭纹及腹部黑色；亚成体似成鸟，但亚髭纹带褐色，黑喉带淡斑。亚种leucogaster体色更灰，翅尾更长，尾端斑更宽清晰，黑髭纹较模糊或缺失，黑喉范围小；lashmari似leucogaster但更暗，尾端斑更宽；oberon亦近似，但翅尾更长，黑髭纹显著。","call":"歌声嘹亮，可传800米，具“腹语”效果，为雌雄轮唱的二重唱，雌雄歌段不同且几乎无缝衔接，乍听似单一个体；雄鸟先发出高而多变的刺耳哨音“it’s a tééchers pet”，雌鸟随即回应较短、变化少的“ti-tickerr-teaar”。联络叫声为咯咯“chuck”；警戒时发出斥责般的“churr”，或两声后接上上扬颤音。","habits":"栖于灌丛高度1.5–2米的密灌丛，或为沿海石南灌丛，或为2–5米高的桉树矮林（内陆）。留鸟；在西南角两洋湾环志个体在1971–1977年间多次被重捕。以节肢动物为主食，主要是昆虫及少量蜘蛛，也食小型软体动物。主要在地面觅食，偶在低植被；翻动枯叶、探查落枝或从低矮枝叶上啄食，偶在树干上觅食；仅用喙翻动叶片。","breeding":"繁殖季7–10月，一夫一妻制。全年占域；与邻鸟对唱，边界处常见追逐。巢由雌鸟独自建造，为粗壮的碗状巢，由枝条、树皮、草（沿海为莎草）构成，内衬细枝、草及细树皮条；指名亚种巢外径10.2–14.5厘米、高7.2–12厘米、内径6.7–8厘米、深4–5.5厘米；置于距地面不足1米的低密灌丛中（常低于0.5米）。领域面积因地而异，沿海灌丛约2.8–5.6公顷，桉树矮林约12公顷。每窝2枚卵，淡蓝色具黑斑、斑块及条纹，大小25.7–27.7×18–22毫米；雌雄轮流孵卵，夜间仅雌鸟，白天雌鸟比例逐渐增加；孵化期21天。雏鸟由双亲共同育雏10天，10–12日龄离巢，能奔跑但不能飞，至少由亲鸟再喂养2个月；若两雏，双亲各负责一只。小样本中孵化成功率80%，54%雏鸟成功出飞。","identification":"与同属地栖啸冠鸫属其他种为姐妹群关系，可通过黑色喉斑、尾端黑白横带及响亮二重唱区分。亚种间差异：leucogaster、lashmari、oberon曾被提议为独立种，但形态及鸣声差异有限，且遗传证据不足；与指名亚种相比，leucogaster体色更灰，翅尾更长；lashmari更暗；oberon翅尾最长且具更显著黑髭纹。","protection":"IUCN: LC（无危）。目前整体被视为近危。属狭域分布种，见于西南澳大利亚EBA与东南澳大利亚EBA。因栖息地清理、破碎化及火灾制度改变，历史上曾大幅收缩分布区，现存多个孤立小种群。各亚种评估：指名亚种约2500只繁殖鸟，分布300平方公里，虽脆弱但略增；oberon约10000只繁殖鸟，分布800平方公里，数量下降；leucogaster约2000只繁殖鸟，不足200平方公里，濒危且下降；lashmari约5000只繁殖鸟，分布500平方公里，稳定。火灾为主要威胁，多数地区需14–25年方可重新定居，部分地点需30–50年。","distribution":"繁殖区：西南澳大利亚的Two Peoples Bay（指名亚种）；西南澳大利亚内陆mallee灌丛（oberon）。东南澳大利亚：南澳大利亚Yorke半岛、Eyre半岛及Murray Mallee，西北维多利亚（leucogaster）；南澳大利亚东南外海的袋鼠岛（lashmari）。非繁殖区：留鸟，无迁徙。","other":"亚种pondalowiensis（南Yorke半岛）已被并入leucogaster。"},{"name":"东啸冠鸫","english_name":"Chirruping Wedgebill","scientific_name":"Psophodes cristatus","overview":"东啸冠鸫（英文名：Chirruping Wedgebill，学名：Psophodes cristatus），是雀形目啸冠鸫科啸冠鸫属的鸟类。以独特的‘chirruping’叫声而得名，主要分布于澳大利亚中东部的低矮灌木丛地带，如蓝布什和金合欢树丛中。这灰褐色的鸟，具有暗色尾巴和明显的白色翼带，头部顶着一个小巧前弯的羽冠。","appearance":"东啸冠鸫体型丰满，长约19.5至20厘米，重约39至42克。其显著特征是拥有一个向前弯曲的暗棕色羽冠，通常带有黑色尖端；上体灰褐色，翅膀略深于背部颜色；尾部暗灰或棕色，除中央一对外，其余尾羽宽幅末端为白色；下巴、喉咙和腹部中间呈偏白色，胸部和两侧腹部为淡灰褐色，比上体颜色更浅，形成对比，胸部有轻微模糊的条纹，下尾覆羽为棕色；眼睛深棕色，喙为黑色，腿为深灰色。雌雄相似，幼鸟与成鸟相似但颜色更浅，羽毛更蓬松，二级飞羽和上翼覆羽边缘呈淡肉桂色，喙为淡色；未成年个体也类似成鸟，但喙为角棕色，二级飞羽和翼覆羽边缘颜色更浅。","call":"东啸冠鸫的叫声独特，由一两个快速音符后接一段快速下降的颤音“（chit-）chit cheeeeeeeeeer”，重复频率高，这是其与其它种类区分的重要标志。","habits":"东啸冠鸫栖息于低矮灌木丛，尤其偏好蓝布什和金合欢树丛，以及沼泽和水道周围的密集植被。它们的生活习性尚不完全清楚，没有大规模迁徙的记录，但可能因应当地资源呈现游牧特性；在某些地区被认为是居民鸟。已知标记个体的再捕获地点均在其初次环志地点的10公里范围内。它们以昆虫和一些种子为食，单个、成对或小群体觅食，偶尔加入混合物种觅食群。它们在地上觅食，据说也会在低矮植被中觅食。","breeding":"繁殖季节从7月至次年3月，多数产卵期为8月至12月，可能受降雨量调节，每季可产一窝或以上。巢为开放的杯状，由小树枝构成，有时掺杂草、根须和干茎，内部铺垫草和根须，外部直径12.7至13.3厘米，高度6.4至7.6厘米，内部直径6.4至7厘米，深度3.8至5.1厘米；巢置于地面以上0.45至4.6米（平均1.5米）的浓密灌木或小树的分叉处，或浓密植被中的槲寄生丛中。每次产卵2或3枚，蛋壳为浅蓝色或蓝绿色，带有小黑点、深紫色斑点、污点和条纹，平均尺寸为24.8×17.7毫米；孵化由两性共同承担，孵化期14至17天；两性都参与喂养雏鸟，关于雏鸟期的持续时间尚无信息。","identification":"东啸冠鸫与西啸冠鸫在外观上极为相似，主要通过叫声和分布范围来区分。东啸冠鸫的胸部有微弱的条纹，尾巴略长，且重复的‘chirruping’叫声是识别关键。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中东部，具体包括昆士兰州西南部、南澳大利亚东北部和新南威尔士州西北部。","other":"东啸冠鸫与鸣啸冠鸫直到1973年前还被视为单一物种，后因叫声差异明显而被区分为两个独立的物种。"},{"name":"西啸冠鸫","english_name":"Chiming Wedgebill","scientific_name":"Psophodes occidentalis","overview":"西啸冠鸫（英文名：Chiming Wedgebill，学名：Psophodes occidentalis），是雀形目啸冠鸫科啸冠鸫属的鸟类。有时亦被称为‘chiming whipbird’。其分布局限于澳大利亚，主要在西澳大利亚中西部至北领地东南部和南澳大利亚中部地区。西啸冠鸫与鸣楔鸫曾被视为同一物种，直到1973年因显著的鸣叫差异而被区分为两个独立物种。","appearance":"西啸冠鸫体型丰满，通体呈现灰褐色，具有一条较暗的尾巴和白色翼带。头部有一向前弯曲的显眼小冠羽，通常黑色尖端。成鸟的喙短而粗壮，颜色较深，而幼鸟的喙色较浅。上体颜色较深，翅膀比背部更暗，尾羽除中央一对外均广泛白色尖端。下体颜色偏淡，胸腹部为灰褐色，与上体颜色对比不大。虹膜呈深棕色，腿脚为深灰色。雌雄外观相似，幼鸟羽毛较为蓬松，边缘带有浅肉桂色。","call":"其鸣唱独特而响亮，由4至6个下降的钟声般的音符组成，最后一个音符强烈且带有金属质感，常被描述为‘did-you-get-drunk’或‘sweet-Kitty-Lintof’，声音单调却贯穿晨昏。","habits":"西啸冠鸫栖息于干旱的灌木丛地带，尤其偏好生长有金合欢树（Acacia aneura）、扫帚灌木、桉树和针茅草的河岸。它们可能在大部分范围内保持定居状态，但在干旱地区可能出现局部迁移。饮食以昆虫和种子为主，观察到会在地面觅食。","breeding":"繁殖季节集中在1月至3月及7月至9月。巢为扁平杯状，由小枝和草构成，内部铺有草，筑于低树或灌木的水平或垂直分叉处，离地高度0.5至3米。每窝产卵2至3枚，卵色为浅蓝色或蓝绿色，带有黑色和深紫色斑点，平均尺寸为24.5×17.5毫米。据报道，孵化期约为17天，但关于双亲角色的信息尚缺。雏鸟由两位个体喂养。","identification":"西啸冠鸫与鸣楔鸫在外观上几乎相同，主要区别在于鸣叫。此外，两者的分布范围也有差异。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚西中部至北领地东南部和南澳大利亚中部，包括西澳大利亚州的中西部至北领地的东南部和南澳大利亚的中部。","other":"在澳大利亚最西端的分布区域，西啸冠鸫的数量有所下降，这可能是由于外来兔种（Oryctolagus）的影响和火势管理的改变所致。"},{"name":"白腹冠鸫","english_name":"White-bellied Whipbird","scientific_name":"Psophodes leucogaster","overview":"白腹冠鸫（英文名：White-bellied Whipbird，学名：Psophodes leucogaster），是雀形目啸冠鸫科啸冠鸫属的鸟类。澳洲南部特有种。曾在维多利亚州消失40年，直到2022年在Big Desert Wilderness Park再次被发现其歌声。此物种曾被认为是黑喉冠鸫的一个亚种。","appearance":"白腹冠鸫具有独特的外观，腹部呈白色，与其他部位的羽毛形成鲜明对比。具体的身体尺寸和其他特征在现有资料中未详述。","habits":"白腹冠鸫生活在澳洲沿海中南部的栖息地中。","identification":"与黑喉冠鸫相比，白腹冠鸫最显著的区别在于其白色的腹部，这是辨识两者的关键特征。","protection":"IUCN：LC（无危）","distribution":"白腹冠鸫分布于澳新界的澳大利亚沿海中南部，具体包括沿海地带的南部区域。","other":"现为黑喉啸冠鸫亚种。"},{"name":"斑丽鸫","english_name":"Spotted Jewel-babbler","scientific_name":"Ptilorrhoa leucosticta","overview":"斑丽鸫（英文名：Spotted Jewel-babbler，学名：Ptilorrhoa leucosticta），是雀形目鹑鸫科丽鸫属的鸟类。主要分布于新几内亚山脉的热带湿润山地森林中。","appearance":"中等体型，拥有长尾巴，适应地面生活的山地森林鸟。灰色腹部，栗色顶冠，翼部有大而明显的白色斑点。脸部两侧及喉部中间有一条狭窄的白色带，上部黑色，下部有小白点。背部颜色因亚种而异，呈现绿色或棕色。雌雄外观相似，幼鸟则呈棕橄榄色，腹部较淡，上翼覆羽有淡锈色尖端。","call":"鸣唱为一系列7至30个短促低沉的钟鸣般的哨音，常以渐强音结束。报警声为尖锐的嘶哑声，伴随嘶嘶声；其他叫声包括微弱的“tsip”声和几个爆炸性的音节。","habits":"栖息于新几内亚高地的亚热带或热带湿润山地森林，具体生活习性细节未详。","identification":"与相似的栗背丽鸫相比，斑丽鸫体型较小，翅膀有斑点，缺乏蓝色羽毛。不同亚种在背部颜色和胸部斑点上有差异。","protection":"IUCN状态未知。","distribution":"主要分布于新几内亚山脉的亚热带或热带湿润山地森林。"},{"name":"蓝丽鸫","english_name":"Blue Jewel-babbler","scientific_name":"Ptilorrhoa caerulescens","overview":"蓝丽鸫（英文名：Blue Jewel-babbler，学名：Ptilorrhoa caerulescens），是雀形目鹑鸫科丽鸫属的鸟类。深蓝色的体羽和白色的喉部与上胸部，以及穿过眼至喙部的宽黑带构成鲜明对比，使它在低地森林中易于识别。在新几内亚的Markham山谷，当地人称之为birisis。主要栖息于热带湿润的低地森林，偏好原始森林而非次生林。","appearance":"蓝丽鸫体型中等，尾巴较长，身长22厘米，体重49-61克。雄鸟全身深蓝色，除白色喉部至胸部上部，这一部分被黑色宽带环绕，从眼部延伸至颈部侧面和胸部。翅膀暗灰黑色，内侧初级飞羽外缘带有蓝色调，次级飞羽外缘全蓝。尾羽呈暗褐色，边缘泛蓝。雌鸟与雄鸟相似但体型略小，白色喉部延伸至眼的下缘。幼鸟似雌鸟，但下体颜色偏褐。neumanni亚种雄鸟与指名亚种难以区分，雌鸟具白色眉纹；nigricrissus亚种尾下覆羽部分黑色，雌鸟有细白眉纹。","call":"鸣唱为一系列强烈哨音，音调下降或保持均匀，可能以响亮尖锐的“chít”或上扬的“swééít”结尾。还有一种上升音调后跟一连串音量渐增的音符，‘tsip fish-fish-fish-fish-fish-fish-físh-físh-físh-físh-físh-físh’。报警和攻击叫声为重复的尖锐‘chóp’，随后是快速的‘ti-ti-ti-ti’。","habits":"蓝丽鸫栖息于雨林、季风林、相邻的高大次生林和画廊森林，偏好潮湿环境。生活在低地和丘陵地带，海拔约300米以下，高于此高度由栗背丽鸫取代，两者几乎没有海拔重叠。该物种为留鸟，已知环志个体在同一地点多次被捕获，持续数年。主要以昆虫为食，在地面觅食，使用喙翻转树叶，探查裂缝。喂食时会拍打翅膀，可能是为了惊飞昆虫。","breeding":"繁殖季节从旱季中期到雨季早期，至少在9月中旬和12月下旬发现筑巢产卵，10月中旬和11月中旬观察到幼鸟离巢。领地性明显。巢为深杯状，由枯叶和棕榈叶片制成，内衬细根须，置于树根间凹陷处或小树基部的地面。每窝产卵2枚，卵壳呈淡褐色，有细小的灰色斑点和条纹，大端有一圈深褐色带，尺寸约为23.5×19.3毫米。关于孵化和育雏期的信息未知。已知环志个体寿命超过5年7个月。","identification":"蓝丽鸫通过其深蓝色背部和冠部与Chestnut-backed和Dimorphic物种区分开来。在地理分布上，通常按海拔与Chestnut-backed分离，而与Dimorphic按地理位置分离，尽管存在轻微的潜在重叠，但蓝丽鸫具有独特的蓝色背部和头部。","protection":"IUCN：LC（无危）","distribution":"蓝丽鸫分布于澳新界，具体包括四王群岛（新几内亚西北部）和新几内亚。"},{"name":"棕头丽鸫","english_name":"Brown-headed Jewel-babbler","scientific_name":"Ptilorrhoa geislerorum","overview":"棕头丽鸫（英文名：Brown-headed Jewel-babbler，学名：Ptilorrhoa geislerorum），是雀形目鹑鸫科丽鸫属的鸟类。分布于新几内亚东北部的Adelbert山脉和休恩半岛东部，以及东南部的坡北地区，地面活动的森林鸟类。","appearance":"体长约22至23厘米，尾长。雄鸟具灰褐色冠羽，略带蓝灰色，背部呈丰富蓝色，黑眼线贯穿眼部下方至颈部侧面；喉部白色，边界有黑色颈环，下胸至腹部均为丰富蓝色，翼羽暗灰黑，次级飞羽外缘全蓝；尾羽深褐色，外缘蓝染。雌鸟上体为暗褐色或橄榄褐色，臀部深栗色，眼后有淡棕色眉纹，下体深栗色至尾下覆羽。幼鸟似雌鸟，但眉纹白色且不明显。","call":"鸣唱为一连串口哨般的钟声，起初短而微弱，渐变成长音、高音且响亮；另有快速低音口哨及三音节响亮短语“tou tou-wheee”，有时伴随高音渐强至低音的模糊音符。警报声为连续急促的哨声。","habits":"栖息于低地和山脚森林，海拔主要在700至800米，Adelbert山脉可达至少1220米。以昆虫和其他小型动物为食，包括青蛙。地面觅食，边走边翻动落叶。","breeding":"领域性强。巢穴和窝卵数数据未知；已知蛋壳颜色为土黄色至红灰色，带有黄灰色和灰褐色斑点，集中在较宽端，尺寸约31.6×23.4毫米。","identification":"与蓝丽鸫在地理上分离，但雌鸟具有独特的棕色羽毛和眼后淡棕色条纹，雄鸟有灰色冠羽。与栗背丽鸫的区别在于后者兼具蓝色和棕色。","protection":"IUCN：LC（无危）","distribution":"分布于新几内亚东北部的Adelbert山脉和休恩半岛东部，以及东南部的坡北地区。","other":"普遍常见，但极为害羞，通常听到声音的机会远多于见到其身影。"},{"name":"栗背丽鸫","english_name":"Chestnut-backed Jewel-babbler","scientific_name":"Ptilorrhoa castanonota","overview":"栗背丽鸫（英文名：Chestnut-backed Jewel-babbler，学名：Ptilorrhoa castanonota），是雀形目鹑鸫科丽鸫属的鸟类。中等体型的地面栖息鸟类，深蓝色的腹部和翅膀，明亮的白色喉部被黑色条纹环绕，雄鸟的臀部呈蓝色，而雌鸟为栗色。分布于新几内亚的山地森林中，栖息于约300至1450米的海拔高度。","appearance":"体长22-24厘米，体重70-74克。雄鸟具宽阔的蓝色眉纹，从额侧延伸至耳羽和颈侧，脸部黑色，眼圈至耳羽有一条黑色边界，额头蓝色，冠部红棕色，披肩和上背部栗色，其余上体部分蓝色。飞羽深灰黑色，内侧初级飞羽外缘带有蓝调，次级飞羽外缘全蓝；尾部蓝色；下体蓝色，尾下覆羽尖端黑色；虹膜深褐色；喙黑色；腿暗灰棕色。雌鸟与雄鸟相似，但上体至尾上覆羽为栗色，蓝色眉纹较窄。幼鸟主要为暗淡的棕色，喉部白色。不同亚种在颜色深浅和某些部位的色调上有细微差异。","call":"发出一系列细薄的哨声，随后是长哨音和下降滑音或快速高音逐渐增强的哨声，有时会接着六个响亮的下滑哨音，‘chuchuchuchuchughu’；还会发出上升的哨声系列和短促高音的嗡嗡声。警戒声是一连串响亮的、常成对出现的音符，‘chewchew chewchew’。","habits":"栖息于丘陵和低山森林地带，主要以昆虫为食，可能也会吃小型蛙类。在地面觅食，用喙翻动落叶。生活方式似乎为定居。","breeding":"繁殖季节可能包括旱季和湿季初期，至少在某些地区。巢为浅开杯状，由旧叶和叶骨架构成，内部衬以极细的根须。每窝产卵1或2枚，蛋壳颜色为浅粉色或淡黄色，带有深红褐色和灰色斑点或黄褐色斑点覆盖着煤黑色斑点（标记可能集中在较大的一端或散布在整个蛋壳上），尺寸约为28.3-29.4×21.6-22.7毫米。关于繁殖行为的其他信息有限。","identification":"与蓝宝石鹦鹉和二态鹦鹉类似，但栗背丽鸫具有栗色的背部和冠部，通常在海拔高于蓝宝石鹦鹉的区域发现。雄鸟和某些雌鸟的亚种具有蓝色的眼上纹，而其他雌鸟则有浅色眼上纹。","protection":"IUCN：LC（无危）；在Varirata国家公园内有分布。","distribution":"分布于新几内亚的山地森林中，主要栖息于海拔约300至1450米的高度，最高可达1580米左右。","other":"栗背丽鸫虽然常见，但由于其害羞的天性，更常被听到而非见到。"},{"name":"斑鹑鸫","english_name":"Spotted Quail-thrush","scientific_name":"Cinclosoma punctatum","overview":"斑鹑鸫（英文名：Spotted Quail-thrush，学名：Cinclosoma punctatum），是雀形目鹑鸫科鹑鸫属的鸟类，是澳大利亚中东部特有种，主要分布在澳大利亚的东南部和塔斯马尼亚州。地面活动的鸟类，具有灰色的胸部和头部，两侧有黑色斑点，长长的淡色眉纹是其显著特征之一。","appearance":"斑鹑鸫体型中等，长24至30厘米，体重雄鸟约119克，雌鸟约107克。雄鸟有明显的特征，如长而狭窄的白色眉纹，黑色的眼前区、喉部和髭纹，以及一个大而圆的白色喉部斑块，边缘为黑色。雌鸟较为暗淡，喉部呈浅色，下喉有大的浅红褐色斑块。它们的上部羽毛橄榄棕色，带有粗黑条纹，下体部分灰白色，腹部有黑色断续带，侧面和尾下覆羽黄褐色，黑色的羽毛中心形成重叠的条纹。","call":"斑鹑鸫的鸣唱包括柔和的双音哨声，第二个音调较高，通常重复10到12次。接触叫声是一系列非常尖锐的‘tseep’音符，报警时会发出缓慢的磨擦音。","habits":"生活在干燥的硬叶林和灌木丛，尤其偏爱岩石山坡。斑鹑鸫以昆虫为主食，包括甲虫、蝽象、直翅目、蝇类、膜翅目和鳞翅目昆虫，偶尔也会捕食小型脊椎动物如蜥蜴，同时也吃多种植物的种子。它们在地面上觅食，用喙翻动落叶和枯枝败叶。","breeding":"繁殖季节为7月至次年2月，南部地区稍晚。雌鸟单独筑巢，用干草、叶子和树皮松散搭建，内部铺垫更细软的材料。巢置于地面凹陷处，靠近树、灌木、岩石或草丛基部。每窝产卵2枚，偶尔3枚，卵壳淡白色，带有深棕色斑点和薰衣草色标记。孵化期约为14天，由雌鸟负责，雏鸟在大约14天后离巢，尚未能飞行时还会返回巢中几个晚上。","identification":"雄鸟和雌鸟的颜色差异明显，雄鸟具有独特的黑色喉部和白色斑块，雌鸟喉部较淡，下喉有浅红褐色斑块。与其它鹑鸫属物种相比，斑鹑鸫的黑色侧斑和眉纹是主要辨识特征。","protection":"IUCN：LC（无危）。然而，斑鹑鸫的某些亚种，如anachoreta亚种，自20世纪30年代以来已极为罕见，最后一次记录是在1984年，可能已经处于极度濒危状态，甚至可能已经灭绝，主要是由于栖息地的破坏和碎片化以及严重的火灾影响。","distribution":"斑鹑鸫主要分布于澳大利亚中东部、东南部以及塔斯马尼亚州，这些地区为其繁殖地。","other":"斑鹑鸫在某些地区的数量有所下降，这主要归因于栖息地的改变或丧失。然而，它们能在砍伐森林的地区重新定居，只要再生的植被不过于密集，有时需要在砍伐后25至35年才能重新出现。"},{"name":"栗鹑鸫","english_name":"Chestnut Quail-thrush","scientific_name":"Cinclosoma castanotum","overview":"栗鹑鸫（英文名：Chestnut Quail-thrush，学名：Cinclosoma castanotum），是雀形目鹑鸫科鹑鸫属的鸟类。主要分布于澳大利亚东南部，包括南澳中部、新南威尔士州西部和维多利亚州西北部。其最显著的外部特征包括深栗褐色背部和复杂的羽翼图案，以及独特的白色眉纹和胡须纹。雌雄有别，雄鸟具有黑色胸部和灰色侧腹，而雌鸟则呈现灰色胸部和腹部，上体颜色较淡。在开放的灌木林地和灌丛地带活动频繁。","appearance":"雄性栗鹑鸫长21-26厘米，体重73-83克。头部上方有一条细长的白色眉纹延伸至颈背侧面，黑色面纹从眼周至喉部边缘，白色须纹从下喙至喉部。冠羽、颈背和耳羽呈棕色，逐渐过渡至灰色。背部、臀部和尾上覆羽灰棕色，带有不明显的黑色细纹，下背部和肩羽深栗色。翅膀黑色，边缘浅棕色，初级飞羽基部有奶油白条纹，三级飞羽有黑色中央纹和淡赤棕色边缘。尾羽中央对深棕灰色，其余尾羽黑色，端部宽白。雌鸟相似但较暗淡，面部无黑色，上体栗色减少且更淡，肩羽灰棕色，喉至胸淡灰色，下体有奶油色底纹，尾下覆羽奶黄色，带暗褐色条纹。幼鸟与雌鸟类似，但上体、喉、胸和侧腹有深棕色斑点。","call":"鸣唱为颤音重复的单调哨声，柔和但传播远，有时融合成颤音。联系叫声为高音尖锐的虫鸣似“tsee”。警报和求救叫声由刺耳音符、喘气声和尖锐“kwit-kwit”组成，还会发出类似鼠类的吱吱声。","habits":"栖息于多低矮灌木的灌丛地带，如金合欢（Acacia）和桉树（Eucalyptus），常见于干旱和半干旱区域，通常位于沙质土壤上。以昆虫为主食，尤其是甲虫、蝽象和直翅目昆虫，也吃种子，食物长度通常1-2毫米，最大可达6-7毫米。地面觅食，沿曲折路径前进，偶尔啄食，会用脚按住食物啄食。","breeding":"繁殖季节为7月至12月，雄鸟自黎明起歌唱。产卵期在8月至12月之间（视降雨量而定），每次产2至3枚蛋，蛋壳颜色为乳白色至奶油色，表面散布黑色褐斑。在地面筑巢，利用周围植被如树皮、草和树枝搭建小凹槽状巢穴。","identification":"与桂红鹑鸫和栗胸鹑鸫相比，栗鹑鸫的侧面为灰色而非温暖的棕色。雄鸟的黑色胸部和灰色侧腹，以及雌鸟的灰色胸部和腹部，是识别特征。不同亚种间上体的栗色带宽度和亮度有所不同。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚东南部，包括南澳大利亚中部至新南威尔士州中部和维多利亚州西北部。","other":"已知在火灾或栖息地严重干扰后，可能1.5至2年内在当地消失。"},{"name":"铜背鹑鸫","english_name":"Copperback Quail-thrush","scientific_name":"Cinclosoma clarum","overview":"铜背鹑鸫（英文名：Copperback Quail-thrush，学名：Cinclosoma clarum），是雀形目鹑鸫科鹑鸫属的鸟类。2015年自栗鹑鸫分离出来。其自然生境为地中海型灌木植被。","appearance":"雄鸟成鸟有长达眉线的白色超眉纹，黑色条纹延伸至喉咙侧边，边界清晰的白色髭纹，棕色的冠部、颈背和耳羽，灰色的后颈和颈侧，灰棕色的背部、臀部和上尾覆羽带有不明显的黑色细纹，深栗色的下背和肩羽，黑色的翅膀带有淡棕色边缘，初级飞羽基部有奶油白条纹，尾羽中央一对暗灰褐色，其余尾羽黑色带宽白尖，胸部黑色，腹部白色，两侧灰色，翼下覆羽白色，有显著的黑色条纹。雌鸟相似但较暗淡，面部无黑色，上体的栗色减少且更淡，肩羽灰棕色，胸部至腹部浅灰色，翼下覆羽奶油色，有暗棕色条纹。幼鸟像雌鸟，但上体、喉部、胸部和两胁有深棕色斑点。","call":"发出颤音重复单调的口哨声，柔和但传播远，有时融入颤音。接触叫声为高音刺耳的‘tsee’声；警报和求救声包含粗哑的音符、呼气声和尖锐的‘kwit-kwit’声；也会发出类似鼠类的吱吱声。","habits":"栖息于干旱和半干旱地区的金合欢（Acacia）和桉树（Eucalyptus）低矮灌木丛下层，通常在沙质地基上。以昆虫为主食，尤其是甲虫（Coleoptera）、蝽（Hemiptera）和直翅目昆虫；也吃种子；食物尺寸通常为1-2毫米，但也有记录到6-7毫米的食物。在地上觅食，沿着刻意而蜿蜒的路线前进，不时用喙啄食；在啄食时会用脚固定物品。","identification":"与桂红鹑鸫和黑胸桂红鹑鸫的区别在于侧面为灰色而非温暖的棕色。","protection":"IUCN：LC（无危）。局部地区较为常见，东部种群（指名亚种）被认为是‘近危’。栖息地的改变和丧失，以及牲畜的放牧，导致了局部种群的消失或碎片化。在火灾或大规模栖息地扰动后1.5至2年内曾记录到该物种消失。指名亚种出现在维多利亚州的Wyperfeld国家公园。","distribution":"分布于澳大利亚中西部至中南部，具体包括维多利亚州等地。"},{"name":"桂红鹑鸫","english_name":"Cinnamon Quail-thrush","scientific_name":"Cinclosoma cinnamomeum","overview":"桂红鹑鸫（英文名：Cinnamon Quail-thrush，学名：Cinclosoma cinnamomeum），是雀形目鹑鸫科鹑鸫属的鸟类。澳大利亚特有种，主要栖息于澳大利亚中部的干旱和半干旱地区。雄鸟具有独特的白眉、黑脸和侧颈白色条纹，而雌鸟则呈较暗淡的色彩，喉部为淡黄色。幼鸟标记与成鸟相似，但雄鸟可能有不明显的胸带。","appearance":"成年雄鸟拥有黑色眼罩，窄奶油色眉纹延伸至枕部侧面，棕色灰色耳羽；黑色狭窄的髭纹沿颈部继续向下，下方由宽阔的白色次髭纹环绕，后者因黑色喉咙和下巴而更加突出；头部和颈部其余部分为棕色灰色，冠部泛着浅红棕色；上体红棕色，上背泛着浅灰色；飞羽为深褐色，外缘窄红棕色；翼尖和大部分上翼覆羽为黑色，尖端白色；内侧大覆羽红棕色，窄黑纹；中央尾羽红棕色，其余尾羽深褐色，具宽白色尖端；胸部中心白色，向两侧渐变为浅肉桂红棕色，狭窄的黑色胸带上方为白色腹部，黑色断续线从下胸部侧面向后延伸到臀部覆羽的侧面；虹膜红棕色；喙黑色；腿灰黑色。雌鸟与雄鸟的区别在于眼罩为灰棕色，颊区淡黄色，肩羽较暗淡且对比度较低，喉咙和下巴为奶油黄，胸部淡棕色灰色，无白色次髭纹，下部无黑色侧纹。幼鸟上体和下体有斑点。","call":"鸣唱为一系列音调相同或两个音调的音符。联络呼叫为高音、类似昆虫的哨声；报警时发出咯咯声。","habits":"主要栖息于石质平原和台地上的低矮灌木覆盖区，偶尔出现在沙丘上。似乎定居，无大规模迁徙证据，但可能根据条件进行局部移动。以种子、昆虫和蜘蛛为主食，在地面觅食，缓慢而有目的地行走，通常围绕灌木基部活动，使用喙在沙中挖掘。","breeding":"繁殖记录全年都有，时间可能受降雨影响；可能双窝育雏，但在严重干旱时期放弃繁殖。领地性。巢为松散的杯状，由草、树皮和树枝构成，内部衬以草，外部直径6.3-10.2厘米，内部直径7.6厘米，深度3.2厘米，置于树、灌木或岩石底部的地表凹陷处。每窝产卵2枚（有时3枚），卵白色或乳白色，带有橄榄棕色斑点和覆盖在薰衣草色斑块上的细小斑点，通常在较大端最密集，平均尺寸28×20毫米；孵化由雌鸟负责，偶尔雄鸟也会参与；雌鸟和可能雄鸟都会喂养雏鸟和离巢幼鸟；关于孵化和离巢期持续时间的信息不足。在遭遇入侵者时，会采用装伤的分散注意力展示，可能朝着入侵者奔跑，同时垂下翅膀并展开尾巴。","identification":"雄性铜背鹑鸫的胸部为黑色，而黑胸桂红鹑鸫具有与喉咙相连的实心黑色胸带。雌鸟与雄鸟相比，颜色较为暗淡，喉部为淡黄色，无黑色下部标记。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚中部和南部，包括西南昆士兰、西北新南威尔士、东北南澳大利亚和北领地东南部。","other":"曾被视为与黑胸桂红鹑鸫和栗胸鹑鸫同种，目前认为有两亚种。"},{"name":"黑胸桂红鹑鸫","english_name":"Nullarbor Quail-thrush","scientific_name":"Cinclosoma alisteri","overview":"黑胸桂红鹑鸫（英文名：Nullarbor Quail-thrush，学名：Cinclosoma alisteri），是雀形目鹑鸫科鹑鸫属的鸟类。仅见于澳大利亚南部的Nullarbor平原。其最显著的外部特征是雄鸟个体具有独特的黑喉和黑色胸带，形成倒置的‘T’形状。","appearance":"成年黑胸桂红鹑鸫约20厘米长，体重50至67克。雄鸟具有富丽的红褐色前额、冠、颈侧和上体，白色眼后眉纹，黑色颊部和狭窄的黑色髭纹，下方为宽大的白色次髭纹，突出的黑色喉部和喉咙，翅膀覆羽黑色，尖端白色，内侧大覆羽深红褐色；中央一对尾羽深红褐色，其他尾羽黑褐色，尖端白色；胸部全黑，下体其余部分白色，侧翼带有红褐色斑点和黑色条纹；虹膜红棕色；喙黑色；腿灰黑色。雌鸟头部多为灰色，具有细白上眶线和眉纹，颊部、喉咙和脸颊区域呈淡黄色，上身颜色较暗，翅膀覆羽较暗且对比度较低，胸部中灰色，下部无黑色侧纹。幼鸟上下体斑驳。","call":"叫声包括高音长哨声‘seeeep’。","habits":"黑胸桂红鹑鸫是地面觅食者，通常只有在觅食时才可见。它们积极移动，尽管方式杂乱无章，翻转石头寻找种子和小型无脊椎动物。在开阔的平原上，这种鹑鸫能够远距离发现接近的物体，并迅速躲藏在灌木下或引入的兔子洞穴中。非繁殖季节时，它们可能以小群体出现。","breeding":"繁殖期间，一对鹑鸫会保卫领地。繁殖可能发生在一年中的任何适宜时间，但通常在8月至9月间。繁殖地点可能是由雌鸟刮入土中的轻微凹陷处，或是靠近灌木、岩石或草丛的一片区域，用植物材料条纹铺垫。每次产卵数量通常是两枚，尺寸约为28 x 20毫米，蛋壳为乳白色，带有棕色或灰色斑点。","identification":"雄性黑胸桂红鹑鸫的连续黑色从喉咙延伸到胸部，与两侧的栗色形成对比，而雌鸟的头部更偏灰色，上体颜色较暗。与铜背鹑鸫相比，雄鸟具有连续的黑色胸带。","protection":"IUCN：LC（无危）。这种物种虽然不多见，但由于家畜放牧和引进的兔子影响，以及不可预测的降雨和火灾互动，其数量已有所下降。","distribution":"分布限于澳大利亚南部的Nullarbor平原，横跨西澳大利亚东南部和南澳大利亚西南部。","other":"历史上，它常被视为与同种，但基于分子证据，最近主张其为独立物种。"},{"name":"栗胸鹑鸫","english_name":"Chestnut-breasted Quail-thrush","scientific_name":"Cinclosoma castaneothorax","overview":"栗胸鹑鸫（英文名：Chestnut-breasted Quail-thrush，学名：Cinclosoma castaneothorax），是雀形目鹑鸫科鹑鸫属的鸟类。是澳大利亚特有种，主要分布在昆士兰中西部至新南威尔士州中北部的半干旱沙漠地带。以其独特的栗色胸部和复杂的羽色图案著称。","appearance":"雄鸟拥有奶油色眉纹，光泽黑喉部，深红棕色胸部带黑色边缘，白须纹和黑色喉斑。头部和颈部暗灰褐色，背部深棕灰色，翼上有黑白标记，腹部白色，胸部有宽红棕色带。雌鸟类似，但色彩较淡，喉部和脸颊橙色，胸部淡棕色，侧身和腰部红棕色。幼鸟类似雌鸟，但上体和下体有斑点。","call":"叫声包括一系列相同音调的哨音，有时首音较高，也有高音的‘seep’声。","habits":"栖息于干燥的林地灌木丛，尤其是mulga树下的低矮植被，常在石质地面活动。以昆虫、蜘蛛和种子为食，觅食时缓慢行走，用喙啄食。","breeding":"繁殖季节变化，通常在7月至9月间开始筑巢，可能尝试多次繁殖，视条件而定。巢由草、叶和枝条构成，放置于灌木或树下的地面凹陷处，每次产两枚，罕见三枚，蛋壳白色，有薰衣草色斑点和深棕色斑点覆盖。","identification":"与桂红鹑鸫相比，栗胸鹑鸫的眉纹更浅，雄鸟的胸部中央有白色部分。","protection":"IUCN：LC（无危）。由于生境改变和过度放牧，需要持续监测，已从分布区东部边缘消失。","distribution":"分布于澳大利亚中东部，从昆士兰中西部至新南威尔士州中北部。","other":"在Diamondina国家公园有记录。"},{"name":"西鹑鸫","english_name":"Western Quail-thrush","scientific_name":"Cinclosoma marginatum","overview":"西鹑鸫（英文名：Western Quail-thrush，学名：Cinclosoma marginatum），是雀形目鹑鸫科鹑鸫属的鸟类。是澳大利亚特有的一种小型陆生鸟类。主要特征包括灰棕色背部、斑点腹部和翼上的黑白标记。雄鸟拥有独特的白色髭纹、黑色喉部斑块、红褐色胸部逐渐过渡到侧面，以及白色边缘的黑色腰带覆盖在白色腹部之上。西鹑鸫广泛分布于西澳大利亚的半干旱和干旱地带。","appearance":"西鹑鸫体型约21-25厘米，体重约65克。雄鸟头部顶部深灰色，其余部分黑色或深黑色，有明显的窄白色眉纹和宽阔的白色髭纹；上体大部分为赤褐色，翼覆羽粗大白尖；具有赤褐色胸带，与喉部由窄淡色带分隔，后方有狭窄的白色带和更宽的黑色带，后者继续作为赤褐色侧腹与白色腹部的边界；虹膜深棕色；喙黑色；腿灰色至灰黑色。雌鸟外观相似，但颜色较暗淡，对比度较低；下巴和喉咙呈淡黄褐色；胸带灰色，侧腹橙褐色，没有明显的白色/黑色边界。幼鸟似雌鸟，但斑驳感更强。","call":"鸣叫声包括一系列5-11个渐快的吹哨声，音调基本不变，最后一个音有时会延长，通常随后跟一两个非常短的高音调上升音符，‘pi..pi..pi-pi-pi-pi-peee...tswee..see-see-see’。还有几种高音调的叫声，包括一系列短促重复的音符‘tsee..tsee..tsee..tsee’，或较长的单音符‘tseeeee’。","habits":"西鹑鸫栖息于干燥的林地灌木丛中，位于半干旱和干旱地区的石质地面。它们在冬季繁殖，繁殖季节从1月持续到9月。其食物以节肢动物为主，包括蜘蛛和昆虫，通过在地上缓慢行走并用喙啄食来觅食。","breeding":"西鹑鸫主要在雨后繁殖，以应对干旱环境。它们的筑巢期为3月至9月，巢似绿色草碗，由草叶和树枝编织而成，直径约15厘米，深度约5厘米，通常位于灌木或树下。每次产卵2枚，偶尔3枚，卵为白色，带有薰衣草色和栗褐色斑点。雌雄双方共同孵化，但雌鸟主要负责孵卵和喂养幼鸟。","identification":"与桂红鹑鸫相比，西鹑鸫有更淡的眉纹，雄鸟的胸部中心为红色而非白色。此外，雄性西鹑鸫的下胸黑斑更宽。","protection":"IUCN：LC（无危）。西鹑鸫在其分布范围内常见，但栖息地破坏和过度放牧对其造成威胁。","distribution":"西鹑鸫主要分布在西澳大利亚州的中西部至南澳大利亚州西南部和北领地西南部，适应干旱和半干旱环境。","other":"西鹑鸫曾被认为是桂红鹑鸫的亚种，但分子证据显示它更接近黑胸桂红鹑鸫和桂红鹑鸫。"},{"name":"彩鹑鸫","english_name":"Painted Quail-thrush","scientific_name":"Cinclosoma ajax","overview":"彩鹑鸫（英文名：Painted Quail-thrush，学名：Cinclosoma ajax），是雀形目鹑鸫科鹑鸫属的鸟类。中等体型的地面栖息鸟类，主要分布在新几内亚的丘陵森林和低地森林中。","appearance":"其特征包括棕色的尾巴、背部和冠纹，黑色面罩，白色腹部，以及红褐色的两侧。雄鸟具有黑色的喉部和胸部，以及脸部上明显的白色条纹，而雌鸟则拥有白色的喉部和细长的淡白色眉纹。","call":"鸣唱由三个下降的哨声组成，前两个短促，最后一个较长，随后是一声爆发式的“Whip！”叫声。","habits":"彩鹑鸫偏好生活在亚热带或热带湿润的低地森林环境中，活动范围受限于特定的地理区域。","identification":"与相似体型的蓝丽鸫和栗背丽鸫相比，彩鹑鸫不具备任何蓝色的羽毛，这是辨识的关键特征。","protection":"IUCN：LC（无危）","distribution":"彩鹑鸫在澳新界零星分布于新几内亚西部、南部和东南部，其分布呈斑块状。"},{"name":"非洲鵙鹟","english_name":"African Shrike-flycatcher","scientific_name":"Megabyas flammulatus","overview":"非洲鵙鹟（英文名：African Shrike-flycatcher，学名：Megabyas flammulatus），是雀形目钩嘴鵙科非洲鵙鹟属的鸟类。是钩嘴鵙科非洲鵙鹟属的唯一物种，广泛分布在非洲西部和中部的森林地带。该鸟以独特的红眼和白臀斑而著称。","appearance":"雄鸟成鸟上身光泽蓝黑，下身纯白，尾部宽大且呈钩状，喙黑色，腿色从紫红到深粉或棕色，爪黑色，眼红色。雌鸟头部和背部呈暗褐色，逐渐过渡至背部的赤褐色，臀部橙褐，尾羽中央深褐，两侧渐变为赤褐色边缘，下身白色，密布深褐色条纹，眼橙褐色。幼鸟上身棕色，有淡色斑点，下身白色，杂有棕色条纹和斑点。","call":"鸣叫包括下降的'PWHEEEeeeer'声，单个'cherdew'叫声，以及变化多端、几乎机械式的双音节短语，如'perit-perit, tchledew-tchledew'。","habits":"栖息于森林环境，包括原始森林、次生林、林缘、旧种植园，高度从12至36米不等，海拔从海平面至2150米。可能为热带内的迁徙鸟种，如在加蓬东北部仅于11月至3月出现。以多种昆虫为食，如甲虫、直翅目和鳞翅目昆虫，主要捕食15至25毫米大小的昆虫。","breeding":"繁殖季节在几内亚、利比里亚和加纳为3月，在象牙海岸为12月至5月，在喀麦隆为5月，在加蓬为1月，在安哥拉为3月，在刚果民主共和国北部为4月，东部则全年均可繁殖。筑巢于树叉处的暴露枝条上，高35至40米（偶尔低至15米），巢由树皮碎片和苔藓构成，通过蛛丝固定。孵化期至少16天，雏鸟离巢时间未详，但据说是'长时间'。","identification":"与黑白领鵙鹟相似，但非洲鵙鹟有白色喉部且无顶冠，雌鸟腹部有条纹。","protection":"IUCN：LC（无危）","distribution":"非洲鵙鹟分布于安哥拉、贝宁、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、科特迪瓦、赤道几内亚、加蓬、冈比亚、加纳、几内亚、肯尼亚、利比里亚、马里、尼日利亚、塞拉利昂、南苏丹、坦桑尼亚、多哥、乌干达和赞比亚。","other":"在某些地区，如刚果民主共和国，非洲鵙鹟在次生林中非常常见，甚至在人类居住区附近也能见到。"},{"name":"黑白鵙鹟","english_name":"Black-and-white Shrike-flycatcher","scientific_name":"Bias musicus","overview":"黑白鵙鹟（英文名：Black-and-white Shrike-flycatcher，学名：Bias musicus），是雀形目钩嘴鵙科黑白鵙鹟属的独特鸟类，分布于非洲西部、中部至东南部，包括安哥拉、贝宁、喀麦隆等地。其显著特征为雄鸟拥有醒目的黑白色调，而雌鸟则呈现暗褐色头部与栗色背部。该物种偏好栖息于湿润森林的树冠层，活动于低海拔至中海拔地带。","appearance":"雄性黑白鵙鹟身长16厘米，体重约20-30克，具厚实体型，长冠羽及短尾。上体光泽黑色，翼基白色，形成宽广的翼斑；喉部及上胸亦为光泽黑色，其余下体白色，两胁带有黑色新月形图案。眼睛黄色明显，喙宽且黑色，腿黄色，爪黑褐色。雌鸟外观差异大，头部深棕色，背部栗色，翅膀呈栗色，带有棕色和黑色混合的色彩；下体白色带肉桂色，两胁有棕色条纹。幼鸟类似雌鸟，但上体有浅色条纹，年轻雄鸟逐渐显现出混杂的棕色黑色背部。","call":"鸣唱多样，包含模糊的哨音，叫声包括粗糙的鼻音双音节接触声，以及更清晰的类似八哥的音符。","habits":"栖息于原始森林和次生林，常见于加蓬和刚果东部近人类居住区，进入东非的农田和花园。活动范围从海平面至1700米高。以昆虫为主食，包括膜翅目、双翅目、直翅目和鞘翅目昆虫，偶尔捕食蜘蛛和蜥蜴。在树冠边缘活跃觅食，常飞向树叶下捕捉昆虫，也能在空中捕食，动作敏捷。","breeding":"繁殖季节在利比里亚为4月至5月，在加蓬为10月至11月，刚果民主共和国也有记录。筑巢于树枝末端，通常靠近道路或河流，高度从低处到高达30米，巢为小而浅的杯状，由植物纤维构成，外表覆盖蛛网。每窝产2-3枚蛋，孵化期18-19天，幼鸟在巢附近停留22-27天，直至下一个繁殖季节。","identification":"雄性黑白鵙鹟的独特黑白配色，以及雌鸟的暗褐色和栗色组合使其易于辨识。与同属其他物种相比，其短尾和长冠羽特征鲜明。","protection":"IUCN：LC（无危）","distribution":"分布于西非的几内亚比绍至南苏丹，乌干达和坦桑尼亚西北部，南至安哥拉北部和刚果民主共和国西南部；在肯尼亚中部和坦桑尼亚沿海至马拉维南部、津巴布韦东部和莫桑比克南部也有零星分布。","other":"其生存状况在肯尼亚受到威胁，由于森林砍伐，该物种在当地变得非常罕见。"},{"name":"褐背鹟鵙","english_name":"Bar-winged Flycatcher-shrike","scientific_name":"Hemipus picatus","overview":"褐背鹟鵙（英文名：Bar-winged Flycatcher-shrike，学名：Hemipus picatus），是雀形目钩嘴鵙科鹟鵙属的小型鸟类。俗名: 褐背花伯劳，显著特征为黑白相间的羽毛，头部、背部及尾羽呈黑色光泽，颈侧及腹部为白色，翼部有明显白色条纹，尾羽外侧白色。广泛分布于亚洲热带森林，从喜马拉雅山脉到印尼群岛。","appearance":"体长约14-15厘米，体重8.5-9.5克。雄鸟成鸟头部、背部、翅膀呈黑亮色，脸颊和颈部侧面为白色；臀部白色，上臀部带黑色横纹，尾上覆羽黑色；中大飞羽和初级覆羽具宽白尖，内侧次级飞羽具纵向白边；尾羽黑色，仅中央羽毛无白尖，最外侧羽毛边缘白色；下巴和喉侧纯白色；下体灰白色，胸部略带紫红色，腹部更白，尾下覆羽和翼下覆羽白色；大腿灰色；虹膜红棕色；喙黑色；腿深灰至黑色。雌鸟类似雄鸟，但黑亮部分为烟黑色。幼鸟似雌鸟，但臀部白色条纹窄，尾上覆羽尖端白色，其余上体和小翼羽烟褐色带淡色羽缘，中大飞羽和次级飞羽淡黄白色带两细窄棕色条纹，次级飞羽和三级飞羽尖端和边缘淡黄白色，下体全淡黄色；亚成鸟似雌鸟。","call":"发出尖锐的“chisik”或“chir-rup”声，以及较短的“tsik”声；还有高音颤音反复的“wiraka”声。","habits":"偏好高大的开放森林冠层及低地森林边缘，包括受干扰的森林环境；也见于次生林、竹林、灌木丛、种植园和远离真正森林的园林。在山区可达2100米高度，繁殖季节主要在喜马拉雅区域的600-1800米。以昆虫为食，包括蝴蝶、甲虫、飞蚁和飞白蚁。常加入混合物种觅食群，以飞捕的方式捕食，从常规使用的暴露枝头垂直起飞捕猎。偶尔也会从地面捕食。","breeding":"繁殖期为2月至8月在印度次大陆，4月在缅甸，2月和4月在马来半岛，3月至7月在中国。巢由两性共同建造，为小巧浅杯状，由根、细枝、苔藓和草制成，用蛛网加固，置于离地3-12米的树枝上。每窝产2-3枚蛋，两性共同孵卵和抚育幼鸟，但孵化和离巢期未知。","identification":"与黑翅鹟鵙相比，翼部和尾羽尖端有白色。雌雄异色，雄鸟更黑亮。亚种intermedius颜色更深，capitalis雄鸟具黑色顶冠和深棕色披肩，leggei无性别差异。","protection":"IUCN：LC（无危）","distribution":"分布于喜马拉雅山脉从印度西北部至中国东部，印度半岛和斯里兰卡，越南，印尼的苏门答腊岛和婆罗洲。在喜马拉雅山区域主要在600-1800米的高度繁殖。","other":"在一些受保护区域常见，如尼泊尔的皇家奇旺国家公园、印度的科比特国家公园、泰国的Kaeng Krachan国家公园和马来西亚半岛的Taman Negara国家公园。"},{"name":"黑翅鹟鵙","english_name":"Black-winged Flycatcher-shrike","scientific_name":"Hemipus hirundinaceus","overview":"黑翅鹟鵙（英文名：Black-winged Flycatcher-shrike，学名：Hemipus hirundinaceus），是雀形目钩嘴鵙科鹟鵙属的鸟类。体长约15厘米，雄鸟上体呈黑色带绿光泽，下体白色，胸灰色，腹部白。雌鸟上体为烟褐色，而非黑色。幼鸟具棕色喙，上体烟褐，羽缘浅色。分布于马来半岛至苏门答腊、婆罗洲、爪哇和巴厘岛，生境多样，包括低地森林、沼泽和红树林。","appearance":"体长14-15厘米，体重10-14克。雄鸟头部、上体及翅膀黑色，带绿色光泽，颊和颈侧白色，臀部白色，背部有黑色横纹，尾黑色，最外侧羽毛边缘白色。雌鸟类似雄鸟，但黑色部分替换为烟褐色。幼鸟上体烟褐色，羽缘浅色，翼覆羽宽幅浅色，次级飞羽和三级飞羽尖端浅色，尾羽边缘和尖端白色。","call":"发出粗糙的‘tu-tu-tu-tu-hee-tee-tee-teet’和‘hee-too-weet’声，穿插着高音‘cheet-weet-weet-weet’。","habits":"栖息于森林树冠，包括淡水沼泽森林、高大的次生林和森林边缘，也会出现在红树林、成熟的种植园和树木繁茂的花园。活动于海拔低至1100米，但在爪哇和巴厘岛可达1500米。加入混合物种觅食群，捕捉树叶下的小昆虫。","breeding":"繁殖期在马来半岛为4月至6月，在苏门答腊为1月至4月和8月至11月，在婆罗洲为8月至9月。巢由两性共建，形状为杯状或截顶锥形，以苔藓、树皮碎片、纤维、苔藓和蜘蛛网制成，置于7至40米高的水平树枝上。每窝产卵2枚，由双亲共同喂养和孵化。","identification":"与褐背鹟鵙相比，本种缺乏翅膀和尾尖的白色，雌鸟上体为烟褐色。幼鸟上体羽缘颜色不同于成鸟。","protection":"IUCN：LC（无危）","distribution":"分布于远东地区的马来半岛，印尼苏门答腊岛，Simeulue和尼亚斯岛（西部，印尼苏门答腊岛北部），Riau和Lingga is.（东部，印尼苏门答腊岛中部），邦加岛和勿里洞岛（东部，印尼苏门答腊岛南部），爪哇岛，巴厘岛，婆罗洲和Banggi（北部，婆罗洲东北部）。","other":"其自然栖息地为低地森林，偶尔可见于沼泽和红树林。"},{"name":"钩嘴林鵙","english_name":"Large Woodshrike","scientific_name":"Tephrodornis virgatus","overview":"钩嘴林鵙（英文名：Large Woodshrike，学名：Tephrodornis virgatus），是雀形目钩嘴鵙科林鵙属的鸟类。中南半岛至东南亚热带地区的常见鸟类。其特征是厚实的喙和明显的鼻羽簇。分布于印度、尼泊尔、不丹至中南半岛，南至印度尼西亚，中国境内见于云南、广西、广东、海南和福建。偏好低地和丘陵森林，最高可达1500米。","appearance":"体长18.5至23厘米，体重28.3至46克。雄鸟具白色前额，蓝黑色面罩延伸至眼周和耳羽；上身蓝灰色，下背白，翼羽和覆羽蓝灰至黑色，次级飞羽和三级飞羽多为蓝灰色；尾羽和上尾覆羽黑色；下体白，胸略带灰粉。雌鸟较雄鸟暗淡，上翼覆羽更淡，面罩较淡且棕色。幼鸟上体棕色，冠至肩部有白色羽轴和尖端，翼覆羽和三级飞羽有条纹。","call":"鸣声为连续的单调哨音，起始一两个音符有时较低沉。也频繁发出刺耳的咔哒声。","habits":"栖息于常绿阔叶林、混交落叶林、森林边缘、伐木林区高树、次生林和林地；偶尔出现在过密的柚木种植园、树木花园和红树林。以大型昆虫为主食，如螳螂、蟋蟀、竹节虫、蚱蜢、甲虫、蜻蜓、大型蛾子和毛虫。通常成对或小群活动，有时加入混合种类的觅食群。","breeding":"繁殖期在印度和东南亚为12月至6月，中国为7月。筑巢于3至9米高的水平树枝上，巢由细草茎、根、枝条和藤蔓交织而成，内衬蛛网。每窝产2至5枚蛋，主要由雌鸟孵卵。幼鸟出生时盲且裸体。","identification":"与林鵙相比，钩嘴林鵙体型更大，喙更粗重，无白色眉纹，臀部白色较多，尾部无白色。不同亚种在体型、上体和下体颜色上有差异。","protection":"IUCN：LC（无危）。在中国、尼泊尔和印度的保护区内较为常见，但在马来半岛因栖息地丧失而被视为‘近危’。","distribution":"分布于东洋界，广泛见于南亚和东南亚的低地和丘陵森林，包括印度、尼泊尔、不丹、中南半岛、印度尼西亚的苏门答腊、爪哇和婆罗洲。","other":"有记录显示，该物种在新加坡已经灭绝，但在苏门答腊和婆罗洲的森林中仍然频繁出现。"},{"name":"西钩嘴林鵙","english_name":"Malabar Woodshrike","scientific_name":"Tephrodornis sylvicola","overview":"西钩嘴林鵙（英文名：Malabar Woodshrike，学名：Tephrodornis sylvicola），是雀形目钩嘴鵙科林鵙属的鸟类。体型较大的林鵙属鸟类，通体呈暗灰色，翼与尾更深，具明显的黑色面罩与淡黄虹膜，下体纯白，分布于印度西高止山脉的常绿林、林缘及林隙，属该区的特有留鸟。","appearance":"体长16.5–18.5厘米。成鸟上体灰暗灰褐，翼覆羽形成较暗的翼斑，尾羽深灰并常带褐调；头侧具宽阔黑色面罩，无浅色眉纹；下体除喉胸略沾灰褐外几乎纯白。雄鸟头顶至上背呈深蓝灰色，三级飞羽及次级飞羽端缘略浅，眼下有白色细纹；喙全黑，虹膜黄色。雌鸟上体暗石板褐，黑色面罩较淡，腰羽具白缘，有时次级飞羽外缘具细暗横斑；喙暗褐，下喙基部色浅。幼鸟似雌鸟，但飞羽及尾羽缘淡色更明显，下喙基部更浅。","call":"鸣唱常以短促沙哑音起头，接2–3个“ker-wíck”或“wícky-wícky”响铃般双音组，每句2–3秒，每秒2–3组，可重复；长句先快后慢且音高下降。叫声包括低沉鼻音“gwup”及粗糙刺耳的“rasps”，与近缘种叫声类似但更低沉。","habits":"栖息于常绿林边缘及林隙，偏好较湿润的中上层，活动范围自低地至海拔1800米，但多见于较低处。留鸟，局部有季节性短距离或垂直移动。以大型昆虫及幼虫为主食，偶见成对或5–10只小群活动，非繁殖季常加入混合觅食群，与山椒鸟、卷尾等共栖；多在树冠或下层枝叶间缓慢移动觅食，极少下地，通过啄叶、短距离突袭及探树皮缝隙等方式捕虫，亦会掠取水面昆虫。","breeding":"繁殖期1–4月（喀拉拉邦），若首巢失败可再筑。巢为苔藓、纤维、树皮片及地衣以蛛丝缠结而成的浅碟，置于离地8–13米的水平枝或主干基处。12巢记录均建于柚木和榄仁树，筑巢需8–12天。每巢产卵2枚，乳白至淡黄底具褐、灰、淡紫斑，孵化期15–16天，雏鸟期约17天。喀拉拉研究显示孵化成功率26.6%，整体巢成功率13.3%，每对平均育雏0.33只，有四巢在产卵前即遭破坏。","identification":"与同属的钩嘴林鵙（原视作同种）相比，具更大的黑色面罩、更深的灰黑色上体及尾羽，体型亦更大，鸣唱为双音组而非单音，音调略低。与分布重叠的林鵙相比，偏好更湿润的森林生境且缺少浅色眉纹。","protection":"IUCN: LC（无危）。总体数量被认为稳定且在当地尚称常见，但于古吉拉特邦可能已局部灭绝，即便在保护区内亦极罕见。该种已知出现于佩里亚尔虎保护区等多个保护单元。","distribution":"繁殖区：印度西部西高止山脉，自果阿向南，并见于东南古吉拉特（苏拉特丹格斯地区）。非繁殖区：无迁徙，局部有短距离移动。","other":"过去被视为钩嘴林鵙的亚种，因体型、羽色、鸣声差异而被提升为独立种，目前为单型种，无亚种分化。"},{"name":"林鵙","english_name":"Common Woodshrike","scientific_name":"Tephrodornis pondicerianus","overview":"林鵙（英文名：Common Woodshrike，学名：Tephrodornis pondicerianus），是雀形目钩嘴鵙科林鵙属的鸟类。中等体型的鸟类，上体灰褐色，面部有黑色面罩，臀部白色，尾巴灰色带白色外缘羽毛。喙呈强烈钩状，暗灰褐色。下体白色，与西钩嘴林鵙和大型鵙相似，但在较干燥的森林中更为常见。白眉显著。栖息于干燥森林和灌木丛地带。","appearance":"雄鸟标本体长13至18厘米，体重18至27克。上体棕灰色，头部有明显的白色眉纹，眼周至耳羽黑色，臀部羽毛带小白色尖端，尾羽黑色，外侧两对尾羽白色，端部有黑色斑点。脸颊和下巴白色，喉部和下体白色，胸部淡灰，有时新鲜羽毛带粉色调。腋下和翼下覆羽灰白色。虹膜暗黄色，喙暗褐色，腿暗灰色。雌鸟类似雄鸟，但面罩略浅。幼鸟上体更棕色，头顶和颈背有白色斑点，上翼覆羽有宽白色尖端，喉侧和胸部有斑驳的暗褐色。成鸟的亚成体特征未完全描述。亚种pallidus比标本更苍白，上方更灰，下方奶油色；orientis更暗，上方深棕色，有白色臀带，强烈的白色眉纹，下方有强烈的棕色色调。","call":"明亮快速的鸣唱开始于两个尖锐的'wheeet'音符，随后是一系列下降的短音符。叫声多样，但通常听起来像是歌曲的孤立片段。","habits":"栖息于开阔的龙脑香森林、干落叶森林、次生林、竹林、荆棘灌木、Olea cuspidata灌木林、巴基斯坦的林地、果园、桉树种植园、花园、树篱和干燥开阔地带带有散落的树木。主要生活在低地，海拔主要低于400米，局部可达1600米。常以成对或5至8个个体的小群体出现，经常加入混合物种觅食队伍，尤其是与红喉姬鹟、扇尾莺和偶尔与大型鵙一起。在树冠层搜索昆虫，也会飞扑捕食飞行中的昆虫，有时在地上取食。","breeding":"繁殖季节主要为2月至7月，印度则为1月至9月，尤其3月至5月。一夫一妻制。巢由双方共同建造，大约4至5天，小而整洁的浅杯状巢，由苔藓、地衣、树皮或根构成，用蛛丝粘合，内部铺有毛发或植物绒毛，放置于树干水平叉处，高度2至9米，通常低于6米，有时隐藏在茂密的树叶中。每窝产卵2至4枚，卵呈淡绿灰色或乳白色，带有红棕色、紫棕色和灰色斑点，平均大小19毫米×15.1毫米，间隔约24小时产下一枚，孵化期约14至16天，由双方轮流孵卵。雏鸟孵化时盲眼无毛，之后获得深灰色绒毛，由双方喂养，但没有关于离巢期的信息。","identification":"与大型鵙和西钩嘴林鵙相似，但体型较小，喙较小，有白色眉纹和白色外侧尾羽。亚种间颜色差异明显，如pallidus和orientis。","protection":"IUCN：LC（无危）。在其分布范围内相当普遍。在印度次大陆广泛分布且常见；尼泊尔局部地区较为常见。东南亚常见。","distribution":"广泛分布在亚洲，主要栖息于薄森林和灌木丛生环境，从印度次大陆到东南亚。","other":"斯里兰卡的形态曾被视为亚种，现通常被认为是一个独立的物种，即斯里兰卡林鵙。"},{"name":"斯里兰卡林鵙","english_name":"Sri Lanka Woodshrike","scientific_name":"Tephrodornis affinis","overview":"斯里兰卡林鵙（英文名：Sri Lanka Woodshrike，学名：Tephrodornis affinis），是雀形目钩嘴鵙科林鵙属的鸟类。拥有厚实的喙、深色面罩和白色眉纹。腹部呈淡白色，飞行时可见白色的臀部。主要栖息于斯里兰卡低地和较低山丘的林木地带及灌木丛，尤其是干燥区；避开密集湿润的森林。树栖物种，常见于成对或小群体出现。与体型更大、喙同样厚重的钩嘴林鵙相比，其苍白的眉纹和平淡的下体羽毛有助于辨识。","appearance":"体型12.8至14.2厘米，相较于之前被归为同种的林鵙，成年斯里兰卡林鵙具有较短的尾巴，眉纹不明显，背部颜色更深，呈板岩灰色，臀部更多白色，翅膀呈灰褐色，飞羽边缘带灰色。雌鸟色彩较暗淡，上体呈棕色，下体带灰褐色，眉纹更显著。幼鸟和初次换羽冬季羽毛与林鵙相似年龄的个体非常相像，但有白色臀斑和眉纹减弱。","call":"鸣唱为一系列甜美响亮的“fit-fwít-fwít-fwít-fwéét-fwéét”音符，每秒约4个音符，每节持续3至4秒，通常被认为比前同种林鵙的类似鸣声更为清脆，少有拖沓。亦发出较短、粗糙、音调起伏的模糊版本的鸣唱，有时开始带有快速气泡声；厚实、颤音的“chyup”叫声，每隔几秒重复一次，声音不如林鵙尖锐悦耳，以及短暂、低沉、略降调的“fyew”。","habits":"栖息于多种开放的林地环境，包括林间空地和路边，主要位于低地，但在山区可上升到中等海拔。关于觅食行为和饮食的信息尚无，但可能与林鵙相似。","breeding":"筑巢主要在3月至5月期间；数据很少，但从有限资料来看，巢和巢址似乎与林鵙相同。","identification":"与林鵙相比，斯里兰卡林鵙有较短的尾巴、不显眼的眉纹、较深的板岩灰色背部和更多的白色臀部。此外，鸣叫声和音调也有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于东洋界，具体在斯里兰卡，主要在干燥区较为常见，而湿地区则更为稀少且分布局限。"},{"name":"棕翅王鵙","english_name":"Rufous-winged Philentoma","scientific_name":"Philentoma pyrhoptera","overview":"棕翅王鵙（英文名：Rufous-winged Philentoma，学名：Philentoma pyrhoptera），是雀形目钩嘴鵙科王鵙属的鸟类。体型中等至较大的森林鸟类，外表模糊，似帝王鸟与天堂燕尾的结合体。部分雄鸟拥有温暖的红褐色翅膀与洁净的白色腹部，而有些个体则全身呈灰蓝色。分布于远东地区，自马来半岛至婆罗洲。","appearance":"雄鸟成鸟标准形态下头部至背部呈暗蓝色，翼中部覆羽及下腹部为蓝灰色；背下半部和臀部呈灰蓝，带淡黄色调；翅膀其余部分及尾羽为红栗色，除深灰色的初级飞羽；下腹部至尾下覆羽为乳白色；眼红色或深红色；喙黑色；腿蓝灰色。蓝色形态雄鸟全身暗蓝灰色，仅下腹部至尾下覆羽为灰白色，可能有灰白条纹在下腹、胁及尾下覆羽，尾羽微带栗色。雌鸟头顶部和面部深灰，偶带蓝色，上体中棕色，翼中部及大覆羽、三级飞羽和次级飞羽边缘暖棕色或红棕色，尾羽红棕色；下体大部分呈淡黄褐色，胸侧及胁更偏棕色，腹部至尾下覆羽较白。幼鸟外观类似雌鸟，但头部和肩部偏棕色，胸部橙红棕色。不成熟雄鸟在早期即呈现蓝色羽毛。","call":"发出清晰的双音节哨声，'tu-tuuuuu'，第二个音节略低于第一个，以及上升的'teu-ii'哨声。还有一系列尖锐的斥责音符，频繁重复。","habits":"栖息于低地和山地常绿森林，尤其是混合龙脑香林，也见于泥炭沼泽森林、采伐过的森林和邻近的橡胶种植园；主要在海拔800米或1000米以下，但在北婆罗洲的凯拉比特高地可达1600米。以小型无脊椎动物为食，包括苍蝇（双翅目）和小胡蜂（膜翅目）。单独或成对活动，常在森林较低和中间层次觅食，经常在低矮的灌木丛或地面活动。动作缓慢，通常从枝叶间捕获昆虫，而非追逐飞行中的猎物。","breeding":"繁殖季节从2月至9月。在马来西亚半岛发现的一个巢是由蜘蛛网粘合的小杯状巢，置于细水平枝的分叉处；至少有两个雏鸟，似乎由双亲共同照料。无更多繁殖信息。","identification":"与同类物种相比，棕翅王鵙的红褐色翅膀和尾羽是显著的识别特征，雄鸟的蓝色或灰蓝色形态提供了额外的辨识点。雌鸟的灰褐色上体和红棕色翼尾也是关键区别。","protection":"IUCN：LC（无危）","distribution":"分布在马来半岛至婆罗洲，包括印尼、马来西亚、文莱等地的低地和山地森林。","other":"曾经分布到新加坡，但至1950年已不再存在。在一项关于婆罗洲（砂拉越）森林鸟类种群动态的研究中，高达75%的成鸟能存活至下一个繁殖季。"},{"name":"栗胸王鵙","english_name":"Maroon-breasted Philentoma","scientific_name":"Philentoma velata","overview":"栗胸王鵙（英文名：Maroon-breasted Philentoma，学名：Philentoma velata），是雀形目钩嘴鵙科王鵙属的鸟类。雄鸟头部黑色，胸前有独特的酒红色斑块，雌鸟则全身较为均匀的石板灰色，喉部颜色较深。主要分布于马来半岛、爪哇岛和婆罗洲的低地至山脚森林。","appearance":"成年栗胸王鵙体长约17-21厘米，体格健壮。雄鸟标本几乎通体呈深靛蓝色，除额头、眼周至耳羽及喉咙为黑色；胸部为深栗色（光线不佳时可能显得全黑），腹部和臀部带有灰色；眼睛深红或鲜红；喙及腿脚黑色或蓝黑色。雌鸟与雄鸟相似，但整体更接近石板灰色，脸部略暗，喉部及胸部颜色较淡；下腹部及臀部可能有白色羽基。幼鸟特征尚不明晰，但背部有条纹和斑点；雄鸟幼鸟早期胸脯即显现出深栗色或酒红色。","call":"其歌声为一系列清澈的钟铃般‘phu phu phu phu phu phu’的音节，有时更为有力地发出类似松鼠的‘chut-ut chut-ut chut-ut chut-ut’声。典型的联络叫声是刺耳的金属质感‘churr’，头部垂直上扬时发出。","habits":"栗胸王鵙通常成对或小家庭群活动，以中层至树冠层森林树叶中的小型到大型昆虫为食。它们的觅食方式是在叶间搜索并追逐猎物，行动缓慢，长时间保持静止，之后才移动捕食。偶尔也会在空中以微弱或起伏的飞行方式捕捉昆虫，翅膀振动产生明显的声音。","identification":"雄性栗胸王鵙与蓝型的棕翅王鵙相比，具有更深的靛蓝色羽毛，面部黑色，胸部有酒红色斑块。雌鸟与雄鸟相似，但全身颜色更加均匀，喉部和胸部颜色较暗淡。","protection":"IUCN：NT（近危）","distribution":"分布于马来半岛、爪哇岛和婆罗洲的低地至山脚森林，具体包括文莱、印尼、马来西亚、缅甸、新加坡和泰国。"},{"name":"长冠盔鵙","english_name":"White-crested Helmetshrike","scientific_name":"Prionops plumatus","overview":"长冠盔鵙（英文名：White-crested Helmetshrike，学名：Prionops plumatus），是雀形目钩嘴鵙科盔鵙属的鸟类。显著特征为灰白色的延长冠羽，黄色的眼睛和眼眶，以及黑白相间的羽毛。分布广泛，主要栖息在非洲的落叶阔叶灌木林地，包括Baikiaea、Brachystegia等树种为主的环境。","appearance":"体长19至25厘米，体重25至49克。头部具灰色的延长冠羽，可达45毫米，前额有较短的白色尖刺状冠羽，约10毫米。颈和下体呈白色，两翼黑色并带有绿色光泽，翼上有明显的白色横纹。尾部外侧羽毛全白，内侧羽毛黑色带白色尖端。眼睛暗绿灰色，有黄色外环，眼眶橙黄色。喙黑色，腿脚粉红至红色。幼鸟冠羽较短，无暗色新月纹，体羽偏棕色，眼褐色，无眼眶环，腿脚黄色。成年特征在约12个月时形成。不同亚种间存在差异，如iris颜色、冠羽长度和翼条图案。","call":"发出奇特的咔哒声和哨音，包括点击和口哨，群体中常有合唱。","habits":"主要栖息于落叶阔叶灌木林地，非繁殖季节会迁移到其他类型的森林和草地。以小型昆虫为主食，也会吃小爬行动物和果实。生活在紧密的群体中，通常由5到10只组成，活跃于混合或单一物种的群落中，寻找中低层的食物。飞行时展现出明显的黑白相间图案。","breeding":"繁殖季节几乎全年，尤其在3月至11月。一夫一妻制，群体成员共同参与筑巢和育雏。巢为紧凑杯状，由树皮条和蜘蛛网制成，内部铺有草和苔藓。产卵数为2至5枚，平均孵化期为17天。雏鸟由群体成员共同喂养，离巢期为17至22天。","identification":"与同属其他物种相比，长冠盔鵙具有更长的灰色冠羽和独特的黑白羽毛模式。亚种之间在冠羽长度、翼条上的白色条纹和虹膜颜色上有所区别。","protection":"IUCN：LC（无危）","distribution":"广泛分布在非洲的安哥拉、贝宁、博茨瓦纳、布基纳法索等国家，栖息于多种森林和草原环境中。","other":"在干旱时期，长冠盔鵙可能大规模迁移到不适合繁殖的地区，如高地草地，甚至城市公园和花园。"},{"name":"灰冠盔鵙","english_name":"Grey-crested Helmetshrike","scientific_name":"Prionops poliolophus","overview":"灰冠盔鵙（英文名：Grey-crested Helmetshrike，学名：Prionops poliolophus），是雀形目钩嘴鵙科盔鵙属的鸟类，别称源自其独特的灰白色羽冠和鲜明的黑白对比羽毛。广泛分布在非洲肯尼亚西南部和坦桑尼亚西部的适度湿润林地与草原地带。","appearance":"成鸟长约23至26厘米，体重约49克。最显著的特征是中冠上耸立的20毫米左右灰色绒毛冠羽，前额至眼窝处有较短的灰白尖端冠羽，后颈和颈背呈深灰色，脸颊后方有黑色新月形斑块。喉部和下巴为灰色，两翼和背部为黑色，带绿色光泽。翼上的主飞羽有宽阔的白色中央条纹，次级飞羽的外缘和末端有白色，形成飞行中的显著白色斑块。尾羽末端白色，腹部白色，胸部侧面有黑色斑点。虹膜亮黄色，眼周橙色环。喙黑，腿和脚橙红至粉红色。幼鸟特征未详述，但眼睛颜色较暗，冠羽比成鸟短且直。","call":"群居时发出奇特的齿轮声和铃声般的叫声，包含咔嗒声和哨音，与长冠盔鵙的叫声相似但音调更低。","habits":"常以紧密的小群体出现，由4至9个个体组成，偶尔可达17个，栖息于低矮灌木丛中。有时会加入混杂的物种群体，与长冠盔鵙一同出现在特定地区（如坦桑尼亚的Loliondo地区）。主要以昆虫为食，包括昆虫幼虫、蚱蜢和螳螂。","breeding":"繁殖信息有限，已知巢中幼鸟的食物主要是昆虫幼虫、蚱蜢和螳螂。巢筑于树上，每窝仅产一枚蛋。","identification":"与长冠盔鵙外观相似，但可通过较长的灰色羽冠和眼部周围缺乏裸露的黄色皮肤加以区分。","protection":"IUCN：NT（近危）。灰冠盔鵙的分布范围较小，约52,800平方公里，且数量被认为正在经历快速减少。面临栖息地破坏和退化的威胁，如过度放牧和耕作。","distribution":"主要分布于非洲肯尼亚西南部和坦桑尼亚西部，包括纳库鲁湖、埃尔门泰塔湖和奈瓦沙湖附近区域，以及马赛马拉国家公园、萨巴林戈谷地到洛伊塔山和恩古鲁曼山丘等地。","other":"曾于20世纪初期出现在基戈马和塔博拉地区，但之后未再有记录。在裂谷区域消失多年后，于1989年在纳库鲁湖地区再次发现有繁殖迹象，显示可能的再殖民化过程。"},{"name":"黄冠盔鵙","english_name":"Yellow-crested Helmetshrike","scientific_name":"Prionops alberti","overview":"黄冠盔鵙（英文名：Yellow-crested Helmetshrike，学名：Prionops alberti），是雀形目钩嘴鵙科盔鵙属的大型鸟类。以黑色羽毛搭配鲜明的黄色冠羽而著称。其分布区域主要集中在刚果民主共和国中东部的阿尔伯丁裂谷山区。","appearance":"黄冠盔鵙体长22至24厘米，体重约61至62克。头部具有一圈圆形的黄色冠羽，从眉区延伸至后冠部，有时黄色冠羽在野外并不显眼，可能带有棕色或灰色边缘；其余羽毛呈黑色，带绿色光泽。有报告指出部分个体的初级飞羽内部可能有白色或灰色条纹。虹膜呈绿黄色，眼周有狭窄的橙色环；喙为黑色；腿脚颜色从暗粉色到红色。雌雄相似。幼鸟的冠羽呈白色、棕色或淡黄色，羽毛较暗淡，缺乏光泽，眼睛棕色，喙部棕色。","call":"鸣叫被描述为两音节的‘tlu-uk’或‘clu-uk’，在野外可重复多达六次。对来自其他个体的警报叫声反应强烈。","habits":"黄冠盔鵙栖息于阿尔伯丁裂谷的亚热带或热带湿润山地森林，海拔高度大约在1120至2500米之间。它们通常以昆虫为食，以14至20个个体组成的快速移动群体在森林树冠层中积极搜索和捕猎节肢动物。","breeding":"巢穴尚未被描述。据推测，北部分布区的繁殖季节可能不固定。在北基伍省Lutunguru，幼鸟的记录出现在8月中旬至10月间，这表明产卵可能发生在6月或7月左右。","identification":"与其他Prionops属物种相比，黄冠盔鵙的独特之处在于其黑色的羽毛和明亮的黄色冠羽。幼鸟的特征与成鸟有所不同，具有较暗淡的羽毛和不同色彩的冠羽。","protection":"IUCN：VU（易危）；物种受到栖息地丧失的威胁。","distribution":"黄冠盔鵙分布于刚果民主共和国中东部的阿尔伯丁裂谷山区，包括从Mwitanzige湖西侧的Lendu高原向南至Kabobo山的地带。","other":"2023年，由生物学家Michael Harvey带领的团队在Itombwe山脉的六周探险中重新发现了黄冠盔鵙，这一物种曾被认为已消失。他们在三个地点发现了18只这种神秘的鸟类，暗示着可能拥有一个较为健康的种群。"},{"name":"栗腹盔鵙","english_name":"Red-billed Helmetshrike","scientific_name":"Prionops caniceps","overview":"栗腹盔鵙（英文名：Red-billed Helmetshrike，学名：Prionops caniceps），是雀形目钩嘴鵙科盔鵙属的鸟类。拥有醒目的红色喙，黑色背部和栗色腹部，分布于西非至中非的热带森林地带，包括贝宁、喀麦隆、象牙海岸、加纳、几内亚、利比里亚、马里、尼日利亚、塞拉利昂和多哥等地。","appearance":"成年栗腹盔鵙长约20-22厘米，重42-62克。头部冠部至眼水平处蓝灰色，其余头颈黑；上体黑，带绿光泽；飞羽黑，主翼羽有宽白中央条纹，尾上覆羽黑而有光泽；胸和上腹白色，与下腹的淡黄色界限明显；翅膀下覆羽和腋羽暗灰；虹膜黄，有狭窄橙红眼环；喙和腿均为红色。雌雄相似。幼鸟外观更棕色，具暗色眉纹，缺乏蓝灰色冠羽，眼环不显，眼睛褐色，喙先黑后转黄，腿色较淡。","call":"其复杂多变的鸣叫声包括哨声、嘶哑声和叽叽喳喳声。最常见的是‘wrrraak, wrraak’的接触叫声，被描述为柔和而干涩皮革般的质感；还有更尖锐刺耳的类似乌鸦的接触叫声。歌声由响亮的哨音组成，或在歌曲中间升高音调，或总体下降。","habits":"生活在低地原生林、画廊森林、成熟的次生林、密集的河岸植被、森林边缘、伐木后的森林和农田，以及旧咖啡种植园，海拔高度从低地到几内亚的700米。以昆虫、蜘蛛、果实和种子为食，主要在森林中层10-20米高处捕食，偶尔在树冠层。捕食方式类似于鵙科，既空中捕食也从树叶和细枝上捕获猎物，但避开粗壮的树干。通常以4-8只的小群体生活和觅食，最多记录过20只的群体；群体成员在觅食时保持1-4.5米的距离。会加入混合物种的觅食群，特别是在非繁殖季节，与同类和其他鸟类如Campephagidae、Dicrurus和Malimbus一起，但常处于群队的后方。","identification":"通过其栗色腹部与其它盔鵙相区别。西部种群有更多白色下体和面部黑色，而西部种群则有更多的栗色下方和脸部灰色。在喀麦隆的Mount Kupé，harterti亚种的叫声类似于棕腹盔鵙。","protection":"IUCN：LC（无危）","distribution":"分布在西非至中非的热带森林地带，包括贝宁、喀麦隆、象牙海岸、加纳、几内亚、利比里亚、马里、尼日利亚、塞拉利昂和多哥等地。","other":"在中非，由栗腹盔鵙的近亲，有时被视为亚种的棕腹盔鵙所取代。"},{"name":"棕腹盔鵙","english_name":"Rufous-bellied Helmetshrike","scientific_name":"Prionops rufiventris","overview":"棕腹盔鵙（英文名：Rufous-bellied Helmetshrike，学名：Prionops rufiventris），是雀形目钩嘴鵙科盔鵙属的鸟类。生活在非洲中部热带森林中。常以小群出现，发出响亮的鸣叫。头部和下巴呈银灰色，胸白腹红，翼黑带白，喙和腿橙红色。与栗腹盔鵙相似，但可通过银灰色的下巴和更广泛的红褐色腹部区分。","appearance":"成鸟体长20至22厘米，体重37至63克。头部从冠到耳羽、脸颊和下巴为蓝灰色，前额较白，眼周和眼圈附近颜色较浅。喉部和颈部黑色，上体黑色，带有绿色光泽；飞羽黑色，初级飞羽有宽白中央条纹，在飞行中显眼；尾上覆羽黑色并有光泽；胸部白色，与红褐色的下胸和腹部形成鲜明对比。幼鸟比成鸟更棕色，条纹明显，缺乏蓝灰色的冠羽，眼圈不显，眼睛棕色，喙起初黑色（后转黄色），腿色暗淡。","call":"鸣叫复杂多样，包括流畅的‘tyooyoo’歌曲和粗糙尖锐的‘chaja’变体重复叫声，还有嘶哑和哨音，有时结合使用，以及咔嗒声、鼻音和滑音。两鸟合唱记录。","habits":"栖息于低地原始森林，包括开阔和封闭树冠的森林以及山坡上的森林，也见于成熟次生林和森林边缘，海拔高度可达1450米。似乎终年定居。主要以昆虫为食，如甲虫、蝴蝶、蛾子、毛虫、蝉、蚱蜢、螳螂和竹节虫，以及蜘蛛；也吃种子和果实，如Musanga和Croton的果实。在树冠下或树冠内猎食，跳跃于枝头，飞行中搜索叶间和藤蔓。通常以4至8个个体组成的群体生活和觅食，最高记录为12个个体。经常加入混群，尤其是在非繁殖季节，可能是此类群的催化物种。","breeding":"繁殖信息知之甚少。据信繁殖期为5月至7月和11月至12月。可能为合作繁殖者。领地性，所有成员参与领土防御；领地广阔，至少20公顷。雏鸟由所有群体成员喂养。可能被厚嘴杜鹃寄生。无更多信息。","identification":"与栗腹盔鵙相似，但通过银灰色的下巴和头顶，以及更广泛的红褐色腹部来识别。东部亚种P. r. mentalis具有较深的下体颜色和灰棕色的眼睛。","protection":"IUCN：LC（无危）。在大范围内频繁至常见。但在卢旺达已灭绝，乌干达的Bwamba和Bugoma森林中数量似乎减少，可能在后者已灭绝。在多个保护区中存在，如中非共和国的Dzanga-Ndoki国家公园，刚果共和国的Odzala和Nouabalé-Ndoki国家公园。","distribution":"分布于非洲中部，包括喀麦隆南部、赤道几内亚大陆部分、中非共和国西南部、加蓬北部和西部、安哥拉卡宾达和刚果共和国部分地区，刚果民主共和国西北部和中西部，乌干达西部，曾出现在卢旺达。","other":"历史上，它有时被归入西非的栗腹盔鵙中。"},{"name":"雷氏盔鵙","english_name":"Retz's Helmetshrike","scientific_name":"Prionops retzii","overview":"雷氏盔鵙（英文名：Retz's Helmetshrike，学名：Prionops retzii），是雀形目钩嘴鵙科盔鵙属的鸟类。特征为黑色和棕色为主，拥有醒目的橙色眼睛、红色腿和眼睑，以及橙色尖端的红喙。群居，通常出现在成熟的阔叶林和河岸及沿海森林，避开干旱环境。","appearance":"身长19至24厘米，体重33至61克。头部、颈部、上背部和下腹部呈光泽黑色，具小冠羽；下背部、肩羽至臀部为灰棕色，长黑尾羽覆羽；翅膀和外侧初级飞羽黑色，初级飞羽带有明显的白色中央条纹（飞行时明显），尾巴光泽黑色，外侧尾羽有宽白尖，内侧尾羽逐渐减少白色直至中央一对完全黑色；下腹至尾下覆羽白色，翼下覆羽和腋羽灰棕色；虹膜黄色，有显眼的橙红至红色眼环；喙红色，尖端橙黄；腿橙红色。雌雄相似。幼鸟整体灰棕色，上体羽端淡褐色，无眼环，眼棕色，喙初期黑色后转黄，腿初期黑色后转黄；幼鸟羽衣可能需24个月才能完全转变成成年羽衣。","call":"声音丰富，至少16种不同的叫声被识别，有些叫声可能反映个体的社会地位或性别。叫声比长冠盔鵙更响亮且音乐性更强，包括‘tweeoo’的口哨声，类似旧大陆的莺类。叫声常以群体合唱形式发出，二重唱在维护伴侣关系中很重要。","habits":"偏好湿润的落叶阔叶林，包括Baikiaea、Brachystegia、Colophospermum林，特别是在较干燥地区，河岸林；也见于低地森林和杜松林。非繁殖季节，会迁移到孤立的灌木丛、干燥的高草原和混合金合欢林、森林、种植园和红树林。主要食物为昆虫，如甲虫、蝴蝶、蛾、毛虫、蝉、蚱蜢、螳螂、白蚁；也会捕食蜘蛛和小型爬行动物，如壁虎和其他蜥蜴。通常在较高的植被层中捕食，有时倒挂如同山雀，利用听觉线索定位猎物。","breeding":"繁殖季节主要在东非1月至3月和8月至3月（高峰9月至10月）在中南部非洲，由树木发芽刺激。一夫一妻制，群体合作繁殖，所有成员参与筑巢和其他繁殖任务。巢为浅杯状，由苔藓、叶片柄、草、藤蔓和薄树皮构成，用蛛网固定，内部铺细草和树皮条。产卵数2至5枚，平均孵化期约17天，孵化和喂养由整个群体共同承担。雏鸟在巢中的时间约20天，离巢后至少依赖群体3个月，直到约7个月大才完全独立。","identification":"与长冠盔鵙相比，巢更高、更宽、更浅、墙壁更厚，位于更高的树上。叫声和行为模式也有助于区分。","protection":"IUCN：LC（无危）；在某些地区因生境退化而受到威胁，例如津巴布韦的Brachystegia林破坏。","distribution":"分布于安哥拉、博茨瓦纳、刚果民主共和国、斯威士兰、肯尼亚、马拉维、莫桑比克、纳米比亚、索马里、南非、坦桑尼亚、赞比亚和津巴布韦。","other":"存在四个亚种，适应不同生境条件。"},{"name":"安哥拉盔鵙","english_name":"Gabela Helmetshrike","scientific_name":"Prionops gabela","overview":"安哥拉盔鵙（英文名：Gabela Helmetshrike，学名：Prionops gabela），是雀形目钩嘴鵙科盔鵙属的鸟类。主要分布于非洲安哥拉西部的狭窄地带。该鸟以黑色头部、橙色眼睛、红色腿脚和眼泡，以及橙尖红喙为显著特征。","appearance":"成年安哥拉盔鵙体长18至19厘米，头部至胸上部呈现光泽黑，头顶具微小冠羽向前覆盖喙部；背部、肩羽至臀部呈灰褐色调；长的黑色尾上覆羽；翅膀和外侧初级飞羽黑色，外侧初级飞羽中央有白色斑点形成翼条（飞行中可见），内侧上翼覆羽灰色；尾巴黑色，外侧羽毛有宽阔白端，内侧尾羽白端逐渐减小；胸下部和腹部上部灰色，下腹部至尾下覆羽白色，腋下覆羽和翼下覆羽深灰色。虹膜黄色，有显眼的橙红色眼环，边缘呈波浪状（尤其是上方眼周）；喙红色，尖端橙黄；腿脚橙红色。与非常相似的雷氏盔鵙相比，体型较小，胸下部和腹部上部灰色而非黑色，冠羽前伸过喙，翼条仅限于外侧初级飞羽，较为不明显。两性相似，雌鸟的翼斑可能较小。幼鸟上下体色主要为灰褐色，背部羽毛尖端淡黄，翼羽常有狭窄白尖，无眼环，眼睛暗色，喙黑色，腿脚橙黄色。","call":"鸣叫特征几乎未知，但据报告发出类似雷氏盔鵙的嘶哑声和咔哒声。","habits":"安哥拉盔鵙栖息于成熟干燥森林、次生林、灌木丛和开阔地带，包括森林中的咖啡种植园。通常在100至900米的海拔范围内活动，最近的记录显示它们在约300米高的干燥森林中。它们可能主要是居民，但有记录显示它们在悬崖下方的干燥灌木丛和开阔林地中活动，这可能意味着繁殖季节后会有游荡行为。以昆虫为主食，包括幼虫，通常在树冠层觅食，以紧密的群体形式活动，群体由3至8个个体组成。","breeding":"繁殖季似乎在6月至9月间，可能是合作繁殖模式，但具体繁殖信息尚不清楚。","identification":"与雷氏盔鵙的区别在于体型更小，下胸部和上腹部颜色为灰色而非黑色，冠羽前倾覆盖喙部，翼条仅限于外侧初级飞羽，不如雷氏盔鵙明显。","protection":"IUCN：EN（濒危）","distribution":"安哥拉西部，从Chio南至Gabela之间，沿悬崖带分布。","other":"自1970年代后直到2003年，安哥拉盔鵙才再次被记录到，2005年在Kissama、Bimbe和Bango地区的300米海拔处发现了10个群体。"},{"name":"栗额盔鵙","english_name":"Chestnut-fronted Helmetshrike","scientific_name":"Prionops scopifrons","overview":"栗额盔鵙（英文名：Chestnut-fronted Helmetshrike，学名：Prionops scopifrons），是雀形目钩嘴鵙科盔鵙属的鸟类。最显著的特征是栗色的额前冠羽、蓝灰色的眼环和橙色的眼睛。分布于非洲东部和东南部，包括肯尼亚、莫桑比克、索马里、南非、坦桑尼亚和津巴布韦。","appearance":"体长约16至18厘米，重约20至40克，是最小的钩嘴鵙科成员。头部黑色带灰，额头有淡栗色的细小冠羽，脸颊和耳羽黑灰色，上体灰褐色，翅膀和尾部黑色，翼上有明显的白色中央条纹。下体灰色至白色，喉咙暗灰色。虹膜黄色，眼周有蓝灰色的裸皮环，喙红色尖端橙黄，腿红色。幼鸟体色更淡，头部棕色，羽毛尖端白，眼周无蓝环，眼睛棕色，喙和腿黑色。","call":"鸣声多样，包括鼻音、沙哑音的叫声，类似愤怒的颤音，还有嗡嗡声、咯咯声、咕噜声、哼鸣声、咔哒声、滑音、叮当声、颤音、呼呼声和缠绵的叫声，通常交替着吹哨音。尖锐的“shuk”声可能表示警报。","habits":"栖息于沿海森林和茂密的林地，偏好小叶树。以昆虫为主食，如蚁狮、甲虫、毛虫、蚱蜢和蛾子，也吃蜘蛛、小型脊椎动物和果实。狩猎时利用听觉定位猎物，常倒挂在树枝上捕食，像山雀一样。飞行时捕捉猎物，有时会冲入树叶丛中驱赶猎物。","breeding":"繁殖期为12月至次年7月，北部分布区高峰在1月至4月，南部分布区在10月至12月。合作繁殖，整个群体参与筑巢、孵卵和喂养。巢为浅杯状，由草和薄树皮条构成，用纤维、苔藓、地衣和蜘蛛网固定。巢置于大树林中层到顶层的枝叉间，高度4.5至23米。一窝产3枚卵，由群体成员轮流孵化，孵化期间个体偶尔会被其他成员喂食。幼鸟由群体成员共同喂养。","identification":"与雷氏盔鵙相比，主要通过栗色的额前冠羽和蓝灰色而非红色的眼环容易区分。","protection":"IUCN：LC（无危）","distribution":"非洲东部和东南部，具体包括肯尼亚、莫桑比克、索马里、南非、坦桑尼亚和津巴布韦。"},{"name":"红尾钩嘴鵙","english_name":"Red-tailed Vanga","scientific_name":"Calicalicus madagascariensis","overview":"红尾钩嘴鵙（英文名：Red-tailed Vanga，学名：Calicalicus madagascariensis），是雀形目钩嘴鵙科红尾钩嘴鵙属的鸟类，为马达加斯加的特有种，广泛分布于岛上除中部和远南部之外的所有森林类型中。雄鸟色彩鲜艳，而雌鸟则呈平淡的褐色。其活跃且嗓音丰富，常引领森林中的鸟群。","appearance":"体型小巧，与山雀相似，长度约13至14厘米，体重14至18.6克。雄鸟头部灰至颈背，黑色面颊带环绕眼睛，上体灰色略带绿色，红棕色臀部和尾羽覆羽；翼绿灰色，翼下覆羽白色。雌鸟额头至颈背较暗淡的灰色，明显的偏白色眼环，上体橄榄褐色，臀部和尾羽覆羽砖红色。幼鸟似雌鸟，但下体羽毛有明显的浅色条纹和尖端。","call":"最常见的是类似狼哨的鸣声，雄鸟在北部和东部发出'per-whew'的下降音调叫声，在西部则为'pew-poo-whee'或'oo-oo-whi'，最后一音节较高。","habits":"栖息于各种森林层级，偏好在小枝上觅食，主要以小型至中型昆虫为食，包括蚱蜢、甲虫、毛虫，偶尔捕食小型脊椎动物，如变色龙。通常在繁殖季节成对出现，有时组成小群体，混群中可能包含其他种类的鵙鸟，以及常见的森林鸣禽，如北杂鹛、纹喉杂鹛和萨卡织雀，或较大的物种如马达加斯加冠鹃和马岛鹃鵙。","identification":"与红肩鵙通过其深色的眼睛和翅膀上较少的红色来区分。雌鸟与罕见且分布局限的红尾牛顿尼亚非常相似，但可通过其更大的体型、更宽大的喙和眼周的淡黄色环来识别。","protection":"IUCN：LC（无危）","distribution":"主要分布在马达加斯加，除了中部和远南部。","other":"该物种由Mathurin Jacques Brisson于1760年首次描述，后被Linnaeus归入其第十二版《自然系统》中，现分类于Bonaparte于1854年建立的Calicalicus属中，是该属的唯一物种。"},{"name":"红肩钩嘴鵙","english_name":"Red-shouldered Vanga","scientific_name":"Calicalicus rufocarpalis","overview":"红肩钩嘴鵙（英文名：Red-shouldered Vanga，学名：Calicalicus rufocarpalis），是雀形目钩嘴鵙科红尾钩嘴鵙属的鸟类。是马达加斯加西南部特有种。雄鸟色彩鲜艳，雌鸟则为淡褐色。在1990年代才被科学界正式描述。该鸟种的最显著特征是其红肩和独特的鸣叫。","appearance":"红肩钩嘴鵙体长约14至15厘米，体重介于15至17.4克之间。雄鸟具有黑色的眼纹和上眼线，连接至喙上方，上方有一条细白线；头部、颈背和肩部呈浅灰色；翅膀棕色，翼盖砖红色，有时边缘呈灰褐色；尾巴淡砖红色，中央羽毛略带褐色；脸颊和耳羽白色，与黑色的下巴、喉部和颈部侧面形成鲜明对比；下体白色，胸部和侧腹带有淡粉色；虹膜柠檬黄色；喙黑色；腿粉色。雌鸟上身橄榄色带灰，下体洗成淡黄色，腹部白色，裸露部分颜色与雄鸟相同。","call":"主要的鸣叫为上升的两到三音节哨声。","habits":"生活在海拔约100米的半干旱荆棘灌木丛中。以小型无脊椎动物为食，通常在2至3米高的密集矮树丛中觅食，主要通过掠取和飞扑捕食。常以小家庭群体活动。","breeding":"繁殖信息未知，曾记录到一月份的雏鸟。","identification":"与更广泛的红尾钩嘴鵙的区别在于其淡色的眼睛、较长的喙、尾巴和腿，较短的翅膀，以及头部图案和红色的翼盖。","protection":"IUCN：VU（易危）","distribution":"分布于非洲的马达加斯加远西南部，包括Toliara地区和Mahafaly高原，南至Lintsa。","other":"红肩钩嘴鵙是国际知名观鸟者Phoebe Snetsinger生前观察到的最后一鸟种。"},{"name":"钩嘴鵙","english_name":"Hook-billed Vanga","scientific_name":"Vanga curvirostris","overview":"钩嘴鵙（英文名：Hook-billed Vanga，学名：Vanga curvirostris），是雀形目钩嘴鵙科钩嘴鵙属的鸟类，马达加斯加特有种，广泛出现在各种森林类型，包括密集灌木丛、退化和原始森林，以及村落周边和远离森林的种植园。其显著特征为强壮的钩状喙，黑色与白色相间的羽色，尤其是独特的黑白色翅膀标记。","appearance":"中等体型（25-29厘米），具长而弯曲的喙，腿长而结实。头部中央至后颈上部光泽黑色，其余头部和颈部，包括颈背围巾，为白色；背部黑色，翼上的中覆羽和大覆羽有宽白边，形成闭合翼上的白色区域；初级和次级飞羽有较窄的白色边缘；尾基部三分之二灰中色，亚端带黑色，尖端白色；下体白色；虹膜非常深棕色；喙黑色，近尖端有一小银色斑点，长度25-30毫米；腿暗蓝灰色。性别相似。幼鸟与成鸟类似，但上体黑色部分可能带有褐色斑纹，喙基部最初灰色。","call":"发出高亢穿透性的哨声，持续约2秒，早晨时单调重复，间隔规律。两个体常对鸣。西部地区的叫声通常为'karr-karr-karr'（伴随两到三下大声的喙击）后接愤怒的'tew-tew-tew-tew'；东部和南部地区则经常仅听到最后一部分('tew'音符)。","habits":"栖息于多种原始森林类型，包括密林、退化和原始森林，村庄周围，以及远离森林的种植园。主要为留鸟。以大型昆虫为主食，也捕食小型脊椎动物，如中型变色龙、蛙类、小鸟、鸟蛋，甚至幼年Microcebus狐猴。长时间静止观察猎物，亦缓慢搜寻树枝上的食物。有时单独活动，有时成对，也会加入混种鵙鸟群或其它森林物种的群体。","breeding":"繁殖季节为10月至次年1月（西北部Ampijoroa）。一夫一妻制。巢由两个体（推测为雄鸟和雌鸟）共同建造，是一个由枯叶构成的大型杯状结构，覆盖蜘蛛网和苔藓，通常建于树叉距地面3-10米处。产卵3枚，白色，密集覆盖小酒红色斑点；双亲共同孵卵，孵化期约22-24天；雏鸟由双亲共同照料喂食，巢期约20-22天。","identification":"具有独特的黑白相间羽色和长曲喙，与任何其他鵙鸟都不相同，尤其黑色和白色的翼部标记极为显眼。","protection":"IUCN：LC（无危）","distribution":"非洲：马达加斯加。从海平面至约1500米高度，但在海拔约1000米以上较为稀少。","other":"钩嘴鵙的学名Vanga源自马达加斯加语，意指该物种。"},{"name":"黑头莺嘴鵙","english_name":"Bernier's Vanga","scientific_name":"Oriolia bernieri","overview":"黑头莺嘴鵙（英文名：Bernier's Vanga，学名：Oriolia bernieri），是雀形目钩嘴鵙科黑头莺嘴鵙属的鸟类。仅见于马达加斯加东北部的低地热带雨林。其特征为雄鸟黑色光泽羽毛，雌鸟棕色带暗条纹，两性皆有醒目淡色眼睛。","appearance":"成年鸟长约23厘米，重52至59克。雄鸟全身羽毛呈黑色并带有蓝光泽，雌鸟为深褐色，翼部较亮，羽毛上细密的黑色条纹尤其在背部和胸部明显。幼鸟与雌鸟相似。","call":"叫声为尖锐的“chew”音，类似青脚鹬的叫声，以及刺耳的连续啁啾声。飞行时，翅膀拍打产生响亮的嗡嗡声。","habits":"栖息于低地常绿湿润森林，最高可达约1000米。以昆虫、蜘蛛、蟑螂和小型脊椎动物如变色龙为食。在所有植被层次觅食，主要在树冠层活动，使用啄木鸟式的觅食技巧，如剥开苔藓和树皮，能紧贴几乎垂直的树干。经常在旅人树、棕榈和Pandanus树叶中搜寻食物。","breeding":"繁殖季节为9月至12月。繁殖系统不确定，有时一雌多雄共居。巢由两性共同建造，主要是杯状，由根材、棕榈纤维、干叶和苔藓构成，通常位于地面以上10.8至14.4米的棕榈叶丛中。每窝产3枚粉白色、带洋红色斑点的蛋，孵化期约17天，两性共同孵卵和喂养雏鸟，雏鸟期约17天。","identification":"与同属物种相比，黑头莺嘴鵙的雄鸟具有独特的黑色光泽羽毛和蓝绿色光泽，而雌鸟则有明显的暗褐色条纹。其独特的叫声和特定的觅食行为也是辨识要点。","protection":"IUCN：EN（濒危）。受严重森林生境丧失和退化威胁，导致种群数量下降。存在于几个保护区，包括Marojejy、Masoala和Zahamena国家公园，以及Ambatovaky、Anjanaharibe-South和Mangerivola特别保护区，Betampona严格保护区，和Anjanaharibe、Bezavona和Haute Rantabe分类森林。","distribution":"分布于马达加斯加东北部，从Marojejy国家公园南至R Rianala附近。","other":"在繁殖区域外的地理分布信息有限，可能呈现定居性，未观察到迁徙行为。"},{"name":"拉氏厚嘴鵙","english_name":"Lafresnaye's Vanga","scientific_name":"Xenopirostris xenopirostris","overview":"拉氏厚嘴鵙（英文名：Lafresnaye's Vanga，学名：Xenopirostris xenopirostris），是雀形目钩嘴鵙科厚嘴鵙属的鸟类。其名称来源于法国鸟类学家Frédéric de Lafresnaye。这种大体型、具有显著大喙的鵙类，主要分布在马达加斯加西南部的低海拔棘森林中，以昆虫、蠕虫及小型脊椎动物为食。","appearance":"拉氏厚嘴鵙体长约24厘米，体重介于52至63克之间，拥有粗壮而侧扁的大喙，喙间有间隙。雄鸟头部黑色，喉部和胸部白色，形成鲜明对比；上体呈中灰色，带微褐色调，翼羽和尾羽颜色较深；下体白色。雌鸟头部顶部黑色，其余部位白色较多。幼鸟外观与雌鸟相似，但背部带有棕色斑纹。喙蓝灰至灰蓝色，腿脚灰蓝。","call":"最常见的是快速、尖锐的哨声和‘chi-che-che’的斥责声。","habits":"拉氏厚嘴鵙栖息于低海拔的棘森林，常在树冠中层和下层活动，接近地面。它们会系统地在裂缝、枯木的缝隙和树枝下搜寻猎物，主要技术是拾取和探查。通常单独或成对活动，偶尔会组成小群体，多达八只，常与其他大型鵙类混群。","breeding":"繁殖资料有限。观察到的繁殖期在11月至12月。杯状巢由植物材料构成，外覆蜘蛛网加固，内衬叶柄和长根须，通常筑于离地面5米高的树叉处。每窝产2枚蛋，红白色，散布红灰色斑点，双亲共同孵化。","identification":"与Van Dam's和Pollen's鵙通过分布区相区分。与马达加斯加杜鹃鵙的区别在于喙更大，下体白色而非灰色。","protection":"IUCN：NT（近危）","distribution":"拉氏厚嘴鵙的分布局限于马达加斯加西南部，从R Mangoky河以南的次沙漠生态系统至Andohahela国家公园。","other":"该物种的分布范围较小，且在其范围内并不常见。2022年因栖息地退化和丧失导致的中等速率种群下降，其保护状态从无危上调至近危。"},{"name":"范氏厚嘴鵙","english_name":"Van Dam's Vanga","scientific_name":"Xenopirostris damii","overview":"范氏厚嘴鵙（英文名：Van Dam's Vanga，学名：Xenopirostris damii），是雀形目钩嘴鵙科厚嘴鵙属的鸟类。大型、具有显著大喙的厚嘴鵙科鸟类，仅见于马达加斯加的干燥落叶林中，属于罕见的特有种。雄鸟拥有黑色头部，而雌鸟仅限于黑色帽羽。其独特的外形和声音使其易于识别。","appearance":"范氏厚嘴鵙身长约为23厘米，喙粗壮且侧扁。雄鸟的头部为黑色，与白色的喉部和宽阔的白色颈环形成鲜明对比，上体呈深灰色，翼和尾部暗灰至黑灰，其余部分白色；雌鸟头部顶部、颈背黑色带蓝光泽，额头和颊部淡色，上体带褐色调，下体有时微黄。幼鸟色泽较淡，带有棕色斑纹。","call":"范氏厚嘴鵙的叫声包括穿透力强的长哨音，以及短促的斥责声，有时会发出响亮的‘鞭打’声和较为柔和的口哨或咕噜声，两鸟有时会进行反向二重唱。","habits":"它们栖息于马达加斯加北部和西北部的原始干燥落叶森林及其周边植被中，以昆虫如甲虫、蟑螂和其他节肢动物、蠕虫为主食，偶尔也会捕食小型脊椎动物，如变色龙。它们会剥开树皮寻找猎物，独自或成对活动，有时加入由多种鵙科鸟类组成的混合觅食群。","breeding":"繁殖季节从十月持续到至少一月，实行一夫一妻制。巢由双方共同建造，杯状，位于树叉中，高6.5至14.5米，通常用枯叶和蜘蛛网覆盖。每窝产卵3至4枚，白色带红褐色斑点，孵化由双亲轮流进行，雏鸟由双亲共同喂养。","identification":"范氏厚嘴鵙通过其巨大的喙和白色的下体与马岛鹃鵙区分，后者喙较小且下体为灰色。与Lafresnaye’s和Pollen’s Vangas的区别在于分布范围。","protection":"IUCN：EN（濒危）。该物种全球分布范围极小，仅在马达加斯加西北部的Ankarafantsika国家公园和远东北部的Analamerana保护区有记录，面临栖息地减少和质量下降的威胁。","distribution":"分布于非洲的马达加斯加西北部和远东北部，包括Analamera、Ankazomborona附近Ambaro湾、Bongolava和Ankarafantsika高原。","other":"尽管在两个已知地点被官方列为保护区，但其长期生存前景并不乐观，主要威胁来自森林的清理、燃烧、商业伐木以及木炭和薪柴的开采。"},{"name":"白额厚嘴鵙","english_name":"Pollen's Vanga","scientific_name":"Xenopirostris polleni","overview":"白额厚嘴鵙（英文名：Pollen's Vanga，学名：Xenopirostris polleni），是雀形目钩嘴鵙科厚嘴鵙属的特有鸟类，仅分布于马达加斯加东部的热带雨林中。具有独特的黑色头部和大喙，雄鸟腹部白色，雌鸟淡赤褐色。","appearance":"体型中等，长约24厘米，体重约61.5至65克。雄鸟头部和喉部黑色，颈侧白色，上体灰色，翼上覆羽和尾羽深灰，下体白色或微带橙色。雌鸟头部黑色延伸到喉部，胸腹部橙色变异性较大，背部橄榄色更浓。幼鸟下体浅橙色，喙淡粉色，有明显橙色口腔。","call":"发出尖锐上升的哨声和‘chi-che-che’的斥责声，常见叫声为响亮下降的‘tseeang’或‘tseeeo’。","habits":"栖息于东部雨林，常单独、成对或家族群活动，有时加入混合物种的鸟群。以昆虫如甲虫、蟑螂和其他无脊椎动物为主食，偶尔捕食小型脊椎动物，如变色龙。觅食于森林中层和上层，善于探查枯木和树皮下的食物。","breeding":"繁殖期在9月至12月，巢为杯状，由树叶和草叶构成，通常位于离地面5米高的树杈中。每窝产卵2枚，雄雌共同孵化和喂养幼鸟。","identification":"与Van Dam's和Lafresnaye's Vangas的区别在于分布范围。与马岛鹃鵙和泰拉钩嘴鵙相比，喙更大。与马岛鹃鵙不同，下体从不呈现灰色。","protection":"IUCN：VU（易危）。因森林砍伐和退化面临快速减少的风险。","distribution":"分布于马达加斯加东部至东南部，主要在海拔400至2000米的常绿湿润森林中较为常见。","other":"人口估计较小，由于栖息地破坏，预计未来几十年内会经历较快速的下降。"},{"name":"弯嘴鵙","english_name":"Sickle-billed Vanga","scientific_name":"Falculea palliata","overview":"弯嘴鵙（英文名：Sickle-billed Vanga，学名：Falculea palliata），是雀形目钩嘴鵙科弯嘴鵙属的鸟类。以极长弯曲的喙著称。马达加斯加特有种，常见于低海拔的棘林、干燥落叶林、灌木丛和种植园。其体型远超白头钩嘴鵙和黑钩嘴鵙，拥有更长且弯曲的喙。","appearance":"体长32厘米，体重介于106至119克之间。特征鲜明，具有最长可达70毫米、强烈向下弯曲的喙。头部、颈部、下巴、喉咙及下部均为白色，上身黑色带有蓝光泽，臀部白色，上翼和尾羽黑色；翅膀下覆羽白色；虹膜深棕色，眼周环黑色；喙由蓝灰色渐变为象牙色尖端，口裂黑色；腿脚暗灰至淡蓝色。雌雄相似，幼鸟与成鸟相似，但背部和翼羽末端有淡褐色尖端。","call":"发出各种响亮的尖叫、啼哭和咯咯声，群体成员同步发声，特别是在归巢时。最具特色的叫声是一声响亮的'wa-aah'，类似婴儿哭泣声。联系叫声鼻音重的'gaaa gaaa gaaa'；警报声'kekekeke...'。","habits":"栖息于干燥落叶林和荆棘森林，也能在稀树草原甚至村庄周边的林地中发现。活动范围从海平面至900米海拔。非迁徙物种。以昆虫、蜘蛛、甲虫、蠕虫等无脊椎动物为主食，也捕食小型脊椎动物如壁虎和变色龙。常在大树枝上觅食，利用长喙探入树洞和裂缝寻找食物，有时会倒挂取食。群居，非繁殖季节形成20至30只以上的群体，有时共用超过50只的夜宿地。与白头钩嘴鵙和冠卷尾共同觅食。","breeding":"繁殖季为10月至次年1月，西北部安皮乔罗阿地区。实行多雄制：一雌与多雄交配，所有雄鸟和雌鸟共同喂养幼鸟；雄鸟参与领地防御、抵御捕食者，偶尔参与筑巢、孵卵和孵化。巢呈杯状，直径30至40厘米，由带刺或光滑的小枝构成，内部衬以柔软材料，建于离地面9至16米的树叉中。每窝产3至4枚蛋，乳白色，布满灰色至紫灰色或栗色斑点，孵化期16至18天；幼鸟期19至23天。","identification":"体型远大于白头钩嘴鵙和黑钩嘴鵙，喙更长且显著弯曲。与近缘物种相比，羽毛色彩相似，但体型和喙形差异明显，反映鵙科辐射适应中的形态和生态多样性。","protection":"IUCN：LC（无危）","distribution":"非洲：马达加斯加北部、西部、南部。","other":"常见于多个保护区，如安卡拉凡齐卡国家公园、基林迪和安多哈拉国家公园以及贝伦蒂保护区。"},{"name":"白头钩嘴鵙","english_name":"White-headed Vanga","scientific_name":"Artamella viridis","overview":"白头钩嘴鵙（英文名：White-headed Vanga，学名：Artamella viridis），是雀形目钩嘴鵙科白头钩嘴鵙属的鸟类。仅分布于马达加斯加岛。其特征为雄鸟头部和下体纯白色，雌鸟呈淡灰色，雄雌均有黑色上体带绿金属光泽。属马达加斯加特有种，栖息于低至中海拔的各类森林，偶尔出现在邻近的种植园和灌木丛。","appearance":"体长约20厘米，体重44至57克。雄鸟头部与下体白色，上体黑色并带有绿色光泽，尾部和翼上覆羽黑色，翼下覆羽白色，虹膜深棕色。雌鸟头部灰，喉部较浅，胸淡灰，腹、胁及下尾覆羽白色微带黄褐色。幼鸟与成鸟相似，但冠羽暗色，上体有宽大的棕色边缘。","call":"雄鸟从固定歌位发出哨声'weety-woo weety-woo weety-woo'，对邻近雄鸟的歌声做出反应。有多种响亮的chucking和哨声叫声，包括短促的'whert'。","habits":"主要以昆虫为食，包括蜘蛛、毛虫、蚱蜢和蟋蟀，偶尔摄取小型脊椎动物如变色龙，也会食用果实和种子。在植被的中上层觅食，偶尔在地面活动。善于在各种尺寸的树枝上搜寻食物，即使枝条几乎垂直。会探查剥落树皮下的昆虫，有时摘除碎片，常倒挂。以抓取和啄食为主，也能从叶片和枝条上飞扑捕食。大型猎物用一只脚固定，用大喙撕裂。","breeding":"繁殖期记录于10月至次年1月西北部（Ampijoroa）。有时合作繁殖，一对有时会有帮手，通常是换羽中的幼鸟雄鸟，参与领地防御和驱赶天敌，但不参与喂养雏鸟。巢由双方共建，杯状，由植物纤维和细枝编织，用蛛网覆盖，高度通常6至19米，位于树叉中。每窝产3枚卵，每天一枚，白色，有栗色、灰色和棕色斑点，双亲轮流孵化约19天；雏鸟由双亲共同照料，育雏期22至24天。","identification":"比Chabert鵙大，头部全白；比镰嘴鵙小，喙明显短。雌雄幼鸟间可通过头部颜色、体型和喙的差异进行区分。","protection":"IUCN：LC（无危）","distribution":"分布于马达加斯加岛（除外中部），主要栖息于低至中海拔的森林。","other":"曾被一些权威认为绯胸黄鹂属于Artamella属内。"},{"name":"黑钩嘴鵙","english_name":"Chabert Vanga","scientific_name":"Leptopterus chabert","overview":"黑钩嘴鵙（英文名：Chabert Vanga，学名：Leptopterus chabert），是雀形目钩嘴鵙科黑钩嘴鵙属的鸟类。体型小巧的钩嘴鵙科鸟类，主要分布在马达加斯加的各种森林类型中，有时也会出现在种植园和灌木丛。其特征为黑白两色，具有独特的蓝色眼环，叫声如同其名，发出类似“cha-bert”的干燥声音。相较于白头钩嘴鵙和蓝鵙，黑钩嘴鵙体型更小。","appearance":"体长约14厘米，体重介于17.6至26.7克之间。头部、翅膀和上体呈黑色，光泽下带蓝光，下体白色。虹膜深红色，眼周上方天蓝色，下方深蓝色。喙淡蓝色，腿黑色。幼鸟缺乏蓝色眼环，头部有白色条纹，背部和翼羽边缘白色，随年龄增长逐渐减少。雄雌相似。","call":"发出特有的机械式节奏叫声，每秒重复2-3次，类似“tch-tch-tch-tch”，常由数只鸟同时发出，亦有‘teedee’系列叫声。受刺激时会咔哒作响。","habits":"栖息于各类原生森林，次生林，灌木植被和种植园，甚至远离原生森林的地带。活动海拔从海平面至1000米，偶尔更高。以昆虫、小型脊椎动物和小浆果为食，主要在树冠觅食，擅长倒挂枝梢，空中捕食。通常成小群活动，有时多达约30只，参与混合物种群。","breeding":"繁殖期记录在8月至3月，季节集中在9月至1月。合作繁殖，巢杯状，由植物纤维和蜘蛛网编织而成，悬挂于树的水平枝上，离地面6至19米。产卵3-4枚，蛋壳蓝绿色带斑点，孵化和喂养由双亲及助手共同承担，但孵化和雏鸟期具体时长未知。","identification":"与白头钩嘴鵙相比，体型较小，具黑色顶冠；与蓝鵙相比，背部黑色而非蓝色。不同亚种间尾巴颜色有异，西南部亚种尾基部有白色斑块。","protection":"IUCN：LC（无危）","distribution":"分布于马达加斯加全岛，包括西部、北部和东部，以及西南部特定区域。","other":"黑钩嘴鵙存在两个亚种， chabert分布于马达加斯加西部、北部和东部， schistocercus则限于西南部的半沙漠地带。"},{"name":"蓝钩嘴鵙","english_name":"Madagascar Blue Vanga","scientific_name":"Cyanolanius madagascarinus","overview":"蓝钩嘴鵙（英文名：Madagascar Blue Vanga，学名：Cyanolanius madagascarinus），是雀形目钩嘴鵙科蓝钩嘴鵙属的鸟类。主要分布在非洲马达加斯加岛的干燥落叶森林和雨林中，除了中部地区。其最显著的特征是雄鸟的亮蓝色外观，而雌鸟则颜色稍淡，背部呈现蓝色，腹部为白色或淡黄色。","appearance":"雄性蓝钩嘴鵙全身亮丽的蓝色，眼线黑色，翼尖和尾部边缘呈黑色，喉部和腹部雪白。雌鸟则颜色较暗，腹部偏白色，有时带有淡橙色或浅米色色调。幼鸟头部灰蓝色，上体橄榄绿色，尾部比成年雌鸟更暗淡，喉咙污白色，其余下体橄榄色。","call":"蓝钩嘴鵙的叫声被描述为重复不断的粗糙责骂声，与黑钩嘴鵙类似，但有其独特的声音模式。","habits":"它们生活在中低海拔的森林中，通常以2至6只的小群体活动，特别是在非繁殖季节。蓝钩嘴鵙的食谱主要由昆虫构成，偶尔也会食用浆果。","breeding":"繁殖期大约在10月至12月之间，巢穴位于近垂直细枝间的叉口处，离地面约12米高，由细枝和柔软材料搭建。","identification":"与黑钩嘴鵙相比，蓝钩嘴鵙的背部颜色更为蓝色，雌鸟上半身呈现蓝绿色，叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"广泛分布在马达加斯加的西部干燥落叶林和东部雨林，以及东南部的海岸森林，海拔高度从海平面到约1200米，偶尔可达1600米。","other":"蓝钩嘴鵙在马达加斯加以外的地方未见报道，其历史分布未曾有过重大变化。"},{"name":"科摩罗蓝钩嘴鵙","english_name":"Comoro Blue Vanga","scientific_name":"Cyanolanius comorensis","overview":"科摩罗蓝钩嘴鵙（英文名：Comoro Blue Vanga，学名：Cyanolanius comorensis），是雀形目钩嘴鵙科蓝钩嘴鵙属的鸟类。仅分布于科摩罗群岛的Mohéli和Grand Comoro岛屿，栖息于残留的湿润森林中。","appearance":"雄鸟全身闪耀钴蓝色，喙尖黑色，下至超群的深蓝色喙基，喉及下体明亮白色。雌鸟上体较雄鸟暗淡，下体接近杏白色，喙全黑。雄鸟额头至颈背、耳羽和上颈呈现闪亮的钴蓝色，上体余部至尾上覆羽颜色稍淡。尾部黑色，但部分被蓝色覆盖。雌鸟上体统一蓝色，但头侧和耳羽有细小白点。","call":"叫声为连续不断的粗糙责骂声。","habits":"通常成对出现，常与其他鸟类混群。栖息于科摩罗群岛的残存湿润森林中，活动范围限于较低的树层。","breeding":"相关信息缺失。","identification":"在科摩罗群岛内无类似物种，通过其独特的蓝色外观和叫声即可辨认。","protection":"IUCN：EN（濒危）","distribution":"分布于科摩罗群岛的Grand Comore和Mohéli两岛，栖息于海拔300米以上的森林，以及Grand Comore山的斜坡，海拔约700至900米。","other":"由于栖息地范围有限，面临森林砍伐和入侵植物导致的生境退化威胁。"},{"name":"棕钩嘴鵙","english_name":"Rufous Vanga","scientific_name":"Schetba rufa","overview":"棕钩嘴鵙（英文名：Rufous Vanga，学名：Schetba rufa），是雀形目钩嘴鵙科棕钩嘴鵙属的鸟类。分布于马达加斯加岛，常见于干燥森林与雨林，偏好干燥森林。其显著特征为鲜明的红褐色、黑色与白色相间的羽毛。雄鸟头部至胸部为黑色，带有蓝色光泽，而雌鸟头部为黑色帽状，喉部白色。体型中等，喙宽厚。","appearance":"成年雄鸟头部至胸部、颈背为黑色，带蓝光泽；上体红褐色，初级飞羽暗棕色，次级飞羽和三级飞羽棕红沾染；尾部红褐色；侧胸、胁腹、下腹部及余下下体白色。雌鸟前额、头顶及颈背黑亮，上体除灰色颈环外均为红褐色；上翼及尾部红褐色，内侧初级飞羽灰棕色；颊部、颏部及上喉白色，渐变为浅灰色胸部和胁部，腹部及下尾覆羽白色。幼鸟头黑混杂暗棕色，上体和翅膀暗棕色，尾部暗红褐色，胸部带棕色，虹膜深棕色，喙黑色尖端白色。","call":"鸣唱为悠长的降调、旋律优美的颤音。叫声包括响亮的‘ti-ti-tong’（‘tong’音节音调低得多）可能也是歌曲之一，雌鸟以‘twit-twit-twit’回应。报警声为鼻音的‘ees’。","habits":"生活在低地常绿湿润森林东部和西部的落叶森林，需原始森林环境，海拔0至约800米。坐等捕食者，长时间停留在低枝上观察潜在猎物，捕食昆虫、蠕虫及小型脊椎动物如蜥蜴、变色龙和壁虎。偶尔在地上觅食，很少在空中捕食。飞行罕见，仅作短距离飞行。","breeding":"繁殖季节为10月至次年1月。合作繁殖模式，由成对的鸟和帮手（一年生雄鸟和两年以上的雄鸟）组成。筑巢由配偶双方建造，偶尔得到帮手协助，杯形巢由苔藓、编织的植物纤维和树枝制成，用蜘蛛网固定，通常位于树叉处离地面4米高。一窝产4枚蛋，每天一枚，白色，散布小量深褐色和红色斑点，孵化期14至19天，一般约16天，由双方共同孵化和喂养，助鸟亦参与。雏鸟期12至17天，通常约15天。","identification":"雄鸟头部至胸部黑色，雌鸟黑色帽状头部和白色喉部，是与同类物种区分的主要特征。幼鸟颜色较暗，与成鸟有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于马达加斯加岛，除了中部和西南部。常见于东部的雨林和西部的干燥森林。","other":"依靠未受干扰的森林生存，局部地区数量可观。"},{"name":"盔鵙","english_name":"Helmet Vanga","scientific_name":"Euryceros prevostii","appearance":"体长28至31厘米，体重84至114克。具有显著的大弯喙，长51毫米，深30毫米。头部、翅膀覆羽、飞羽、臀部和尾羽外侧呈纯蓝黑色；背部、肩羽和次级飞羽覆羽以及中央一对尾羽为赤褐色；腹部全黑，腹部、胁部和下尾羽覆羽有淡棕色模糊条纹；虹膜浅奶油色；喙亮蓝色，尖端黑色；腿黑色。两性相似。幼鸟的成年黑色区域为淡黄褐色，赤褐色区域为深棕色；喙最初为角质色。","call":"清晨时发出一系列约8个柔和的哨音'树'音符，音量逐渐降低，常重复数次。领地叫声被描述为悦耳的下降涟漪声，类似''但不如其悠长或发音清晰。警报叫声为粗糙的‘treh treh treh...’或响亮的鼻音‘hink hink hink...'，与''的警报声相似；接触叫声为短暂的哨音‘phu’和更高的‘tseeah’。","habits":"栖息于低地和中低海拔的常绿湿润森林。以昆虫为主食，包括蟑螂、蝴蝶和蛾类、蟋蟀和螽斯、甲虫等，偶尔食用蛙类、壁虎、变色龙和蜥蜴。在森林中层觅食，通常离地面3至10米，长时间静止不动，难以察觉。单独或与其他鵙科鸟类、马岛鹃鵙和其他森林雀形目鸟类混群。","breeding":"繁殖季节为10月至次年1月，仅在马索阿拉半岛观察到。一夫一妻制。杯状巢直径15厘米，由苔藓、编织的植物纤维和枝条制成，放置于距地面2至4米的树叉或棕榈叶旋涡内。产卵2至3枚，粉白色，带有洋红色斑点，尤其在较大端明显；雄鸟和雌鸟共同孵卵和育雏；孵化期和育雏期未知，雏鸟期约17天。","identification":"体型大，具有显著的蓝色巨大弯喙和赤褐色背部，容易识别。与同属物种如赤褐色鵙相比，弯喙更为巨大。","protection":"IUCN：EN（濒危）","distribution":"分布于马达加斯加东北部，包括Marojejy、Tsaratanana和Mantadia等地。","other":"面临栖息地丧失威胁，依赖于未受干扰的湿润雨林，因农业和林业开发导致栖息地快速减少，种群数量严重碎片化和下降。"},{"name":"泰拉钩嘴鵙","english_name":"Tylas Vanga","scientific_name":"Tylas eduardi","overview":"泰拉钩嘴鵙（英文名：Tylas Vanga，学名：Tylas eduardi），是雀形目钩嘴鵙科泰拉钩嘴鵙属的鸟类。属于雀形目。其最显著的特征是拥有白色颈圈、黑色头部和通常呈赤褐色的下体。该物种主要栖息于东部雨林，偶尔在西部干燥落叶林中可见，其中白胸亚种更为常见。","appearance":"成年泰拉钩嘴鵙体型中等，长约20-21厘米，体重在35.5至54克之间。雄鸟具有黑色头颈部，绿色灰色的上体，上翼为绿灰色，初级飞羽深棕色，尾巴绿褐色。颈侧和上胸部有一白色带，其余下体颜色变化较大，常带有橙色色调。翼下覆羽白色，偶尔可见深橙色胸部和白色喉部。眼睛通常是深棕色，偶尔浅色，喙黑色，腿灰色至黑色。雌雄相似，幼鸟翼羽边缘淡黄色，下巴稍淡，有时额头白色，喙基部淡橙色。","call":"其最常见的叫声是一系列快速音符，随后是一个爆发性的哨声：“chu-chow-wheeeet”。歌曲为‘weeta weet yew ew’，特征性的‘tu-too whirrit’系列，包括至少一个鞭打般的音符。接触呼叫为安静的‘whit-whit-whit’或‘quip-quip’。","habits":"泰拉钩嘴鵙主要生活在马达加斯加的东部雨林，偶尔出现在西部的干燥落叶林中，海拔高度从海平面到1800米。它们是群居性鸟类，常加入混合物种群。主要以昆虫为食，如蝴蝶、毛虫、蜻蜓、马蝇和其他双翅目昆虫、蚱蜢、蜗牛和蜘蛛。它们在森林的中上层觅食，通过悬停和伏击捕捉猎物。","breeding":"繁殖季节为10月至次年1月（东马达加斯加），可能在8月至9月（西部）。一夫一妻制，以简单配对形式繁殖。雄鸟保卫领地。杯状巢直径9.5厘米，由两性共同建造，材料包括枯叶、蛛网和苔藓，通常位于树叉处距地面4-7米。每次产卵2枚，蛋壳绿色带蓝，表面散布着少量的栗色和红灰色斑点，孵化期约为16天，主要由雌鸟承担。幼鸟由雌鸟主要照料，雄鸟辅助，双亲喂养，雏鸟期约15天。","identification":"与白额厚嘴鵙相比，泰拉钩嘴鵙的喙较小。与Ashy Cuckooshrike相似，但下体颜色为黄褐色或偶尔白色，而非灰色。","protection":"IUCN：LC（无危）。指名亚种种群在大部分分布区内普遍常见，而albigularis亚种稀少且分布零散，仅在马达加斯加西北部至Mangoky区域的少数地点记录到，需进一步研究确定其分布和种群数量。","distribution":"泰拉钩嘴鵙分布在马达加斯加中部、西部和东部。在东部，它们主要栖息于原始雨林和相邻的次生林；在西部，albigularis亚种在落叶干燥森林和红树林中被记录，海拔高度从海平面到约900米。","other":"泰拉钩嘴鵙仅限于原生森林生存，目前在多个保护区中得到保护。"},{"name":"红嘴钩嘴鵙","english_name":"Nuthatch Vanga","scientific_name":"Hypositta corallirostris","overview":"红嘴钩嘴鵙（英文名：Nuthatch Vanga，学名：Hypositta corallirostris），是雀形目钩嘴鵙科红嘴钩嘴鵙属的小型蓝色鸟类，仅分布于马达加斯加东北部至东部。以其独特的树干攀爬觅食行为而著称。","appearance":"体长约13至14厘米，体重13.5至15.5克。雄鸟全身呈中蓝色，腹部略带淡黄色；雌鸟背部蓝绿色，头部褐色，胸部及腹部淡黄色。两性均具鲜亮珊瑚红色的长喙，腿色深灰。幼鸟类似雌鸟，但随着成长，雄鸟幼鸟头部和胸部逐渐显现蓝色。","call":"最常见的是高音、加速、模糊的颤音叫声。","habits":"栖息于未受干扰的常绿湿润森林，海拔从海平面至1800米，主要在1000米以下。以小昆虫、甲虫、蟑螂、蠕虫和其他小型脊椎动物为食。通常成对出现，加入混群，与多种鸟类共同活动。","breeding":"繁殖季节可能在8月至9月，巢由活苔藓和死苔藓制成的杯状结构，固定于树干上。具体繁殖细节未知。","identification":"通过其体型、颜色和树干攀爬的行为模式很容易识别，尤其是独特的珊瑚红色长喙。","protection":"IUCN：LC（无危）；物种分布受限，但在多个保护区中局部常见。","distribution":"分布于马达加斯加北部至东部，主要集中在北部地区，南部较为罕见。","other":"神秘的'perdita'形式很少被提及，当被认为是有效分类单元时，被视为数据不足的分类群。"},{"name":"暗牛顿莺","english_name":"Dark Newtonia","scientific_name":"Newtonia amphichroa","overview":"暗牛顿莺（英文名：Dark Newtonia，学名：Newtonia amphichroa），是雀形目钩嘴鵙科牛顿莺属的鸟类。为马达加斯加东北部特有种。栖息于热带湿润低地森林，常见于中海拔的东部雨林。体型小巧，精力充沛且好斗。","appearance":"该鸟体长约12厘米，体重9至18克。其外观为橄榄褐色，头顶部及上身颜色较深，略带橄榄褐色，臀部和尾羽覆羽颜色较暖。上翼为橄榄褐色，飞羽稍深，边缘宽阔且呈淡橄榄色。尾羽为橄榄褐色。下身颜色为深黄褐色或橄榄黄褐色，颏部和喉部颜色较浅，胸部和侧腹颜色较深且偏棕色；尾下覆羽为淡黄色。虹膜为金黄色，看似深色。喙黑色或深褐色，腿深灰色。雌雄同形同色，幼鸟在离巢初期比成鸟更偏赤褐色，尤其是臀部和下身，冠羽和背羽有较淡的羽轴；眼睛为灰褐色。","call":"鸣唱复杂，自近地面灌木发出响亮滚动的颤音，持续3至5秒，叫声为尖锐的“shreep”，常伴随反复轻柔的“pit”。","habits":"暗牛顿莺在中层林间不断移动，通常成对出现。生活在马达加斯加东部雨林，偏好中海拔地区。","identification":"与普通牛顿莺相比，暗牛顿莺眼色更深，整体颜色更暗；与罕见的红尾牛顿莺相比，颜色更为暗淡。2018年的一项研究表明，暗牛顿莺与南部暗牛顿莺（N. lavarambo）在遗传和物理特性上有显著差异，因此被区分为不同物种。","protection":"IUCN：LC（无危）","distribution":"主要分布在马达加斯加西北部山区和东部地区。"},{"name":"棕尾牛顿莺","english_name":"Common Newtonia","scientific_name":"Newtonia brunneicauda","overview":"棕尾牛顿莺（英文名：Common Newtonia，学名：Newtonia brunneicauda），是雀形目钩嘴鵙科牛顿莺属的小型鸟类。具有明显的白色眼睛和橙色胸部中心。马达加斯加特有种，广泛分布于各种森林环境中。","appearance":"体长约12厘米，体重介于7至14克。头部和上体呈冷灰褐色，头颈两侧颜色略浅。上翼覆羽灰褐，与背部颜色一致，飞羽稍暗，具细小的淡黄色边缘。尾巴灰褐色，外侧羽毛较淡。下体呈温暖的淡黄色，下巴、喉咙和腹部更白，臀部羽毛偏白。虹膜呈奶油黄至金黄色，喙黑色，腿为淡粉色或灰褐色。雌雄相似，幼鸟上体比成鸟更棕色，翅膀大覆羽尖端有变异性红棕色，三级飞羽有姜黄色调，虹膜深灰褐色。","call":"鸣唱时从栖木发出连续的‘kitrikitrikitrik’颤音，持续2至3秒；叫声包括刺耳响亮的‘shir, shir shir’。","habits":"常在树冠中层活跃移动，通常成对出现，经常加入由鵙和其他中等体型鸟类组成的混合群。以昆虫为食，广泛分布于马达加斯加，栖息于从海平面到海拔2,300米的各种森林和树木环境，主要局限于本土森林。","breeding":"关于生长繁殖的信息在现有资料中未提及。","identification":"与暗牛顿莺的区别在于其较浅的整体色调和苍白的眼睛。与罕见的红尾牛顿莺区别也在于其苍白的眼睛。与阿氏牛顿莺相比，没有眼周的红褐色。亚种monticola比指名亚种更大，上体颜色更深，下体色彩更丰富。","protection":"IUCN状态未提供。","distribution":"主要分布在非洲的马达加斯加，包括从海平面至海拔2,300米的森林地带。","other":"无"},{"name":"阿氏牛顿莺","english_name":"Archbold's Newtonia","scientific_name":"Newtonia archboldi","overview":"阿氏牛顿莺（英文名：Archbold's Newtonia，学名：Newtonia archboldi），是雀形目钩嘴鵙科牛顿莺属的鸟类。特有于马达加斯加。其显著特征包括眼周的红褐色环和苍白的眼色，以及略带淡黄色调的下体。分布于马达加斯加南部的棘森林和干燥落叶林。","appearance":"阿氏牛顿莺是一种小型、短翼、长腿的雀鸟，体长约12厘米，体重7-8.5克。上体灰褐，头部前方和眼周有红褐色斑块；顶冠至背部呈灰褐色；脸颊和耳羽灰褐色，有时带有红褐色调；尾部灰褐色，边缘泛白；翅膀灰褐色，暗色飞羽边缘泛白；下颚和喉部淡黄白色，胸部和两胁肉桂色，腹部和下尾覆羽变为淡黄白色；虹膜淡黄白色；喙黑色；腿色由浅灰色至黑色。性别相似，幼鸟头部红褐色较少，次级飞羽边缘明显泛肉桂色，大覆羽尖端宽而红褐色。","call":"其鸣唱是从隐蔽的栖木发出独特变化的颤音，由4或5个音节组成：“tee-too tekhew”或“chichichich wit-tee tew”。叫声包括训斥般的“tchiew”。","habits":"阿氏牛顿莺栖息于棘Dideria和Euphorbia森林及其相邻的灌木丛生植被，以及退化的落叶森林边缘；海拔从海平面到100米。它们似乎不迁徙，全年定居于其范围内。以小节肢动物为食，包括蜘蛛、甲虫、同翅目昆虫、白蚁和鳞翅目昆虫。它们活跃地在灌木和低树的枝条间跳跃觅食，从枝条和树叶中获取食物。","breeding":"关于繁殖的资料非常有限。幼鸟在11月至12月被观察到。巢穴是隐藏在低矮密集灌木中的深杯状巢。除此之外，没有更多信息。","identification":"与棕尾牛顿莺相似，但眼周有红褐色环，鸣唱不同。","protection":"IUCN：LC（无危）","distribution":"主要分布在马达加斯加西南部，从Morondava南部沿着海岸向南至Fort Dauphin西部约100公里的狭窄地带。","other":"纪念新几内亚探险家兼鸟类学家Richard Archbold而命名。"},{"name":"红尾牛顿莺","english_name":"Red-tailed Newtonia","scientific_name":"Newtonia fanovanae","overview":"红尾牛顿莺（英文名：Red-tailed Newtonia，学名：Newtonia fanovanae），是雀形目钩嘴鵙科牛顿莺属的鸟类。头部呈灰色，背部显现出独特的红褐色，腹部则为白色。这种稀有而神秘的马达加斯加特有种鸟，仅在东部雨林的低至中海拔地带被发现，分布零散。其鸣声由一系列响亮的“wheet”或“chu-wheet”音符组成。","appearance":"体型小巧，长度约12厘米，体重仅12.5克。头部顶部及侧面为灰烬色，与灰褐色的背部、肩羽及臀部形成鲜明对比，上尾覆羽呈现淡褐色。翅膀颜色较深，具有一块由浅锈色边缘形成的明显浅色区域。尾巴羽毛为红褐色，边缘和尖端颜色较暗。下巴、喉咙及腹部皆为白色，胸部两侧及两肋带有变异性较强的肉桂色。眼睛虹膜为红棕色，可能为深棕色；喙部上侧黑色或暗角质色，下侧较浅的灰色；腿脚为深角质色或黑色。雌雄外观相似，幼鸟特征尚未详细描述。","call":"其鸣唱由一连串5至15个下降的‘pitchi’或‘swee’音符构成，同时伴有嗡嗡声的叫声。","habits":"主要以昆虫为食，常在森林树冠层高处觅食，通常与其他树栖物种一同活动。捕食方式多样，既能在枝梢间飞扑捕食，也能悬停取食，比棕尾牛顿莺更为灵活。活动范围主要限于未受破坏的低地森林地带，低于800米的海拔。","identification":"与更常见的红尾钩嘴鵙相比，红尾牛顿莺体型更小，喙部较小且更尖锐，眼部周围无淡黄色环状斑纹。其深色的眼睛和更为鲜艳的羽毛使其区别于Common和暗牛顿莺s。","protection":"IUCN：VU（易危）。自1989-90年重新发现以来，已知分布于马达加斯加东部的Anjanaharibe-sud至Andohahela国家公园之间，但分布零散，主要存在于未受破坏的低地森林。尽管在七个保护区有所记录，但其适宜生存的栖息地正遭受严重的农耕威胁，且在当前的保护区内所占比例极小。该物种仅在上述保护区中残存的低地森林部分出现，且在Masoala国家公园中未见踪迹。","distribution":"分布在马达加斯加东部，自最北端的Anjanaharibe-sud至最南端的Andohahela国家公园，包括Marojejy和Zahamena国家公园在内的多个保护区内。"}];
